xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:9:\"Nha Trang\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:26:\"Nha Trang WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1161\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:348:\"⭐ Đăng ký tham dự Nha Trang WordPress Meetup 25/08/2024 ⭐ Xin chào tất cả mọi người, vậy là Nha Trang WordPress Meetup đã quay trở lại sau nhiều tháng gián đoạn, Meetup 25/08/2024 sẽ diễn ra để chào mừng sinh nhật lần 21 và phiên bản mới nhất WordPress 6.6.1 của mã nguồn mở [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"Nguyễn Xuân Bình Minh\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8537:\"\n<figure class=\"wp-block-image aligncenter size-large\"><a href=\"https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-1024x576.jpg\" alt=\"\" class=\"wp-image-1172\" srcset=\"https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-1024x576.jpg 1024w, https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-300x169.jpg 300w, https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-768x432.jpg 768w, https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX.jpg 1200w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đăng ký tham dự Nha Trang WordPress Meetup 25/08/2024 <img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></strong></p>\n\n\n\n<p>Xin chào tất cả mọi người, vậy là Nha Trang WordPress Meetup đã quay trở lại sau nhiều tháng gián đoạn, Meetup 25/08/2024 sẽ diễn ra để chào mừng sinh nhật lần 21 và phiên bản mới nhất WordPress 6.6.1 của mã nguồn mở xây dựng website phổ biến nhất thế giới WordPress tại thành phố biển Nha Trang.</p>\n\n\n\n<p>WordPress là nền tảng xuất bản mã nguồn mở được hàng triệu trang web trên toàn thế giới lựa chọn—từ người sáng tạo và doanh nghiệp nhỏ đến các doanh nghiệp lớn.</p>\n\n\n\n<p>Lần này Ban tổ chức sẽ mang đến cho toàn thể các bạn yêu mến WordPress tại Nha Trang các chủ đề hấp dẫn như sau</p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f4a5.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Chủ đề 1: Quy trình xử lý mã độc cho website WordPress</strong><br>Speaker: Nguyễn Xuân Bình Minh &#8211; CEO Minh Duy Solutions</p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f4a5.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Chủ đề 2: Bí quyết x10 doanh số với chiến lược phễu bán hàng trong WordPress</strong><br>Speaker: Nguyễn Minh Phụng &#8211; CEO Công ty TNHH Giải Pháp ETI</p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f4a5.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Chủ đề 3: 5 Ways to increase your Businesses Profits</strong><br>Speaker: Hà Anh Lĩnh &#8211; CEO Công ty TNHH TM &amp; DV ANHLINHMKT</p>\n\n\n\n<p><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /><strong> Hình thức: </strong>Offline</p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Thời gian tổ chức: 08h30 ngày 25/08/2024</strong></p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Địa điểm: </strong>Stockholm Bistro &amp; Co-working<br>43 Lý Tự Trọng, Thành phố Nha Trang, Khánh Hoà<br>Google Maps: <a href=\"https://g.co/kgs/Ke3J66q\">https://g.co/kgs/Ke3J66q</a> </p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Phí tham dự:</strong><br>&#8211; Miễn phí tham dự<br>&#8211; Số lượng tối đa: 30 người</p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đăng ký tham dự tại: </strong> <a href=\"https://forms.gle/5in6wkP7Yjn1jhT9A\" target=\"_blank\" rel=\"noreferrer noopener\">https://forms.gle/5in6wkP7Yjn1jhT9A</a></p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đơn vị tài trợ chính:</strong><br><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Công ty TNHH Xây Dựng &amp; Công Nghệ Quỳnh An (<a href=\"https://www.solar-nhatrang.com/\" data-type=\"link\" data-id=\"https://www.solar-nhatrang.com/\" target=\"_blank\" rel=\"noreferrer noopener\">Quỳnh An Solar</a>)<br><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> CÔNG TY CỔ PHẦN FUTE (<a href=\"https://web2m.com/\" data-type=\"link\" data-id=\"https://web2m.com/\" target=\"_blank\" rel=\"noreferrer noopener\">Web2M</a> &amp; <a href=\"https://pay2s.vn/\" data-type=\"link\" data-id=\"https://pay2s.vn/\" target=\"_blank\" rel=\"noreferrer noopener\">Pay2S</a>)</p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đơn vị tổ chức: <a href=\"https://minhduy.vn/\" data-type=\"link\" data-id=\"https://minhduy.vn/\" target=\"_blank\" rel=\"noreferrer noopener\">Minh Duy Solutions</a></strong></p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Các kênh truyền thông khác</strong><br>&#8211; Meetup: <a href=\"https://www.meetup.com/nha-trang-marketing-meetup/events/302732875/\">https://www.meetup.com/nha-trang-marketing-meetup/events/302732875/</a><br>&#8211; Facebook Event: <a href=\"https://www.facebook.com/events/1864084187435658/\">https://www.facebook.com/events/1864084187435658/</a> </p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Câu hỏi thường gặp</strong><br><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f449.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Nha Trang WordPress Meetup là hoạt động offline hàng tháng nhằm phát triển cộng đồng yêu thích và sử dụng WordPress tại Nha Trang<br><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f449.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Nha Trang WordPress Meetup là LOCAL GROUP chính thức được công nhận bởi WordPress.Org hoạt động từ năm 2016.<br><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f449.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Nha Trang WordPress Meetup là chương trình hoàn toàn miễn phí, không thu phí tham dự đối với người tham gia (Trừ một số trường hợp phải hỗ trợ Ban tổ chức chi phí thuê địa điểm tổ chức meetup)</p>\n\n\n\n<p><strong><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> The Five Good Faith Rules</strong><br>5 Nguyên tắc đảm bảo các group theo tinh thần Của WordPress khi tổ chức meetup xây dựng cộng đồng<br>&#8211; Phi lợi nhuận: Hướng tới cả cộng đồng, không phục vụ cho một tổ chức kinh doanh nào.<br>&#8211; Mọi người đều được tham gia, không phân biệt về tiền bạc, khả năng về lập trình…<br>&#8211; Không trả tiền cho Speakers, nếu có chi phí thêm thì chỉ là những chi phí cho meetup như thuê địa điểm, nước uống.<br>&#8211; Các meetup có thể do bất cứ ai trong group mà có thể tin tưởng được để tổ chức.<br>&#8211; Không có các hành động xúc phạm về bất cứ ai, bất cứ vấn đề gì trong meetup.</p>\n\n\n\n<p><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f3af.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Lưu ý:<br>– Các sản phẩm mà không có GPL thì không được phép trình bày tại meetup<br>– Không giới thiệu kiểu sale, bán các sản phẩm mà vi phạm bản quyền.</p>\n\n\n\n<p><br>#NhaTrangWordPress #MeetUp #NhaTrang #WordPress</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://vi.wordpress.org/2024/08/09/dang-ky-tham-du-nha-trang-wordpress-meetup-25-08-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1161\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Hà Nội WordPress Meetup tháng 04.2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2024/04/08/ha-noi-wordpress-meetup-thang-04-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"https://vi.wordpress.org/2024/04/08/ha-noi-wordpress-meetup-thang-04-2024/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 08 Apr 2024 03:22:23 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:22:\"Hanoi WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1146\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:346:\"Sự kiện dành cho các bạn quan tâm tới cách sử dụng WordPress ở mức độ mới tìm hiểu. Trong buổi Meetup lần này, bạn sẽ được tham gia buổi giới thiệu về WordPress, những gì cơ bản nhất để tiếp cận WordPress và sử dụng nó để làm blog, trang giới thiệu cơ bản [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:1526:\"\n<p>Sự kiện dành cho các bạn quan tâm tới cách sử dụng WordPress ở mức độ mới tìm hiểu. Trong buổi Meetup lần này, bạn sẽ được tham gia buổi giới thiệu về WordPress, những gì cơ bản nhất để tiếp cận WordPress và sử dụng nó để làm blog, trang giới thiệu cơ bản hoặc thậm chí là website bán hàng.</p>\n\n\n\n<span id=\"more-1146\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Địa điểm</h2>\n\n\n\n<p>Tầng 5, Toà nhà Đinh Trọng Dật, Đường CN1, Xuân Phương, Bắc Từ Liêm, Hà Nội (<a href=\"https://maps.app.goo.gl/GodtTVGattFQGdnE9\" data-type=\"link\" data-id=\"https://maps.app.goo.gl/GodtTVGattFQGdnE9\">xem bản đồ</a>)</p>\n\n\n\n<p><em>Cảm ơn đơn vị hỗ trợ về địa điểm: <strong><a href=\"https://itci.edu.vn/\">Viện Đào Tạo Và Hợp Tác Quốc Tế ITCI &#8211; Đại học Công Nghệ Đông Á</a></strong>. </em></p>\n\n\n\n<h2 class=\"wp-block-heading\">Lịch trình dự kiến</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>18:00 – 18:15: Networking</li>\n\n\n\n<li>18:15 – 18:45: Điểm tin WordPress</li>\n\n\n\n<li>18:45 &#8211; 19:15: Sử dụng WordPress cơ bản</li>\n\n\n\n<li>19:15 &#8211; 19:45: Thảo luận mở về WordPress</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia</h2>\n\n\n\n<p>Để việc chuẩn bị được tốt nhất, các bạn <a href=\"https://www.meetup.com/hanoi-wordpress-meetup/events/300180394/\">đăng ký tham dự tại trang chính thức Meetup</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://vi.wordpress.org/2024/04/08/ha-noi-wordpress-meetup-thang-04-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1146\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Hà Nội WordPress Meetup tháng 01.2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2024/01/04/ha-noi-wordpress-meetup-thang-01-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"https://vi.wordpress.org/2024/01/04/ha-noi-wordpress-meetup-thang-01-2024/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 04 Jan 2024 13:05:01 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:22:\"Hanoi WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1136\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:350:\"Những ai đang sử dụng và yêu thích WordPress lại có cơ hội gặp nhau tại buổi meetup đầu tiên của năm 2024, được tổ chức bởi cộng đồng WordPress tiếng Việt. Thời gian và địa điểm Đăng ký tham gia Hãy đăng ký trước để đảm bảo có vị trí ngồi trong buổi meetup. [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2574:\"\n<p>Những ai đang sử dụng và yêu thích WordPress lại có cơ hội gặp nhau tại buổi meetup đầu tiên của năm 2024, được tổ chức bởi cộng đồng WordPress tiếng Việt.</p>\n\n\n\n<span id=\"more-1136\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Thời gian và địa điểm</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Thời gian: <strong>08:30 &#8211; 11:30 ngày 06.01.2024</strong></li>\n\n\n\n<li>Địa điểm: Trường CĐ Việt Mỹ (Cơ sở 2) &#8211; Coworking tầng 5, <strong>số 39 Hoàng Quán Chi, Cầu Giấy</strong>, Hà Nội (gần CV Cầu Giấy) &#8211; <a href=\"https://maps.app.goo.gl/z1xVwgVEAD5bzYny5\" data-type=\"link\" data-id=\"https://maps.app.goo.gl/z1xVwgVEAD5bzYny5\">link bản đồ</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia</h2>\n\n\n\n<p>Hãy đăng ký trước để đảm bảo có vị trí ngồi trong buổi meetup.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-vivid-red-background-color has-background wp-element-button\" href=\"https://forms.gle/9oqvSJDm6pAhfZtCA\">Đăng ký tham gia meetup</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Các chủ đề trong chương trình</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Build Your GeneratePress Theme</h3>\n\n\n\n<p>Speaker: Nguyễn Minh Khôi (Founder/CEO <strong>Code Tốt</strong> &#8211; Locale Manager &#8211; WordPress tiếng Việt)</p>\n\n\n\n<h3 class=\"wp-block-heading\">Build a website with YooTheme Builder Framework</h3>\n\n\n\n<p>Speaker: Vũ Mạnh Tiến (Founder/CEO Jupiter Media)</p>\n\n\n\n<h3 class=\"wp-block-heading\">Make Money from Google Adsense</h3>\n\n\n\n<p>Speaker: Nguyễn Công Minh (Founder SEO Thành Công)</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>Ngoài ra, còn một phiên thảo luận tự do về WordPress và các vấn đề liên quan dành cho các bạn tham gia.</p>\n</blockquote>\n\n\n\n<h2 class=\"wp-block-heading\">Tổ chức cùng đồng hành với Meetup</h2>\n\n\n\n<p>Dù đây là chương trình không thu phí, BTC xin cảm ơn sự đồng hành của các đơn vị nhằm giúp chương trình diễn ra có chất lượng hơn.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Trường Cao đẳng Việt Mỹ (hỗ trợ địa điểm và tình nguyện viên)</li>\n\n\n\n<li><a href=\"https://hazomedia.com/\" data-type=\"link\" data-id=\"https://hazomedia.com/\">HazoMedia</a></li>\n\n\n\n<li>HostVN</li>\n\n\n\n<li>VietCham Singapore (quà tặng)</li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://vi.wordpress.org/2024/01/04/ha-noi-wordpress-meetup-thang-01-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1136\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Sài Gòn WordPress Meetup tháng 08.2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://vi.wordpress.org/2023/08/02/sai-gon-wordpress-meetup-08-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://vi.wordpress.org/2023/08/02/sai-gon-wordpress-meetup-08-2023/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 02 Aug 2023 03:14:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:26:\"Sài Gòn WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1088\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:342:\"Vào ngày 19.08.2023 tới đây, những người yêu thích WordPress tại Sài Gòn sẽ cùng nhau gặp gỡ và chia sẻ về các chủ đề thú vị. Thời gian 13:30 &#8211; 17:30 ngày 19.08.2023 Địa điểm 8 Trần Quang Diệu, phường 14, quận 3, TP. HCM Nội dung thảo luận Chủ đề 1: Tối ưu [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2428:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"577\" src=\"https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-1024x577.png\" alt=\"\" class=\"wp-image-1089\" srcset=\"https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-1024x577.png 1024w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-300x169.png 300w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-768x433.png 768w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-1536x865.png 1536w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023.png 1640w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p>Vào ngày 19.08.2023 tới đây, những người yêu thích WordPress tại Sài Gòn sẽ cùng nhau gặp gỡ và chia sẻ về các chủ đề thú vị.</p>\n\n\n\n<span id=\"more-1088\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Thời gian</h2>\n\n\n\n<p><strong>13:30 &#8211; 17:30</strong> ngày <strong>19.08.2023</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Địa điểm</h2>\n\n\n\n<p><strong>8 Trần Quang Diệu, phường 14, quận 3, TP. HCM</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Nội dung thảo luận</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Chủ đề 1: Tối ưu tốc độ website WordPress</h3>\n\n\n\n<p class=\"has-medium-font-size\"><strong>Khôi Nguyễn</strong></p>\n\n\n\n<p class=\"has-small-font-size\">Founder/CEO <strong><a href=\"https://codetot.vn/ve-code-tot/\">Code Tốt</a></strong><br>CTO <strong>Nhà Phố Net</strong><br>Locale Manager tại <strong>WordPress tiếng Việt</strong><br>Admin nhóm <strong><a href=\"https://www.facebook.com/groups/toiuuweb\">Tối ưu Web</a></strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia Meetup</h2>\n\n\n\n<p>Bạn vào nhóm Zalo <a href=\"https://zalo.me/g/hblyng586\" data-type=\"link\" data-id=\"https://zalo.me/g/hblyng586\">WordPress Meetup Sài Gòn</a> để vote chủ đề yêu thích.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Đơn vị tài trợ và đồng hành</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://123host.vn\" data-type=\"link\" data-id=\"https://123host.vn\">123Host</a></li>\n\n\n\n<li><a href=\"https://interdata.vn/\">InterData</a></li>\n\n\n\n<li><a href=\"https://vietnix.vn/\">Vietnix</a></li>\n\n\n\n<li>Giải Pháp SEO</li>\n\n\n\n<li>In Hương Giang</li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2023/08/02/sai-gon-wordpress-meetup-08-2023/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1088\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"Online Meetup Nha Trang tháng 08.2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2023/08/02/online-meetup-nha-trang-thang-08-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://vi.wordpress.org/2023/08/02/online-meetup-nha-trang-thang-08-2023/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 02 Aug 2023 02:54:30 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:26:\"Nha Trang WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1085\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:355:\"Vào ngày 13/08/2023, những người yêu thích WordPress tại Nha Trang sẽ tổ chức một buổi thảo luận để kết nối mọi người đã, đang và sẽ sử dụng WordPress tại Nha Trang sau một thời gian dài tạm dừng hoạt động meetup do COVID. Các chủ đề thảo luận Topic 1: Kinh nghiệm tối [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2966:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"538\" src=\"https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-1024x538.png\" alt=\"\" class=\"wp-image-1086\" srcset=\"https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-1024x538.png 1024w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-300x158.png 300w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-768x403.png 768w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-1536x807.png 1536w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-2048x1075.png 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p>Vào ngày 13/08/2023, những người yêu thích WordPress tại Nha Trang sẽ tổ chức một buổi thảo luận để kết nối mọi người đã, đang và sẽ sử dụng WordPress tại Nha Trang sau một thời gian dài tạm dừng hoạt động meetup do COVID.</p>\n\n\n\n<span id=\"more-1085\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Các chủ đề thảo luận</h2>\n\n\n\n<h3 class=\"wp-block-heading has-medium-font-size\"><strong>Topic 1: Kinh nghiệm tối ưu website WordPress mới nhất</strong></h3>\n\n\n\n<p class=\"has-medium-font-size\"><strong>Khôi Nguyễn</strong></p>\n\n\n\n<p class=\"has-small-font-size\">Founder/CEO&nbsp;<strong><a href=\"https://codetot.vn/ve-code-tot/\">Code Tốt</a></strong><br>CTO&nbsp;<strong>Nhà Phố Net</strong><br>Locale Manager tại&nbsp;<strong>WordPress tiếng Việt</strong><br>Admin nhóm&nbsp;<strong><a href=\"https://www.facebook.com/groups/toiuuweb\">Tối ưu Web</a></strong></p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Topic 2: Thiết Kế Website với WordPress dành cho Marketer</strong></h3>\n\n\n\n<p><a href=\"https://vominhhuy.com/\" data-type=\"link\" data-id=\"https://vominhhuy.com/\"><strong>Võ Minh Huy</strong></a></p>\n\n\n\n<p class=\"has-small-font-size\">Founder <a href=\"https://tadateam.com/\" data-type=\"link\" data-id=\"https://tadateam.com/\">TADA</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Thời gian</h2>\n\n\n\n<p>08h30 – 11h00 ngày 13/08/2023 (GMT +7)</p>\n\n\n\n<h2 class=\"wp-block-heading\">Địa điểm</h2>\n\n\n\n<p>Trực tuyến qua Google Meet hoặc Zoom (sẽ thông báo qua email)</p>\n\n\n\n<p>Hãy gia nhập trên <a href=\"https://zalo.me/g/uhmmlm126\">nhóm Zalo</a> để nhận cập nhật liên kết tham gia.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia</h2>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://forms.gle/4zxDZUb8jNLBFboY8\">Đăng ký tham gia</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Đồng tổ chức</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Hỗ trợ tổ chức sự kiện: <a href=\"https://minhduy.vn\">Minh Duy Solutions</a>.</li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://vi.wordpress.org/2023/08/02/online-meetup-nha-trang-thang-08-2023/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1085\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"Recap: WordPress Meetup Hà Nội tháng 07/2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://vi.wordpress.org/2023/07/22/recap-wordpress-meetup-ha-noi-thang-07-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://vi.wordpress.org/2023/07/22/recap-wordpress-meetup-ha-noi-thang-07-2023/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 22 Jul 2023 22:53:23 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:22:\"Hanoi WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"Recap Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1078\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:341:\"Cảm ơn anh chị em đã tham dự WordPress Meetup tại Hà Nội tháng 07/2023. Đã tròn một năm mới thấy sự quay trở lại của Meetup, và sự nhiệt thành, cùng nhau đóng góp, trao đổi đã khơi dậy rất nhiều năng lượng cho mỗi người. Trong buổi hôm nay, đại diện từ Code [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5857:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/07/image-2.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"767\" src=\"https://vi.wordpress.org/files/2023/07/image-2-1024x767.png\" alt=\"WordPress Meetup Hà Nội tháng 07/2023\" class=\"wp-image-1081\" srcset=\"https://vi.wordpress.org/files/2023/07/image-2-1024x767.png 1024w, https://vi.wordpress.org/files/2023/07/image-2-300x225.png 300w, https://vi.wordpress.org/files/2023/07/image-2-768x575.png 768w, https://vi.wordpress.org/files/2023/07/image-2-440x330.png 440w, https://vi.wordpress.org/files/2023/07/image-2.png 1276w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p>Cảm ơn anh chị em đã tham dự WordPress Meetup tại Hà Nội tháng 07/2023. Đã tròn một năm mới thấy sự quay trở lại của Meetup, và sự nhiệt thành, cùng nhau đóng góp, trao đổi đã khơi dậy rất nhiều năng lượng cho mỗi người.</p>\n\n\n\n<span id=\"more-1078\"></span>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/07/image.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"569\" src=\"https://vi.wordpress.org/files/2023/07/image-1024x569.png\" alt=\"Tối ưu Web mới nhất từ Code Tốt\" class=\"wp-image-1079\" srcset=\"https://vi.wordpress.org/files/2023/07/image-1024x569.png 1024w, https://vi.wordpress.org/files/2023/07/image-300x167.png 300w, https://vi.wordpress.org/files/2023/07/image-768x427.png 768w, https://vi.wordpress.org/files/2023/07/image.png 1094w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p>Trong buổi hôm nay, đại diện từ Code Tốt đã chia sẻ những định hướng tối ưu web hiệu quả và có mục, đúng mục đích, đạt kết quả. Đó không chỉ là việc tối ưu PageSpeed Web, mà là tổng thể phải xác định mục tiêu dùng website vào việc gì và các bước tiến hành ra sao.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/07/image-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"572\" src=\"https://vi.wordpress.org/files/2023/07/image-1-1024x572.png\" alt=\"Tìm hiểu về ReactJS, NextJS\" class=\"wp-image-1080\" srcset=\"https://vi.wordpress.org/files/2023/07/image-1-1024x572.png 1024w, https://vi.wordpress.org/files/2023/07/image-1-300x168.png 300w, https://vi.wordpress.org/files/2023/07/image-1-768x429.png 768w, https://vi.wordpress.org/files/2023/07/image-1.png 1291w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p>Ở phần chia sẻ của anh Hoàng từ Melisoft về mô hình NextJS sử dụng API từ bên thứ ba (như WordPress REST API), tập trung vào việc xoay quanh mô hình mô-đun hoá, tinh chỉnh liên tục, tạo ra những nền tảng có mức độ tái sử dụng cao. Anh Hoàng cũng đã giới thiệu một số kiến trúc được phát triển và tạo ra MeliPlatform khá thú vị, nhận được sự quan tâm của mọi người thông qua số câu hỏi.</p>\n\n\n\n<p>Một số câu hỏi khác về WordPress cũng được giải đáp và trao đổi khá nhiệt tình.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Việc định kỳ nâng cấp website WordPress là cần thiết, đặc biệt là các phiên bản Minor (định dạng x.x.[x]). Các phiên bản Major thì cần tiến hành sao lưu trước khi nâng cấp.</li>\n\n\n\n<li>Nên sử dụng các plugin bảo mật giúp hạn chế tấn công như Wordfence.</li>\n\n\n\n<li>Việc sử dụng kết hợp giữa NextJS và WP REST API có những mục tiêu cụ thể, đặc biệt là phải quan tâm tới đối tượng sử dụng chính là ai.</li>\n\n\n\n<li>Xu hướng ChatGPT áp dụng trong công việc digital marketing.</li>\n\n\n\n<li>Việc tối ưu website phụ thuộc nhiều vào tài nguyên, chi phí, và có nhiều giải pháp khác nhau. Tuy nhiên, việc hướng tới phát triển với nguồn lực đầu tư phù hợp là hướng đi đúng đắn nhất cho doanh nghiệp.</li>\n</ul>\n\n\n\n<p><strong>Tham gia các sự kiện tiếp theo</strong></p>\n\n\n\n<p>Các Meetup tiếp theo tại Hà Nội được công bố trên nhóm Zalo: <a href=\"https://zalo.me/g/gfqysr978\">https://zalo.me/g/gfqysr978</a> (nơi bạn sẽ được chọn chủ đề, thời gian, địa điểm).</p>\n\n\n\n<p><strong>Slide chương trình:</strong><br>&#8211; <a href=\"https://docs.google.com/presentation/d/1ZNT9RDVyoBHXYN08LusDfeAKp1RCGYsm1OZBVDUZJm8/edit?fbclid=IwAR39tITgZOJHvC_j2u-Ty7I3SpIZXagPce8mIlZVxmsCKDkr9av4O73tN5I\" data-type=\"link\" data-id=\"https://docs.google.com/presentation/d/1ZNT9RDVyoBHXYN08LusDfeAKp1RCGYsm1OZBVDUZJm8/edit?fbclid=IwAR39tITgZOJHvC_j2u-Ty7I3SpIZXagPce8mIlZVxmsCKDkr9av4O73tN5I\">Tối ưu web mới nhất</a>, từ Mr. Khôi (Founder/CEO Code Tốt)<br>&#8211; Chia sẻ về <a href=\"https://www.figma.com/proto/hLFfSDh2GihHNAhPDyMA5w/Melisoft---Reactjs\">React+NextJS</a> từ Mr. Hoàng (Founder/CEO Melisoft) <br>&#8211; Quà tặng thêm 1 bài viết về <a href=\"https://codetot.vn/inp/\" data-type=\"link\" data-id=\"https://codetot.vn/inp/\">INP</a> để mọi người đọc lược qua nội dung cập nhật mới nhất.</p>\n\n\n\n<p>Cảm ơn phần tài trợ nước uống từ nhà cung cấp Hosting InterData, tài trợ địa điểm của <a href=\"https://codetot.vn/ve-code-tot/\">Code Tốt</a>, sự tham gia từ các cộng đồng <strong>Yêu SEO</strong>, <strong>SEO Meetup</strong>, <strong>CxO Hà Nội</strong>, nhóm <strong><a href=\"https://www.facebook.com/groups/toiuuweb/\" data-type=\"link\" data-id=\"https://www.facebook.com/groups/toiuuweb/\">Tối ưu web ✪</a></strong> để có được những kết nối tham gia.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"https://vi.wordpress.org/2023/07/22/recap-wordpress-meetup-ha-noi-thang-07-2023/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1078\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://vi.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096074\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Sat, 25 Oct 2025 03:09:11 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Thu, 04 Sep 2025 03:08:03 GMT\";s:4:\"link\";s:61:\"<https://vi.wordpress.org/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 1\";}}s:5:\"build\";i:1727736619;s:21:\"cache_expiration_time\";i:1761404951;s:23:\"__cache_expiration_time\";i:1761404951;}','off'),(4597,'_transient_timeout_feed_d117b5738fbd35bd8c0391cda1f2b5d9','1761404954','off');
INSERT INTO `wp_options` VALUES (4598,'_transient_feed_d117b5738fbd35bd8c0391cda1f2b5d9','a:6:{s:5:\"child\";a:1:{s:0:\"\";a:1:{s:3:\"rss\";a:1:{i:0;a:6:{s:4:\"data\";s:3:\"\n\n\n\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:7:\"version\";s:3:\"2.0\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:1:{s:7:\"channel\";a:1:{i:0;a:6:{s:4:\"data\";s:112:\"\n	\n	\n	\n	\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"WordPress Planet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"language\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"en\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress Planet - http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"item\";a:50:{i:0;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"Gutenberg Times: WordPress 6.9 Beta, Weekend Edition 346\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=42361\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"https://gutenbergtimes.com/wordpress-6-9-beta-weekend-edition-346/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:23364:\"<p>Hi there, </p>\n\n\n\n<p>I am genuinely giddy about WordPress 6.9 and its delightful updates.  Major kudos to all contributors, who push it over the first hurdle of this release cycle. <a href=\"https://make.wordpress.org/core/2025/10/21/wordpress-6-9-beta-1/\">The Beta 1</a> release happened earlier this week. The final release is scheduled for December 2nd, 2025. </p>\n\n\n\n<p>There are lots of different update for the full range of WordPress users. </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Content creators</strong> get a number of new and waited-for Blocks, with Accordion, Time to Read, Term Query and MathML Block, and further refinements to block handling and existing blocks. </li>\n\n\n\n<li><strong>Theme and site builders</strong> get additional tools to style a site via theme.json and majorly improved template management right in the site editor, and </li>\n\n\n\n<li><strong>Developers</strong> can build faster with an enhanced Block Bindings API and Interactivity API, and for the admin side of plugins the component library of DataViews and DataForms has some great updates as well. </li>\n</ul>\n\n\n\n<p>Release Test co-lead, <strong>Krupa Nanda</strong> posted great instructions on how you can <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\"><strong>Help test the Beta 1 release of WordPress 6.9 </strong></a>. It&#8217;s the best way to learn how to use the new features and report quirks and bugs back to the contributors, so they can be fixed before Release Candidate 1 which is scheduled for November 11. </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://make.wordpress.org/core/2025/10/21/wordpress-6-9-beta-1/\"><img alt=\"WordPress 6.9 Highlight grid [WIP]\" class=\"wp-image-42382\" height=\"375\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/WordPress-6-9-Highlight-grid-variation-1.png?resize=652%2C375&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<p>In Europe we will turn back our clocks one hour on Sunday (Oct 26). The US will follow suit next week (Nov 2). This will be the week of &#8220;pick-up meetings&#8221; for me. It&#8217;s what I call the phase where I miss a meeting and instead turn up at someone else&#8217;s meeting and meet new people. Win-win. <img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f389.png\" style=\"height: 1em;\" /> But seriously, if you scheduled a meeting with me next week, you can&#8217;t send too many reminders if you want me to turn up in time. </p>\n\n\n\n<p>Have a splendid weekend ahead, </p>\n\n\n\n<p>Yours, <img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<p><strong>Table of Contents</strong></p>\n\n\n\n<nav class=\"wp-block-table-of-contents\"><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-beta-weekend-edition-346/#0-word-press-release-information\">Developing Gutenberg and WordPress</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-beta-weekend-edition-346/#upcoming-learn-wordpress-online-workshops\">Upcoming Learn WordPress online workshops </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-beta-weekend-edition-346/#0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-beta-weekend-edition-346/#2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-beta-weekend-edition-346/#3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor.</a></li></ol></nav>\n</div></div>\n</section>\n\n\n<p><strong>This week in WordPress</strong> is a great long-running show by WPbuilds and host <strong>Nathan Wrigley</strong>. A panel of three people chats about last week&#8217;s WordPress news. They comment, explain and present addtional view points. It&#8217;s loosely inspired by &#8220;This week in Google&#8221; an even longer-running show of the <a href=\"https://twit.tv/\">This week in Tech (TWiT) network</a> that was <a href=\"https://www.twit.community/t/this-week-in-google-is-becoming-intelligent-machines/17988\">renamed</a> at the beginning of this year to <a href=\"https://twit.tv/shows/intelligent-machines\"><strong>Intelligent Machines.</strong></a> With Jeff Jarvis, Leo LaPorte and others. It&#8217;s my favorite podcast. But I digress. </p>\n\n\n\n<p>In the latest episode, <a href=\"https://wpbuilds.com/2025/10/21/this-week-in-wordpress-353/\"><strong>This week in WordPress 353</strong></a>, <strong>Michelle Frechette</strong>, <strong>Tim Nash</strong>, <strong>Nathan Wrigley</strong> and yours truly discussed the great Internet outage of 2025 aka AWS outage, the WordFence Security Report, WordPress 6.9 upcoming features, Gutenberg updates, and Tammie Lister&#8217;s fun blocks and so much more. <a href=\"https://www.youtube.com/watch?v=ArFYfbkypA8\">Listen in on YouTube</a> or your favorite Podcast app. </p>\n\n\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p><strong>Ray Morey</strong>, The Repository, reported that <a href=\"https://www.therepository.email/wordpress-6-9-beta-1-now-available-and-ready-for-testing\"><strong>WordPress 6.9 Beta 1 Now Available and Ready for Testing</strong></a> and gives and overview of the features and also what&#8217;s didn&#8217;t make it into the release, a nice recap on the progress of the Admin Redesign. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>Besides WordPress 6.9 Beta, the fabulous crew of contributors also <a href=\"https://github.com/WordPress/gutenberg/releases/tag/v21.9.0\"><strong>released Gutenberg 21.9.</strong></a> It brings three new blocks: MathML, Term name and Term Count blocks, the latter two used in the context of the new Term Query block. The <code>allowedBlocks</code> feature has been expanded to all blocks and users can also use the new UI tools to controls allowed blocks for templates and patterns, without writing code or editing raw block markup. Hide/show block features was added also to synced patterns and template parts. It can also be called upon via Command Palette and keyboard shortcut <kbd>cmd/ctrl+shift+H</kbd>. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Isabel Brison</strong>, JavaScript developer at Automattic and core contributor, joined me on the podcast and filled various knowledge gaps about the updates in this release. We also had great fun discussing WordPress 6.9 features, soon coming to your a WordPress instance near you. The podcast episode <strong>Gutenberg Changelog #123</strong> will land in your favorite podcast app over the weekend. </p>\n\n\n<div class=\"ng-block-39c21af6ef674808 wp-block-newsletterglue-image ng-block size-large is-resized\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 0px; padding-bottom: 0px; padding-left: 0px; padding-right: 0px;\"><img alt=\"Gutenberg Changelog 123 with Isabel Brison and host Birgit Pauli-Haack\" class=\"wp-image-42384 ng-image\" height=\"170\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-23-at-17.20.50.png?resize=600%2C170&#038;ssl=1\" style=\"border-style: none; border-color: transparent;\" width=\"600\" /></div></div></div></div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\" id=\"upcoming-learn-wordpress-online-workshops\">Upcoming Learn WordPress online workshops </h2>\n\n\n\n<p>On <strong>Thursday, Oct 30, 10:00 UTC</strong>, <strong>Maruti Mohanty</strong> will hold a workshop and show off  <a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/311670069/\"><strong>WordPress 6.8 Features in Action + 6.9 Sneak Peek: A Hands-On Workshop.</strong></a></p>\n\n\n\n<p>On <strong>Thursday, Oct 30, at 20:00 UTC</strong>, <strong>Velda Christensen</strong>&#8216;s workshop will be about  <strong><a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/311632066\">Landing Pages, Posts, &amp; More: Strategies for a Stronger Site</a></strong> -In this beginner-friendly workshop, we’ll explore simple ways to organize your WordPress content so visitors can easily find what they need and take the next step.</p>\n\n\n\n<p></p>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/\">Gutenberg Changelog #122 – Gutenberg 21.8 and WordPress 6.9</a> with Beth Soderberg of <a href=\"https://bethink.studio/\">Bethink Studio</a></p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Gutenberg Changelog 122 with Beth Soderberg\" class=\"wp-image-42236\" height=\"193\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-11-at-12.32.48.png?resize=652%2C193&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p class=\"has-small-font-size\"><em>If you are listening via Spotify, please leave a comment. If you listen via other podcast apps, please leave a review. It&#8217;ll help with the distribution.</em></p>\n</div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p><strong>Brian Coords</strong> has the details on the latest release of WooCommerce 10.3. in his release post. <a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/\"><strong>WooCommerce 10.3: COGS comes to core and MCP beta</strong></a> he highlights: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/#h-address-autocomplete-for-checkout-blocks-and-shortcode\">Address autocomplete for Checkout blocks and shortcode</a></li>\n\n\n\n<li><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/#h-product-collection-editor-improvements\">Product Collection Editor improvements</a></li>\n\n\n\n<li><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/#h-cost-of-goods-sold-cogs-is-here\">Cost of Goods Sold (COGS) is here</a></li>\n\n\n\n<li><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/#h-woocommerce-mcp-is-available-for-testing-in-beta\">WooCommerce MCP is available for testing in beta.</a></li>\n\n\n\n<li><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/#h-more-new-features-and-updates\">More new features and updates</a></li>\n\n\n\n<li><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/#h-api-updates\">API Updates</a></li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/\"><img alt=\"Product Collection editor improvements in Woo 10.3 \" class=\"wp-image-42365\" height=\"320\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Product-collections-improvments-Woo-10.3.webp?resize=652%2C320&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Blocktober Fun</strong>, the October challenge to build a block a day with Automattic&#8217;s Telex, is almost over. This week, <strong>Tammie Lister</strong> prompted the Block building AI tool for another set of fun blocks: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://blocktober.fun/sketch-image/\">Sketch Image</a> </li>\n\n\n\n<li><a href=\"https://blocktober.fun/ripple-text/\">Ripple Text </a></li>\n\n\n\n<li><a href=\"https://blocktober.fun/vhs-glitch/\">VHS glitch</a></li>\n\n\n\n<li><a href=\"https://blocktober.fun/flip-card/\">Flip Card</a></li>\n\n\n\n<li><a href=\"https://blocktober.fun/emoji-voting/\">Emoji voting</a></li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42370\" height=\"220\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-23-at-10.33.01.png?resize=652%2C220&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>A new fun plugin arrived at the WordPress plugin repository: It&#8217;s called  <a href=\"https://wordpress.org/plugins/throwable/\"><strong>Throwable</strong></a> by <a href=\"https://x.com/qarayahya\"><strong>Qara Yahya</strong></a>, founder of BlockLayouts. Using it you can place buttons, paragraphs or image into the Throwable block. The adjust Gravity aka speed items fall and Bounce setting, and have some nice animation on your site.  </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42369\" height=\"477\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/throwable.png?resize=652%2C477&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong><a href=\"https://x.com/justintadlock\">Justin Tadlock</a></strong> released <a href=\"https://wordpress.org/plugins/x3p0-breadcrumbs/\"><strong>Breadcrumbs Block v. 3.0</strong>.</a> The update includes support for the built-in Layout and Block Gap (Spacing) features in WordPress. &#8220;There are quite a few other changes and some notable bug fixes, particularly if you extend the block with custom code. Be sure to check out the changelog&#8221; he <a href=\"https://x.com/justintadlock/status/1971721876306382889\">wrote on X.</a></p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42377\" height=\"350\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-23-at-13.25.01.png?resize=652%2C350&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p><strong>Sid Sharma</strong>, content creator from Nepal, demonstrates <a href=\"https://www.youtube.com/watch?v=sul4r-KjfAc\"><strong>how to create a transparently floating sticky header in WordPress</strong></a>, all in the Site Editor for Block Themes.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n<section class=\"wp-block-newsletterglue-callout undefined not-color-set\" style=\"border-color: #f9f9e5; border-radius: 22px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f9f9e5;\">\n<p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2025&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. The previous years are also available: <strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p>\n</section>\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor.</h2>\n\n\n\n<p><strong>Seth Rubenstein</strong>, lead developer at the Pew Research Center and speaker at WordCamp US, chatted with <strong>Nathan Wrigley</strong> on the Jukebox podcast about  <a href=\"https://wptavern.com/podcast/190-seth-rubenstein-on-block-composability-in-wordpress-future\"><strong>Block Composability in WordPress’ Future</strong></a>. Rubinstein &#8220;shares fascinating stories from the work h e’s recently been doing. He breaks down what block composability really means, the ability to build modular, reusable, and even interactive blocks that work seamlessly together, empowering both developers and end users to create sophisticated web applications within the familiar WordPress block editor.&#8221; wrote Wrigley in his podcast show notes. </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-rich is-provider-pocket-casts wp-block-embed-pocket-casts\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong><a href=\"https://x.com/fellyph\">Fellyph Cintra</a></strong>, developer advocate working for Automattic, published <a href=\"https://make.wordpress.org/playground/2025/10/23/things-you-might-have-missed-about-the-playground-project-over-the-past-few-months/\"><strong>Things you might have missed about the Playground project over the past few months</strong></a>. It&#8217;s a great roundup post about the amazing work of the team. He mentions the PHP-Wasm changes, updates to the Playground CLI, the JavaScript API,  how to use Playground with Playwright and the performance improvements with OPCache enabled by default. He also addresses rumors about missing features compared to traditional WordPress installs, noting that this gap is becoming less significant.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p>In preparation for the WordPress 6.9 Field Guide, <strong>André Maneiro</strong> just posted an update about the <a href=\"https://github.com/WordPress/gutenberg/issues/70936#issuecomment-3437790150\"><strong>Fields API</strong></a>, that has been worked on for many Gutenberg releases. It lists functions and options with code examples. Updates on DataViews and DataForm are still to come. </p>\n\n\n<section class=\"wp-block-newsletterglue-callout undefined not-color-set\" style=\"border-color: #eeeeee; border-radius: 26px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f3efe9;\">\n<p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review. </p>\n\n\n\n<p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience</p>\n\n\n\n<p><img alt=\"GitHub all releases\" src=\"https://img.shields.io/github/downloads/bph/gutenberg/total?style=for-the-badge\" /></p>\n</section>\n\n\n<p class=\"has-text-align-center has-small-font-size\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<p>Featured Image: Naples Beach photo by Birgit Pauli-Haack</p>\n\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-left\"><strong>Don&#8217;t want to miss the next Weekend Edition? </strong></p>\n\n\n<form action=\"https://gutenbergtimes.com/feed/\" autocomplete=\"on\" class=\"wp-block-newsletterglue-form ngl-form ngl-portrait\" method=\"post\"><div class=\"ngl-form-container\"><div class=\"ngl-form-field\" style=\"margin-bottom: 25px;\"><label class=\"ngl-form-label\" for=\"ngl_email\"><br />Type in your Email address to subscribe.</label><div class=\"ngl-form-input\"><input autocomplete=\"email\" class=\"ngl-form-input-text\" id=\"ngl_email\" name=\"ngl_email\" required=\"required\" style=\"border-radius: 21px;\" type=\"email\" /></div></div><button class=\"ngl-form-button\" style=\"background-color: #005075; border-color: #005075; border-width: 1px; border-style: solid; color: #ffffff; border-radius: 21px;\" type=\"submit\">Subscribe</button><p class=\"ngl-form-text\">We hate spam, too, and won&#8217;t give your email address to anyone <br />except Mailchimp to send out our Weekend Edition</p></div><div class=\"ngl-message-overlay\"><div class=\"ngl-message-svg-wrap\"><svg fill=\"none\" height=\"24\" stroke=\"#fff\" stroke-width=\"2\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><polyline points=\"20 6 9 17 4 12\"></polyline></svg></div><div class=\"ngl-message-overlay-text\">Thanks for subscribing.</div></div><input id=\"ngl_list_id\" name=\"ngl_list_id\" type=\"hidden\" value=\"26f81bd8ae\" /><input id=\"ngl_double_optin\" name=\"ngl_double_optin\" type=\"hidden\" value=\"yes\" /></form>\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n</section>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 25 Oct 2025 02:53:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:44:\"Matt: Automattic 20 &amp;amp; Counter-claims\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150355\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:37:\"https://ma.tt/2025/10/counter-claims/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2269:\"<p>It&#8217;s a bit of <a href=\"https://automattic.com/\">Automattic</a> lore, but although I founded the company in June 2005, <a href=\"https://www.cnet.com/\">CNET</a> asked me to stay on for a few more months to finish out some projects, which I did. Our HR systems have me as the second employee, after <a href=\"https://odd.blog/\">Donncha O Caoimh</a> (still at the company!) So today is my 20<sup>th</sup> anniversary at Automattic! It&#8217;s 20 years since I started hacking on <a href=\"https://akismet.com/\">Akismet</a>, our first product, and on <a href=\"https://wordpress.com/\">WordPress.com</a>.</p>\n\n\n\n<figure class=\"wp-block-image alignwide size-large\"><img alt=\"\" class=\"wp-image-150359\" height=\"453\" src=\"https://i0.wp.com/ma.tt/files/2025/10/IMG_0435-1024x768.jpeg?resize=604%2C453&#038;quality=89&#038;ssl=1\" width=\"604\" /></figure>\n\n\n\n<p>The team gave me a sweet surprise! I&#8217;ve been fighting for the open web for 20 years, and hope to do it for at least 20 more. There&#8217;s a lot of exciting behind-the-scenes stuff happening inside Automattic that also made this day special, but one significant thing is public.</p>\n\n\n\n<p>Automattic has finally had its first chance to file its counterclaims against <a href=\"https://wpengine.com/\">WP Engine</a> and <a href=\"https://www.silverlake.com/\">Silver Lake</a>, <a href=\"https://techcrunch.com/2025/10/24/automattic-files-counterclaims-against-wp-engine-in-wordpress-lawsuit-alleging-trademark-misuse/\">as reported here by TechCrunch</a>. You may recall that last month, <a href=\"https://ma.tt/2025/09/legal-win/\">the court dismissed several of their most serious claims</a>, and they responded by filing an amended complaint. In our dogged defense of the free, open, and thriving WordPress ecosystem, Automattic responded today with a comprehensive counter-filing, <a href=\"https://automattic.com/wp-content/uploads/2025/10/automattic-counterclaims.pdf\">which you can read in a 162-page PDF here about all the things WP Engine/Heather Brunner and Silver Lake did wrong</a>. </p>\n\n\n\n<p>We&#8217;ve got receipts!</p>\n\n\n\n<p>I don&#8217;t think WP Engine employees or investors were aware of the depths they did, hopefully some of this is enlightening. And there&#8217;s a lot more discovery to go!</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 25 Oct 2025 02:14:10 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:97:\"WordCamp Central: Bhopal Hosts WP Build Tour 2025: Empowering 1700+ Students Across Central India\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"https://central.wordcamp.org/?p=12042668\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:120:\"https://central.wordcamp.org/news/2025/10/bhopal-hosts-wp-build-tour-2025-empowering-1700-students-across-central-india/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:21792:\"<p>WordPress Bhopal has been at the forefront when it comes to igniting young minds, empowering them with knowledge, generating new ways to achieve optimal and maximum value, and sparking a positive social impact— kind of feels like a motto. </p>\n\n\n\n<p>We love doing all of it!</p>\n\n\n\n<p>And as <a href=\"https://wpbhopal.org/\">we</a> proudly complete our <strong>10th year of formation</strong> (Oct. 2nd), this year in particular, we’ve been targeting ways to amplify our impact. A special highlight was EmpowerWP Bhopal (Women’s Day event), where we hosted women in different stages &amp; walks of their lives and demonstrated how WordPress &amp; the community can support them in achieving/expanding their potential. The response was heartwarming.</p>\n\n\n\n<p><a href=\"https://central.wordcamp.org/news/2025/04/empowerwp-bhopal-2025-a-journey-of-inclusion-and-impact/\">Read more about EmpowerWP Bhopal 2025</a></p>\n\n\n\n<p>Post this event’s success, and that of last year’s <a href=\"https://asthajain.in/my-experience-as-pm-at-do_action-bhopal-2024/\">do_action</a>, where we empowered NGOs by building their websites, it felt only natural that the next chapter in our mission of <em>empowering the social community</em> should focus on the students. </p>\n\n\n\n<p>And honestly, why we feel more drawn towards the student community can be traced back to the fact that the genesis of the WP Bhopal community itself was by a second-year college student back in 2015. Ever since, we’ve been taking workshops in colleges of our city, but this year, it was more about formalising it and making it more impactful &amp; grander than ever.</p>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3061\" src=\"https://asthajain.in/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-13-at-6.36.08-PM-1024x576.jpeg\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<p class=\"has-white-color has-blue-background-color has-text-color has-background has-link-color wp-elements-54e8d22bf0aa76571dde8c4451ca6aec\">Being the only active chapter in the State of Madhya Pradesh—a state with 55 districts and over 400 cities—there was always a little nudge to take our initiative beyond our home, Bhopal.</p>\n\n\n\n<p>I still vividly remember while pitching sponsors for <a href=\"https://bhopal.wordcamp.org/2023/cheers-to-the-success-of-wordcamp-bhopal-2023-a-heartfelt-thank-you/\">WordCamp Bhopal 2023</a>, the idea kept resurfacing: <em>the student community must benefit from this</em>. The lack of exposure and the gap between theory &amp; practical skills is profusely felt. <a href=\"https://profiles.wordpress.org/ethicaladitya/\">Aditya</a> often mentions that when he started with WordPress, it was purely out of his own interest, not something taught or exposed to him in his institute. For him, building websites was uncommon among his batchmates. And the truth is, the situation hasn&#8217;t changed, and we still need revitalisation to help the youth realise their potential. This became the agenda of this initiative.</p>\n\n\n\n<p>Too much foundation-building&#8230; now’s the time to reveal what I’ve so heartily been tucking in…</p>\n\n\n\n<h3 class=\"wp-block-heading has-text-align-center has-black-color has-white-background-color has-text-color has-background has-link-color wp-elements-8ce23c0821326885e4daea60f27a6275\"><em><strong>WE ARE SO PROUD &amp; DELIGHTED to share that possibly the largest event of its kind, so far—the WP Build Tour 2025—has been successfully organised, impacting and empowering more than 1700 students across Madhya Pradesh in one go!</strong></em></h3>\n\n\n\n<h2 class=\"wp-block-heading\">What&#8217;s in the Name? And Why This Matters.</h2>\n\n\n\n<p>The name came after much thought. We wanted it to reflect the core idea: <em><strong>Tour</strong></em> to capture the essence of a tour bus going around the State, empowering students (especially first-timers) to <em><strong>Build</strong></em> their very first WordPress websites, apart from expanding their technical confidence.</p>\n\n\n\n<p>The mission was rooted in our identity as the only active WP chapter in Madhya Pradesh:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Expanding our reach to more students across the State.</li>\n\n\n\n<li>Spreading WordPress awareness to inspire new local chapters</li>\n\n\n\n<li>Giving students confidence to bring their ideas online</li>\n</ul>\n\n\n\n<p>This plan was a win-win for us personally, for the community, and for the social cause we stand for.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-9d6595d7 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\"></div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full is-resized\" id=\"logo\"><img alt=\"\" class=\"wp-image-3073\" src=\"https://asthajain.in/wp-content/uploads/2025/09/120a9bb6-03ab-4991-9ad3-644d5bb8677e.jpg\" style=\"width: 623px; height: auto;\" /><figcaption class=\"wp-element-caption\">WordPress Bhopal x WP Build Tour</figcaption></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\"></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">The Planning Phase: How Did We Pull This Off?</h2>\n\n\n\n<p>The initial plan was to cover colleges in major cities. Ties with GDG (Google Developer Groups) communities and college clubs helped spread the word and support with arrangements that differed from college to college.</p>\n\n\n\n<p>Interests were called in from colleges. Once we had a number, like the location, student profiles, number of students, etc, we initiated the process. We designated volunteers from each college to be a bridge, because, of course, they know the best way in there. Each college had around 120-600 students in one sitting.</p>\n\n\n\n<p><em>Thanks to their support, we were able to pull this off smoothly. Special shout-outs to: SIRT Student Body (Bhopal), Advance Studies Club- Medicaps Indore, GDG Indore &amp; E-Cell, SATI Vidisha.</em></p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-9d6595d7 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3058\" src=\"https://asthajain.in/wp-content/uploads/2025/09/IMG_5148-1024x768.jpg\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-3060\" src=\"https://asthajain.in/wp-content/uploads/2025/09/IMG_6283-1024x768.jpg\" /></figure>\n</div>\n</div>\n\n\n\n<p>Sessions were designed for all levels, no matter the technical background. We were conscious of common hurdles &amp; from day zero of planning, we decided to remove those barriers at first instance. In this regard, at preliminary registration itself, students were guided to apply for the <strong>GitHub Education Pack</strong>, so by the event day, they have access to <span style=\"text-decoration: underline;\">free domains &amp; developer tools</span>. For hosting, we relied on <strong>InfinityFree</strong> and <strong>FreeHosting.com</strong>. Sometimes, a challenge was GitHub taking too long to approve the account(s), so the backup was to manage through <em><strong>subdomains</strong></em> from InfinityFree and additional free hosting setups.</p>\n\n\n\n<p>The setup also included swags and refreshments to keep up with the momentum. Thought was put into keeping those as relevant as possible. Participants were provided with <a href=\"https://central.wordcamp.org/feed/#cleaning-kit\">mini cleaning kits</a> to take home. For refreshments, we relied on the quick &amp; easy- Pizzas &amp; Burgers along with beverages.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Building Website in a Day: The Possibility</h2>\n\n\n\n<p>Now that&#8217;s a given, building your own website (properly) takes time— planning, ideation, resources, so what&#8217;s the catch? No catch, really. Here, with a 4–5 hour workshop, we wanted students to experience the spark of: <em>“I can actually do this.”</em> The pressure wasn&#8217;t to build the whole of it in one day but to cover all the basics then &amp; there. So the next time they open it, it&#8217;s only to further mould it as per their requirements.</p>\n\n\n\n<p>From purchasing a domain, to pointing DNS records, to watching DNS propagation happen live—and finally installing WordPress—it was a crash course in turning abstract concepts into real, working websites.</p>\n\n\n\n<p>And the output? A portfolio, a blog, a project showcase, even startup ideas. The pride was real. Social media lit up with links saying, <em>“We built this.”</em></p>\n\n\n\n<p>Honestly, we were a little sceptical at times—like when there weren’t many doubts, or when lunch was announced and students walked out. We wondered, <em>“Will they even come back?”</em> Because this wasn’t meant to be just another attendance exercise; we wanted it to be voluntary, something they <em>chose</em> to be part of.</p>\n\n\n\n<p>But there was consensus in the team that even if just one kid shows up, we’ll keep going. And guess what? Not only did they come back, but they jumped in with full energy. Doubts, queries, ideas, thoughts—their enthusiasm blew us away. It’s hard to put into words how fascinating it was to see the effort actually paying off.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-9d6595d7 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-3047\" src=\"https://asthajain.in/wp-content/uploads/2025/09/51d60eb2-eaf0-4611-aa65-b7965d8ebf04-1024x768.jpg\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large is-resized\"><img alt=\"\" class=\"wp-image-3064\" src=\"https://asthajain.in/wp-content/uploads/2025/09/IMG_4180-1215x2160-1-edited.jpeg\" style=\"width: 348px; height: auto;\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3052\" src=\"https://asthajain.in/wp-content/uploads/2025/09/b9791e02-3291-4c7e-a633-82b4f964c873-2-768x1024.jpg\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n</div>\n</div>\n\n\n\n<p>By the end, every participant had not just knowledge but something concrete: a live website, <em><strong>their website</strong></em>! Photos, reels, and hashtags like #WPBuildTourBPL amplified the energy far beyond the classrooms.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Beyond the Website</h3>\n\n\n\n<p>Though the primary goal was to help students build their own websites from scratch, the sessions were also designed to introduce them to the WordPress community. They covered career opportunities, ways to get involved, and the benefits the community offers. Students were given an overview of how to contribute, how chapters operate, and how they can become a part of the ecosystem. The aim was to make the experience not just hands-on but also empowering—equipping them to pave their own path, with community connection as a strong starting point. This also supports our broader goal of fostering new chapters across the state.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Route We Took</h2>\n\n\n\n<p><em>We’re very thankful to the college administrations of each institute we took the Tour to for their trust and support throughout. This post would be failing in its agenda without giving them due credit for opening their doors and believing in the vision of the WP Build Tour.</em> </p>\n\n\n\n<p>Here’s where the Tour travelled:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Sagar Institute of Research &amp; Technology, Bhopal<br /></li>\n\n\n\n<li>Oriental Institute of Science &amp; Technology, Bhopal<br /></li>\n\n\n\n<li>Samrat Ashok Technological Institute, Vidisha<br /></li>\n\n\n\n<li>Acropolis Institute of Technology &amp; Research, Indore<br /></li>\n\n\n\n<li>Medicaps University, Indore<br /></li>\n\n\n\n<li>Oriental College of Technology, Bhopal</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3067\" src=\"https://asthajain.in/wp-content/uploads/2025/09/IMG_6666-1024x410.jpg\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<p><br />Each stop added its own flavour and warmth. If we could’ve squeezed in more, we surely would have, but even with the stretch, it was worth it.</p>\n\n\n\n<p>The social media was our backbone—announcements, posts, designs, keeping the buzz alive. Big thanks to <em><a href=\"https://www.linkedin.com/in/mansi-chaturvedi-298832259/?original_referer=https%3A%2F%2Fwww%2Egoogle%2Ecom%2F&amp;originalSubdomain=in\">Mansi</a></em> (also our go-to content person), along with <em>Md. <a href=\"https://www.linkedin.com/in/md-farid-1aa563291/\">Farid</a></em>, <em><a href=\"https://www.linkedin.com/in/amit-vishwakarma-b46380193/\">Amit</a></em> &amp; <em><a href=\"https://www.linkedin.com/in/riddhima-singh-b3b860274?utm_source=share&amp;utm_campaign=share_via&amp;utm_content=profile&amp;utm_medium=android_app\">Riddhima</a></em>. And yep, that cool <a href=\"https://central.wordcamp.org/feed/#logo\">Build Tour logo </a>you see up there? Amit designed it.</p>\n\n\n\n<p>On the ground, <a href=\"https://www.linkedin.com/in/shashank-jain1\">Shashank</a>, <a href=\"https://www.kapilarya.com\">Kapil</a>, and <a href=\"https://www.linkedin.com/in/shivammishra-styx\">Shivam</a> held things together—guiding students through technicalities, taking charge of arrangements, managing logistics, and even stepping in as resource persons when needed. Shashank went the extra mile, balancing all this while also supporting social media.</p>\n\n\n\n<p><em><a href=\"http://adityashah.dev\">Aditya</a></em>, <em><a href=\"https://guneet.in\">Guneet</a></em>, and <a href=\"http://kripeshadwani.com\">Kripesh</a> led as resource persons, bringing not only their WordPress expertise but also their effortless way of connecting with students. (Classic engineers with their own fanbase, haha!)<br /><br />Mayur, Anshika, Pooja, Malay, Ninay, Roshini, and Prabal each <a href=\"https://events.wordpress.org/bhopal/2025/wpbuildtour/organizers/\">contributed</a> in various roles, adding strength to the endeavour.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Sponsors who made this Possible</h2>\n\n\n\n<p>This tour wouldn’t have been possible the way it happened without our incredible sponsors. Gold Sponsors <strong>Jetpack, Bluehost, Woo, Hosting.com, Kinsta, StellarWP, </strong>and<strong> </strong>our Bronze Sponsor, <strong>ForthFocus</strong>. </p>\n\n\n\n<p>Their support helped us take the Tour across campuses in the best way possible, provide refreshments and swags, and equip students with the right resources.</p>\n\n\n\n<p>And of course, a big thanks to the global WordPress community for having our back throughout!</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-9d6595d7 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large is-resized wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3054\" src=\"https://asthajain.in/wp-content/uploads/2025/09/e236d14a-79a5-4a3a-80d1-ae65a8c11499-768x1024.jpg\" style=\"width: 146px; height: auto;\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button><figcaption class=\"wp-element-caption\">Giveaway winner</figcaption></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3048\" src=\"https://asthajain.in/wp-content/uploads/2025/09/930f22b9-d597-4749-b328-7d6b8c5a37fa-2-1024x592.jpg\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\" id=\"cleaning-kit\"><img alt=\"\" class=\"wp-image-3074\" src=\"https://asthajain.in/wp-content/uploads/2025/09/IMG_6671-795x1024.jpg\" /><figcaption class=\"wp-element-caption\">Swags</figcaption></figure>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Moments beyond: In our Hearts</h2>\n\n\n\n<p>Some moments will stay with us forever:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>The warmth of teamwork, swag, and refreshments turns workshops into mini-celebrations</li>\n\n\n\n<li>The collective gasp when a site went live</li>\n\n\n\n<li>Proud social media posts </li>\n\n\n\n<li>Smiles of giveaway winners walking away with specially curated kits.</li>\n</ul>\n\n\n\n<p>Because at its heart, the WP Build Tour 2025 was never just about code or content. It was about confidence. About potential realised. About futures being built—one student, one website, one breakthrough at a time.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-9d6595d7 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3062\" src=\"https://asthajain.in/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-15-at-7.17.55-PM-501x1024.jpeg\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large wp-lightbox-container\"><img alt=\"\" class=\"wp-image-3066\" src=\"https://asthajain.in/wp-content/uploads/2025/09/32bf637e-10fc-492f-b1c3-3171f6ffadab-edited.jpg\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button><figcaption class=\"wp-element-caption\">We were featured in local newspapers</figcaption></figure>\n</div>\n</div>\n\n\n\n<figure class=\"wp-block-pullquote has-black-color has-text-color has-link-color wp-elements-542803687f2e82ce724dbba5a67a7e9f\"><blockquote><p>Organising events is one thing, and adding purpose to them takes it to another level. For us in Bhopal, organising events has never been just about the “event.” It’s about going a step further and sparking change, no matter how small. Thankfully, the WordPress community has always been open and kind enough to welcome such ideas and encourage us to push boundaries. And for that, we&#8217;re so grateful!</p></blockquote></figure>\n\n\n\n<p><em>The WP Build Tour 2025 wasn’t the end but rather the beginning of a movement. And as we now look forward to <a href=\"https://bhopal.wordcamp.org/2025/\">WordCamp Bhopal 2025</a> this December, we carry with us 1,700 sparks of possibility, ready to light up the future of WordPress and beyond.</em></p>\n\n\n\n<p></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 24 Oct 2025 19:36:37 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"Astha Jain\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"Matt: Under the Weather\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150347\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"https://ma.tt/2025/10/under-the-weather/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:638:\"<p>I don&#8217;t get sick very often, but when it catches up to me it hits like a freight train. Just trying to keep all the plates spinning while operating at 10% capacity, been sleeping a ton. Today was in some ways better, some ways worse than yesterday. I try to avoid hospitals and emergency care, as you wind up in their system, so I&#8217;m trying to ride this one out at home. Had to cancel a bunch of travel and conferences and meetings I was looking forward to this week. Really makes you appreciate and be grateful for good health — it&#8217;s a baseline for everything else and I&#8217;m blessed with it 99% of the time.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 24 Oct 2025 03:14:24 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Matt: New Woo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150338\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://ma.tt/2025/10/new-woo/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:902:\"<p><a href=\"https://developer.woocommerce.com/2025/10/22/woocommerce-10-3-cogs-comes-to-core-and-mcp-beta/\">WooCommerce 10.3 is out</a>, just in time for Black Friday / Cyber Monday, with some nice improvements to the checkout experience, tracking cost of goods sold, and a new beta MCP server, &#8220;This new feature enables AI assistants like Claude, Cursor, VS Code, or any other MCP-compatible client to interact directly with WooCommerce stores through a standardized protocol, opening up new possibilities for AI-assisted store management and development workflows.&#8221; <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\">You can also help out in testing WordPress 6.9</a>, which comes out on December 2<sup>nd</sup>.</p>\n\n\n\n<p>If I&#8217;m slow on anything right now, I apologize. I&#8217;ve got some flu/Covid thing, so I&#8217;m operating at reduced capacity.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 23 Oct 2025 06:54:56 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"Open Channels FM: The Power of Customer Support and Building Relationships in SaaS\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110952\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"https://openchannels.fm/the-power-of-customer-support-and-building-relationships-in-saas/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:162:\"Strong customer support is key for SaaS success. Building relationships with users and hosting providers boosts satisfaction and can be a powerful marketing tool.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 22 Oct 2025 12:56:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"Matt: To Cut A Pineapple\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:22:\"https://ma.tt/?p=99215\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"https://ma.tt/2025/10/to-cut-a-pineapple/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:567:\"<p>Google has turned 25, which is wow, and they made a cute video about it:</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p>Of course I tried to visit the original howtocutapineapple.com site, and unfortunately saw a database error connection. <a href=\"https://web.archive.org/web/20221206055636/http://howtocutapineapple.com/\">From Archive.org</a> it looks like whoever had that domain made a nice WordPress site.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 22 Oct 2025 06:20:50 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"WPTavern: #190 – Seth Rubenstein on Block Composability in WordPress’ Future\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=200244\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://wptavern.com/podcast/190-seth-rubenstein-on-block-composability-in-wordpress-future\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:59361:\"<details>Transcript<div>\n<p>[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p>Jukebox is a podcast which is dedicated to all things WordPress. The people, the events, the plugins, the blocks, the themes, and in this case, block composability, what it is and how it&#8217;s shaping WordPress&#8217;s future.</p>\n\n\n\n<p>If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p>If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox and use the form there.</p>\n\n\n\n<p>So on the podcast today we have Seth Rubenstein. Seth is the head engineer at the Pew Research Center, where he leads a team of developers managing the organization&#8217;s WordPress based publishing platform for its news site. Passionate about open source, Seth ensures that everything his team builds not only meets the Pew Research Center&#8217;s needs, but also benefits the wider community. By actively contributing to the Gutenberg project, he strives to share their solutions, always asking how their work can be given back to help others in the WordPress ecosystem.</p>\n\n\n\n<p>Seth shares fascinating stories from the work he&#8217;s been doing recently. He breaks down what block composability means, the ability to build modular, reusable, and even interactive blocks that work seamlessly together, empowering both developers and end users to create sophisticated web applications within the familiar WordPress block editor.</p>\n\n\n\n<p>The conversation gets into some of WordPress&#8217;s newest, and most promising, features including the Block Bindings API, Block Bits, which is still very much in development, and the Interactivity API. Seth explains how these tools open a world of possibilities, like building interactive quizzes, dynamically updating content, or even prefetching data, all using blocks, without having to rely on custom React front ends, or heavy server side processing.</p>\n\n\n\n<p>Seth also talks about the path forward for democratizing these advanced capabilities, discussing current limitations, the potential for new UI tools, and what&#8217;s still missing in the quest for truly responsive device contextual blocks.</p>\n\n\n\n<p>Throughout the episode, Seth makes a compelling case for why now is a golden opportunity for developers and plugin builders to start experimenting, get involved, and shape the next evolution of WordPress as a cutting edge web application platform.</p>\n\n\n\n<p>Whether you&#8217;re a developer curious about the future of Gutenberg, or an editor dreaming of more drag and drop web app power, this episode is for you.</p>\n\n\n\n<p>If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p>And so without further delay, I bring you Seth Rubenstein.</p>\n\n\n\n<p>I am joined on the podcast by Seth Rubenstein. How are you doing, Seth?</p>\n\n\n\n<p>[00:03:40] <strong>Seth Rubenstein:</strong> Very good. How about you?</p>\n\n\n\n<p>[00:03:41] <strong>Nathan Wrigley:</strong> Yeah, good. Nice to have you back.</p>\n\n\n\n<p>[00:03:42] <strong>Seth Rubenstein:</strong> Yeah, second time.</p>\n\n\n\n<p>[00:03:43] <strong>Nathan Wrigley:</strong> This doesn&#8217;t happen too many times. I&#8217;ve got to be perfectly honest with you, the audience, I&#8217;ve already said this to Seth. Each time I come to WordCamp US, I&#8217;m always confounded by how remarkably clever people are, and the depth of the content is sometimes beyond me. I think this is one of those examples.</p>\n\n\n\n<p>I think there&#8217;s a high chance that you are going to have to shepherd me. There&#8217;s probably going to be a lot of editing, when I pause and you explain what you are talking about. So let&#8217;s get into it. First of all, tell us a little bit about you, where you work, what you do in the WordPress space.</p>\n\n\n\n<p>[00:04:10] <strong>Seth Rubenstein:</strong> Sure. So I work for Pew Research Center. I&#8217;m the head of engineering there. I manage a team of four other developers, and I like to tell people that we work with and on WordPress every day.</p>\n\n\n\n<p>We manage a publishing platform for a small news site in the US, Pew Research, but we also contribute to Gutenberg. Everything that we do, everything that we build day in and day out, we try to do from a perspective of how can we open source this? How can we contribute this back to Gutenberg in some way? What can we build to fulfill our needs that would also fulfill other people&#8217;s needs?</p>\n\n\n\n<p>[00:04:39] <strong>Nathan Wrigley:</strong> You said a small organisation, the Pew Research Center. I don&#8217;t actually know what they do.</p>\n\n\n\n<p>[00:04:44] <strong>Seth Rubenstein:</strong> We are a nonprofit, call ourselves a fact tank. What we do is we survey the American public on a variety of issues. Where are they on things like abortion, or religion, or crime, or the economy, or the use of AI, whatever. And we like to kind of say we hold up a mirror to the American public to tell them what they believe back to them.</p>\n\n\n\n<p>[00:05:04] <strong>Nathan Wrigley:</strong> And so is the WordPress website that you have with them, is that a mechanism to distribute that data back to the public?</p>\n\n\n\n<p>[00:05:09] <strong>Seth Rubenstein:</strong> Yes, yes.</p>\n\n\n\n<p>[00:05:10] <strong>Nathan Wrigley:</strong> Okay, that&#8217;s interesting. So it&#8217;s a data heavy industry that you are dealing with.</p>\n\n\n\n<p>[00:05:13] <strong>Seth Rubenstein:</strong> It is. It is. We&#8217;re very, a kind of academic research institution, but we publish in kind of a news oriented way.</p>\n\n\n\n<p>[00:05:21] <strong>Nathan Wrigley:</strong> Okay. So we figured out a little bit about you, however you are here at WordCamp US to do a presentation. I actually don&#8217;t know if you&#8217;ve done it</p>\n\n\n\n<p>[00:05:28] <strong>Seth Rubenstein:</strong> I have, yeah. I did it the other day.</p>\n\n\n\n<p>[00:05:29] <strong>Nathan Wrigley:</strong> How did it go?</p>\n\n\n\n<p>[00:05:29] <strong>Seth Rubenstein:</strong> It went okay. I had a problem with my speaker notes, so I had to ad lib a good bit of it. So it might not be as coherent, or clear as it should have been.</p>\n\n\n\n<p>[00:05:41] <strong>Nathan Wrigley:</strong> Well we&#8217;re here to fix that. You can ad lib all you like here. So it was called, and forgive the pronunciation if I get this wrong, Block Composability: The Past and The Future. I&#8217;m actually just going to read the blurb into the record. And I&#8217;ll also make sure that there&#8217;s a link in the show notes to the page at the WordCamp US website where you can find out about the content. And also if by the time this comes out a WordPress TV episode with your presentation has landed, then I&#8217;ll mention that as well.</p>\n\n\n\n<p>Gutenberg excels at crafting beautiful static content, but what if you could empower anyone to build dynamic, interactive web experiences directly within the Block Editor? This session dives into block composability, a powerful concept that enables the creation of rich, interactive content using blocks, making advanced web development accessible to even less technically inclined users, which begs the question, what is block composability?</p>\n\n\n\n<p>[00:06:31] <strong>Seth Rubenstein:</strong> Block composability, I guess let&#8217;s define composability first. Composability in computer science and in software development is the idea that you can create and assemble web applications with reusable components in a modular way. That&#8217;s really all that means.</p>\n\n\n\n<p>If you&#8217;ve ever used React, if you&#8217;ve ever written in React, it means React Component, really. It&#8217;s a self-contained modular unit that can act on its own, but when plugged in with other units, it becomes something new, or extend its functionality or changes its functionality in some way.</p>\n\n\n\n<p>[00:07:01] <strong>Nathan Wrigley:</strong> When Gutenberg dropped, I had this notion that we were going to see mini apps inside of a block. So for example, I had this notion that right off the bat, so I&#8217;m going back to 2018 or something, when Gutenberg was still a, so prior to when it was in Core, let&#8217;s go with that. And I had this notion that you would drop in, let&#8217;s say a real estate block, and that block would encapsulate all the information about this particular house. And you would drop in the block and it would ask you a bunch of questions about the house and out would come a house custom post type, if you like.</p>\n\n\n\n<p>However, what happened was we got paragraph blocks, and we got an image block, and we got these fairly, well, useful, but they do one thing. They do a paragraph. They do an image, and that seems to be kind of where it ended. Are you trying to draw a line in the sand where it&#8217;s possible to go beyond that simple, does one thing, paragraph, image, to more the, we have a real estate block with loads of different facets and capabilities?</p>\n\n\n\n<p>[00:07:57] <strong>Seth Rubenstein:</strong> That&#8217;s right, yeah. I think where we&#8217;re at now is we&#8217;ve reached a point where the block editor, Gutenberg, in both its block editor and site editor kind of flavors, is you can build web applications. Blocks can do something now. They&#8217;re not just presenting text or an image and they&#8217;re kind of static and, you know, maybe you can style them differently from one post to another, but now they can actually do something.</p>\n\n\n\n<p>And more importantly, they can communicate with one another. You know, one block is adjacent to another. It can tell that block what to do when you click on it. If it&#8217;s inside of it, it can change its functionality accordingly. So you might imagine, we have a quiz builder. That&#8217;s actually one of our, probably our most technical product.</p>\n\n\n\n<p>And the way it works is there&#8217;s a results block where you can build out your results page for your quiz, but if you were to drop in a special block for, we have a special quiz that does scoring a very specific way, well, it changes the scoring functionality in the quiz builder. It doesn&#8217;t overwrite that. If you take that block out, the scoring functionality returns back to normal.</p>\n\n\n\n<p>So now we&#8217;re at a point where it&#8217;s very much possible to build web applications in the block editor with blocks.</p>\n\n\n\n<p>[00:09:00] <strong>Nathan Wrigley:</strong> So this little quiz block that you&#8217;ve described, if I was using, so ignore the developer experience and everything that you have built, the technicalities of all that. If I was somebody that was working for the Pew Research Center and I was, I don&#8217;t know, an editor and I needed to create a quiz, would that be my process? I drop in the quiz block, and boom, I have a quiz.</p>\n\n\n\n<p>[00:09:20] <strong>Seth Rubenstein:</strong> It&#8217;s really simple. You would go into, we do kind of store it all in a nice post type. So there&#8217;s a quiz post type. And then you open that up, you say, I want to go make a new quiz. And by default, there&#8217;s a quiz, we call it the quiz controller block that&#8217;s there first. And we have a few templated things in there for you. So like a start page and a question, an answer, and all of those things are block. So a question is a block, and inside of that question goes the answers for that question. That&#8217;s a block.</p>\n\n\n\n<p>Go further than that, we also have these kind of bindings. So you drop an answer in, well, there&#8217;s text for the answer, right? What if you want an image in there? What if you want a chart? What if you want a video? What if you want some other interactive piece of content to be corresponding to that answer? Well, you can drop that in too. And you can kind of freely move all these things within an answer, while still having that text bound to the answer block.</p>\n\n\n\n<p>So it&#8217;s a highly technical product, but for the editors, for the designers, it is literally just drag, drop, drag, drop, drag, drop. Create a page, create a question, type in your answer.</p>\n\n\n\n<p>[00:10:16] <strong>Nathan Wrigley:</strong> So in the world of 2018 that I alluded to a moment ago when the block editor launched, it feels like there were big missing pieces that prevented what you&#8217;ve just described. And maybe they&#8217;re APIs. I think possibly in some scenarios they are. What are the bits more recently, I don&#8217;t even know if it&#8217;s more recently in all honesty, but what are the bits that have enabled the features that you&#8217;ve just described?</p>\n\n\n\n<p>[00:10:38] <strong>Seth Rubenstein:</strong> Sure. So I think it&#8217;s funny that you bring back to 2018 because we built Quiz Builder in 2019. I think I&#8217;ll go on the record here and say, I think it might be the first kind of product in Gutenberg that was drag and drop building web applications. So I think we kind of pushed really early on the idea of composability inside of Gutenberg.</p>\n\n\n\n<p>And I see it as, there are kind of three waves in Gutenberg. First was, okay, Gutenberg is a CSS generator. That&#8217;s how I first kind of imagined it. You&#8217;re creating content and you have a style system and that outputs some CSS for your site.</p>\n\n\n\n<p>And then we got, I think the kind of HTML part of that a few years later. With the site editor and the theming inside of the block editor and things like that.</p>\n\n\n\n<p>And now we&#8217;ve gotten to the JavaScript part of Gutenberg. Where WordPress has the Inactivity API. And so this is a WordPress native JavaScript framework, so blocks can do something on the front end. And I think that is really the key innovation that&#8217;s really opened this up in just the last 12, 16 months.</p>\n\n\n\n<p>[00:11:35] <strong>Nathan Wrigley:</strong> Are there any APIs that have enabled you to short circuit? So again, in 2018, I would imagine there was quite a lot of heavy lifting that you needed to do order to pull that off, to innovate in that way. Are there any things which have fallen, I think quite recently actually, that have enabled it to be more available to developers who don&#8217;t have the time available that you did?</p>\n\n\n\n<p>[00:11:56] <strong>Seth Rubenstein:</strong> Yeah, I mean, so in 2019 when we did this, you know, all we really had was this ability to kind of scaffolded out these quizzes. The were pretty static in their layout. You drop a question and there were the answers in there, and you could type them in and that was it. No images inside the quiz, nothing like that.</p>\n\n\n\n<p>Now, thanks to things like block bindings, block bits, which we can go into in a little bit.</p>\n\n\n\n<p>[00:12:18] <strong>Nathan Wrigley:</strong> Yeah, we&#8217;d need to I think.</p>\n\n\n\n<p>[00:12:19] <strong>Seth Rubenstein:</strong> And the Interactivity API, you know, it is, everything is less static. Everything is less set in stone now. With things like the HTML Tag Processor, you can say, oh, this answer has this flag on it so we&#8217;re going to change out some of the HTML in it, in kind of real time before it gets to the front end for users. That just really wasn&#8217;t possible before, without a lot of work. It wasn&#8217;t very performant.</p>\n\n\n\n<p>Now all those things are in place for developers to really tap into. And the documentation and examples are there too, because that was the problem before, I think, is that a lot of people had to figure out how to do this, and now there are real world examples out there.</p>\n\n\n\n<p>[00:12:52] <strong>Nathan Wrigley:</strong> So you mentioned, quickly skirted over three things there. So there was Block Bits, Block Bindings, which I think the full title would be Block Bindings API, and the Interactivity API, which I think is like a child of the HTML API. I&#8217;m not entirely sure about that, but.</p>\n\n\n\n<p>[00:13:07] <strong>Seth Rubenstein:</strong> It utilises the HTML components.</p>\n\n\n\n<p>[00:13:10] <strong>Nathan Wrigley:</strong> Okay. Let&#8217;s just go through what those three things are in whatever order suits the purposes of this podcast best, because I don&#8217;t know which one you&#8217;d start on.</p>\n\n\n\n<p>[00:13:16] <strong>Seth Rubenstein:</strong> Let&#8217;s start with Block Bindings API. I would actually imagine a good number of people are familiar with this. This has come up a lot in the last year in the Gutenberg project. What that really lets you do is use Core blocks more effectively.</p>\n\n\n\n<p>For example, before, if you wanted to have a button and you wanted to do a very specific thing and look a very specific way, well, good luck. You had to make your own button. Sure there was the Core button and you could style it to some degree, but what it did was it went to a link.</p>\n\n\n\n<p>Now with things like Block Bindings, you can say, okay, well, I have my Core button and I&#8217;m going to style it however I want, but the interior text, you know, what it says, what it does, well, that can be done kind of programmatically on the backend. That&#8217;s where the Block Bindings API comes in. It lets you use Core blocks and change them, well, not Core blocks, any blocks, really, and change them to fit your needs.</p>\n\n\n\n<p>[00:14:07] <strong>Nathan Wrigley:</strong> Can you give us a concrete example of that? So you&#8217;ve just talked about the button, you mentioned a sort of, I was struggling to grasp what you were meaning about changing the text programmatically. How would you do that? What would be an example?</p>\n\n\n\n<p>[00:14:18] <strong>Seth Rubenstein:</strong> Let me give you an example of that, Core paragraph. Very useful with block bindings. And I mentioned answers. So we have this answer block, right? And before it just had a text field in it. You would type in the answer and that was it. That was all you saw. And that meant that you couldn&#8217;t do anything inside of the answer. You couldn&#8217;t provide any other content inside there, because that would then get rolled up as the answer.</p>\n\n\n\n<p>So now with Block Bindings, what we have is we have this core paragraph binding that you can drop into the answer, and it is a text field still. You can type into it. It&#8217;s storing that on the answer block and then you can put other stuff inside the answer block because we&#8217;re not reading what&#8217;s in there as the content.</p>\n\n\n\n<p>What that meant for us is that we didn&#8217;t have to go make another block called answer text. We have hundreds of these kind of scenarios in our system where, yeah, we need a very specific use case, and it&#8217;s usually just some text, right, somewhere. Why would I make another block that&#8217;s just a paragraph block, really?</p>\n\n\n\n<p>So bindings, it makes blocks way more extensible. So one block can perform multiple functions if you need it to.</p>\n\n\n\n<p>[00:15:19] <strong>Nathan Wrigley:</strong> So my takeaway from that, it may be ignorant, it kind of adds a layer where you can add more features into any block, Core or otherwise. So in the example of paragraph, it&#8217;s like paragraph plus. It&#8217;s extended paragraph if you like, and you then get to decide. And that is the binding bit. You bind things to the block.</p>\n\n\n\n<p>[00:15:39] <strong>Seth Rubenstein:</strong> You bind attributes in a block.</p>\n\n\n\n<p>[00:15:40] <strong>Nathan Wrigley:</strong> Attributes.</p>\n\n\n\n<p>[00:15:41] <strong>Seth Rubenstein:</strong> That&#8217;s what it really effectively comes down to, is you bind attributes. So you could say that the text, the content attribute, in Core paragraph, well, that&#8217;s not coming from whatever you typed in there. It&#8217;s coming from some other programmatic interface somewhere in your system, your plugin, whatever.</p>\n\n\n\n<p>So that lets you use Core paragraph as a layout element, put it wherever you&#8217;d like, but then what&#8217;s inside of it, and perhaps even what happens when you click on it, well, that&#8217;s decided elsewhere.</p>\n\n\n\n<p>What&#8217;s nice about that is it lessens the number of controls that you need to present to the end user, to the designer, to the editor. For them, they just drop the block in there. The plugin handles the bindings. The plugin handles, okay, the text for this paragraph inside this answer should come from here. They don&#8217;t have to think about all that. So it&#8217;s less settings for them actually. It&#8217;s more just drop blocks in.</p>\n\n\n\n<p>[00:16:27] <strong>Nathan Wrigley:</strong> You are very much in the weeds of all this, so I suspect the fact that you&#8217;ve done this and done this over and over again renders it fairly straightforward. How available is this? Is the documentation there?</p>\n\n\n\n<p>[00:16:38] <strong>Seth Rubenstein:</strong> Oh yeah. The documentation is there. The WordPress Dev Blog has a number of tutorials on Block Bindings. And I think once you get started with it, it&#8217;s extremely easy to work with really.</p>\n\n\n\n<p>[00:16:47] <strong>Nathan Wrigley:</strong> Okay, so that was Block Bindings. Next one was Block Bits. Now I&#8217;ve only heard this phrase a couple of times, so you&#8217;re going to have to go 101 on this.</p>\n\n\n\n<p>[00:16:54] <strong>Seth Rubenstein:</strong> Sure. So Block Bits is, this is an API that is very much in development. It&#8217;s a concept more than anything else right now. So with Block Bindings, we can kind of take over a whole paragraph block and change it all out. Well, what if you just need to change one word inside that paragraph? That&#8217;s where Block Bits comes into being.</p>\n\n\n\n<p>So this could be you have typed out your sentence, and maybe there&#8217;s a name in the sentence. And you need to change that name dynamically based on whatever the user&#8217;s choosing in this front end interface. Well, Block Bits, you just select the text, you go to the toolbar, you say, I&#8217;m going to bind, quote unquote, this to this thing.</p>\n\n\n\n<p>And Block Bits, the concept is, okay, we&#8217;re going to look inside of a block, down to a bit, maybe just a character and do something with that. Change it, make it a button, whatever. That&#8217;s really all it is. It&#8217;s a fancy name for taking Block Bindings to the next level, which is kind of inside a string of text.</p>\n\n\n\n<p>[00:17:50] <strong>Nathan Wrigley:</strong> Okay. So it is, again, forgive me if I&#8217;ve parsed it incorrectly, but a Block Bit is a binding inside of some other thing. So in the example you gave, swap out this string for a different string, or it could be swap out this image dynamically for a different image, or, I don&#8217;t know, insert a dollar sign here instead of a pound sign or.</p>\n\n\n\n<p>[00:18:15] <strong>Seth Rubenstein:</strong> Well beyond that, beyond just the switching things out, the other kind of powerful part of the concept, and that&#8217;s where I think the API part is really still in development, and this will take a little bit further is, one of the examples used in the Gutenberg project is things like ISBN numbers.</p>\n\n\n\n<p>So you can imagine that, you know, maybe you&#8217;re running some sort of library like site, you type in an ISBN number. Well, what you want to happen on the front end is maybe a little bit more complex than that. So you type in your ISBN number and the block bit could see that that is an ISBN formatted number, and maybe on the front end it becomes a link with a little popup that goes to the Library of Congress, point to that thing, right?</p>\n\n\n\n<p>So it&#8217;s very analogous to Block Bindings, but it&#8217;s very much very specific small string inside of a larger string. So they give it as sub block bindings. Maybe that&#8217;s even a better term for it. Maybe that&#8217;s what would be called in the future. But I really think of it as sub block binding.</p>\n\n\n\n<p>[00:19:10] <strong>Nathan Wrigley:</strong> And presumably then you can just chain these together inside, well, let&#8217;s go with a paragraph. You could just have a one sentence just full of these block bits. So one followed by another, followed by another. Okay, that&#8217;s really interesting. So you could have a whole sentence, for example, just made up of bits from all over the place.</p>\n\n\n\n<p>[00:19:28] <strong>Seth Rubenstein:</strong> Well, and you could imagine that, beyond just like pulling information, it could be really useful when what we&#8217;re using it for currently is templating, right? So you want this string, this sentence to have these parameters. Maybe it&#8217;s got the format of your post type, and then maybe it&#8217;s got the title in there, and then maybe the date. But maybe that&#8217;s all on one line and not three different blocks.</p>\n\n\n\n<p>One of the things that drives me crazy right now is, let&#8217;s say I want to do a post date, post type, kind of above the post title. I insert a row block, and then I insert my date block, and then I insert my meta block. That&#8217;s like a lot of divs, that&#8217;s a lot of markup for that. It&#8217;s like, why isn&#8217;t that just one paragraph line with that bit of information in there? That&#8217;s where block bits comes into play.</p>\n\n\n\n<p>[00:20:08] <strong>Nathan Wrigley:</strong> So it feels like, again, forgive me, it feels like the kind of thing that we would&#8217;ve used custom fields for in past. And we would&#8217;ve had, I don&#8217;t know, dozens of custom fields, each containing their own discreet bit of data, and we would&#8217;ve had to have figured out a way to drop those into this paragraph. Now this is all handled natively.</p>\n\n\n\n<p>[00:20:25] <strong>Seth Rubenstein:</strong> Yeah, and visually in the editor.</p>\n\n\n\n<p>[00:20:26] <strong>Nathan Wrigley:</strong> Visually in the editor. And so it could be anything. It could be markup, it could be text, it could be an image, it could be, I don&#8217;t know, XML, anything you like. That&#8217;s really powerful.</p>\n\n\n\n<p>[00:20:36] <strong>Seth Rubenstein:</strong> It&#8217;s exciting. It&#8217;s very powerful, and it&#8217;s the API that I am most looking forward to seeing completed. I think it will really, without getting too technical, you go a little bit further, Block Bits, Block Bindings. These things I think are kind of critical for responsive blocks. If we&#8217;re going to change attributes at kind of a micro level based on certain conditions, like those are the kind of frameworks that we need to be able to do that.</p>\n\n\n\n<p>So beyond just like the content and templating stuff, there are deep technical reasons that these APIs continue to be developed out.</p>\n\n\n\n<p>[00:21:07] <strong>Nathan Wrigley:</strong> Okay, I think I&#8217;ve grasped what that is. Just running the clock back a couple of minutes, you imply, no, I think you said that this is in development more so than Block Bindings. So the block bits is ready to use.</p>\n\n\n\n<p>[00:21:20] <strong>Seth Rubenstein:</strong> No. There&#8217;s very much in a conceptual phase, and I think there&#8217;s a lot of other technologies that need to be finished out. There are work on the HTML APIs, even though they&#8217;re really well advanced now over the last couple years, there&#8217;s more work being done on those. I think those things are kind of blockers to keep pushing forward with the Block Bits. But you can start doing Block Bits today. And I do go over that in the presentation.</p>\n\n\n\n<p>What it really comes down to, fundamentally today is, it&#8217;s a rich text custom format, which you can do today. You can go in and make your own kind of custom formats inside the rich text component. You know, that might be bold or italic, a custom format. So it&#8217;s really simple as like, okay, well, I have a custom format that adds a class name to something, and then the HTML tag processor, I look for that class name and I change it out. Bingo, bango. So simple.</p>\n\n\n\n<p>But of course, like I said, Block Bits is much bigger than that. There&#8217;s an idea of kind of like a library of bits and, you know, you can plug it into different data sources and post meta and this and that and the other thing. But right now at least, you can start to experiment with this idea, with templating and kind of getting dynamic bits of content into a string.</p>\n\n\n\n<p>[00:22:28] <strong>Nathan Wrigley:</strong> This feels very much to me, like the kind of thing that needs more eyeballs.</p>\n\n\n\n<p>[00:22:31] <strong>Seth Rubenstein:</strong> It does.</p>\n\n\n\n<p>[00:22:31] <strong>Nathan Wrigley:</strong> It&#8217;s one of those things where you let loose a thousand developers and suddenly some curious thing that nobody thought of occurred and it was like, oh, it does that.</p>\n\n\n\n<p>[00:22:40] <strong>Seth Rubenstein:</strong> Yeah. I really want to get people to experiment with this concept further, because I think we need to push it further because it&#8217;s just so powerful.</p>\n\n\n\n<p>[00:22:48] <strong>Nathan Wrigley:</strong> Yeah, really interesting. Okay, so we did Block Bits. We did Block Bindings. I think the final one that we mentioned was the Interactivity API.</p>\n\n\n\n<p>[00:22:55] <strong>Seth Rubenstein:</strong> Yeah. So the Interactivity API, that is about, it&#8217;s probably about two years old, I think, at this point. I won&#8217;t go into all the history of that, but it is effectively a WordPress native, Preact framework. It&#8217;s really easy to work with. You kind of just write basic HTML and the JavaScript is very easy to get into.</p>\n\n\n\n<p>And what that allows you to do is really add interactions at an atomic level to blocks. You can write all sorts of functions. So you might imagine you have a form block, and it has an on submit action. Not every form does the same thing, right? So maybe you have another block, could be send to Firebase. You drop that in there and it changes, it can actually hoist up its own on submit function into that blocks interactivity. And so it makes it really easy to kind of swap JavaScript functionality in and out, and extend functionality across all your blocks.</p>\n\n\n\n<p>[00:23:47] <strong>Nathan Wrigley:</strong> So it, I guess the easiest way that I parse this was it enables you to have things doing things to other things. That was profound. Things doing things to other things in the same interface.</p>\n\n\n\n<p>[00:23:59] <strong>Seth Rubenstein:</strong> Yeah.</p>\n\n\n\n<p>[00:23:59] <strong>Nathan Wrigley:</strong> You click a button and, I don&#8217;t know, the cart increments by one or something like that. So this kind of thing that really, in the year 2025, given that we&#8217;ve had mobile phones in our hands for decades, this sort of stuff feels like it should have been in websites for decades, but it wasn&#8217;t.</p>\n\n\n\n<p>[00:24:12] <strong>Seth Rubenstein:</strong> Yeah. And the other exciting thing about it is it&#8217;s not just about telling blocks what to do. I find it very interesting that it can communicate data across blocks. So I&#8217;ll come back to Quiz Builder as a really good example. We just rebuilt that with all of these things, Block Bits, Block Bindings, Interactivity API. That just got completely revamped in the last couple months. Before that, what we were doing is we were building out a custom React front end for every single quiz.</p>\n\n\n\n<p>So the users would go in, they would drag and drop, you know, build up these quizzes. And then on top of that, we were recreating all that for a new front end interface. And we had all this service side processing to kind of build up a data model for the quiz and then score the quiz, and we made a performant as we could be, but it wasn&#8217;t.</p>\n\n\n\n<p>[00:24:55] <strong>Nathan Wrigley:</strong> It&#8217;s a lot.</p>\n\n\n\n<p>[00:24:55] <strong>Seth Rubenstein:</strong> Yeah, it&#8217;s a lot. And it&#8217;s a lot of like duplicative work and you&#8217;re like, what for? With this, it&#8217;s now the Interactivity API. Those blocks actually, you know, the answer block just hoists its answer into this larger data model using the Interactivity API.</p>\n\n\n\n<p>So now all that happens client side. So now all these things that we were doing server side, we can do client side with the Interactivity API, and that saves us money, that saves us performance. It yields a better experience for the end user.</p>\n\n\n\n<p>[00:25:19] <strong>Nathan Wrigley:</strong> So over the last 10 minutes or so, we kind of atomised these three things, Block Bits, Block Bindings, Interactivity. We kind of talked about them as separate things, which I guess they are. But from your experience, I&#8217;m guessing that they work in concert really well. In other words, if you understand, if you get into the weeds of those three things, and maybe some other things, you prize open capabilities in WordPress which are pretty profound.</p>\n\n\n\n<p>[00:25:43] <strong>Seth Rubenstein:</strong> Yeah, well, obviously one of the things that I love most about WordPress is it&#8217;s flexibility. Let&#8217;s use Block Bits as an example. This kind of pseudo block bits I&#8217;ve just described, where you register a custom format and then you use the HTML Tag Processor to switch that out. Well, the way that we&#8217;re switching it out is using the Interactivity API.</p>\n\n\n\n<p>So all we do is we say, okay, we look for that class name, we use the HTML Tag Processor, and we add the Interactivity API bits that we need to it. We just say, well, the text value should be this, state dot button text, right? That&#8217;s really easy. But you could do it with block context too.</p>\n\n\n\n<p>So there are all these tools in WordPress, all these different APIs related to blocks that once you start to connect them together, you get composability. I mean, that&#8217;s what it really comes down to. This ability for developers to build blocks that can be, one, reusable, that&#8217;s really important concept for composability, two, stand on their own, right? A button block should do something if it&#8217;s on its own. It should go to a link or something. But if that button block is dropped into another block, it&#8217;s nestable, well its configuration changes. Now it submits for the form, right? It doesn&#8217;t go to a link.</p>\n\n\n\n<p>We&#8217;re at this place where just, there&#8217;s all these tools available to you when you start plugging them all together, really powerful stuff happens.</p>\n\n\n\n<p>[00:26:53] <strong>Nathan Wrigley:</strong> Yeah. And I guess it&#8217;s like anything, once you&#8217;ve made those connections in your own head and done the hard work to understand them all, suddenly ideas begin occurring to you that maybe in a podcast like this, you get to the very edge of that, but you don&#8217;t get into the weeds of that. But once you&#8217;ve peeled it back and understood it, suddenly, aha, I didn&#8217;t realise WordPress could do all of this.</p>\n\n\n\n<p>One of the things that I&#8217;m curious about, because I&#8217;m no developer, I kind of have a desire for this stuff to become available to non-developers. And at the minute it feels like you would really need to be a developer to build this stuff. Obviously you can surface it in a way that a non-developer can access. So your quiz, for example, I&#8217;m guessing I could interact with that almost immediately and understand it. Would there be any utility in building a UI for this so that these kind of things can be accessed?</p>\n\n\n\n<p>[00:27:36] <strong>Seth Rubenstein:</strong> I think so. We have our own UI for this. We have an Interactivity API panel that we actually have on all of our blocks that have interactivity enabled. And what it does is it does allow us some interesting things for end users that they don&#8217;t have to know about.</p>\n\n\n\n<p>So one of those things is you can drop a block into a block that supports interactivity. And the panel shows you all the blocks in the hierarchy that you can connect to. And so you might say, okay, well I want to connect to this, and then I want to pull this action from that interactivity store for this block.</p>\n\n\n\n<p>So now we&#8217;ve enabled it so that it&#8217;s not the developers making all the Interactivity API connections. You know, this does this when it&#8217;s in this block. Actually, you can go in there and decide that for yourself if you want.</p>\n\n\n\n<p>Now obviously that does still require a developer to hook that all up, but what you already see today with Block Bindings is a very similar panel. When you go use a Block Binding today, there&#8217;s a little panel called attributes. You click it, it shows you all the attributes you can connect up to a binding. That&#8217;s part of Gutenberg and WordPress Core right now.</p>\n\n\n\n<p>So I think that interface is already there, and I think as more Block Bindings and plugins start to utilise that, the interface is already there for really people to kind of make these interactivity connections themselves.</p>\n\n\n\n<p>[00:28:50] <strong>Nathan Wrigley:</strong> I suppose I&#8217;m kind of thinking back to the day when WordPress shipped for the first time, custom post types. I presume lots of people made use of them. It might be analogous to where we are at now with this, you know, people who are experienced can use it. But then somebody, some bright spark, came up with the idea of a custom post type plugin with a UI, and this way of just making it visually appealing and straightforward.</p>\n\n\n\n<p>And when you were talking about this sort of, it felt almost like a flow chart that you were building there, where you&#8217;ve got, here&#8217;s the options, just sort of clicking on them with a mouse and dragging it so this feature now goes to this feature, and I&#8217;m binding this to this, that&#8217;s what I was imagining. You know, something really straightforward. Drop dead simple, non developery.</p>\n\n\n\n<p>[00:29:29] <strong>Seth Rubenstein:</strong> Well, I will give a plug for my friends at Automattic. Part of my session was also sharing a product that we&#8217;ve built called Remote Pivot Table, which lets you kind of make really quick pivot tables out of Google Sheets so the data&#8217;s not living inside of WordPress, so that our researchers can really quickly update these data sets, and we don&#8217;t have to do a thing to get the updates. Well, that&#8217;s built on Automattic&#8217;s new Remote Data Blocks. And it actually does exactly what you&#8217;re saying.</p>\n\n\n\n<p>You go in there, you tell it what your data sources are. Airtable, Google Sheets, Shopify, Custom HTTP endpoints if you want, and it will go create the blocks for you. It will create the bindings for you, and it&#8217;ll create the interface for you so that you can select, okay, well, when I&#8217;m building out my interface, you know, this text goes to this binding. It should pull from this value from that Google sheet. So that&#8217;s actually already out in the wild right now.</p>\n\n\n\n<p>[00:30:18] <strong>Nathan Wrigley:</strong> What was it called?</p>\n\n\n\n<p>[00:30:18] <strong>Seth Rubenstein:</strong> Remote Data Blocks.</p>\n\n\n\n<p>[00:30:19] <strong>Nathan Wrigley:</strong> Okay.</p>\n\n\n\n<p>[00:30:20] <strong>Seth Rubenstein:</strong> It&#8217;s on the WordPress plugin repo. I think they just published it this week.</p>\n\n\n\n<p>[00:30:23] <strong>Nathan Wrigley:</strong> I&#8217;ll remember to put that into the show notes. I will dig that out and make sure that that gets into the show notes.</p>\n\n\n\n<p>Yeah, I kind of feel like, even if we were to build the perfect UI, I still feel for most people this may end up being the domain of, get the developer to do it.</p>\n\n\n\n<p>[00:30:38] <strong>Seth Rubenstein:</strong> Yeah, it is very much in the domain of the developer. These are all developer APIs for them to build out tools for others. And I think ultimately what these APIs allow is for developers to make products that are easier to use for the end user. Like I said, less settings, less controls, less all these sidebar panels and stuff, and more just, you drag and drop the block in and in the background, through the Interactivity API, through Block Bindings, through Block Bits, you&#8217;re configuring how that application should work. So it&#8217;s more of just drag and drop for the end user.</p>\n\n\n\n<p>[00:31:09] <strong>Nathan Wrigley:</strong> The features exist, you&#8217;d need to sort of go and figure out how to make it work. I guess we&#8217;ve got all these Block Bindings, we&#8217;ve got all these Block Bits, we&#8217;ve got this enormous complexity that we could get into. How performant is all of this?</p>\n\n\n\n<p>[00:31:22] <strong>Seth Rubenstein:</strong> Extremely.</p>\n\n\n\n<p>[00:31:23] <strong>Nathan Wrigley:</strong> So my fear is you just get carried away and you bind everything to every other thing, and where a bit is available, you make a Block Bit. I can&#8217;t summon up an example, but you get the point. You just get totally carried away. The performance, I would assume there is some hit, but it sounds like not so much.</p>\n\n\n\n<p>[00:31:40] <strong>Seth Rubenstein:</strong> I don&#8217;t think so. I think the performance is actually better for a lot of these things. All of our Interactivity API projects, like technical performance is substantially better than if we had just built out a React frontend ourself.</p>\n\n\n\n<p>Because think about the weight of that. I mean, React is pretty heavy, one. Preact on the other hand, which the Interactivity API is built on is very lightweight. But additionally you have this, I guess the other element which we really kind of haven&#8217;t defined is the HTML Tag Processor. That is what underpins all of these things, all of these APIs, even the Interactivity API, even though that&#8217;s JavaScript,</p>\n\n\n\n<p>When you are writing in the Interactivity API, you can write state and context and all these values in HTML, the HTML tag processor that&#8217;s reading that, that&#8217;s processing it. And it does it so extremely fast. You know, if you&#8217;ve worked with a PHP DOM document, it&#8217;s slow, it&#8217;s very bad. This is not that. This is extraordinarily fast.</p>\n\n\n\n<p>In addition, on the technical performance, when you&#8217;re using the Interactivity API, you get speed on the front end as well, because what you can do is you can pre hydrate information into your JavaScript application before it even loads, on the server side, which is really exciting.</p>\n\n\n\n<p>You can see this today actually. Core query, the query loop, and the pagination. Those use an Interactivity API. When you hover over the two or the next page, what&#8217;s happening is there&#8217;s an Interactivity API function for prefetch. So you&#8217;re prefetching the next page of results. So for the user, boom. They click on it, boom. The results are already there. You go a little bit, further, you can cache that information. So now the user has pre fetched the next page and they&#8217;ve cached it for the next person to come to this page. That just really wasn&#8217;t possible before.</p>\n\n\n\n<p>[00:33:18] <strong>Nathan Wrigley:</strong> No. Is that kind of leaning into sort of core browser technologies as well?</p>\n\n\n\n<p>[00:33:22] <strong>Seth Rubenstein:</strong> Oh yes.</p>\n\n\n\n<p>[00:33:22] <strong>Nathan Wrigley:</strong> Yeah, I&#8217;m just thinking of things like.</p>\n\n\n\n<p>[00:33:25] <strong>Seth Rubenstein:</strong> Well, the prefetch thing is part of the browser technology. I&#8217;ll give you an example. We have this very large religious census we do every decade called the Religious Landscape Study. It&#8217;s extremely complex database with a lot of querying, and a lot of SQL logic. If we were to, you go to a page on this database and there&#8217;s maybe like 12 charts. Well, if we were to load all those 12 charts on page load, like it would take a couple minutes to load the page. The site would probably crash.</p>\n\n\n\n<p>But what we do is, as a user hovers over a chart before they click on it, we prefetch, it and we cache it. So for them, they click it, it&#8217;s instantaneous. But also we&#8217;ve now done the extra work of waiting for the next person, that&#8217;s already waiting there ready for the next person. I cannot state how important this innovation has been for the performance of our site and the Interactivity API.</p>\n\n\n\n<p>[00:34:12] <strong>Nathan Wrigley:</strong> That is actually fairly profound, isn&#8217;t it? Yeah. Sometimes when you are explaining these things, the penny kind of half drops. And then a moment later, the penny drops fully and that one&#8217;s just hit. That&#8217;s actually really profound, isn&#8217;t it? Especially on a high traffic site where you don&#8217;t really want to be doing that thing a thousand times a second, just do it once, more or less.</p>\n\n\n\n<p>[00:34:34] <strong>Seth Rubenstein:</strong> I have a philosophy of if I can offload it to the end user, I&#8217;m going to. You know, I&#8217;m going to use your computer if I can.</p>\n\n\n\n<p>[00:34:41] <strong>Nathan Wrigley:</strong> That&#8217;s fascinating. Okay, so pivot slightly. Do you think there&#8217;s a opportunity here? I expect there&#8217;s a bunch of developers listening to this who either haven&#8217;t experienced this before, haven&#8217;t played with it, and are thinking, okay, I want to wrap a UI around that. I want to build a plugin to make this stuff available. We kind of alluded to this a minute ago. Do you think that there is an opportunity there for developers to kind of neaten this interface up?</p>\n\n\n\n<p>[00:35:02] <strong>Seth Rubenstein:</strong> Oh, yeah. Oh, yeah, absolutely. I would be very excited to see where the future of this lands for the WordPress ecosystem. You think of plugins like Advanced Custom Fields and what that did for WordPress, right? It was obviously possible to register post meta and all this stuff before, but what a hassle. It just was. And it really opened up WordPress as a content management system in a way that no other plugin had really done before.</p>\n\n\n\n<p>So some very smart person, some enterprising person out there, there is an opportunity here to kind of build out something that would do that for the Interactivity API and empower less technically inclined people and maybe just not technical people at all to use this.</p>\n\n\n\n<p>[00:35:39] <strong>Nathan Wrigley:</strong> Yeah. Because despite the fact that you&#8217;ve explained it really clearly, and I&#8217;ve got a grip on it, I suspect that I wouldn&#8217;t want to go through all of the weeds to connect all of those pieces. And I don&#8217;t want to open up a code editor. I want everything to be point, click, type, inside of WordPress, in a really straightforward, well-designed, beautifully thought through interface. Kind of like gold rush territory I think. Maybe there&#8217;s an opportunity here for someone, maybe multiple people.</p>\n\n\n\n<p>Yeah, and it&#8217;s what you said before about these kind of custom post type plugins, there&#8217;s many of them and I think without them, nobody would&#8217;ve been using custom post types, well, not nobody, but a tiny proportion of the people would&#8217;ve started to use them. And I feel the same a bit here. I feel like the things that you&#8217;ve described, they&#8217;re fabulous, technically, conceptually brilliant, but if somebody was to come up with a UI that made them not just conceptually brilliant, but drop dead easy to use, we&#8217;ve got something really incredible.</p>\n\n\n\n<p>[00:36:35] <strong>Seth Rubenstein:</strong> Yeah, absolutely. Yeah, I mean, look, when I first started in WordPress, I didn&#8217;t know how to do custom fields, custom post types. You know, ACF helped me out there. And I do them all by hand now, right? I register all my post types and my post meta by hand. But those sort of plugins that make it easier for, well, not even if you&#8217;re less technically inclined, you&#8217;re busy, you don&#8217;t have the time to learn all these new APIs, it really does help out adoption down the road.</p>\n\n\n\n<p>[00:37:00] <strong>Nathan Wrigley:</strong> And also you can imagine scenarios where people build out pre-configured versions of a thing. So that you might have templates for, I&#8217;m struggling to conceptualise that but, you know, you download this plugin, whatever it may be, and they&#8217;ve pre-configured useful scenarios that are repeatable. And you just, okay, click a button, that gets me 90% of what I want to do and then I go from there, kind of thing. Yeah, that&#8217;s interesting.</p>\n\n\n\n<p>In terms of the bits and pieces that you&#8217;ve described, is there anything which you think might be missing? I know that&#8217;s a difficult question to answer because I&#8217;m asking you to stare into a crystal ball and come up with the future. But is there any kind of concept in here that you&#8217;ve thought, you know what, it&#8217;d be really handy to have that?</p>\n\n\n\n<p>[00:37:37] <strong>Seth Rubenstein:</strong> I think it&#8217;s responsive. Responsive blocks, responsive attributes.</p>\n\n\n\n<p>[00:37:41] <strong>Nathan Wrigley:</strong> Describe what that is because in my head, as soon as I hear responsive, I think viewport width.</p>\n\n\n\n<p>[00:37:45] <strong>Seth Rubenstein:</strong> Yeah, and I think that&#8217;s exactly what I&#8217;m talking about. You know, I think all of the APIs are here. All the bits are in place to make that happen, the work just needs to be done. There&#8217;s actually a function in the Gutenberg source code for, I think it&#8217;s called update attribute on screen size or something like that, where you can kind of, desktop, tablet, mobile changes attribute to match for that viewport size.</p>\n\n\n\n<p>I think this has been the Achilles heel for Gutenberg. It&#8217;s the constant complaint that I hear out of people. And I think that is really the missing link, the, last thing that would really make Gutenberg perfect.</p>\n\n\n\n<p>[00:38:19] <strong>Nathan Wrigley:</strong> So scenarios where you could literally change anything based upon, I don&#8217;t know, we&#8217;re on a tablet now, so what we had on a desktop is no longer appropriate. Again, I&#8217;m struggling to conceptualise what that might be, but again, the same on mobile.</p>\n\n\n\n<p>[00:38:32] <strong>Seth Rubenstein:</strong> I&#8217;ll give you a good example. We have our own grid block, columns block. We made our own grid block because we do this responsive attribute stuff. You might have three columns that are x width on desktop, and then on tablet, well, you might want that middle column actually to move to the first position to be 100% width, right? That&#8217;s a really easy example, but doing that right now is next impossible without having a developer build out that system for you. That&#8217;s just one thing I can think of, but there are a myriad of instances like that.</p>\n\n\n\n<p>[00:39:01] <strong>Nathan Wrigley:</strong> Yeah, the domino fell a bit there. I understand what you mean. So yeah, it could be width, it could be background colour, it could be font size or content, anything.</p>\n\n\n\n<p>[00:39:09] <strong>Seth Rubenstein:</strong> A number of things, yeah. Well, it could be also in the Interactivity API. It could be that, you know, on tablet, actually I want, when you click on this thing, I want it to do something else entirely.</p>\n\n\n\n<p>[00:39:16] <strong>Nathan Wrigley:</strong> The button does a different thing.</p>\n\n\n\n<p>[00:39:17] <strong>Seth Rubenstein:</strong> Yeah.</p>\n\n\n\n<p>[00:39:17] <strong>Nathan Wrigley:</strong> Yeah, okay. That&#8217;s really interesting.</p>\n\n\n\n<p>[00:39:18] <strong>Seth Rubenstein:</strong> Well, I&#8217;ll give you another example. We do that. Well, not to that degree, but Core social links. We wrap that in another block called Navigator Share Link. So when you&#8217;re on mobile and you click on the Facebook button, we&#8217;re not taking you to the Facebook share little window. We just open up the little native browser share thing. You just send it off to your app or whatever, friends, your iMessage, whatever you want to do.</p>\n\n\n\n<p>So I think that kind of device contextuality is one area where there&#8217;s not a lot of guidance or APIs or anything, and that is kind of entirely on the developers to figure out themselves. But I think that&#8217;s probably what&#8217;s missing most from Gutenberg, is that kind of idea of screen or device contextuality.</p>\n\n\n\n<p>[00:40:01] <strong>Nathan Wrigley:</strong> I just think this is all so fascinating. Essentially, during the last 40 minutes or so, you&#8217;ve prized open, I think a really different future for WordPress than I had previously thought. I knew all these things existed. I hadn&#8217;t really connected the dots. And it feels to me as if suddenly you go from building a bunch of websites to anything. Literally anything. If it&#8217;s possible to put in a browser.</p>\n\n\n\n<p>[00:40:27] <strong>Seth Rubenstein:</strong> It&#8217;s a web application framework.</p>\n\n\n\n<p>[00:40:28] <strong>Nathan Wrigley:</strong> Right. There you go. Yeah. A web application. Build anything inside of WordPress, which is not something that I was all that familiar with. Gosh, the future is bright.</p>\n\n\n\n<p>[00:40:37] <strong>Seth Rubenstein:</strong> I mean, we have blocks where people are, you know, drag and drop them together and they&#8217;re building out little calculators. You know, one of our more popular content types is like, put in your income and where you live, and then we&#8217;ll tell you some information about you, you know, about your area or whatever. That&#8217;s a web application. That&#8217;s not a blog post. That&#8217;s not content. That&#8217;s a web application that someone just drag and drop built.</p>\n\n\n\n<p>Yeah, we&#8217;re at a place, you know, the content management stuff of WordPress, man, that&#8217;s rock hard. That&#8217;s settled. Now we&#8217;re going into another era, a new direction where WordPress is this web development framework, first and foremost. For you, the developer, but also your end users to build web applications with, inside of.</p>\n\n\n\n<p>[00:41:19] <strong>Nathan Wrigley:</strong> Yeah, absolutely fascinating. So my intuition that I alluded to at the beginning of this podcast, in 2018 or whatever it is, that promise has now become reality. The year 2025, we got there. And now it just needs a bunch of developers, hopefully, dear listener, if you&#8217;re listening to this, get on board and try to figure this out and make it straightforward so people like me can use it.</p>\n\n\n\n<p>Seth, I think that&#8217;s probably the sweet spot to end it. That&#8217;s a very optimistic future you&#8217;ve painted there. Where do we find you, if somebody&#8217;s listening? I would imagine that there&#8217;s a bunch of people listening to this thinking, I need to speak to Seth.</p>\n\n\n\n<p>[00:41:51] <strong>Seth Rubenstein:</strong> You can find me at sethrubenstein.info. And you can find me on Twitter or Bluesky. Please find me on Bluesky, though, I hate Twitter.</p>\n\n\n\n<p>[00:41:57] <strong>Nathan Wrigley:</strong> We will drop the links into the show notes. So if you head to wptavern.com, search for the episode with Seth Rubenstein, that&#8217;s S-T-E-I-N, search for that and then the links will be there for Seth&#8217;s socials, plus anything to do with the talk that we&#8217;ve been mentioning as well. Seth Rubenstein, thank you so much for chatting to me today.</p>\n\n\n\n<p>[00:42:15] <strong>Seth Rubenstein:</strong> Thank you for having me.</p>\n</div></details>\n\n\n\n<p>On the podcast today we have <a href=\"https://sethrubenstein.info\">Seth Rubenstein</a>.</p>\n\n\n\n<p>Seth is the head of engineering at the Pew Research Center, where he leads a team of developers managing the organisation’s WordPress-based publishing platform for its news site. Passionate about open source, Seth ensures that everything his team builds not only meets the Pew Research Center’s needs, but also benefits the wider community. By actively contributing to the Gutenberg project, he strives to share their solutions, always asking how their work can be given back to help others in the WordPress ecosystem.</p>\n\n\n\n<p>Seth shares fascinating stories from the work h   e’s recently been doing. He breaks down what block composability really means, the ability to build modular, reusable, and even interactive blocks that work seamlessly together, empowering both developers and end users to create sophisticated web applications within the familiar WordPress block editor.</p>\n\n\n\n<p>The conversation gets into some of WordPress’s newest and most promising features, including the Block Bindings API, Block Bits (still very much in development), and the Interactivity API. Seth explains how these tools open a world of possibilities, like building interactive quizzes, dynamically updating content, or even prefetching data, all using blocks, without having to rely on custom React front-ends or heavy server-side processing.</p>\n\n\n\n<p>Seth also talks about the path forward for democratising these advanced capabilities, discussing current limitations, the potential for new UI tools, and what’s still missing in the quest for truly responsive, device-contextual blocks.</p>\n\n\n\n<p>Throughout the episode, Seth makes a compelling case for why now is a golden opportunity for developers and plugin builders to start experimenting, get involved, and shape the next evolution of WordPress as a cutting-edge web application platform.</p>\n\n\n\n<p>Whether you’re a developer curious about the future of Gutenberg or an editor dreaming of more drag-and-drop web app power, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p><a href=\"https://www.pewresearch.org\"> Pew Research Center</a></p>\n\n\n\n<p>Seth and Max Schmeling&#8217;s presentation at WordCamp US 2025 &#8211;  <a href=\"https://us.wordcamp.org/2025/session/block-composability-the-past-and-the-future/\">Block Composability: The Past and The Future</a></p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/block-editor/reference-guides/interactivity-api/\">Interactivity API</a></p>\n\n\n\n<p>Block Bits &#8211; <a href=\"https://make.wordpress.org/core/2024/06/08/proposal-bits-as-dynamic-tokens/\">Proposal: Bits as dynamic tokens</a></p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/block-editor/reference-guides/block-api/\">Block Bindings API</a></p>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2023/03/07/introducing-the-html-api-in-wordpress-6-2/\">HTML API</a></p>\n\n\n\n<p><a href=\"https://preactjs.com\"> Preact framework</a></p>\n\n\n\n<p><a href=\"https://github.com/Automattic/remote-data-blocks\"> Automattic&#8217;s new Remote Data Blocks</a></p>\n\n\n\n<p><a href=\"https://www.pewresearch.org/religious-landscape-study/\"> Religious Landscape Study</a></p>\n\n\n\n<p><a href=\"https://sethrubenstein.info\">Seth&#8217;s website</a></p>\n\n\n\n<p><a href=\"https://bsky.app/profile/sethrubenstein.info\">Seth on Bluesky</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 21 Oct 2025 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"Open Channels FM: Transforming Website Analytics for WordPress Users with a Privacy-First Approach\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=111275\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:105:\"https://openchannels.fm/transforming-website-analytics-for-wordpress-users-with-a-privacy-first-approach/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:222:\"In this episode, Adam chats with the creators of Independent Analytics, a WordPress plugin focusing on user-friendly, privacy-oriented website stats. They highlight its benefits over Google Analytics and upcoming features.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 21 Oct 2025 12:45:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"Open Channels FM: From Identica to ActivityPub: How Open Social Protocols Are Shaping the Future of the Web\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110909\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"https://openchannels.fm/from-identica-to-activitypub-how-open-social-protocols-are-shaping-the-webs-future/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:262:\"The Fediverse, shaped by pioneers like Evan Prodromou, evolved from Identica to ActivityPub, fostering decentralization and user control. It contrasts corporate social networks by promoting openness, privacy, and collaborative development for online communities.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 21 Oct 2025 09:03:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:10;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Matt: Simplify\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150316\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://ma.tt/2025/10/simplify/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:826:\"<p>I have some &#8220;grand theories&#8221; of software engineering: I think there are two tribes of engineers that complexify things or simplify things, and they are in eternal conflict. </p>\n\n\n\n<p><strong>Complexify:</strong> <a href=\"https://jamstack.org/\">Jamstack</a>, headless, Contentstack, Contentful, <a href=\"https://www.acquia.com/blog/what-digital-experience-platform-dxp\">DXP</a>, <a href=\"https://business.adobe.com/blog/basics/digital-asset-management\">DAM</a>, micro-services. </p>\n\n\n\n<p><strong>Simplify:</strong> WordPress, Simplenote, Day One, <a href=\"https://en.wikipedia.org/wiki/Djbdns\">djbdns</a>, <a href=\"https://sqlite.org/\">SQLite</a>. </p>\n\n\n\n<p>Not enough engineers have studied under the code of <a href=\"https://en.wikipedia.org/wiki/Daniel_J._Bernstein\">Daniel J. Bernstein</a>.</p>\n\n\n\n<p></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 21 Oct 2025 04:59:30 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:11;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"Matt: Make No Little Plans\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150274\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://ma.tt/2025/10/make-no-little-plans/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:928:\"<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>Make no little plans. They have no magic to stir men’s blood and probably themselves will not be realized. Make big plans; aim high in hope and work, remembering that a noble, logical diagram once recorded will never die, but long after we are gone will be a living thing, asserting itself with ever-growing insistency. Remember that our sons and grandsons are going to do things that would stagger us. Let your watchword be order and your beacon beauty. Think big.</p>\n</blockquote>\n\n\n\n<p>— <a href=\"http://en.wikipedia.org/wiki/Daniel_Burnham\">Daniel Burnham</a>, Chicago architect (1864–1912) (Hat tip: <a href=\"https://intenseminimalism.com/2010/make-no-little-plans/\">Erin</a>, and the <a href=\"https://summit.co/make-no-small-plans\">Summit folks</a>.) (It&#8217;s an old quote but update in your head to include the ladies too.)</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 19 Oct 2025 20:19:33 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:12;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Matt: Albumin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150261\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://ma.tt/2025/10/albumin/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1026:\"<p>Since reading the <a href=\"https://fourhourworkweek.com/\">Four Hour Workweek</a> and <a href=\"https://tim.blog/\">Tim Ferriss</a> I&#8217;ve been a bit of a bio-hacker, always trying weird and new stuff. Today was a new one! I did therapeutic plasma exchange (TPE), also known as plasmapheresis, which supposedly gives you all the <a href=\"https://en.wikipedia.org/wiki/Young_blood_transfusion\">benefits of parabiosis</a> without, you know, needing to be a vampire or <a href=\"https://www.youtube.com/watch?v=hBA0AH-LSbo\">having a blood boy</a>. So with the awesome folks at <a href=\"https://extension.health/\">Extension Health</a> I had my blood filtered and put back in, which took a few hours. My plasma <a href=\"https://x.com/bryan_johnson/status/1845950287032492378\">was not as clear as Bryan Johnson&#8217;s</a>, with 41 years of microplastics and mold and who knows what else in there. The process took a few hours, and afterward I got some chicken on rice from a Halal cart on Broadway so maybe it all evens out.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 19 Oct 2025 00:42:10 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:13;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:131:\"Gutenberg Times: Abilities API, Block Accessibility Check, Gutenberg Framework, AI creating Blocks and themes—Weekend Edition 345\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=42268\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:137:\"https://gutenbergtimes.com/abilities-api-block-accessibility-check-gutenberg-framework-ai-creating-blocks-and-themes-weekend-edition-345/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:20610:\"<p>Hi there, </p>\n\n\n\n<p>A release party is coming up on <strong>Tuesday, October 21, at 15:00 UTC for WordPress 6.9 Beta 1.</strong> It&#8217;s the first time for this release squad. Good luck! </p>\n\n\n\n<p>Will you start testing WordPress 6.9 next week?  You can use the <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">Beta Tester plugin</a> by <strong>Andy Fragen</strong> and install it on your test site. I am using <a href=\"https://developer.wordpress.com/studio/\">WordPress Studio</a> on my computer for systematic testing and prep work for the <em>Source of Truth</em> post to come out in a few weeks.</p>\n\n\n\n<p>The WordPress Test team already published a few pre-beta calls for testing, you can work through, and they are preparing a comprehensive post for all of WordPress 6.9 testing for next week. </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2025/10/03/help-test-changes-to-template-management/\"><strong>Help test changes to template management</strong></a> </li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2025/10/04/call-for-testing-ability-to-hide-blocks/\"><strong>Call for Testing: Ability to Hide Blocks</strong></a> </li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2025/10/06/call-for-testing-accordion-block/\"><strong>Call for Testing: Accordion Block</strong></a> </li>\n</ul>\n\n\n\n<p>WordPress 6.9 is a big focus of my work now. As always, I&#8217;ll keep you updated. </p>\n\n\n\n<p>Have a fantastic weekend! </p>\n\n\n\n<p>Yours, <img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n\n<p>PS:  On Monday, October 20th, I will be on the 353rd episode of <a href=\"https://wpbuilds.com/news-archive/\"><strong>This week in WordPress</strong></a> show together with Michelle Frechette, Tim Nash, and the brilliant host Nathan Wrigley. <a href=\"https://wpbuilds.com/live/\">You can join us live! </a><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f4fa.png\" style=\"height: 1em;\" /></p>\n\n\n\n<p>PPS: This week, I celebrated the <a href=\"https://icodeforapurpose.com/five-year-anniversary-of-the-gutenberg-nightly/\">five-year anniversary of Gutenberg Nightly. </a><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f389.png\" style=\"height: 1em;\" /> </p>\n\n\n<section class=\"wp-block-newsletterglue-callout undefined not-color-set\" style=\"border-color: #eeeeee; border-radius: 26px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f3efe9;\">\n<p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review. </p>\n\n\n\n<p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience</p>\n</section>\n\n\n<div class=\"wp-block-spacer\" style=\"height: 21px;\"></div>\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<p><strong>Table of Contents</strong></p>\n\n\n\n<nav class=\"wp-block-table-of-contents\"><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/abilities-api-block-accessibility-check-gutenberg-framework-ai-creating-blocks-and-themes-weekend-edition-345/#0-word-press-release-information\">Developing Gutenberg and WordPress</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/abilities-api-block-accessibility-check-gutenberg-framework-ai-creating-blocks-and-themes-weekend-edition-345/#0-p\">Plugins, Themes, and Tools for #nocode site builders and owner</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/abilities-api-block-accessibility-check-gutenberg-framework-ai-creating-blocks-and-themes-weekend-edition-345/#2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/abilities-api-block-accessibility-check-gutenberg-framework-ai-creating-blocks-and-themes-weekend-edition-345/#3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor</a></li></ol></nav>\n</div></div>\n</section>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"></div>\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p>Yesterday, <strong>Matt Mullenweg</strong> talked briefly at <strong>WordCamp Canada</strong>, gave a demo, and then answered questions from the  the audience. The wizards behind the scenes already posted the recording of the session to YouTube. <a href=\"https://www.youtube.com/watch?v=RL-XccK30sY\"><strong>WordCamp Canada 2025—Ma.tt Mullenweg &#8220;Town Hall/AMA&#8221;</strong></a>. If you rather read about the talk on Mullenweg&#8217;s blog, <a href=\"https://ma.tt/2025/10/wordcamp-canada/\">WordCamp Canada Talk</a>. He also added the Q &amp; A transcript as well. </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"></div>\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/\">Gutenberg Changelog #122 – Gutenberg 21.8 and WordPress 6.9</a> with Beth Soderberg of <a href=\"https://bethink.studio/\">Bethink Studio</a></p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Gutenberg Changelog 122 with Beth Soderberg\" class=\"wp-image-42236\" height=\"193\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-11-at-12.32.48.png?resize=652%2C193&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p class=\"has-small-font-size\"><em>If you are listening via Spotify, please leave a comment. If you listen via other podcast apps, please leave a review. It&#8217;ll help with the distribution.</em></p>\n</div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owner</h2>\n\n\n\n<p>In his video <a href=\"https://www.youtube.com/watch?v=iCtjWwWi5sQ\"><strong>AI Builds WordPress Blocks</strong></a> , <strong>Jamie Marsland</strong> introduced <em><a href=\"https://telex.automattic.ai/\">Automattic Telex</a></em> and showed off about ten blocks he and other people built with it, like animated text, a countdown counter, and mermaid diagram and more. Check it out; it&#8217;s not only amazing, it borders on voodoo or magic. </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Tammie Lister</strong> continues her October Challenge on the <strong>Blocktober.fun</strong> site. The latest blocks are <a href=\"https://blocktober.fun/flip-card/\">Flip Card</a>, <a href=\"https://blocktober.fun/emoji-voting/\">Emoji Voting</a>, <a href=\"https://blocktober.fun/highlighter/\">Highlighter</a>, <a href=\"https://blocktober.fun/story-generator/\">Story Generator,</a>  <a href=\"https://blocktober.fun/watermark/\">Watermark</a> and <a href=\"https://blocktober.fun/make-the-logo-bigger/\">Make the logo bigger</a>. You not only can try them all out on Telex and remix them with your own ideas. Lister also shares here elaborate prompts you can study and learn how to skill up your AI work. </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42310\" height=\"460\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-18-at-14.04.11.png?resize=652%2C460&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Troy Chaplin</strong> released <strong><a href=\"https://wordpress.org/plugins/block-accessibility-checks/\">Block Accessibility Check v2.2</a></strong>! It introduces Heading structure validation,  alt-text pattern detection and provides an upgraded URL checks with real TLD validation + dev environment support&#8221;Along with the new release comes a <a href=\"https://blockaccessibilitychecks.com/\">new dedicated website</a> featuring improved docs, feature overviews, and developer API guide&#8221;. Chaplin wrote. The site is focused to assist content creators and developers alike. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Anne Katzeff</strong> shared how she created <a href=\"https://www.askdesign.biz/blog/2025/10/overlapping-columns-with-the-media-text-block/#google_vignette\"><strong>overlapping Columns with the Media &amp; Text Block</strong></a> and little Additional CSS. The step-by-step instructions show you how you can build some dynamic layouts with the core block features. </p>\n\n\n\n<figure class=\"wp-block-image\"><img alt=\"\" src=\"blob:https://gutenbergtimes.com/44a2bf47-9c14-481b-bbe1-29e1c6fe25d0\" /></figure>\n\n\n\n<p><strong>Katzeff</strong> also posted a video of her process on YouTube. <a href=\"https://www.youtube.com/watch?v=kNwkwlwKB4I\"><strong>Overlapping Columns With the Media &amp; Text Block</strong></a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Michael Manuel</strong>, WordPress VIP, posted a four-part series of short video: <a href=\"https://wpvip.com/blog/behind-the-build-modernize-publishing/\"><strong>Behind the Build: How Christianity Today Modernized its Publishing Experience</strong></a> and how the team of <em>WebDevStudios</em> helped transform editorial workflows, infrastructure, and content operations for one of America’s most trusted media brands.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Part 1: <strong>Editorial empowerment &amp; workflow efficiency</strong></li>\n\n\n\n<li>Part 2: <strong>Performance &amp; platform modernization</strong></li>\n\n\n\n<li>Part 3: <strong>Homepage &amp; design system overhaul</strong></li>\n\n\n\n<li>Part 4: <strong>Content migration &amp; CMS modernization</strong></li>\n</ul>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Brad Salomons</strong>, 8r4d Consulting, Ltd, created the <a href=\"https://wordpress.org/plugins/panoramic-slider-block/\"><strong>Panoramic Slider Block</strong></a> to scratch an itch. With this block you can post your Pano photos from your phone camera as it provides horizontal sliding controls.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Brad Salomons - screenshot of the Panoramic Slider Block in the editor. \" class=\"wp-image-42308\" height=\"312\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/screenshot-1-1.png?resize=652%2C312&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p>On the WordPress Developer Blog, <strong>Nick Diego </strong>published a Snippet on <a href=\"https://developer.wordpress.org/news/snippets/how-to-add-custom-blocks-to-navigation-menus/\"><strong>How to add custom blocks to navigation menus</strong></a>. It shows how to use  the <code>blocks.registerBlockType</code> filter to extend the navigation block’s <code>allowedBlocks</code> array.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Elliott Richmond</strong> demonstrated <a href=\"https://www.youtube.com/watch?v=6sgJNNm5EOU\"><strong>how to create a block theme using Claude Code</strong></a> on YouTube. He built a theme from scratch with Claude Code, providing clear structure and Markdown tips for the AI tool. You&#8217;ll discover how to set up a CLAUDE.md file for AI-assisted theme development and how Claude works with the WordPress Block Theme structure.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n<section class=\"wp-block-newsletterglue-callout undefined not-color-set\" style=\"border-color: #f9f9e5; border-radius: 22px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f9f9e5;\">\n<p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2025&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. The earlier years are also available: <strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p>\n</section>\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor</h2>\n\n\n\n<p><br /><strong><a href=\"https://x.com/muhsinlk\">Muhammad Muhsin</a> </strong>senior engineer at Fueled gave a talk on <a href=\"https://wordsesh.com/speakers/muhammad-muhsin\">Building a Web App with the Gutenberg Framework at WordSesh</a> earlier this year. <a href=\"https://wordpress.org/gutenberg-framework/\">What is Gutenberg as a Framework?</a> It&#8217;s a way to use the block editor in a JavaScript application outside of WordPress. Muhsin &#8220;built CareerVision.io using Gutenberg outside WordPress—a standalone React framework for block-based apps&#8221;. You can watch the <a href=\"https://www.youtube.com/watch?v=0JXbtZWA3zI\">presentation on YouTube</a> now.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Ryan Welcher</strong> was the <a href=\"https://www.youtube.com/watch?v=T7kLXWvywww\"><strong>Pro WordPress Developer Watches AI Build a Custom Block… and is Blown Away!</strong></a> He put <a href=\"https://telex.automattic.ai/\">Automattic&#8217;s Telex</a> to the test,  to build a live audio visualizer block inspired by the classic iTunes music visualizer. The AI writes the React code, handles audio input, and even makes the block respond to live microphone sound, all in about 15 minutes. It’s an impressive look at how Telex could reshape the way developers build custom blocks for WordPress. </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>JuanMa Garrido</strong>, developer advocate at Automattic,  livestreamed his ongoing discovery of the <a href=\"https://www.youtube.com/watch?v=m19VM2yIbHU\"><strong>Abilities API</strong></a>.  He explored how to register custom abilities, expose them to AI models, and understand how this fits into WordPress’ broader AI architecture alongside the MCP Adapter and PHP AI API. The recording is now available on YouTube.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<p></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<p class=\"has-text-align-center has-small-font-size\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<p>Featured Image: Photo by MRFE MRFE on <a href=\"https://www.pexels.com/photo/vibrant-geometric-abstract-3d-blocks-design-34268918/\">Pexels.com</a></p>\n\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-left\"><strong>Don&#8217;t want to miss the next Weekend Edition? </strong></p>\n\n\n<form action=\"https://gutenbergtimes.com/feed/\" autocomplete=\"on\" class=\"wp-block-newsletterglue-form ngl-form ngl-portrait\" method=\"post\"><div class=\"ngl-form-container\"><div class=\"ngl-form-field\" style=\"margin-bottom: 25px;\"><label class=\"ngl-form-label\" for=\"ngl_email\"><br />Type in your Email address to subscribe.</label><div class=\"ngl-form-input\"><input autocomplete=\"email\" class=\"ngl-form-input-text\" id=\"ngl_email\" name=\"ngl_email\" required=\"required\" style=\"border-radius: 21px;\" type=\"email\" /></div></div><button class=\"ngl-form-button\" style=\"background-color: #005075; border-color: #005075; border-width: 1px; border-style: solid; color: #ffffff; border-radius: 21px;\" type=\"submit\">Subscribe</button><p class=\"ngl-form-text\">We hate spam, too, and won&#8217;t give your email address to anyone <br />except Mailchimp to send out our Weekend Edition</p></div><div class=\"ngl-message-overlay\"><div class=\"ngl-message-svg-wrap\"><svg fill=\"none\" height=\"24\" stroke=\"#fff\" stroke-width=\"2\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><polyline points=\"20 6 9 17 4 12\"></polyline></svg></div><div class=\"ngl-message-overlay-text\">Thanks for subscribing.</div></div><input id=\"ngl_list_id\" name=\"ngl_list_id\" type=\"hidden\" value=\"26f81bd8ae\" /><input id=\"ngl_double_optin\" name=\"ngl_double_optin\" type=\"hidden\" value=\"yes\" /></form>\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n</section>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 17 Oct 2025 22:14:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:14;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"Matt: WordCamp Canada Talk\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150251\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"https://ma.tt/2025/10/wordcamp-canada/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:46239:\"<p>Howdy and bonjour! First, thank you so much, merci beaucoup, for having me at your WordCamp. I love the spirit of local communities gathering and helping each other learn and grow together. I wasn&#8217;t actually planning to speak or even do a Q &amp; A; I was just going to attend this WordCamp. But since the organizers have given me a bit of your time, I will try to make the best of it. </p>\n\n\n\n<p>I love Canada. I first came here for <a href=\"https://en.wikipedia.org/wiki/Northern_Voice\">the Northern Voice conference</a> in 2006. Was anyone at that one? I think Dave Winer was actually there. It was a pretty awesome one. What&#8217;s that?</p>\n\n\n\n<p>[Here I think Dave said he wasn’t at that one, but a different conference, but can’t remember.]</p>\n\n\n\n<p>Well, that&#8217;s why we blog. My memory is not that good. [laughs] By the way, I think this week is your anniversary, right? </p>\n\n\n\n<p><strong>Dave Winer:</strong> It was actually a couple of weeks ago—31 years.</p>\n\n\n\n<p><strong>MM: </strong>Oh, wow. Thirty-one years. Round of applause! I think why I thought it was your anniversary is that on my blog’s related posts, it showed a post from 2014 that was congratulating you on your 20th because I think <em>The Register</em> or someone did a nice article. </p>\n\n\n\n<p>So yeah, I&#8217;ve since been back dozens of times, including several summers in Montreal, at the jazz festival there—they also do <a href=\"https://haitienfolie.com/\">Le Festival Haïti en Folie</a>, and <a href=\"https://montreal.hahaha.com/home/\">Just For Laughs</a>—and a few times here in Ottawa, where I&#8217;m on the board of a cybersecurity company called Field Effect. We might even have some Field Effect people here—oh, hi! Thanks for coming. </p>\n\n\n\n<p>Let me give a little update on what I’ve been up to. My life’s mission is to democratize publishing, commerce, and messaging. So I have some projects in each of those areas. In publishing, my main work is WordPress, the core software available to everyone. We host it on <a href=\"http://wordpress.com\">WordPress.com</a> and <a href=\"https://pressable.com/\">Pressable</a>, and allow others to host it with <a href=\"https://wpcloud.com/\">WP Cloud</a>—a cool product—and we use <a href=\"https://jetpack.com/\">Jetpack</a> to bring all the best cloud features to every WordPress, wherever it is running. And, of course, running the main community hubs at <a href=\"http://wordpress.org\">WordPress.org</a>, <a href=\"http://wordpress.tv\">WordPress.tv</a>, WordCamps, <a href=\"http://wordpress.net\">WordPress.net</a>, which probably some of y&#8217;all haven&#8217;t heard of, et cetera, et cetera. </p>\n\n\n\n<p>On the social side of publishing, I have <a href=\"https://tumblr.com/\">Tumblr</a>, which is a microblogging social network, but right now it&#8217;s on a different technical stack. I need to switch it over to WordPress, but it&#8217;s a big lift. It&#8217;s over 500 million blogs, actually, and as a business, it&#8217;s costing so much more to run than it generates in revenue. We&#8217;ve had to prioritize other projects to make it sustainable. It&#8217;s probably my biggest failure or missed opportunity right now, but we&#8217;re still working on it. </p>\n\n\n\n<p>I&#8217;m really excited about the personal publishing side of our products: <a href=\"https://dayoneapp.com\">Day One</a> and <a href=\"https://developer.wordpress.com/studio/\">WordPress.com Studio</a> and <a href=\"https://wordpress.org/playground/\">WordPress Playground</a>. Day One is a fully encrypted, shared, and synchronized blogging and journaling app that runs on every device and on the web. You can also have shared encrypted journals with others. It uses the same encryption as one password. It&#8217;s the first place I go to draft an idea—for example, to write this talk. Its editor is not as good as Gutenberg yet, but it&#8217;s pretty decent at allowing multimodal input—which means you can record voice notes, draw things, etc.—and capturing it all. It&#8217;s mostly replaced Evernote, Simplenote, and even private P2s for me. It has some fun features, like when you make a new entry it records, the location, what music you&#8217;re listening to on Apple Music, how many steps you&#8217;ve taken, the weather. Honestly, some features that would be nice to get into WordPress, at least as a plugin. Right now, I just copy and paste it in the WC admin or the Jetpack app if I want to publish something; that could also be made smoother in the future. </p>\n\n\n\n<p>So WordPress.com Studio is built on an open source project called Playground that we created to allow you to spin up WordPress in a WASM container in about 30 seconds, right inside your browser. Who’s tried Playground or Studio? It&#8217;s kind of wild, right? You know how hard it&#8217;s been to set up servers and databases and everything like that, and so to see a WordPress virtual machine spin up in like 30 seconds just blows my mind. There&#8217;s so much you can do with it. It&#8217;s the most sci-fi thing happening inside of WordPress right now, and we&#8217;ve just barely begun to take advantage of the massive technical and architectural shift it allows. For example, my colleague <a href=\"https://profiles.wordpress.org/ellatrix/\">Ella</a> builds an iOS app called <a href=\"https://wordpress.org/playground/wordpress-for-native-ios-apps/\">Blocknotes</a>. It’s a lot like Simplenote, but it uses a Gutenberg editor, and it&#8217;s entirely a WordPress playground instance—the entire iOS app. </p>\n\n\n\n<p>Part of the evolution of WordPress has been going from a blogging system to a CMS to a full development platform. So what Dave talked about yesterday, and now that you can build entire mobile apps—which, by the way, can run on every platform, cross-platform, and run the same thing on the web—it&#8217;s kind of like a promise from back in the day of Java or other things, React, Native. It&#8217;s now very possible with this WordPress WASM stuff. WASM stands for <a href=\"https://webassembly.org/\">web assembly</a>. </p>\n\n\n\n<p>The main distractions and things holding back WordPress right now are the legal attacks from WP Engine and Silver Lake—I  can&#8217;t comment on that, but stay tuned for some major updates soon. </p>\n\n\n\n<p>I forgot to put this in my post—WooCommerce! On the commerce side, there&#8217;s, of course, WooCommerce, which is very, very exciting. You can think of it like an open-source Shopify, our enablers here in Ottawa. It now processes over $30 billion of GMV (gross merchant volume) per year, and you can customize it to do pretty much anything: subscriptions, digital, physical goods, everything. And of course, it&#8217;s fully open source and built on WordPress. It&#8217;s actually a WordPress plugin, so pretty exciting. WooCommerce is now on about 8% of all websites in the world—WordPress is 40, so it&#8217;s running on about a quarter of all WordPress sites. It&#8217;s been a big part of the growth of WordPress, actually, the past few years. </p>\n\n\n\n<p>In messaging, we have this product called Beeper. Anyone tried out Beeper yet? We got a Beeper super-user here, actually, in Robert. So Beeper basically takes all the different messaging apps—WhatsApp, Telegram, Instagram DMs, LinkedIn DMs, did you ever check those?—and it brings it all into one app, one interface, kind of like a Superhuman for messaging, and gives you cool features across all of them. Now this is obviously a pretty hard technical challenge, because we have to reverse engineer all the different networks for everything. But check it out, it&#8217;s a pretty fun little app. It&#8217;s, free for up to a couple accounts, and paid after that. </p>\n\n\n\n<p>There&#8217;s also an open source component of that as well. We&#8217;re going to make it easier for people to build bridges and connections to different networks, because there&#8217;s a lot that we don&#8217;t support yet that we get demand for, like <a href=\"https://kakaotalk.en.softonic.com/mac\">KakaoTalk</a> in Asia. People also want to do dating apps, which I guess have messaging platforms. So it’d be pretty fun to have everything all in one. </p>\n\n\n\n<p>I&#8217;ve been in the public a lot, doing lots of talks and actually blogging every single day now for 28 days, which will be 29 when we all hit the publish button at the end of this! So I&#8217;ve been blogging a lot. It&#8217;s a lot to keep up with. Actually been going every day since <a href=\"https://us.wordcamp.org/2025/\">WordCamp US</a>, with one missed day in there. I got very, very inspired at WordCamp US. It was a fantastic event. I got to hang out a lot and go to a bunch of sessions, and it inspired me to blog a lot more. If you run Jetpack, there&#8217;s actually a pretty cool feature where the notifications will tell you what kind of streak you&#8217;re on. So whenever I post, I get this nice little notification, like 28 days. And it has little easter eggs when you get certain number of days in a row, which is fun. So I&#8217;m gonna have to add some of this to the post later—I riffed a little bit. We&#8217;ll get the recording. So now that this is all done, we can push the publish button together. </p>\n\n\n\n<p>This is a cool device called a Daylight computer. So cool. It’s from a startup I&#8217;m invested in through <a href=\"https://audrey.co/\">Audrey Capital</a> and Automattic. Think of it like a cross between a Kindle and an iPad. It works in the daylight, hence the name—it doesn&#8217;t emit any blue light. It&#8217;s great for kids. You can order it on <a href=\"http://daylightcomputer.com\">DaylightComputer.com</a>. It runs Android, so it&#8217;s super hackable. You can have apps like Beeper, Day One, WordPress, Jetpack, WooCommerce on it. Very, very neat device. I actually have WP Admin loaded right here; you can see you can scroll like super, super fast. Soon the wifi is going to work—it&#8217;s a wifi-only device. </p>\n\n\n\n<p>Later I&#8217;ll update this post with an mp3 recording enclosed an RSS in honor of Dave Winer, who spoke here, who invented podcasting and RSS. And actually, if you go way back in my RSS feeds, I have some mp3 enclosures from 2004 and 2005, some very funny early podcasts. Also, whenever they post this video to WordPress TV or YouTube, I&#8217;ll share that too, and I&#8217;ll add some links. Thank you. Merci beaucoup! If you want to follow more. Please check out my blog at <a href=\"https://ma.tt\">ma.tt</a>. No WWW, no .com. Just ma.tt. I cross post to ma.tt on Bluesky and Mastodon and on Tumblr, Instagram and Twitter/X at @photomatt. </p>\n\n\n\n<p>And now we&#8217;re going to push the button together. Y&#8217;all ready? Murphy willing, are you ready to publish? think I need to add a category and stuff, but I&#8217;ll do that later.</p>\n\n\n\n<span id=\"more-150251\"></span>\n\n\n\n<p><strong>Q: </strong>Hi, I’m Michelle Frechette, and I drove up from Rochester, New York on Wednesday, so it&#8217;s good to be here. [Applause] I love that our open source extends beyond just publishing websites and words, and that we have, for now several years, the photo directory, which is available to people—and we are closing in on 30,000 published photos, which I think is phenomenal. </p>\n\n\n\n<p><strong>MM: </strong>And all of those are, I think, <a href=\"https://creativecommons.org/public-domain/cc0/\">CC0</a>, Creative Commons Zero-licensed. So it&#8217;s compatible with GPL, embedded in WordPress themes. You can use it on your site. It&#8217;s very cool.</p>\n\n\n\n<p><strong>Q: </strong>Yeah, you don&#8217;t have to give attribution to anybody. You can just use the photos that are there, which I think is good. What are we going to do so that more people know that it exists, besides the 10,000 people who have submitted photos, because I think it&#8217;s still, it&#8217;s it&#8217;s growing. It&#8217;s huge. There&#8217;s a million beautiful there&#8217;s almost 30,000 beautiful photos in there, but I don&#8217;t think enough people know that it exists yet. So how can we get the word out, to get more people to use it?</p>\n\n\n\n<p><strong>MM: </strong>Well, I think first we should ask questions about it at WordCamps. </p>\n\n\n\n<p><strong>Q: </strong>I&#8217;m on it. </p>\n\n\n\n<p><strong>MM: </strong>So check. We&#8217;re actually just kind of on like a Version One of that whole idea. So in my mind, for things that we should do, is 1: I think we need to better integrate finding those photos in the media library, because right now, it&#8217;s kind of like you have to click a few buttons to get to it. 2: I would like, for every single WP admin when you upload a photo, for you to be able to set the licensing to it. And if it is licensed as CC0, we can submit it to the directory. And of course, the directory has some extra rules, right? Some of these rules, I think we might be able to re-examine now. So for example, right now, in the directory, we don&#8217;t allow anything that shows someone&#8217;s face, right? And the reason for this is, even if something&#8217;s CC0-licensed, to have someone&#8217;s face, you need a model release form. There&#8217;s different laws for that in different countries and things like that make sense, right? You wouldn&#8217;t want someone to take your photo at a WordCamp, and now they think it&#8217;s CC0, and you start seeing them running ads for, you know, some sort of new medicine or Viagra or something; it could be very embarrassing. However, when AI creates a face, there&#8217;s no such restrictions there. So something that we could actually start to do, because right now I think we have some anti-AI rules in the photo directory, I think we should probably start to look at evolving that. So, for example, you can take a picture of me right now, change my face with AI to a face that has never existed, and that could be CC0-licensed and anyone in the world could use it. So I think there&#8217;s some possibilities there. </p>\n\n\n\n<p>Because right now, the laws for AI-generated stuff vary from country to country. I think right now in America, it can&#8217;t be copywritten, at least in the same way. At least if it&#8217;s fully created; when a human starts to modify it, it can be. Sometimes I&#8217;m not familiar with the laws here yet, but I&#8217;m sure I&#8217;ll look them up later. So I think that would be a pretty interesting way to open it up right now, because in theory, we should have way more than 30,000 photos. Actually, I have 30,000 photos on my site, which are mostly GPL-licensed. So how can we—yeah, I do need to submit them. Some of them are already in WordPress Core. So remember <a href=\"https://wordpress.org/themes/twentyten/\">the Twenty Ten theme</a>, which has like the little sheep. People really love those sheep. So all those photos I GPL-licensed a long time ago—in my copious free time, yes. </p>\n\n\n\n<p>So I think those are some of the ideas for it. And also think about another project we do that people aren&#8217;t as familiar with, Openverse search. Has anyone used Openverse yet? It&#8217;s pretty cool. So actually, Creative Commons, the nonprofit, used to have a search engine that indexed the entire web and would allow you to find different types of Creative Commons content, including that requires attribution or other things. The foundation actually was shutting this down, and we took it over, and we now run it on WordPress.org We renamed it to Openverse instead of Creative Commons, but they still index the entire web, including audio files, video files, images, all sorts of stuff. So it&#8217;s a very, very cool project. It is embedded in WP Admin a bit, but again, we probably should combine that with a photo search and other things. </p>\n\n\n\n<p>I also think there&#8217;s some opportunities to use AI analysis of all the photos to give a better semantic understanding and a better search that we currently offer, which right now is typically monollingual, I don&#8217;t think it translates well into the, you know, 60-plus languages that WordPress supports, and it&#8217;s manual tagging. So there might be things to do, like a more automated understanding, which, of course, gets better over time. You know, we started to incorporate some of the AI models like Gemini and other things on WordPress.org to make us way more efficient on things like plug-in submissions and some code scanning. I actually think we&#8217;re very much in chapter one of where this is going to be. It can sort of massively [grow]—because WordPress.org relies on volunteers, basically. Some people are sponsored, but most are not. And we&#8217;re over 60,000 plugins now, or 10,000 themes, and actually, the rate of plugin submission, I think, has basically doubled since last year, and the team has gotten it down where before they had a six-month queue, they&#8217;ve got it down to basically under a week. So you know, we can definitely automate more and more and more and be vastly more efficient and support way more developers and more users, way more everything, and probably improve the code quality. So that&#8217;s another thing I&#8217;m pretty excited about. </p>\n\n\n\n<p><strong>Q: </strong>I love it. <a href=\"http://wordpress.org/photos\">WordPress.org/photos</a>, if you want to look at it. </p>\n\n\n\n<p><strong>MM: </strong>Thank you, Michelle! </p>\n\n\n\n<p><strong>Q: </strong>Hey, Matt. Courtney Robertson. Kind of related to Michelle&#8217;s question: This week, I saw <a href=\"https://iconick.io/\">Nick Hamze</a> recounting how when you go to submit a theme, the image that&#8217;s in the preview for the theme, if it is AI-generated that that&#8217;s getting rejected and the nuances Dion dug into—Dion is one of our long time core commiters, core leads, etc, in the project. A hidden gem. If you haven&#8217;t encountered Dion yet, please find Dion and meet him. So Nick is learning the legal ramifications of having an AI-generated image as part of the theme directory, like what we have to do in the theme directory. Because if the image that&#8217;s in the theme is generated by AI, there&#8217;s a lot of legal stuff about, can we do it? Can we not? And we would all like to just be like, “Yeah, whatever. Move on.” But then there&#8217;s some other ramifications. Is that on your radar? I know we&#8217;ve looked at criteria of what could go into the theme repo and some of those deals.  I don&#8217;t know if. I mean, once we get into legal stuff, that&#8217;s maybe beyond you and I.</p>\n\n\n\n<p><strong>MM: </strong>Well, unfortunately, I&#8217;m getting really good at legal stuff. [Laughter] It wasn&#8217;t on my roadmap for the past year or two, but yeah. So this is very much an evolving area, and the laws from country to country do vary a lot. However, there&#8217;s also some common sense things you can apply, and I think that there is a sort of rapidly—we&#8217;re not putting the genie back in the bottle with AI stuff. One,  just the companies; like, OpenAI is just too big to fail now. The entire economy and growth is based on these systems. The infrastructure buildouts, massive data centers, everything. It&#8217;s kind of incredible. Not to mention the usage, like it&#8217;s really transforming translation, code, so much. </p>\n\n\n\n<p>Now, WordPress.org, particularly, because a lot of this is volunteers, those folks aren&#8217;t comfortable making big policy decisions like this that could have ramifications. They already put a lot on the line. I kind of shield everyone from a legal point of view and everything like that, but in theory, people could go after them, and we have had instances where some of these folks can get oppressed by someone who gets something rejected, or banned from the forums for spamming or stuff like that. So we do try to provide some shelter. </p>\n\n\n\n<p>Now, on this issue, in particular, Nick is someone I talk to almost every day. He&#8217;s doing some very, very cool stuff across WordPress and some innovative things with themes. I like that he pushes the boundaries. So for example, right now, the theme directory is fairly conservative in for example, with the intention that we want the demo to look like the theme when you install it, or we don&#8217;t want it to rely on a plugin. And part of the intention there is that for WordPress, we want you to be able to switch between themes really easily. So one of the beauties of it is that you can take your entire blog site, click a button, and you have a brand new design. Now themes, as they start to incorporate more advanced functionality—which is pretty cool—those sorts of things aren&#8217;t allowed. In fact, one of my favorite examples of something that was in the theme directory a long time ago and is not allowed on the current guidelines, that I think we&#8217;ve made an exception, is the Command Line theme. Has anyone seen this? You load it up, it&#8217;s like a blinking terminal, and you interact with it by typing in commands, like “list,” “post,” and you can type “help,” and it gives you all the things. This is so cool! By the way, I don&#8217;t think it complies with, like, any of our standards. [laughter] Like accessibility, it probably breaks some rules there, all sorts of things. </p>\n\n\n\n<p>So I think part of it is, you know, how can we move? And I think Nick even did a post about this, like rules versus guardrails. So I think part of the way we can do this is as a marketplace. Right now, there&#8217;s certain things that we don&#8217;t allow, and in fact, those rules creep up and get bigger every time, right? Because each sub-team comes in and says, “Oh, I need my rules to be requirements.” Actually, accessibility is a great, great example of that. Now, I think what&#8217;s interesting in a marketplace is we can move these things from being rules to being like tags. So for example, if you were a university, you only want to see themes that were WCAG 2.0 or higher compliant—which are by the way, some pretty strict requirements that don&#8217;t apply to many websites, for good reasons, but that was a requirement. You should be able to do that as a search. Or if you want to see themes that are orange, or all these sorts of things: I feel like those should just be tags in the marketplace, and use the rating system as well to open up what we can host, but then give better tools for people to search and choose what they want. </p>\n\n\n\n<p><strong>Q: </strong>Thanks. Just a shout out. Please let Nick know that a lot of us are reading what he&#8217;s putting forward, and I forget his exact website domain. It&#8217;s <a href=\"https://iconick.io/\">Iconick</a>.</p>\n\n\n\n<p><strong>MM: </strong>It&#8217;s spelled in an interesting way. </p>\n\n\n\n<p><strong>Q: </strong>Yeah, it has his name in it. I wonder where he got that idea. [Laughter]</p>\n\n\n\n<p><strong>MM: </strong>Yeah. So it reads as “iconick.” Nick Hamze, H-A-M-Z-E. Google him. He&#8217;s got some really cool themes. He&#8217;s done a lot of cool projects, <a href=\"https://iconick.io/wapuu-slaps/\">a bunch of Wapuus</a>. Actually, I&#8217;m talking to them about how we can upgrade all the Wapuu stuff. By the way, y&#8217;all have some awesome ones at this event. I got the little swag pack with all the stickers and everything. All the sponsors have different ones. You have like, four or five of them. I&#8217;m actually gonna put this sticker on my laptop later, probably that WCF one, so keep an eye out for that.</p>\n\n\n\n<p><strong>Q: </strong>Paul Bearne. I want to talk about <a href=\"https://wordpress.org/plugins/hello-dolly/\">Hello Dolly</a>, the plugin, which shipped with Core.</p>\n\n\n\n<p><strong>MM: </strong>Which, by the way, people tried to get rid of because of copyright issues. Yeah, there&#8217;s actually some interesting things we did to get around that and make it fair use.</p>\n\n\n\n<p><strong>Q: </strong>Should it be removed?</p>\n\n\n\n<p><strong>MM: </strong>You&#8217;re asking the wrong guy.</p>\n\n\n\n<p><strong>Q: </strong>Well, it’s there because nobody wants to ask you to come and remove it.</p>\n\n\n\n<p><strong>MM: </strong>No, they ask me like once a year. [Laughter]</p>\n\n\n\n<p><strong>Q: </strong>If it stays, perhaps we could redo the description to indicate that it&#8217;s historic—it was the first plugin, it was the proof of concept—but please don&#8217;t copy it. It&#8217;s no longer good code.</p>\n\n\n\n<p><strong>MM: </strong>I completely disagree with that. Tell me why it&#8217;s not good code. Because it doesn&#8217;t use classes or object orientation? Why is it bad code?</p>\n\n\n\n<p><strong>Q:</strong> It’s not accessible, it’s not translatable. </p>\n\n\n\n<p><strong>MM: </strong>It is translatable. It actually goes through the translation functions.</p>\n\n\n\n<p><strong>Q:</strong> There’s no translation around the strings. </p>\n\n\n\n<p><strong>MM: </strong>That&#8217;s not true. </p>\n\n\n\n<p><strong>Q: ’</strong>Tis true. [Laughter]</p>\n\n\n\n<p><strong>MM: </strong>Then it was removed because it was one of the first things we did the underscore for. Well, let&#8217;s look it up later today, but it&#8217;s not true that no one&#8217;s ever asked me. It does get asked about once a year. There&#8217;s lots of issues on the bug tracker about it. And if there&#8217;s ways to improve it, like make it translatable, I think that&#8217;s great, and I know people have actually used that before to also just change the lyrics to, like, put different songs in there, different things they want to</p>\n\n\n\n<p>say. </p>\n\n\n\n<p><strong>Q: </strong>When it becomes translatable, the [inaudible] can have more fun with the translation strings.</p>\n\n\n\n<p><strong>MM: </strong>Yeah, but they don&#8217;t have to, right? That&#8217;s the fun thing.</p>\n\n\n\n<p><strong>Q: </strong>Then I look forward to some patches. </p>\n\n\n\n<p><strong>MM: </strong>What I don&#8217;t want to do is, I don&#8217;t want to make it super-complicated. I know we did some things, like we moved it to a sub-directory. It actually just used to be a single file, so there have been some minor upgrades there. But the whole idea is to show how easy it is to use the actions and filter system inside of WordPress. </p>\n\n\n\n<p><strong>Q: </strong>There are no actions or filters in that plugin.</p>\n\n\n\n<p><strong>MM: </strong>Yeah, that&#8217;s how it looks in the WP Admin.</p>\n\n\n\n<p><strong>Q: </strong>There&#8217;s no filter on the string</p>\n\n\n\n<p><strong>MM: </strong>Well. we can add a filter on the string. And maybe it&#8217;s, it&#8217;s actually a filter and not translation, might be actually better, because, like you said, like maybe the pot system is not appropriate for that. Although, why not? Like, I&#8217;m sure you can translate those lyrics to French and other things, they would be meaningful. And also the connection to jazz musicians. It was one of the first famous jazz songs by one of my idols, Louis Armstrong, and you know, since then, we&#8217;ve named every release of WordPress in honor of a jazz musician. So that&#8217;s one of the cool things about WordPress versus other software is it has soul. You know, it&#8217;s true. Code is poetry. You know, we honor musicians and artists. You know, one of the first blocks we did in Gutenberg was actually a poetry block, a prose block. Has anyone used this one? It&#8217;s one of these things people are always like, “we should remove this.” [Laughter] </p>\n\n\n\n<p>Actually, I did it because I took a writing poetry course, and the author, a famous poet, was complaining how, when she posted to WordPress she couldn&#8217;t have the formatting correctly—you know how a lot of poetry will use interesting formatting where the white space has significance? Or spacing that has kind of unusual things? So the behavior of the editor, which takes multiple line breaks and combines into one, and other things, all that was being collapsed. And so I said, “Oh!” I think it&#8217;s called the Prose block, but it&#8217;s basically a block inside Gutenberg that preserves white space, kind of like a “pre” tag, and it&#8217;s used by some of the poets out there. So sometimes we do these really niche features for like, very high-end users. So for example, I think three or four of the living Fields Medalists use WordPress—actually, WordPress.com. </p>\n\n\n\n<p>Does anyone know about the <a href=\"https://www.mathunion.org/imu-awards/fields-medal\">Fields Medal</a>? A couple people. So it&#8217;s a math award. It&#8217;s more prestigious than a Nobel Prize. They give away a Nobel Prize every year. This happens only every four years, and some of the smartest people in the world have it, like <a href=\"https://terrytao.wordpress.com/\">Terence Tao</a>, who is, if you don&#8217;t know about him, look him up. He is probably one of the top five smartest people in the world, amazing, brilliant mathematician—he actually just got defunded, but the <a href=\"https://www.simonsfoundation.org/\">Simons Foundation</a> is now sponsoring all his work, which is very exciting. If you don&#8217;t know Jim Simons, he&#8217;s the founder of <a href=\"https://www.rentec.com/Home.action?index=true\">Renaissance Technologies</a>. Has anyone heard of Renaissance Tech? RenTec? One or two people? Oh, I&#8217;m telling you all sorts of cool stuff now. </p>\n\n\n\n<p>So Renaissance Technologies is the most successful hedge fund ever in history. They show, I think, annualized returns of over 40% over 35 years. It&#8217;s actually physicists and mathematicians that came together. Jim Simons was one of them, he went out of business or bankrupt or something, and was like, “gosh, I need to make some money. Maybe I&#8217;ll check out the stocks and trading thing.” And they started out, and they actually did really well, but then in the 80s, it all crashed. Jiim’s big, big innovation was that he invented algorithmic trading. So he basically said, we have humans making decisions. One, they&#8217;re too slow. And two, we don&#8217;t know why it&#8217;s working. And so there must be some fundamental sort of physics or rules of the trading markets and the business systems. And so RenTec started to gather the most data of anyone in the world. The next hedge fund to do this well was Bridgewater, but basically they started getting data sets, like shipping back to the 1400s, like really obscure things. They go get stuff out of books and develop all this priority training data, use it to map the economy and essentially create these models that the mathematicians would come up with. You can only be an investor in this fund if you work for the company, which is pretty interesting. And of course, everyone there is like a decamillionaire and everything. I forget how many employees—200 or 150 or something. Really, really small. So legendary. And he passed away a few years ago, but his foundation funds a ton of fundamental research and physics and math and so he&#8217;s someone I really look up to and admire. I <a href=\"https://ma.tt/2024/07/jim-simons-rip/\">blogged about him</a> earlier last year. He reminds me a lot of my dad, just the way he looks and talks. My dad passed away in 2016, so I really like watching Jim Simon’s stuff. </p>\n\n\n\n<p>Oh, I forgot to say, the point of the Fields Medalists. The reason the Fields Medalists use WordPress is we support a LaTeX plugin. LaTeX is basically like a markup language for doing advanced math formulas. We&#8217;re actually working on an update to this to be a bit more user-friendly. We added support for it in 2005 because Terence Tao started a free WordPress.com account, and he was complaining about this and embedding these images. I followed his blog, and I was like, “oh, we should make a block for this kind of shortcode.” And this shortcode is actually built into Jetpack, so anyone who runs Jetpack has access to this, and it&#8217;s now a Gutenberg block as well. So we&#8217;re adding diversity. So maybe tell the math department here. It’d be awesome to get some more mathematicians and folks on WordPress.</p>\n\n\n\n<p><strong>Q: </strong>Matt, just want to give you a heads up. We’ve got about five minutes left. </p>\n\n\n\n<p><strong>MM: </strong>All right, rapid fire. Should I do some fast ones? I just need to talk a little less.</p>\n\n\n\n<p><strong>Q: </strong>I&#8217;m Chris, I work for Pantheon. As you obviously know, Pantheon does Drupal stuff. So I know WordPress, but I have been watching, particularly, the evolution of their development work in AI, specifically integration in the Drupal admin, and also how the Drupal CMS is onboarding new users to Drupal, and the <a href=\"https://www.drupal.org/project/experience_builder\">Experience Builder</a> that they&#8217;re building. As we gather here today, probably most WordPressers might not be aware that there&#8217;s actually DrupalCon Europe happening in Vienna right now, and there&#8217;s lots of things that are happening out of that. And there&#8217;s a lot of really interesting and exciting things happening in that Drupal space. I know you&#8217;ve had conversations with Dries, because at least Dries <em>says</em> that you&#8217;ve had conversations.</p>\n\n\n\n<p><strong>MM: </strong>We talk semi-regularly. You know, there&#8217;s only there&#8217;s like a dozen people in the world who, like their whole life, is creating CMSes, Dave&#8217;s actually one of them in the room. We&#8217;re just going to do it the rest of our lives. And Dries is one of them, so I have incredible respect. We actually did a talk together with Mike Little, the co-founder of WordPress. So if you look up Dries, Mullenweg, Mike Little, you&#8217;ll you&#8217;ll find this. It&#8217;s pretty cool talk. Actually, we got to talk about the history and everything. </p>\n\n\n\n<p><strong>Q: </strong>So the question here is: To what degree are you looking at or thinking about the types of developments that are happening in Drupal but other CMSes as well, and what can we, as WordPress, learn from those other ecosystems?</p>\n\n\n\n<p><strong>MM: </strong>Oh, it&#8217;s a great question. I’ve got to look up the user ID. I think I was one of the first couple hudnred people registered on drop.org, which is the predecessor to <a href=\"http://drupal.org\">drupal.org</a>. Dries was actually at that Northern Voice conference in 2006; he has a post about it on his blog with some photos. So yeah, I keep in pretty close contact with a number of the other CMSes. Well, I won&#8217;t say close contact, but usually about once a year we&#8217;ll get together with Anthony from Squarespace, Tobi from Shopify, with Dries, whenever we&#8217;re in the same country, or I&#8217;m over in Europe or Boston. I try to look them up, and I test out things pretty regularly. </p>\n\n\n\n<p>So I haven&#8217;t seen the very, very latest stuff for Drupal. I think I checked out one of the last iterations they did. I love that with companies like Pantheon now doing both WordPress and Drupal, we&#8217;re getting a lot of overlap between the communities. So I would say, please bring this stuff over. I mean, we&#8217;re both PHP, we&#8217;re both GPL. It&#8217;s one of the reasons I&#8217;ve always really supported Drupal, even though we&#8217;re kind of mutually exclusive solutions. I&#8217;m always going to be supportive with other open source projects. So yeah, for those people who overlap, like yourself, please make some suggestions. You know, start a P2  post, or do a blog post about it. We&#8217;ll get it in the newsletter, or maybe even if there&#8217;s something specific that we could bring over code wise, we can start to get that incentive into <a href=\"https://core.trac.wordpress.org/\">Trac</a> and everything. Cool. </p>\n\n\n\n<p>I think Drupal also has a plugin to use Gutenberg, right? Yeah, which is pretty cool. It was one of the reasons we designed Gutenberg to actually be portable to other CMSes, and why we&#8217;ve been putting it under license, dual-licensing it so to be embedded even more places, not just GPL.</p>\n\n\n\n<p><strong>Q: </strong>Forgive the AI translation of my words, but it&#8217;ll help me be concise. But here&#8217;s the question. Really, really simple—no, it’s not. WordPress has always thrived because of its open, community-driven ethos, but as the ecosystem grows, we&#8217;re seeing more like large, profit-driven players who don&#8217;t necessarily share the values. How can individual contributors and agencies like ours actively help protect WordPress and uphold the values and ethics that have sustained it from bad actors and people who might try to exploit the community? And do you see room for something more formal, like a certification for individuals and agencies that define what being a good actor is, to help educate clients and even the market, to help protect in a more proactive way from those sorts of bad actors?</p>\n\n\n\n<p><strong>MM: </strong>Well, that&#8217;s a big question. I&#8217;ll try to answer quickly. So first I will say, I don&#8217;t want to say that there&#8217;s bad actors. I think there might be bad actions sometimes, and just temporarily bad actors who hopefully will be good in the future. You know, every saint has a past, every sinner has a future. I never want to define any company or any person as permanently good or bad. Let&#8217;s talk about actions. </p>\n\n\n\n<p>Second, I think with these actions, we can start to create incentive systems, and it&#8217;s part of what we&#8217;re doing with Five for the Future, which is basically saying, you contribute back—which also implies that you&#8217;re not violating the GPL, or something like that. So we&#8217;ve got the hard stuff, like, if you violate the GPL, you&#8217;re gonna get a letter. Violate the trademark. You know, that was more of a legal thing. But also the gentle stuff, like, how can we encourage good behavior by giving people higher rankings in the directory or in the showcase, for example? </p>\n\n\n\n<p>Then finally, I&#8217;ll just say, vote with your wallet. Each one of you here has the ability to strongly influence these companies. If they&#8217;re commercially motivated, great, let&#8217;s commercially motivate them to do the right thing by giving more business to the good companies and less business to the other companies. This has actually been happening a lot the past year. I think I can say this: There&#8217;s a site called <a href=\"https://wordpressenginetracker.com/\">WordPress Engine Tracker</a> which is currently tracking a number of sites that have left a certain host. It&#8217;s about to cross 100,000 that have switched to others host. And 74,000 have gone offline since September of last year. We actually used to make all this data public. The whole list was on there. They got a court order so the data could be fact-checked by press or other people. There was actually a court order that made us that down. So again, trying to muzzle free speech and transparency. But you know, we&#8217;re allowed to keep that site up, so check it out while you can. </p>\n\n\n\n<p>Do we have time for one more. Is this last one?</p>\n\n\n\n<p><strong>Q: </strong>Okay, I don&#8217;t think this qualifies as rapid fire, but it&#8217;s a softball. First of all, I came to WordPress as an open source advocate. I became a b2 user. That&#8217;s how I got to WordPress. So my all-time favorite WordPress release is 1.5, because it has what I consider a killer feature. It&#8217;s not the one you&#8217;re thinking. It’s pages.</p>\n\n\n\n<p><strong>MM: </strong>1.5 right? Yeah, I remember introducing that. Originally. I had a different CMS I was going to release called ContentPress. Or Multipattern. I wasn&#8217;t sure what to call it, and so I had this whole other CMS. And I was like, man, we should just build this into WordPress, even though it&#8217;s a blogging system. I think having this pages feature put us ahead of Movable Type and others. So yeah, glad we did. I think we introduced themes and that I released him. </p>\n\n\n\n<p><strong>Q: </strong>Yes, themes was the was kind of the obvious big feature for it, but pages is the point at which I would say that WordPress went from blogging engine to CMS. So that&#8217;s my favorite. But what I was going to ask is—</p>\n\n\n\n<p><strong>MM: </strong>So it&#8217;s all been downhill since then? </p>\n\n\n\n<p>[Laughter]</p>\n\n\n\n<p><strong>Q: </strong>No, it was such a pivotal moment that helped with WordPress&#8217;s meteoric adoption rates. And for me, personally, at that time, it allowed me to take a whole bunch of static HTML and bring it into WordPress so I could manage it so much more easily. So my question was: can you tell us a story, or give us some fun facts about that? Softball question, unless it really taxes your memory.</p>\n\n\n\n<p><strong>MM: </strong>Well, luckily I blog. I&#8217;ll say that two of my favorites ever in history are 1.2 and 1.5—which actually came out right after each other, because we skipped a few releases; it was a time when we actually got pretty delayed. So 1.2 introduced the hooks and filter system, which was pretty revolutionary, I think still, as a unique programming paradigm. But before that, to modify WordPress, you&#8217;d actually open up files and change lines. I used to publish these, we called them hacks, and they were. At one point we introduced the hacks file, which made it a little bit better. But then our plugin hook system allowed a separation between the core and the add-ons, but you could go really deep to modify things. Then 1.5 was themes, I believe. So 1.2 was plugins, 1.5 was themes. And then the other big one—I think it was 2 or 2 point something, was when we introduced WYSIWYG for the first time. Which, by the way, was so controversial; people did <em>not</em> want basic WYSIWYG in WordPress, which was funny, like 10 years later, when they&#8217;re like, “Okay, this Gutenberg thing&#8217;s even worse.” I was like, “Ah, I’ve been through <em>this</em> before.” </p>\n\n\n\n<p>So I think that those are kind of the fun stories around there. Again, some of this stuff was pretty slow to be adopted at first. I wasn&#8217;t certain that this should be rolled into WordPress or there should be separate software, but I&#8217;m glad we did. You know, Movable Type was a dominant thing at the time, and their static page functionality wasn&#8217;t very robust. And so the other thing that WordPress did around this time that I thought was pretty awesome is really clean URLs. So where, prior, you know, people would have crufty URLs, like they’d have an ID in the number, or you&#8217;d have for WordPress,—the default’s still there, actually—is like “?p=123,” so creating the mapping system where we map dates, a hierarchy, and these clean slugs to the pages in the back, in the browsing system, essentially, I think was really crucial. And I love that URLs from 20-something years ago still work or redirect to proper things today. So I think that&#8217;s really, really important. Thank you. All right. Last one,</p>\n\n\n\n<p><strong>Q: </strong>Hey, Matt. I&#8217;m Raquel, and I love kitties and surprises. Just some facts. I have a another question around the community. I want to know how do you feel, what are your raw thoughts, on independent WordPress events that are happening in our space now?</p>\n\n\n\n<p><strong>MM: </strong>And do you want to disclose anything there?</p>\n\n\n\n<p><strong>Q: </strong>I mean, I am the one responsible for <a href=\"https://pressconf.events/\">PressConf</a>, so independent WordPress event. So, yeah, how do you feel? I’m just curious as to how we can all get better together, which tends to be my motto.</p>\n\n\n\n<p><strong>MM: </strong>I&#8217;m very much like a “let a thousand flowers bloom” kind of guy. So thank you. I know it&#8217;s a huge labor of love doing something like PressConf. That’s something that’s been very active in WordCamps and other things in the past, and hopefully with WordCamp US going to Phoenix, we’ll have an opportunity to do some work together there. </p>\n\n\n\n<p>So I think that&#8217;s my fundamental, you know, raw thoughts. You know, I do think about, you know, what do we want to encourage in the world as well? So I would just encourage you as an independent organizer. You know, there&#8217;s some beauty there that you don&#8217;t have to follow the rules or guidelines necessarily. And it&#8217;s commercial events. Well, like the tickets cost more than WordCamp and stuff, right? How much is a ticket?</p>\n\n\n\n<p><strong>Q: </strong>Depending on early bird to total, $700 average.</p>\n\n\n\n<p><strong>MM: </strong>And so that’s a bit of a smaller event, right? That&#8217;s part of what people like about it. So the ticket price actually becomes like a little bit of a barrier to entry. It&#8217;s more intimate. You get some really awesome attendees and talks there, as I think about this as well, just like, you know, what do we want to see more of in the world? And, you know, trying to focus time, particularly my time, to those types of things. So that&#8217;s why I came to WordCamp Canada. You know, this is not the biggest WordCamp in the world, but man, this spirit here, and the people and the everything, and like you know, what you’ve all put together, as it’s come together over the past few months, the incredible work of the organizers,the social media team&#8217;s been doing a great job getting some awesome speakers like Jill and Dave and like, I was like, man! That&#8217;s why I was just planning to come and attend. You know, just to check it out, because I was very interested in the content and everything y&#8217;all put together. So again, I guess we&#8217;re out of time. So I just want to say thank you. Thank you. Thank you. I&#8217;m going to run to the restroom, but then I&#8217;ll be right back out in the lobby. I&#8217;m going to take pictures, shake hands, kiss babies. </p>\n\n\n\n<p>[Laughter]</p>\n\n\n\n<p>I can shake the hand of a baby too. It&#8217;s whatever. I’m open-minded. But hey, thank you. I appreciate it.</p>\n\n\n\n<p><strong>Update:</strong> The video is up, it&#8217;s pretty bad I think the audio is pulling from a DJI thing not the microphones, <a href=\"https://www.youtube.com/watch?v=RL-XccK30sY\">but here it is</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 17 Oct 2025 14:24:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:15;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: On Money Stuff\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150241\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://ma.tt/2025/10/money-stuff/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1862:\"<p>There are a few writers who I follow religiously, and one is <a href=\"https://www.bloomberg.com/opinion/authors/ARbTQlRLRjE/matthew-s-levine\">Matt Levine of Bloomberg&#8217;s Money Stuff</a>. For business and finance it&#8217;s one of the smartest and funniest things you can read. Yesterday, I think for the first time, <a href=\"https://www.bloomberg.com/opinion/newsletters/2025-10-15/openai-has-a-business-plan\">he mentioned WordPress</a>! In the context of his quote on this <a href=\"https://x.com/FhantomBets/status/1977410624343965999\">great X thread about how the Polymarket insider predicted the Nobel peace prize winner</a>.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>This trader apparently <em>didn’t </em>have inside information, in the traditional bad sense of like bribing a Nobel committee staffer. Instead, web scraping:</p>\n\n\n\n<p>&#8220;The Nobel site runs on WordPress. Like many WordPress setups, it has an XML sitemap that lists every indexable page, even ones not yet public. If someone were monitoring this sitemap, they could easily notice a new page appear, something like &#8220;http://nobelprize.org/prizes/peace/2025/machado/facts/&#8221;</p>\n</blockquote>\n\n\n\n<p>If you run a WordPress site and want the best advice in the world for how to avoid this sort of thing, I <a href=\"https://wpvip.com/\">highly recommend our enterprise WordPress VIP service</a>! They help run some of the largest and most secure WordPress sites in the world, and could easily help navigate avoiding something like this from happening. WordPress is easy and cheap to run everywhere, <a href=\"https://projects.raspberrypi.org/en/projects/lamp-web-server-with-wordpress\">even on a Raspberry Pi</a>, but you get what you pay for, and any serious organization or mission-critical website should be on VIP.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 17 Oct 2025 04:25:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:16;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"Matt: The Curse of the Muse\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150237\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"https://ma.tt/2025/10/muse/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2443:\"<p>Some days, like this morning when I almost missed <a href=\"https://ma.tt/2025/10/in-canada/\">my flight to WordCamp Canada in Ottawa</a>, I’m so overwhelmed with the maelstrom of ideas and sparks of creation that it feels like waves crashing against a dam. There are so many ways I can imagine new software, new products, new ways for the world to be.</p>\n\n\n\n<p>This is a beautiful process, but it&#8217;s also painful! The anguish and agony arise as you attempt to distill the ideas and sparks; the creativity dims, and the beauty and perfection of the original inspiration fade, as I try to translate it into something that can become real and be legible to others. That’s why I have to drop everything when inspiration strikes, because if I try to return to it later, I find the muse has left and I can’t bottle that energy anymore. (There&#8217;s a reason <a href=\"https://meyerweb.com/\">Eric</a>, <a href=\"https://tantek.com/\">Tantek</a>, and I put &#8220;muse&#8221; <a href=\"https://gmpg.org/xfn/background\">into the XFN standard</a>!)</p>\n\n\n\n<p>To the extent I’ve been successful at all in my life, it is because I’m able to contain this tornado and break it down into plans, business models, people, and teams.  <em>I’ve never done anything useful on my own</em>; it’s always been in conversation and partnership with others. </p>\n\n\n\n<p>I&#8217;m grateful to everyone I work with across <a href=\"https://automattic.com/\">Automattic</a>, WordPress, <a href=\"https://audrey.co/\">Audrey</a>, <a href=\"https://tinkertendo.com/\">TinkerTendo</a>, <a href=\"https://keysjazzbistro.com/\">Keys</a>, <a href=\"https://www.theinstitute.com/\">The Institute</a>, <a href=\"https://illuminate.org/\">Illuminate</a>, <a href=\"https://ecoamerica.org/\">EcoAmerica</a>, <a href=\"https://fieldeffect.com/\">Field Effect</a> (in Ottawa!), as well as all my <a href=\"https://www.facebook.com/saxmatt\">friends</a> and <a href=\"https://www.linkedin.com/in/mattm/\">professional connections</a>. They are the ones that help me shape this energy into things that actually have an impact in the world and aren’t just fever dreams.</p>\n\n\n\n<p>This essay itself had <a href=\"https://quoteinvestigator.com/2012/04/28/shorter-letter/\">hundreds more words</a>, but I have to <a href=\"https://www.amazon.com/dp/0060891548?tag=photomatt08-20\">edit</a>, <a href=\"https://www.youtube.com/watch?v=aStHTTPxlis\">delete delete delete</a>, trim things down.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 16 Oct 2025 00:01:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:17;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"WPTavern: #189 – Weston Ruter on Unlocking WordPress Performance\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=200138\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://wptavern.com/podcast/189-weston-ruter-on-unlocking-wordpress-performance\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:60131:\"<details>Transcript<div>\n<p>[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p>Jukebox is a podcast which is dedicated to all things WordPress. The people, the events, the plugins, the blocks, the themes, and in this case how WordPress Core continues to strive to unlock greater performance.</p>\n\n\n\n<p>If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p>If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox, and use the form there.</p>\n\n\n\n<p>So on the podcast today, we have Weston Ruter. Weston is a longtime WordPress user and contributor. He has been a core committer for 10 years, and he co-led the WordPress 4.9 release. He worked in the WordPress agency space, and has also been sponsored to work on the Core Performance Team. He lives in Portland, which as you will hear, was quite handy for this interview.</p>\n\n\n\n<p>We start the conversation by getting into the big picture, why website speed matters more now than ever, and how WordPress performs out of the box. Weston shares details about measuring true performance. Revealing, for example, that achieving a perfect Lighthouse score isn&#8217;t the end game, and that real user experience metrics like Core Web Vitals and Largest Contentful Paint should shape how developers and site owners think about optimization.</p>\n\n\n\n<p>Throughout the episode, you&#8217;ll learn about the advances made by the WordPress Performance Team, from lazy loading and new image formats, to speculative loading that shaves precious milliseconds off page transitions. Weston explains how many performance improvements are designed to work automatically, democratizing speed, so that even casual WordPress users benefit without needing to be technical experts.</p>\n\n\n\n<p>The conversation also touches on the balance between adding features and avoiding plugin bloat. The hidden impact of browser and device differences, and how large companies, like Google, are working hand in hand with WordPress to raise the bar on speed and usability.</p>\n\n\n\n<p>Weston offers practical tips, deep technical wisdom, and a glimpse of where WordPress performance is heading next, and it&#8217;s sure to inspire you to think differently about how your sites load, how your users engage, and how you can squeeze out every last drop of speed from the platform you love.</p>\n\n\n\n<p>Whether you&#8217;re a developer, designer, site owner, or just someone curious about what keeps the web running smoothly. This episode is for you.</p>\n\n\n\n<p>If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p>And so without further delay, I bring you Weston Ruter.</p>\n\n\n\n<p>I am joined on the podcast by Weston Ruter. Hello.</p>\n\n\n\n<p>[00:03:28] <strong>Weston Ruter:</strong> Thank you for having me.</p>\n\n\n\n<p>[00:03:29] <strong>Nathan Wrigley:</strong> You are very welcome. I&#8217;m quite jealous of Weston because we&#8217;re in Portland, Oregon at WordCamp US. I had to get on a plane, which was no hardship really in the grand scheme of things. Nevertheless, it was a lengthy plane journey. You, on the other hand, had to get on some public transport to get here because you live in Portland. That must be nice</p>\n\n\n\n<p>[00:03:45] <strong>Weston Ruter:</strong> I live about five miles to the east of here, and so I jumped on the bus and I got off and walked to coffee shop and over to the conference center.</p>\n\n\n\n<p>[00:03:53] <strong>Nathan Wrigley:</strong> And twice, two years in a row as well. You&#8217;re very, very lucky.</p>\n\n\n\n<p>[00:03:56] <strong>Weston Ruter:</strong> I was very happy when I found out.</p>\n\n\n\n<p>[00:03:57] <strong>Nathan Wrigley:</strong> Yeah. So Weston&#8217;s here today because of a presentation that he&#8217;s giving at WordCamp US. I will read into the record the title of the presentation that you&#8217;re giving, The Site Speed Frontier with Performance Lab and Beyond. So it&#8217;s all about performance, this episode essentially.</p>\n\n\n\n<p>This is one of those subjects where I feel you have to tell us your credentials so that we understand that what you are saying is true. Because I think there&#8217;s a lot of snake oil, certainly from my point of view, quite a lot of ignorance. I don&#8217;t really understand this topic inside and out. So would you mind, a minute or something like that? Just tell us about you and your history with, well, WordPress, but also performance and so on.</p>\n\n\n\n<p>[00:04:32] <strong>Weston Ruter:</strong> Yeah, sure. I have been a WordPress Core committer for 10 years. And I was in the agency space working at XWP, working on enterprise WordPress sites. And then I joined Google and I was a software engineer working on developer programs engineer, then develop a relations engineer working on the AMP project, which is all about making webpages faster using the AMP framework. And from there I transitioned into working on the Core Performance Team for the past couple years. And we are focused on making WordPress fast for everybody.</p>\n\n\n\n<p>[00:05:15] <strong>Nathan Wrigley:</strong> Okay, great. Thank you so much. So the topic at hand then is going to be about performance. Why are you interested in this? I know obviously there&#8217;s a career in it and what have you. Is this something that you lie awake at night thinking about? Do you obsess about this kind of stuff?</p>\n\n\n\n<p>[00:05:28] <strong>Weston Ruter:</strong> Yeah, it&#8217;s a passion of mine because who likes a slow webpage, right? So it&#8217;s fun to eke every bit of performance out of the loading of something. There&#8217;s a lot of little technical details and things to know and best practices to observe. And so it&#8217;s a fun challenge to be as fast as possible and there&#8217;s always room for improvement.</p>\n\n\n\n<p>[00:05:52] <strong>Nathan Wrigley:</strong> And it kind of feels as if the mantra over many, many years has basically been that, you know, if you can make your website faster, it will be successful. People will visit it, people are getting weary of page load time or what have you. And so maybe we&#8217;ll get into the weeds of all of that.</p>\n\n\n\n<p>How does WordPress, if I was just to go, okay, ignore the hosting that it&#8217;s on. Let&#8217;s just imagine we&#8217;ve got a good host, we&#8217;ll just use that term. If I was to download a vanilla version of WordPress and use the default theme, currently 2025, and do nothing else with it, I&#8217;ve written a few blog posts, maybe that&#8217;s it. How does it do out of the box like that?</p>\n\n\n\n<p>[00:06:25] <strong>Weston Ruter:</strong> Yeah, it turns out my talk is exactly about this, and it uses the 2025 theme as a test case to show how the performance of WordPress fares out of the box. And if you were to load up a site running 2025, the theme and nothing else, and you run it through Lighthouse, the performance testing tool from Google, you&#8217;ll most likely get a 100 score, performance score. And you would think, I&#8217;m done, there&#8217;s nothing else to do. But if you dig into it, just because you get a good score, that doesn&#8217;t mean there&#8217;s still not room for improvement. And there&#8217;s still head room even after 100.</p>\n\n\n\n<p>But yeah, WordPress Core does great out of the box, but there are still many opportunities to make it even faster. And as you had Felix on previously to talk about speculative loading, that&#8217;s one example where the performance is improved yet further. And in the performance lab plugin, which the performance team maintains, we have different performance feature plugins that implement additional optimisations that address different scenarios and use cases that WordPress doesn&#8217;t do well out of the box.</p>\n\n\n\n<p>[00:07:40] <strong>Nathan Wrigley:</strong> It&#8217;s kind of interesting, and I&#8217;ve never heard it framed that way. I&#8217;ve never heard that there was a ceiling above 100. It kind of feels as if that is the ceiling. If you score 100, all bets are off, game over, you&#8217;ve succeeded, hooray, have a party, kind of thing. But no, there&#8217;s still room to be squeezing a little bit out here and there.</p>\n\n\n\n<p>[00:07:57] <strong>Weston Ruter:</strong> Yeah, if you look at a Lighthouse audit, Lighthouse is an example of a lab metric. It simulates a page load for a user, but it&#8217;s not an actual page load for an actual user. It&#8217;s just a simulation. And if you really want to know how your site is actually performing, you need to measure those visits from actual users.</p>\n\n\n\n<p>And if you load up a popular site in Google&#8217;s page speed insights tool, you&#8217;ll see there&#8217;s two different sections on the page. At the top, you&#8217;ll see what users are experiencing, and then at the bottom you&#8217;ll see lab data. And the top is coming from actual site visitors through what&#8217;s called the Chrome User Experience Report. And that tells you how the site is performing in terms of the Core Web Vitals that Google has spearheaded.</p>\n\n\n\n<p>And one of those is called the Largest Contentful Paint or LCP, and that measures the time it takes for the largest element that is most likely going to be the main content of the page to be rendered, from the time you start navigating to the page and that element finishes rendering.</p>\n\n\n\n<p>And a good LCP value is considered from 0 to 2.5 seconds. And so you can have, within 2.5 seconds there&#8217;s a big range in the user experience. So if it&#8217;s just under 2.5 seconds, it&#8217;s considered good, but that doesn&#8217;t mean a 1.5 second page load is actually way better, and a 0.5 second page load is even better yet, and a 0.05 second page load is great, is perfect. That would be the perfection. And that is what we&#8217;re working on.</p>\n\n\n\n<p>[00:09:36] <strong>Nathan Wrigley:</strong> There&#8217;s gradations of it, okay. So within that 100 there may be room to do, aspects of the 100 can be improved. And in this case, by taking the LCP time down.</p>\n\n\n\n<p>We&#8217;re at a conference event. There&#8217;s over a thousand people. There must be designers, developers, SEO people here. There&#8217;s everybody. There&#8217;s the whole gamut of people that use WordPress, probably some people that are new to the whole platform as well. Do you think that performance is something that everybody needs to worry about or are you happy to be one of the few that obsess about it? Is it basically better to leave an expert like yourself to worry about it, or is this something that we can all have a little dabble at and be successful about?</p>\n\n\n\n<p>[00:10:14] <strong>Weston Ruter:</strong> Well, that&#8217;s what we&#8217;re concerned about with the Core Performance Team is making it so that the regular WordPress user doesn&#8217;t have to worry about this, because nobody&#8217;s got time to spend learning like, what is LCP? What is time to first bite? What are these different metrics? And nobody has time to worry about optimising for all these. So WordPress Core should do all this out of the box, and the WordPress ecosystem should implement best practices so that users don&#8217;t have to worry about it.</p>\n\n\n\n<p>[00:10:44] <strong>Nathan Wrigley:</strong> It&#8217;s kind of interesting. I remember, I&#8217;m thinking it was about six years ago, but I don&#8217;t really remember the date. But Google kind of informed everybody that in a period of time, a year&#8217;s time or what have you, these metrics, LCP and, Core Web Vitals basically were going to come in.</p>\n\n\n\n<p>And it felt like everybody in our industry was running around like a headless chicken, trying to understand something that they knew, there was this sword of Damocles moment, this date in the calendar where the SERPs were going to change. It didn&#8217;t feel like a comfortable time. In some senses, it felt like Google was kind of poisoning the water a bit because they were alienating developers who suddenly had to learn this new thing, because they realised their client websites were going to probably tumble in the SERPs.</p>\n\n\n\n<p>And so they had to upskill in this thing that probably they didn&#8217;t want to be involved with. So it was a curious time, but the dust seems to have settled. I don&#8217;t know too much about, you know, whether they were penalties that really were paid by people because they didn&#8217;t have these fabulous Core Web Vital scores. But it definitely put the cat amongst the pigeons for a while anyway.</p>\n\n\n\n<p>[00:11:38] <strong>Weston Ruter:</strong> The factors that go into ranking pages and Google search are, I never knew what they are, so the knowledge I have is that the performance of a page contributes to the ranking in some way. And basically, as I understand it, all things being equal, you have two sites with the same content and same relevance to the user, and one has better performance, then in theory that would rank higher.</p>\n\n\n\n<p>How much value you get in terms of your ranking is debatable or unknown. I don&#8217;t know. But what is important is the user experience and the benefits that you get for your users. And if they have a good experience on your site, then they&#8217;re more likely to come back. More likely to result in a conversion or a purchase, or whatever you&#8217;re looking to get out of your site. So that&#8217;s where I would focus the concerns.</p>\n\n\n\n<p>[00:12:34] <strong>Nathan Wrigley:</strong> If this were the Squarespace or Wix podcast, which of course it isn&#8217;t, it would be much more straightforward to have a conversation about why your site was quick because, you know, it&#8217;s this proprietary platform. There&#8217;s constraints about what you can do on that platform, and they run the whole thing, you know, they&#8217;ve got their arms around everything.</p>\n\n\n\n<p>WordPress, you download it from .org in most cases, and start to pile things on top of it. And very quickly we get the problems developing I guess, you know, the more things that you throw into it, the more plugins and what have you. Would your advice simply be circumspect about what you throw in, or can you, for want of a better phrase, can you concentrate on additional tech to mask over any problems that you have?</p>\n\n\n\n<p>You know, with the best one in the world, if you&#8217;ve got an LMS, it&#8217;s probably going to slow your website down because it&#8217;s doing a lot. If you&#8217;ve got WooCommerce, it&#8217;s probably going to slow yourself, the website, down from the vanilla install with using the 2025 theme that you just mentioned.</p>\n\n\n\n<p>But there&#8217;s this whole marketplace of hosting companies and performance companies who are selling you things that kind of undo the, and I&#8217;m doing air quotes, the damage that you did by putting the plugins in.</p>\n\n\n\n<p>So I don&#8217;t know if you&#8217;ve got anything to say to that. You know, the whole thing about bloating the website, slowing it down, unpicking it with different tech.</p>\n\n\n\n<p>[00:13:49] <strong>Weston Ruter:</strong> Yeah, well, the WordPress ecosystem has a problem with the kitchen sink issue and a plugin that has more features is somehow valued more highly than a plugin that does one thing and does it really well.</p>\n\n\n\n<p>And so in the Performance Lab plugin in our suite of plugins that we feature, we have the goal that a plugin should do one thing and do it really well. And if you don&#8217;t like what the plugin is doing, you deactivate it and switch to another one that is doing that one issue and doing it well.</p>\n\n\n\n<p>But if you have plugins that do so many things, then you&#8217;re really kind of, your hands are tied and it&#8217;s difficult to switch. And maybe that&#8217;s a strategy by some plugins to lock you in to their ecosystem, but it&#8217;s a difficult problem, yeah.</p>\n\n\n\n<p>[00:14:39] <strong>Nathan Wrigley:</strong> And we also have a, you know, we have plugins which are performance plugins. I mean, there&#8217;s dozens of them. I&#8217;m sure we could rattle off, whose job is to fix the problems that you may have created elsewhere in the website. If you&#8217;re in the weeds of it, like you are, you&#8217;ve probably got some vague understanding about it. You understand whether something is snake oil or not, but for the rest of us, that is a Pandora&#8217;s box, and there&#8217;s only chaos in there.</p>\n\n\n\n<p>I don&#8217;t know what will slow my website down. If I download, I&#8217;m going to use LMS again, if I download an LMS platform, I&#8217;m going to hope that the work has been done successfully. But I&#8217;m probably also going to be thinking about, okay, now do I need to talk to my host, get a different hosting environment, get it set up so it&#8217;s perfect for that? Do I need a performance plugin? Caching layers, putting things on the edge.</p>\n\n\n\n<p>And on and on it goes. It makes WordPress a difficult thing for many, many people to use. And so this idea of democratising publishing sort of goes out the window a little bit because it&#8217;s really extraordinarily hard to use.</p>\n\n\n\n<p>[00:15:34] <strong>Weston Ruter:</strong> Yeah. And I think that in addition to democratising publishing, WordPress should also be as part of that democratising performance. And again, making it so that users don&#8217;t have to worry about that.</p>\n\n\n\n<p>And what we&#8217;re doing in Core, we&#8217;re doing exactly that where as one of WordPress&#8217;s core philosophies is decisions, not options, and things should work out of the box.</p>\n\n\n\n<p>But when it comes to the ecosystem, it&#8217;s a open source environment and there&#8217;s no top down control over what a plugin does. So I think there&#8217;s opportunities with projects like the Plugin Check plugin to do more analysis on the performance, in addition to the security and the best practices for being accepted into the directory.</p>\n\n\n\n<p>But if there&#8217;s also a surfacing of performance issues or additional audits that are done on the impact of installing a plugin, that could be really valuable for site owners to get a sense of, this may cause problems if you install it.</p>\n\n\n\n<p>[00:16:37] <strong>Nathan Wrigley:</strong> How long has the Performance Team been a thing? I feel like three years or something like that, but I could be really wrong.</p>\n\n\n\n<p>[00:16:43] <strong>Weston Ruter:</strong> About four years I think.</p>\n\n\n\n<p>[00:16:45] <strong>Nathan Wrigley:</strong> Okay, yeah. And could you just run over the history of that? I was going to say organisation, but let&#8217;s go with team. Could you run us through the history of that team and what you&#8217;ve been able to do?</p>\n\n\n\n<p>Each of the little steps, some of them are quite profound. Some of them feel less profound, but very important. But over those four years, a lot of really incredible work has been done actually. Certainly from my perspective, it does seem that without that team we&#8217;d be in a very, very different place.</p>\n\n\n\n<p>[00:17:15] <strong>Weston Ruter:</strong> I hope that&#8217;s true. I think it is. Yeah, well, it started out focusing on, I think lazy loading of images was one of the first things to land through this team. And with that we also then uncovered that actually lazy loading everything, which while great for reducing the weight of a page, because you&#8217;re not downloading images that aren&#8217;t actually shown. If you lazy load images that are in the initial viewport, that actually hurts the Largest Contentful Paint metric because the browser wastes to start downloading those images until it knows that they&#8217;re in the viewport.</p>\n\n\n\n<p>So out of that came work to not lazy load images that are in the initial view port, and then also moving on to this attribute called fetch priority, which you can have the value of high, for example. So if you add fetch priority high to an image, then the browser&#8217;s going to prioritise loading that first. And so a lot of work was done to add sensible defaults in WordPress Core so that, for example, the featured image of a post gets fetch priority high, so that it gets loaded sooner over images that are not going to be the Largest Contentful Paint, most likely.</p>\n\n\n\n<p>So there&#8217;s that. And then there was also an issue with like emoji in posts where, on every page load there&#8217;s some JavaScript that runs in the head of the page, and it computes whether the browser supports the emoji, like all the emoji. And if the browser doesn&#8217;t support all the emoji, then it loads the Twitter emoji library to render them. And that JavaScript was causing a long task in lower performing browsers, or devices, that was hurting the largest contentful paint as well. So that was fixed as well.</p>\n\n\n\n<p>And then work has been done to add support for new image formats, like AVIF and WebP so that site owners can upload those image formats instead of JPEGs, which take longer to download.</p>\n\n\n\n<p>We talked about speculative loading, and you talked about that with Felix. So that landed in 6.8, which by default will start prefetching the HTML for a page when you mouse down or tap or click, pointer down on a link to give the browser a bit of a headstart. But then the API allows you to be more aggressive about starting that process, just when you hover over the link, for example, and then not just to prefetch the HTML, but to actually render the whole page.</p>\n\n\n\n<p>And so in my talk, which I gave earlier today, I showed the difference between no speculative loading, speculative loading as in WordPress Core right now, the default, and then moderate prefetch. And then lastly, moderate pre-render.</p>\n\n\n\n<p>[00:19:57] <strong>Nathan Wrigley:</strong> Is that done with the plugin? Well, I guess you could do that with code, but there&#8217;s an option to, if you download the plugin, you&#8217;ve got a UI for that as well.</p>\n\n\n\n<p>[00:20:04] <strong>Weston Ruter:</strong> Exactly. There&#8217;s a UI in the plugin that allows you to opt into moderate eagerness, or to use pre-render instead of prefetch. And in the example I showed, let&#8217;s say your time to first bite is a second. Then in the initial example, like on a slow, or on a fast 4G connection, you&#8217;re going to get like 2.27 seconds to load the page. But then with conservative prefetch, that shaves off like 50 milliseconds because the amount of time it takes to mouse down and mouse up is just a little bit of time that it can shave off that&#8217;s just a little bit to the loading of the page.</p>\n\n\n\n<p>But then when you go to moderate prefetch, then the browser can load the page fully in the background. And so then the time to first bite in that case becomes zero because the whole page is already in the browser&#8217;s cache. And that can reduce it to like one second because you totally eliminated the time to first bite.</p>\n\n\n\n<p>And then with the moderate pre rendering, then when you&#8217;re hovered over that link, the browser not only downloads the HTML, but also all the images, builds out the layout, runs the JavaScript. And so then when you click on that link, the page can load instantaneously.</p>\n\n\n\n<p>[00:21:12] <strong>Nathan Wrigley:</strong> So literally instantaneous.</p>\n\n\n\n<p>[00:21:14] <strong>Weston Ruter:</strong> 0.05 seconds.</p>\n\n\n\n<p>[00:21:16] <strong>Nathan Wrigley:</strong> Yeah. It&#8217;s instantaneous. I mean that&#8217;s pretty incredible. All of that is available inside of WordPress, but just to rewind, probably about 50 seconds, the default is not aggressive. The default in WordPress in order to satisfy the kind of 80 20 rule and what have you, the default is to make it so that there has to be some interaction. The mouse has to be invoked. There&#8217;s a click involved.</p>\n\n\n\n<p>That&#8217;s fascinating. So if you really want to get into the weeds of that, you can basically make the next page load almost instantaneously, should you wish to do that.</p>\n\n\n\n<p>One thing that I did get into with, I believe it was Adam Silverstein not that long ago when I had a podcast episode with him. And I don&#8217;t mean to go deeply into this, but there&#8217;s a curious balancing act here, I think with the environment and all of this speculative loading. Because it wouldn&#8217;t be desirable to load, I don&#8217;t know, there&#8217;s 12 navigation links and the mouse happens to go across all of them. And suddenly 12 unnecessary pages were entirely pre-rendered and what have you. So yeah. I don&#8217;t know if you&#8217;ve got any thoughts on that, whether there&#8217;s a balancing act between performance and environmental concerns.</p>\n\n\n\n<p>[00:22:23] <strong>Weston Ruter:</strong> Yeah. By default, speculative loading only operates on pages when you&#8217;re not logged in. And so when you&#8217;re not logged into WordPress, that is most of the time when you&#8217;re going to have a page cache that can serve it from the cache. And so as long as you have page caching in place, then the server isn&#8217;t going to be overly taxed by those requests.</p>\n\n\n\n<p>In the newest version of the Speculative Loading plugin, it has an opt in to speculative loading for logged in users as well. But there&#8217;s a warning that shows up if you don&#8217;t have a persistent object cache active, for example. So, yeah, it&#8217;s important to have good caching in place, good best practices for scaling.</p>\n\n\n\n<p>However, in addition to pre rendering, which the speculative loading plugin enables, there&#8217;s a much older technology for instant page loads that browsers all support, and that is the back forward cache.</p>\n\n\n\n<p>And WordPress sites, by default when you&#8217;re logged out, will benefit from this most of the time. But as soon as you login or if you&#8217;re navigating to like a shopping cart page, or an account page, or checkout page in an e-commerce site. Oftentimes the plugin will invoke this no cash headers function that tells the browser, primarily tells the page cache, hey, don&#8217;t hold onto this response because you don&#8217;t want to cache the shopping cart for one user and then serve it to another user, because then you would be seeing something embarrassing potentially.</p>\n\n\n\n<p>And so that is one of the benefits of sending that header. But it also has the effect of preventing the browser from holding onto that page as well. So if you navigate back and forward from the shopping cart, then you&#8217;ll notice that it doesn&#8217;t load very fast. It loads slow, because the browser has to re-fetch it all from the server, and has to rebuild everything from scratch.</p>\n\n\n\n<p>And so there&#8217;s a effort underway for 6.9 to stop doing that. To allow the browser to hold onto that in memory. And then to address, one of the issues that turned this off to begin with, allowing the browser to store the pages in the cache. Is if you aren&#8217;t logged in, for example, into WordPress. You&#8217;re on some sensitive page maybe putting some API key in or something, and you go to log out, with this back, forward cache, you could hit the back button to go back into the WordPress admin as another person, maybe on a shared computer and look at that page, even though the user had logged out.</p>\n\n\n\n<p>[00:24:50] <strong>Nathan Wrigley:</strong> Yeah, really not good.</p>\n\n\n\n<p>[00:24:51] <strong>Weston Ruter:</strong> Not good. So there&#8217;s a ticket for 6.9 which would solve that problem by invalidating those pages from bfcache so that that privacy concern isn&#8217;t there. And this issue is not just about, well, these back, forward navigations are very common. So the Chrome team found that one in 10 navigations on desktop are these back, forward navigations?</p>\n\n\n\n<p>[00:25:15] <strong>Nathan Wrigley:</strong> A tenth?</p>\n\n\n\n<p>[00:25:16] <strong>Weston Ruter:</strong> Yeah. And on mobile, I think it&#8217;s one in five. So 20% of the time on mobile, you&#8217;re going back and forward using a gesture instead of hitting a link.</p>\n\n\n\n<p>[00:25:25] <strong>Nathan Wrigley:</strong> That maps to my life, but I hadn&#8217;t thought about it.</p>\n\n\n\n<p>[00:25:28] <strong>Weston Ruter:</strong> But the benefit here is not just in that you get a faster page load, but also bfcache, this back, forward cache will preserve the entire state of the page. So in my talk, I showed an example where you, if you have BuddyPress installed, you start typing in an update, a status update, and then you click away to a separate tab, and then if you hit the back button to go back to that initial tab, then you&#8217;ll find without this back, forward cache that your update&#8217;s gone because that input field was constructed with JavaScript. And when you don&#8217;t have back, forward cache, then the entire document object model has to be rebuilt. All the JavaScript has to re-execute. This is also an issue for the block editor. If you navigated away from a page and you didn&#8217;t save a draft, then everything gets lost without this back, forward cache.</p>\n\n\n\n<p>So back, forward cache not only improves performance, giving you the possibility of these instant page loads, but it also preserves that important state on a page that could be lost otherwise.</p>\n\n\n\n<p>[00:26:25] <strong>Nathan Wrigley:</strong> You have a plugin if memory serves, recently in the repo.</p>\n\n\n\n<p>[00:26:30] <strong>Weston Ruter:</strong> Yes. And I got some feedback that it&#8217;s a terrible name, which I agree.</p>\n\n\n\n<p>[00:26:32] <strong>Nathan Wrigley:</strong> What&#8217;s the name? I&#8217;ve forgotten.</p>\n\n\n\n<p>[00:26:33] <strong>Weston Ruter:</strong> It&#8217;s called no cache, bfcache.</p>\n\n\n\n<p>[00:26:36] <strong>Nathan Wrigley:</strong> That was it, yeah.</p>\n\n\n\n<p>[00:26:37] <strong>Weston Ruter:</strong> But if I were to rename it, which I probably will now, it would probably be called Instant Back Forward Navigations or something. It&#8217;s not so short, but.</p>\n\n\n\n<p>[00:26:43] <strong>Nathan Wrigley:</strong> So is the intention to take, are you spearheading that basically? is the intention to roll the learnings from that plugin into Core?</p>\n\n\n\n<p>[00:26:50] <strong>Weston Ruter:</strong> Yeah.</p>\n\n\n\n<p>[00:26:50] <strong>Nathan Wrigley:</strong> And I&#8217;m just going to read this into the record so that everybody understands. You are talking about backwards and forwards by using the buttons, which I guess typically live at the top left of a browser. Those buttons, the arrows that point backwards and forwards.</p>\n\n\n\n<p>[00:27:03] <strong>Weston Ruter:</strong> That&#8217;s right, or the navigation in like the gesture on Android to go back.</p>\n\n\n\n<p>[00:27:07] <strong>Nathan Wrigley:</strong> Yeah, so swipe typically and swipe right. okay. Yeah, that&#8217;s really interesting because I do that all the time. It really hadn&#8217;t occurred to me that was something that could be cached. And if, as you say it&#8217;s 20% on mobile, or 10% on, that&#8217;s a lot of time that you&#8217;re saving.</p>\n\n\n\n<p>Because you do, it&#8217;s a journey, isn&#8217;t it? And sometimes you get to a dead end, and so you just back three times, because you know that you wanted to go back to that product that you saw a minute ago, but you kind of got lost along the way. So that&#8217;s kind of almost like a roadmap item. That&#8217;s 6.9, hopefully. Are there any other things coming in 6.9 that are interesting?</p>\n\n\n\n<p>[00:27:39] <strong>Weston Ruter:</strong> Well, one of the new features in WordPress Core is this Interactivity API.</p>\n\n\n\n<p>[00:27:44] <strong>Nathan Wrigley:</strong> Oh, so nice.</p>\n\n\n\n<p>[00:27:46] <strong>Weston Ruter:</strong> And one of the great things about the Interactivity API is one of its key design principles is server side rendering. So let&#8217;s say you have a navigation block, or you have an image block with a lightbox. All of the HTML and the CSS needed to render those blocks are output on the server. There&#8217;s no need for JavaScript to construct the user interface.</p>\n\n\n\n<p>Nevertheless, there&#8217;s JavaScript needed because there&#8217;s interactivity involved in these interactive blocks. And so with each of these interactive blocks, there&#8217;s a script module that gets added to the page, and it&#8217;s added in the head of the page. And browsers download those script modules with a high priority. And the impact of that is, well, the browser doesn&#8217;t know that these aren&#8217;t important. It could be important, it could not be important.</p>\n\n\n\n<p>But by loading them with a high priority, they compete with loading of more important critical resources like the Largest Contentful Paint image, for example. So by having these modules in the head, then they cause the LCP metric to degrade. And so there&#8217;s a ticket to add fetch priority low to these script tags, which causes the browser to bump them down in priority so that the Largest Contentful Paint image has a chance to load sooner.</p>\n\n\n\n<p>[00:29:04] <strong>Nathan Wrigley:</strong> Yeah. It seems like a game of tennis, this whole thing. For example, the Interactivity API, what a fabulous thing that is, but smuggled into that with something, it sounds unexpected that nobody foresaw that one and okay, need to address that. And here we are, 6.9, that gets addressed.</p>\n\n\n\n<p>[00:29:21] <strong>Weston Ruter:</strong> Yeah, and one of the great things about the Interactivity API as well is that it has really pushed forward the new Script Modules API in WordPress, where what are also called ESM modules or scripts. And these are a new way of writing JavaScript and they are, by default they don&#8217;t block the rendering of the page.</p>\n\n\n\n<p>Whereas if you have a classic script like jQuery in the head of your page, as you start loading the page, the browser has to stop parsing the HTML, it has to fetch the JavaScript, it has to execute the JavaScript, and then because that JavaScript may be doing something like document.write, where it like adds HTML to the page as it&#8217;s executing. Then only after that&#8217;s all finished then the parser can continue and continue laying out the page. So it&#8217;s very bad for performance to have any external, or even inline sometimes, JavaScript in the head.</p>\n\n\n\n<p>And so one way to solve that issue is to slap a defer attribute on that script tag, or an async attribute, and that causes the script to then not block rendering, and it will be executed once the page has finished loading.</p>\n\n\n\n<p>And a nice feature of script modules is that they&#8217;re deferred by default. You can&#8217;t have a blocking script. And so the thinking was, oh, they don&#8217;t block rendering, so we can just put them in the head. But it turns out that they do impact the network, because there&#8217;s other things on the network than just the scripts. And we need to make sure that the critical resources are prioritised, like the LCP image and not just load everything with high priority.</p>\n\n\n\n<p>[00:30:55] <strong>Nathan Wrigley:</strong> It&#8217;s kind of curious because the past of WordPress has been about, you know, you click on links and you generate, I don&#8217;t know a post, a page or something, but you&#8217;ve got this static piece of content, largely. You know, there may be some JavaScript or something, which is doing something fun.</p>\n\n\n\n<p>But the interactivity, API suddenly presents a page which, I don&#8217;t know, you might be stuck on that page for quite a while doing other things. I don&#8217;t know how that leans into the whole performance thing. I don&#8217;t know we could search and filter a bunch of houses or real estate or what have you, and update things. And we are on this one URL but everything&#8217;s getting changed in front of our eyes. So I don&#8217;t know how that whole LCP thing gets bundled into that. It suddenly becomes a much more difficult problem to identify and solve, I guess.</p>\n\n\n\n<p>[00:31:35] <strong>Weston Ruter:</strong> Yeah. So with LCP, it is for that initial page load. So as soon as you interact with the page, then whatever is the largest element then going to be.</p>\n\n\n\n<p>[00:31:47] <strong>Nathan Wrigley:</strong> Oh, that ceases there does it?</p>\n\n\n\n<p>[00:31:48] <strong>Weston Ruter:</strong> Yeah, it stops at that point. However, there are other problems with performance that can arise after that Largest Contentful Paint. So one of the newer Core Web Vital metrics is the Interaction to Next Paint, and that is this INP value. And that is all about how much JavaScript is executing on the page. And JavaScript functions can do a lot of work, so much work that they cause the user interface to appear to halt.</p>\n\n\n\n<p>[00:32:19] <strong>Nathan Wrigley:</strong> Hang.</p>\n\n\n\n<p>[00:32:20] <strong>Weston Ruter:</strong> Yeah, hang. And so that&#8217;s called jank. And it can cause animations to stutter, it can cause a user interface to be sluggish, and you click a button and then nothing happens and then all of a sudden it opens up. And so that&#8217;s an example of a metric that is still very relevant with the Interactivity API. And there&#8217;s been work to establish best practices to make sure that the event handlers for these interactive blocks are using the best practices. Like, it&#8217;s called scheduler.yield, and it allows you to break up a long running task to give the browser a chance to catch its breath so that it doesn&#8217;t cause those long tasks.</p>\n\n\n\n<p>And then another important metric, which continues to matter even after the page is loaded is called the Cumulative Layout Shift or CLS. And that is a very common issue with, where you have ads or something that will just expand as you&#8217;re scrolling down and you lose your place in the page and that hurts your cumulative layout, that CLS score.</p>\n\n\n\n<p>[00:33:19] <strong>Nathan Wrigley:</strong> Yeah. You end up with your finger in entirely the wrong place just as you&#8217;re about to click on things.</p>\n\n\n\n<p>[00:33:23] <strong>Weston Ruter:</strong> That&#8217;s exactly right.</p>\n\n\n\n<p>[00:33:24] <strong>Nathan Wrigley:</strong> Old TechCrunch website. I don&#8217;t know if you&#8217;ve ever came across that one. That was a WordPress one, I believe. And I don&#8217;t know how many times I click entirely the wrong article because it just shifted just at the moment that my finger was descending.</p>\n\n\n\n<p>[00:33:33] <strong>Weston Ruter:</strong> Very aggravating yeah.</p>\n\n\n\n<p>[00:33:34] <strong>Nathan Wrigley:</strong> Yeah, really annoying. We&#8217;re really in the weeds here and what&#8217;s kind of fascinating, obviously you understand it all, I&#8217;m just holding on for dear life here. But it feels as if there&#8217;s a dance between what we&#8217;re expecting the browser to be able to do, and what it actually can do. And I don&#8217;t know if that&#8217;s the case.</p>\n\n\n\n<p>You know, I don&#8217;t know if the fact that I&#8217;ve got a shiny new Mac means that my experience of the web in the future will be better than my 8-year-old Mac over there. That never used to be something that I worried about. It took time to boot that machine, but once it was up and running, that machine was probably just as good at displaying the web as the shiny new one. But now it feels as if that&#8217;s maybe not the case.</p>\n\n\n\n<p>[00:34:13] <strong>Weston Ruter:</strong> It&#8217;s funny you say that because this emoji issue that I described earlier where it was causing this long task as the page was loading, I only discovered that as a problem because I was using a Chromebook as development device.</p>\n\n\n\n<p>[00:34:25] <strong>Nathan Wrigley:</strong> Yeah, notoriously low on specs.</p>\n\n\n\n<p>[00:34:27] <strong>Weston Ruter:</strong> Relatively, that one was even a fast one. But yes, much slower than one of the newer Macs. And so it&#8217;s important to always be testing in an average device, and not always just use the latest and greatest. Because you&#8217;re going to miss performance issues that are probably impacting a lot of users.</p>\n\n\n\n<p>And one of the issues with emojis is, going back to what I described earlier with this long script in the head, now there&#8217;s just an inline script, and even with an inline script, there is still a performance impact where it will stop, because the browser has to stop parsing the page, execute the JavaScript, and then keep going.</p>\n\n\n\n<p>And so I used my new Mac to analyse the performance of that and I didn&#8217;t see a problem. But then I tried the CPU throttling in Chrome Dev Tools where you can emulate low end, low tier device. And in that case, then all of a sudden I saw this 100 millisecond long task pop up, I can&#8217;t remember how long exactly, but it negatively impacted the LCP because it had to spend that time with this underpowered device.</p>\n\n\n\n<p>So, yeah, there&#8217;s many opportunities for optimising things that, if you&#8217;re using devices that people are actually using.</p>\n\n\n\n<p>[00:35:41] <strong>Nathan Wrigley:</strong> I don&#8217;t really know what the expectation is from WordPress over the next decade, but it doesn&#8217;t feel like it&#8217;s going to be limiting itself to websites. It feels like that&#8217;s a portion of it, but Matt Mullenweg often has talked about it being almost like the operating system for the web. Whether or not that will transpire, I don&#8217;t know.</p>\n\n\n\n<p>But certainly for me, a lot of the things that I used to associate with a downloaded app that would run on MacOS or Windows or what have you, I&#8217;m now fully expecting that to be in a browser. And so I expect that the same would be true of our websites. We&#8217;re going to be doing more with them. They&#8217;re going to be requiring more grunt in the background, you know, more interactivity, more filtering, more searching, more database queries. And yeah, I guess WordPress has got to try and keep up with all that.</p>\n\n\n\n<p>[00:36:29] <strong>Weston Ruter:</strong> In improving web performance, it&#8217;s a top down and a bottom up problem. Browsers are working to get faster. They&#8217;re competing with each other, trying to be as fast as possible for all the bragging rights, right? But oftentimes it&#8217;s impossible for the browser to know, even if it&#8217;s as smart as possible, what to prioritise when loading a page.</p>\n\n\n\n<p>So that&#8217;s why when I was working at Google, we were prioritising improving the web at scale through WordPress to implement best practices in how WordPress builds pages so that Chrome doesn&#8217;t have to figure out everything because it&#8217;s impossible for Chrome to figure that out from the top down.</p>\n\n\n\n<p>So if you look at the, over time these Core Vital Metrics, they all consistently are going up and improving, even if a CMS isn&#8217;t necessarily focused on a performance. They all are inching upward. And that&#8217;s because the browser is getting better at performance as well. But when a CMS like WordPress also invests in improving performance, then you can start to see it edging out other CMSs in terms of the relative improvement in performance.</p>\n\n\n\n<p>[00:37:35] <strong>Nathan Wrigley:</strong> Yeah, okay. Let me just parse that. So whether WordPress is at the top or the browser is at the top, you&#8217;ve got this top bottom thing, and it&#8217;s kind of inching in from the top, coming down. Maybe that&#8217;s the browser, and then WordPress at the bottom inching up, if they happily meet in the middle.</p>\n\n\n\n<p>So what you&#8217;re saying is that even if no performance work was done by a Performance Team in WordPress, there would have been in recent years a performance improvement, But the fact that there&#8217;s those two things in symphony with each other means that there&#8217;s a greater performance improvement.</p>\n\n\n\n<p>Given that WordPress, I don&#8217;t know what the number is right now, but the statistic of 43% was always banded around. So it&#8217;s a huge proportion of the internet. Does WordPress have a voice toward Mozilla and Chrome? Does it get to say what the future of browsers might look like? It feels like with that market share, It ought to have a big voice, but I don&#8217;t know if it does.</p>\n\n\n\n<p>[00:38:26] <strong>Weston Ruter:</strong> Well, I remember back when responsive images became a thing, and as I recall that it was WordPress implementing these responsive images that caused browsers to say, okay, we&#8217;re going to implement these now as well. So I think Chrome, I can&#8217;t remember which browser did at first, but it was kind of a catalyst that caused everything to get going.</p>\n\n\n\n<p>And similarly, recently with the speculative loading, it being adopted by WordPress has, I think, caused other browsers to say, okay, we&#8217;re going to implement this as well.</p>\n\n\n\n<p>And yeah, I know that when I was working at Google, and still I&#8217;m in contact with people at Google who work on web standards work, there are initiatives that they&#8217;re working on that they want feedback from WordPress developers to know like, is this going to work for WordPress? And if WordPress can leverage this, and going back and forth between what works for WordPress and what works for browsers and there&#8217;s ongoing conversations, yeah.</p>\n\n\n\n<p>[00:39:25] <strong>Nathan Wrigley:</strong> Yeah, it is kind of interesting. I was talking to somebody from Google, from the Site Kit team, they obviously put up quite a lot of money to be marquee sponsors, if you like. I don&#8217;t know what the word is, you know like a top tier sponsor often at these events. I don&#8217;t know if they&#8217;re sponsoring this one, but there does seem to be some interest from Google.</p>\n\n\n\n<p>I know that Mozilla doesn&#8217;t have the deep pocket, so we&#8217;re not really expecting that. But it&#8217;s nice to hear that, even if it&#8217;s kind of back channels, and it may not be that WordPress gets asked all the time, that there is some sort of symbiosis there. That&#8217;s nice to know.</p>\n\n\n\n<p>[00:39:55] <strong>Weston Ruter:</strong> Well, I remember also seeing recently that Site Kit was voted one of the most trusted WordPress plugins.</p>\n\n\n\n<p>[00:40:01] <strong>Nathan Wrigley:</strong> Yeah, 5 Million plus installs in under five years. And I was kind of surprised by that actually. when I did that interview, I didn&#8217;t realise the numbers were so big. And then after the interview I went out and asked a bunch of random people whether they&#8217;d used it, and a hundred percent of the random selection of 10 people that I asked used it on everything.</p>\n\n\n\n<p>[00:40:20] <strong>Weston Ruter:</strong> Yeah. I use it for sure.</p>\n\n\n\n<p>[00:40:22] <strong>Nathan Wrigley:</strong> Yeah, yeah. It&#8217;s kind of amazing. So just sort of rounding it off a little bit, I&#8217;m guessing that if you were to have your performance hat on, I could be wrong about this. You would be advising people to step away from the classic way of doing things in WordPress with, you know, the classic editor, the classic themes and things. I genuinely don&#8217;t know if there&#8217;s a performance improvement in full site editing, block-based themes, and what have you. Over to you really, it&#8217;s an open ended question.</p>\n\n\n\n<p>[00:40:46] <strong>Weston Ruter:</strong> Yeah, there definitely is a performance benefit to using block themes, and that is because the way that classic themes load, they load progressively where they will print out the head, head tag in the page and then before they render any of the template, they basically locked in the scripts and styles that the page is going to need even though that doesn&#8217;t actually know what&#8217;s going to be in the page for sure. It can make some guesses, but it doesn&#8217;t know for sure.</p>\n\n\n\n<p>And so for classic themes, you&#8217;ll have these massive style sheets that are printed in the head, you&#8217;ll have a whole bunch of scripts that you may or may not use. And as we said before, those scripts may be blocking the rendering and causing all kinds of problems in performance.</p>\n\n\n\n<p>But with block themes, the way that a template is rendered is completely different, where it actually will render all of the blocks in the content first before it goes about rendering the head, the links, the style sheets and the scripts that go in the head of the HTML. And so because of that, a block theme is able to selectively load just the styles and just the scripts that are relevant to the blocks on that specific page. And so the amount of CSS and JavaScript that&#8217;s on a page can be greatly reduced, which greatly improves performance.</p>\n\n\n\n<p>And also, one of the initiatives that we&#8217;ve been working on in the Core Performance Team is related to these responsive images that we were talking about. Where a responsive image, it has all of the different intermediate image sizes that are available. When you upload an image, it&#8217;ll reference all those different image sizes in the source set attribute. And then there&#8217;s the sizes attribute that says which of those intermediate image sizes should be loaded for that image in the page. But because WordPress doesn&#8217;t know classically, in the classic themes, how big an element is going to be, it uses by default the image that is the width of the view port.</p>\n\n\n\n<p>And so on a mobile device, that&#8217;s often fine because images are often the full width of the content. But on a desktop you often have a center column with margins on either side, and maybe the image is going to be in a column or floated to the right. And so oftentimes on desktop, you&#8217;re going to download a much larger image than is relevant to that container on the page.</p>\n\n\n\n<p>And so there&#8217;s a, one of the plugins in Performance Lab is called Enhanced Responsive Images. And what it does is it leverages the block structure in block themes to be able to figure out what the width is for the container of a given image. And then it can craft that sizes attribute to be much more accurate compared to the default sizes attribute. And in my talk, I showed that the performance gains from that enhancement alone are one of the largest that you can have, much more than just using AVIF or a modern image format.</p>\n\n\n\n<p>[00:43:51] <strong>Nathan Wrigley:</strong> Really?</p>\n\n\n\n<p>[00:43:51] <strong>Weston Ruter:</strong> Yeah because, for example, in my test page, I had a jpeg and then I tried it again with an AVIF and the AVIF was 20% smaller, so maybe I could compress it even further. But the Largest Contentful Paint improvement for that was only 2%. But with the Enhanced Responsive Images plugin active, it was able to use a much smaller image size, which is much fewer bites, even as a jpeg compared to the AVIF. And that improved the LCP by I think 45%. So a magnitude and a half higher.</p>\n\n\n\n<p>[00:44:28] <strong>Nathan Wrigley:</strong> It feels like this work is never, ever going to come to an end. There&#8217;s always going to be little things to tweak and squeeze out here, there and everywhere. And there was a really good example just there.</p>\n\n\n\n<p>I think somebody listening to this podcast, if they&#8217;ve got to this point, it&#8217;s kind of really fascinating that most of this stuff would go under the radar for most people.</p>\n\n\n\n<p>I&#8217;m sure almost everything that you&#8217;ve mentioned, for the casual WordPress user, they would never know that that happened. Not many people are going to read the change log or delve into the weeds of what the Performance Team are doing. And yet there it all is, laid out in front of us over the last 40 minutes or so. Yeah, absolutely loads and loads of work. and never ending. You&#8217;ll be here this time next with new things to say.</p>\n\n\n\n<p>[00:45:06] <strong>Weston Ruter:</strong> Hopefully. I don&#8217;t want to work myself out of a job.</p>\n\n\n\n<p>[00:45:07] <strong>Nathan Wrigley:</strong> That&#8217;s absolutely true. Where do you go to find information about this? You know, who are the scholars, or the YouTubers, or the blog post authors? Who are the people that are pushing the boundaries here?</p>\n\n\n\n<p>[00:45:20] <strong>Weston Ruter:</strong> Well, I have recently been loving the WordPress newsletters that go out, like the Repository and Remkus de Vries, his WP, I forget the name.</p>\n\n\n\n<p>[00:45:32] <strong>Nathan Wrigley:</strong> It&#8217;s okay.</p>\n\n\n\n<p>[00:45:33] <strong>Weston Ruter:</strong> It&#8217;s something in, WP in the name. I think, Within WP, but don&#8217;t quote me on that.</p>\n\n\n\n<p>[00:45:36] <strong>Nathan Wrigley:</strong> Oh, it is, Yeah Remkus, Within WP, you&#8217;re right.</p>\n\n\n\n<p>[00:45:39] <strong>Weston Ruter:</strong> Yes. So I subscribe to his performance blog. So Jono Alderson, Jono or Jono?</p>\n\n\n\n<p>[00:45:46] <strong>Nathan Wrigley:</strong> I think Jono. Yeah, we&#8217;ll go with that. And apologies if it&#8217;s not.</p>\n\n\n\n<p>[00:45:49] <strong>Weston Ruter:</strong> Yes. And so all of his posts are brilliant, so yeah. And then, yeah, following just the newsletters, because I don&#8217;t have time to keep up on social media anymore, but I really am thankful for those newsletters because it really saves me a lot of time. It gets me what I need to know.</p>\n\n\n\n<p>[00:46:05] <strong>Nathan Wrigley:</strong> Yeah, I will, link to the ones, the three that you&#8217;ve just mentioned.</p>\n\n\n\n<p>Yeah, that&#8217;s amazing. Thank you. Honestly, it seems a bit trite, but I&#8217;ve been following what the Performance Team have done for the last four years now, from the capacity that I have to understand it, which is pretty low in all honesty. You know, most of what you&#8217;re saying, I can get a purchase on the overarching idea, but as soon as you were to draw back, if you were to show me what you were doing, the code and so on, I would immediately lose my purchase.</p>\n\n\n\n<p>I&#8217;d just like to express how profoundly happy I am that people like you are taking the time to do it. I don&#8217;t know how much thanks you get for stuff like this, but for my part, thank you.</p>\n\n\n\n<p>[00:46:42] <strong>Weston Ruter:</strong> Well, thank you, but no thanks are required because I enjoy doing it, so.</p>\n\n\n\n<p>[00:46:45] <strong>Nathan Wrigley:</strong> Yeah, great. Well thank you. anyway.</p>\n\n\n\n<p>[00:46:46] <strong>Weston Ruter:</strong> I&#8217;ll do it anyway.</p>\n\n\n\n<p>[00:46:47] <strong>Nathan Wrigley:</strong> Yeah, well Weston Ruter thank you so much for chatting to me today. It&#8217;s been a pleasure.</p>\n\n\n\n<p>[00:46:51] <strong>Weston Ruter:</strong> Thank you very much.</p>\n</div></details>\n\n\n\n<p>On the podcast today we have <a href=\"https://weston.ruter.net/\">Weston Ruter</a>.</p>\n\n\n\n<p>Weston Ruter is a long-time WordPress user and contributor. He has been a core committer for 10 years and he co-led the WordPress 4.9 release. He worked in the WordPress agency space and has also been sponsored to work on the Core Performance Team. He lives in Portland, which, as you will hear, was quite handy for this interview.</p>\n\n\n\n<p>We start the conversation by getting into the big picture: why website speed matters more now than ever, and how WordPress performs out of the box. Weston shares details about measuring true performance, revealing, for example, that achieving a perfect Lighthouse score isn’t the end game, and that real user experience metrics like Core Web Vitals and Largest Contentful Paint (LCP) should shape how developers and site owners think about optimisation.</p>\n\n\n\n<p>Throughout the episode, you’ll learn about the advances made by the WordPress Performance Team, from lazy loading and new image formats, to speculative loading that shaves precious milliseconds off page transitions. Weston explains how many performance improvements are designed to work automatically, democratising speed so even casual WordPress users benefit without needing to be technical experts. The conversation also touches on the balance between adding features and avoiding plugin bloat, the hidden impact of browser and device differences, and how large companies like Google are working hand-in-hand with WordPress to raise the bar on speed and usability.</p>\n\n\n\n<p>Weston offers practical tips, deep technical wisdom, and a glimpse of where WordPress performance is heading next, and it’s sure to inspire you to think differently about how your sites load, how your users engage, and how you can squeeze out every last drop of speed from the platform you love.</p>\n\n\n\n<p>Whether you’re a developer, designer, site owner, or just someone curious about what keeps the web running smoothly, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p><a href=\"https://us.wordcamp.org/2025/session/the-site-speed-frontier-with-performance-lab-and-beyond/\">The Site Speed Frontier with Performance Lab and Beyond</a> &#8211; Weston&#8217;s presentation at WordCamp US 2025</p>\n\n\n\n<p>A post about the presentation (above) on <a href=\"https://weston.ruter.net/2025/08/27/the-site-speed-frontier-with-performance-lab-and-beyond/\">Weston&#8217;s own website</a></p>\n\n\n\n<p><a href=\"https://en.wikipedia.org/wiki/Accelerated_Mobile_Pages\">Accelerated Mobile Pages (AMP)</a></p>\n\n\n\n<p><a href=\"https://make.wordpress.org/performance/\">WordPress Core Performance Team</a></p>\n\n\n\n<p><a href=\"https://developer.chrome.com/docs/lighthouse/\">Lighthouse</a></p>\n\n\n\n<p>Podcast &#8211; <a href=\"https://wptavern.com/forums/topic/171-felix-arntz-on-how-speculative-loading-is-speeding-up-your-wordpress-website\">Felix Arntz on How Speculative Loading Is Speeding Up Your WordPress Website</a></p>\n\n\n\n<p><a href=\"https://wordpress.org/plugins/performance-lab/\">Performance Lab plugin</a></p>\n\n\n\n<p><a href=\"https://developer.chrome.com/docs/crux\">CrUX</a> &#8211; Chrome User Experience Report</p>\n\n\n\n<p><a href=\"https://web.dev/articles/lcp\">Largest Contentful Paint (LCP)</a></p>\n\n\n\n<p><a href=\"https://wordpress.org/plugins/plugin-check/\">Plugin Check (PCP)</a></p>\n\n\n\n<p><a href=\"https://web.dev/articles/fetch-priority\">Optimize resource loading with the Fetch Priority API</a></p>\n\n\n\n<p>Podcast &#8211; <a href=\"https://wptavern.com/podcast/178-adam-silverstein-explores-transformative-browser-features-impacting-wordpress-sites\">Adam Silverstein Explores Transformative Browser Features Impacting WordPress Sites</a></p>\n\n\n\n<p><a href=\"https://web.dev/articles/bfcache\">Back/forward cache</a></p>\n\n\n\n<p>Weston&#8217;s <a href=\"https://wordpress.org/plugins/nocache-bfcache/\">Instant Back/Forward plugin</a> (mentioned in the podcast with an older name)</p>\n\n\n\n<p><a href=\"https://developer.wordpress.org/block-editor/reference-guides/interactivity-api/\">Interactivity API Reference</a></p>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2024/03/04/script-modules-in-6-5/\">Script Modules API</a></p>\n\n\n\n<p><a href=\"https://web.dev/articles/inp\">Interaction to Next Paint (INP)</a></p>\n\n\n\n<p><a href=\"https://developer.chrome.com/blog/introducing-scheduler-yield-origin-trial/\">Introducing the scheduler.yield origin trial</a></p>\n\n\n\n<p><a href=\"https://web.dev/articles/cls\">Cumulative Layout Shift (CLS)</a></p>\n\n\n\n<p><a href=\"https://sitekit.withgoogle.com/\">Site Kit plugin</a></p>\n\n\n\n<p><a href=\"https://wordpress.org/plugins/auto-sizes/\">Enhanced Responsive Images plugin</a></p>\n\n\n\n<p><a href=\"https://withinwp.com/\">Within WordPress</a></p>\n\n\n\n<p><a href=\"https://www.jonoalderson.com/\">Jono Alderson&#8217;s website</a></p>\n\n\n\n<p><a href=\"https://www.therepository.email/\">The Repository</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 15 Oct 2025 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:18;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"Matt: D’Angelo &amp;amp; Diane\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150230\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:36:\"https://ma.tt/2025/10/dangelo-diane/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1141:\"<p>Just last night I was re-watching <a href=\"https://en.wikipedia.org/wiki/Annie_Hall\">Annie Hall</a> to remember and <a href=\"https://www.newyorker.com/culture/postscript/diane-keatons-shadows-and-light\">honor Diane Keaton</a>, and now <a href=\"https://www.nytimes.com/2025/10/14/arts/music/dangelo-dead.html\">the  news that D&#8217;Angelo had passed</a>. I&#8217;m writing this listening to <a href=\"https://open.spotify.com/album/2lO9yuuIDgBpSJzxTh3ai8\">Voodoo</a>, one of the great albums of all time. That CD in my beater car in Houston was on constant rotation, the richness of the tracks— it&#8217;s an album you have to listen to in its entirety, it takes you on a journey, the way the tracks blend in to each other. Not ideal for the atomized world of songs being stand-alone.</p>\n\n\n\n<p>D&#8217;Angelo was obviously a star, but one amazing thing about his bands is he brought so many people with him, so many amazing jazz musicians, including Roy Hargrove, Robert Glasper (<a href=\"https://khspva.houstonisd.org/\">HSPVA</a>!), Chris Dave (HSPVA!), Kenny Garrett, Pino Palladino, Questlove&#8230; May his memory be a blessing.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 15 Oct 2025 03:49:42 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:19;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"Open Channels FM: Why Focus Matters When Building a Successful WordPress Plugin Business\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110790\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://openchannels.fm/why-focus-matters-when-building-a-successful-wordpress-plugin-business/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:160:\"Learn the importance of focus in scaling a WordPress plugin, advocating for prioritizing core products over numerous side projects to achieve long-term success.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 14 Oct 2025 11:38:15 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:20;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"Open Channels FM: How Great Storytelling Builds Brand Loyalty and Differentiates Products\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=111053\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:96:\"https://openchannels.fm/how-great-storytelling-builds-brand-loyalty-and-differentiates-products/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:166:\"In this episode, Rae and Adam dig into why storytelling is key for brands to shine in WordPress, sharing tips on connection, differentiation, and authentic messaging.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 14 Oct 2025 08:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:21;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"Matt: Nanochat &amp;amp; MCP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150223\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2025/10/nanochat-mcp/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1156:\"<p>Probably the most interesting thing on the internet today is <a href=\"https://x.com/karpathy/status/1977755427569111362\">Andrej Karpathy&#8217;s nanochat</a>, &#8220;a minimal, from scratch, full-stack training/inference pipeline of a simple ChatGPT clone in a single, dependency-minimal codebase.&#8221; 8,000 lines of beautiful code, <a href=\"https://simonwillison.net/2025/Oct/13/nanochat/\">as Simon Willison notes</a>. If you want to understand how LLMs work, <a href=\"https://github.com/karpathy/nanochat\">study this</a>. Andrej is a code poet.</p>\n\n\n\n<p>In hacking news, Wired has <a href=\"https://www.wired.com/story/satellites-are-leaking-the-worlds-secrets-calls-texts-military-and-corporate-data/\">an amazing article on intercepting geostationary satellite signals</a>.</p>\n\n\n\n<p>On Friday, we turned on something cool: <a href=\"https://wordpress.com/blog/2025/10/07/mcp/\">every WordPress.com site now supports MCP</a>. Right now this is read-only access to your site, because the S in MCP stands for Security, but <a href=\"https://developer.wordpress.com/docs/mcp/prompt-examples/\">you can already start to do some cool stuff with it</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 14 Oct 2025 06:07:14 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:22;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Matt: Last Ball\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150219\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2025/10/last-ball/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:319:\"<p>If you appreciate golf at all, <a href=\"https://www.espn.com/golf/story/_/id/26902640/down-last-ball-how-tiger-avoided-disaster-won-2000-us-open-15\">the story of how Tiger Woods won the U.S. Open at Pebble Beach without knowing he was down to his last golf ball because of arcane rules is pretty interesting</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 13 Oct 2025 06:36:52 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:23;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"Gutenberg Times: Gutenberg Changelog #122 – Gutenberg 21.8 and WordPress 6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://gutenbergtimes.com/?post_type=podcast&p=42245\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:67394:\"<p>In episode 122 of the GT Changelog podcast, host Birgit Pauli-Haack is joined by Beth Soderberg, CEO of bethink Studio, to discuss the latest updates in Gutenberg 21.8 and WordPress 6.9. The conversation kicks off with reminiscing about past WordCamp experiences and transitions into a deep dive on block themes, evolving design tools, and the challenges of adopting new workflows. Beth shares practical insights from her agency work, highlighting the benefits of section and block styles, synced patterns, and strategies for cleaning up legacy code as Gutenberg advances.</p>\n\n\n\n<p>The episode covers new features like section styles, the highly anticipated accordion block, and improvements to template management, aimed at making theme and site building more flexible for users and developers. They also talk about experimental features such as PHP-only blocks, block bindings, and upcoming blocks like breadcrumbs and table of contents, which promise to streamline site navigation and content organization.</p>\n\n\n\n<p>Birgit and Beth underscore the importance of continuous testing and learning, encouraging listeners—especially those hesitant to adopt block themes—to experiment, seek support, and embrace gradual change. The episode wraps with practical advice, recent security updates, and a look at promising innovations coming to the WordPress ecosystem.</p>\n\n\n\n<p><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/#shownotes\">Show Notes</a> / <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/#transcript\">Transcript</a></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Editor: <a href=\"https://www.linkedin.com/in/sandy-reed/\">Sandy Reed</a></li>\n\n\n\n<li>Logo: <a href=\"https://markuraine.com/\">Mark Uraine</a></li>\n\n\n\n<li>Production: <a href=\"https://icodeforapurpose.com\">Birgit Pauli-Haack</a></li>\n</ul>\n\n\n\n<p class=\"has-larger-font-size\" id=\"shownotes\"><strong>Show Notes</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Special Guest: Beth Soderberg</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://bethink.studio/\">Bethink Studio</a></li>\n\n\n\n<li><a href=\"https://profiles.wordpress.org/bethsoderberg/\">WordPress.org Profile + Slack </a></li>\n\n\n\n<li><strong>Talks by Beth Soderberg</strong>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://wordpress.tv/2025/07/25/my-process-for-building-a-custom-wordpress-theme-in-2025/\">My Process for Building a Custom WordPress Theme in 2025</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/2020/04/16/bill-ericksonellen-bauer-beth-soderberg-case-studies-how-to-prepare-your-theme-for-gutenberg/\">Bill Erickson,Ellen Bauer, Beth Soderberg: Case Studies &#8211; How to Prepare your Theme for Gutenberg</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/?s=beth%20soderberg&amp;sort=newest\">And more</a></li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Calls for Testing WordPress 6.9 </h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2025/10/03/help-test-changes-to-template-management/\">Template management</a> </li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2025/10/04/call-for-testing-ability-to-hide-blocks/\">Ability to Hide Blocks</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2025/10/06/call-for-testing-accordion-block/\">Accordion Block</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Community Contributions</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://gutenbergtimes.com/blocks-galore-test-template-management-woo-product-collections-and-more-weekend-edition-343/#blocks-galore-with-telex\">Block Galore</a> by designers and developers using Automattic’s Telex </li>\n\n\n\n<li><a href=\"https://gutenbergtimes.com/block-commenting-fun-with-telex-from-classic-to-block-theme-weekend-edition-341/#building-blocks-with-telex\">Moar Blocks</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">What&#8217;s Released</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://wordpress.org/news/2025/09/wordpress-6-8-3-release/\">WordPress 6.8.3</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/10/08/whats-new-in-gutenberg-21-8-08-october/\">What’s new in Gutenberg 21.8? (8 October)</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">New Blocks still in the works</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f7e3.png\" style=\"height: 1em;\" /> <a href=\"https://github.com/WordPress/gutenberg/pull/71588\">Time to Read</a> (m) </li>\n\n\n\n<li><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f7e3.png\" style=\"height: 1em;\" /> <a href=\"https://href.li/?https://github.com/WordPress/gutenberg/pull/64119\">Accordion Block</a> (m) </li>\n\n\n\n<li><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f7e3.png\" style=\"height: 1em;\" /> <a href=\"https://github.com/WordPress/gutenberg/pull/71793\">Breadcrumbs Block</a> (m)</li>\n\n\n\n<li><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f7e3.png\" style=\"height: 1em;\" /> <a href=\"https://github.com/WordPress/gutenberg/pull/70720\">Terms Query block</a> (m) </li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/71618\">Dialog Block </a></li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/71227\">Icon Block</a></li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/71904\">Stretchy Text</a></li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/69789\">Tabs Block</a></li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/issues/42229\">Table of Contents block</a></li>\n</ul>\n\n\n\n<p><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f7e3.png\" style=\"height: 1em;\" /> = already merged into trunk, as experiments. </p>\n\n\n\n<p class=\"has-large-font-size\">Stay in Touch</p>\n\n\n\n<div class=\"wp-block-group\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<ul class=\"wp-block-list\">\n<li>Did you like this episode? <a href=\"https://lovethepodcast.com/gutenbergchangelog\"><strong>Please write us a review </strong></a></li>\n\n\n\n<li>Ping us on X (formerly known as Twitter) or send DMs with questions. <a href=\"https://twitter.com/gutenbergtimes\">@gutenbergtimes </a>and <a href=\"https://twitter.com/bph\">@bph</a>.</li>\n\n\n\n<li><em>If you have questions or suggestions, or news you want us to include, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. </em></li>\n\n\n\n<li><em>Please write us a review on iTunes! <a href=\"https://gutenbergtimes.com/itunes/\">(Click here to learn how)</a></em></li>\n</ul>\n</div></div>\n\n\n\n<p class=\"has-large-font-size\" id=\"transcript\"><strong>Transcript</strong></p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Hello and welcome to our 122nd episode of the Gutenberg Changelog. In today&#8217;s episode, we will talk about Gutenberg 21.8 and WordPress 6.9, what we already know about it. And I&#8217;m your host, Birgit Pauli-Haack, curator at Gutenberg Times, co contributor on the Word Open Source project, and I work as a developer advocate for Automattic. I&#8217;m thrilled that I finally have Beth Soderberg join me on the show. Beth is the CEO of Bethink Studio, a special web design and development agency in Alexandria, Virginia, in the U.S. Beth, welcome to the show. How are you doing?</p>\n\n\n\n<p><em>Beth Soderberg:</em> Thank you. Welcome. Welcome to my morning. I&#8217;m doing great. Good to see you.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. So I tried to recollect how we actually met or we met over the last few years, and I think it was the first time we met at the WordCamp New York in 2019.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I think that&#8217;s right. Ish. I definitely have eaten tacos late at night at WordCamp New York. Okay, so that tracks.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah.</p>\n\n\n\n<p><em>Beth Soderberg:</em> And I definitely met you sometime before the pandemic, so I&#8217;m not sure exactly, but that sounds about right. And then I know we had lunch at WordCamp us when it was in San Diego.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Oh, okay. Nice. Oh, right. We had this.</p>\n\n\n\n<p><em>Beth Soderberg: </em>There was.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>There was a group of women kind of coming together.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, yeah, I saw a table of women. And if I see a table of women at a conference like that, I&#8217;m going to sit down at it. And you did exactly the same thing.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Nice. So.</p>\n\n\n\n<p><em>Beth Soderberg: </em>But that&#8217;s the first time I saw you after the pandemic, for sure.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, yeah. And in between, I think we did together the WP Blog Talk virtual conference that was organized by Automattic, but there were a lot of community members in there talking about the Gutenberg and the stage of it and all that.</p>\n\n\n\n<p><em>Beth Soderberg: </em>That was when I realized that I don&#8217;t like presenting at virtual conferences in front of audiences that you can&#8217;t see.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, it&#8217;s interesting.</p>\n\n\n\n<p><em>Beth Soderberg:</em> I&#8217;m good with Zoom, because you can get some feedback. But the speaking into the void was. I don&#8217;t know. It could have also been that I wasn&#8217;t speaking to anyone in real life at the time, so it felt extra weird.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, yeah, no. I get it. The pre-recording and then just be there for the live part of it. But we had a great live discussion there.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, I. It was fun. And we actually did the presentation live. I think that could be why later things were recorded, because it was a really weird experience. It was very strange because you knew you were live. You had no idea if even your audio was working, but you just kind of had to keep talking. And, yeah, it&#8217;s the least feedback I&#8217;ve ever had from anything I&#8217;ve ever spoken at. And I think that not even being sure that the technology was working part. Like, even that level of feedback wasn&#8217;t there. It was fun. And hopefully next time I do something like that, it will be recorded in advance.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah. But it was a. It was a good place talk because it was kind of together with Ellen Bauer, and you had 15 minutes, Ellen had 15 minutes. And I think Bill Erickson was there as well.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>There were three of us.</p>\n\n\n\n<p><em>Birgit Pauli-Haack</em>: Yeah. And every one of you kind of took a different take on the block themes. Yeah. And that was really interesting to kind of. Well, we started out in 2020 with that. Yeah. Now it&#8217;s five years later, and we finally connected again at WordCamp. Us, because I made it there again.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I know. I was excited to see you. And I think. Yeah, I mean, doing that talk was interesting. I think there&#8217;s still some divergence around how people are building and how people are utilizing the tools. That set of like 15-minute talks was a really good microcosm of that because each one of us had been actively building with all of the new tools and had a slightly bigger, different approach. I still think there&#8217;s some divergence there, but we&#8217;re starting to see some patterns of, like, actual best practices with the new tools, which I think is really exciting. And also it&#8217;s fun to sort of invent on the fly. Like, okay, how should this work as the people who really are using it with clients right away, what is the standard we want to set? What does and doesn&#8217;t work? And I think that was still in a time period where we were learning so much about what you could do, what the restrictions were. I know in a lot of what we&#8217;re going through today, there&#8217;s like little tiny changes that end up being so impactful. Right. Like, my favorite thing I hated from that time period was it could have been a little earlier, I don&#8217;t remember. But originally you couldn&#8217;t set text colors on lists.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Oh, yeah, yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Stuff like that. Where it&#8217;s so small, but when it&#8217;s missing, it&#8217;s a big problem.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So, yeah, I think that a lot of work has been put into having consistent design tools for each block that you can control through the theme JSON file and then make it really a unique experience or unique design for your clients. Yeah, that&#8217;s definitely something there where you don&#8217;t, oh, I can&#8217;t do the fonts. Yeah, well, I guess I need to do a variation of it. So there was a lot of coding done to kind of get around those restrictions. How do you feel about kind of ripping out all this additional around coding now that certain things are in core and that are available? Does that kind of trip you up a bit?</p>\n\n\n\n<p><em>Beth Soderberg: </em>I feel great about it and there&#8217;s not that much I need to rip out. Some of that is because of how I&#8217;ve built things over time. Some of that is because things like the tab block, which I am so excited about, I know it&#8217;s not ready and all that, but I have a few sites where I have random solutions for that, but I&#8217;ve got them compartmentalized. So pulling them out and putting in something new that makes more sense is going to be easy.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Because I know, you know, like, especially something like the tabs, they don&#8217;t appear that often. And the other thing with stuff like that, you can just search the database for the machine name of block to find where you&#8217;re using it. I do that a lot and sometimes I don&#8217;t know. I ripped Jetpack out of a site recently because it was only being used for slideshows in like six blog posts. There was no need for it. And it might have been more than six, but still this is a major publishing website that has thousands of posts. They didn&#8217;t need Jetpack sitting there doing this like a very minor task. And so that&#8217;s one of my tactics for sure. When I&#8217;m going to rip something out. People forget that you can search easily. Not even in the database. You can use the WordPress search. Search.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Right. For the posts. Yes. Yeah, that&#8217;s what I do. Yeah. Kind of. You can kind of put the blog name in there and then see which post uses what block, especially the third party blocks. When you find out, okay, I have now three query blocks and core blocks and why am I doing this to me?</p>\n\n\n\n<p><em>Beth Soderberg: </em>Right.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg:</em> And I&#8217;ve always been pretty conservative about what I&#8217;ll add.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>So I think that&#8217;s part of why it&#8217;s not super daunting to me. Because if I can make it work with the tools that exist, I will.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I&#8217;m not going to over engineer it just because I could. And that makes it easier to clean up long term.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So I think the last big feature that was introduced to theme development was the section styles. Style variation in one and then the section styles, the smaller things and block styles, now that you can edit them in the global styles. How much do you use about that? Is that something that comes up quite a bit in your work?</p>\n\n\n\n<p><em>Beth Soderberg: </em>I use them a lot. Especially when you&#8217;re dealing with semantics, I want to give people the ability to have something look the way they want it to look, but also be semantically correct. So especially with things like headings. Right. Having tooling that&#8217;s easy for an end user to understand to say this should be an H2, but I would like it to look like an H4 without making it an H4 is a game changer. It improves SEO, it improves accessibility, it keeps everything cleaner. And so that kind of tooling, I think when used strategically can really help. When used randomly, you&#8217;re just going to confuse people. But you know.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Well, aren&#8217;t we in the business of confusing people?</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, sometimes. Right.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>All right. Yeah, no, it&#8217;s interesting too. So are you using also side styles variations or just the section styles or block styles?</p>\n\n\n\n<p><em>Beth Soderberg: </em>Heavily using block styles. Okay, not so much the whole site variations yet. Yeah, there hasn&#8217;t. It&#8217;s again, it&#8217;s like you want to use the right tool for the right use case and yeah, normally you don&#8217;t.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Want to change how the site looks.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah. There&#8217;s only. You kind of need like a site within a site to make that required. And the only thing like that I&#8217;ve been building lately is a voter guide that&#8217;s like within a site but the voter guide has all the same styling as the rest of the site. Because it&#8217;s supposed to match.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, right. Right. Yeah. Yeah. I&#8217;ve always felt that the style variations are more for theme product developers that want to give more options to modify the theme. For agencies, I didn&#8217;t see that there are a whole lot of use cases for. For them. I might be wrong, but. Yeah, but you&#8217;re kind of confirming a little bit my bias here.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, I. I don&#8217;t know. I look at anything that&#8217;s coming in that&#8217;s new. I look at it in terms of strategic utility and there&#8217;s a bunch of stuff that is super cool but it&#8217;s just not necessary for my clients. Right. Like it&#8217;s not the use case for that but for somebody else that could really help. And I&#8217;ve had a few where you end up building this random micro site within the site because some weird reason why they need it. And like that&#8217;s really what you would use that for. It doesn&#8217;t happen all that often.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So yeah. Do you apply section styles to your patterns? Yeah, so that. And you give them design choices and they don&#8217;t have to spend time with kind of reorganize their design just because they want to have a pair of a pink background or a yellow background or something like that.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah. I also, I restrict color palettes, of course, because we don&#8217;t want anything looking like, you know, we&#8217;re in the. We&#8217;re in some sort of sci fi. Yeah.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: Geocities. </em>I&#8217;m dating myself now.</p>\n\n\n\n<p><em>Beth Soderberg: </em>It&#8217;s okay. I told the checker at the grocery store the other day about how I worked at Blockbuster in high school and how that dated me, but it was a good job because you could I had to walk around to put the movies back. So I also use a lot of synced and partially synced blocks to achieve design consistency. So paired together. Because that I have found is really good for editorial teams where you can give them a style guide. And usually I make a page on the inside of the site that&#8217;s just privately published so that they can see like, okay, we have these patterns to work from. And, you know, this is the human part. You have a discussion about how, yes, you can do all these things, but you should use these things that we&#8217;ve all agreed upon that follow the style guide.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. Well, it also makes for production much, much faster when you don&#8217;t have to make those design decisions. They&#8217;re already there and then.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Exactly. And you don&#8217;t have to train people. I mean, the number one thing I see real clients, real site administrators doing weirdly with formatting is inconsistent vertical spacing.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Okay. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>The tooling is there to make it consistent, but people don&#8217;t. Even if you train them, they&#8217;re like, wait a minute, do I pick it at the fourth hash? Or like, which setting is it again? And does that look. And like as much as I can look at spacing on anything and know if it&#8217;s wrong, many people cannot.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Oh, no, no. Yeah. That&#8217;s a skill.</p>\n\n\n\n<p><em>Beth Soderberg: </em>It&#8217;s a skill.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>And many people really. And I found that like syncing those patterns that way and getting. Locking down some of that basic stuff that like, you don&#8217;t want your end user to be thinking about how much space they need below something.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Like that&#8217;s not what they should be ever actively thinking about. So that&#8217;s how I have approached that.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. Yeah. So far. Yeah. Makes sense. Have you taken a survey of how often your clients actually use the spacer block? Because I found that WordPress.com that&#8217;s one of the top five blocks used, I.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Have not, but now I&#8217;m curious and I. Some of them, I mean you definitely have some, some where it&#8217;s used more than it should be. But I think that we&#8217;ve avoided some of that and some of it is what we&#8217;ve been able to do recently. Right. A few years ago you had to use it if you were going to get any consistency at all across things. But I think sometimes the patterns and the pattern syncing, that type of thing has dramatically reduced the need to use the spacer block, which is great because the speaker, the spacer block is so annoying on mobile.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, that&#8217;s one thing. It&#8217;s also, you cannot rip it out when, when you redesign the site or something like that, it&#8217;s going to be the. In your content.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, yeah. So I mean, I haven&#8217;t seen similar dislike as it sounds of the spacer block, but when you shrink a screen down suddenly you get wildly different vertical spacing on mobile. And for the average person there is not a straightforward way to make it not do that.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>You have to know how to write a workaround for yourself to make it work and that&#8217;s not great.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So. Yeah, well, yeah, it&#8217;s good to know. So before we head into our usual sections, is there anything else that you would like to tell people who have not yet done the jump into block themes, why they should do it?</p>\n\n\n\n<p><em>Beth Soderberg: </em>I think, I think that it is, it&#8217;s a scary jump, and I have always been an early adopter of the new tooling, and so I look at something like that and it freaks me out a little bit. And then I&#8217;m like, well, why not? And I just push myself through and I know that I have the liberty of doing that because I&#8217;ve been working independently for almost 10 years. So I am in a lot of ways in control of what is and is not allowed in my environment. I&#8217;ve talked to a few folks who have. They understand how it&#8217;s working and they, they personally buy in, but their employer does not.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Okay. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>And so for those folks, I think building up your skill set with your personal site or a personal project so that you can advocate for different things internally. It&#8217;s very hard to advocate for something that you haven&#8217;t done and that you don&#8217;t have hands-on experience with. But you know, the ability to spin up a little like MVP demo of, hey, this is how this would solve a problem that we have systemically is really how you sort of gain permission in those sorts of environments. There&#8217;s some really good resources out there on learning how to do this. I think that they are much harder to find than they used to be. When I was first learning how to code, it was much easier to find like beginner entry level stuff, to like level yourself up. And now I think fewer people are creating it and I think it&#8217;s harder to find just because of how it&#8217;s labeled. Everything starts to look the same because it&#8217;s all named the same. But I think giving yourself the challenge to &#8211; even if you don&#8217;t understand everything, listening to a podcast like this, listening to a talk that you&#8217;re finding online, having it playing in the background like it does, seep in to how you think about it. And what will happen is that later you&#8217;ll encounter the same subject again and you&#8217;ll be like, oh, wait, that&#8217;s what they were talking about. And that&#8217;s how you start to connect the dots when you&#8217;re learning anything new. And I think the idea that you&#8217;re going to get somebody who has been building themes the classic way, building themes that are heavily reliant on advanced custom fields, something like that, to just magically one day pick up a whole new set of tools with a whole different way of thinking and be completely comfortable from the get is like ludicrous. That&#8217;s not going to happen.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>But, you know, giving yourself the ability to slowly absorb it, because it is a different way of thinking, it&#8217;s a completely different way of thinking about how to structure the theme. And for me, that has been the hardest part to learn. Once I figured it out, it was great. But of course, it&#8217;s always the hardest thing to figure out a new way of thinking. When you say it like that, it&#8217;s so obvious. But I think people really get down on themselves about it. And I think really just paying attention, reaching out to folks, you know, when you have questions, not being shy about it. What I&#8217;ve figured out over the course of the last, I guess we&#8217;re almost at eight years of Gutenberg. Yeah, Gutenberg is a month older than my eldest child. So it&#8217;s very easy for me to keep track of how old it is. But we are in a time period where what I have noticed as an early adopter, when I talk to the other early adopters, everybody is making it up. Everybody is inventing their process, everybody is inventing the “ right way.” We&#8217;re starting to congeal on some common things. But it has been a time of innovation. And so being a little bit afraid to stick your toe in. That is so reasonable. And at the same time, when you think about it that way, it becomes less scary to fail in air quotes. Right. Because ultimately, how many light bulbs did Edison make before one worked? Like, it&#8217;s just, you know, you have to experiment in order to figure out how something works. And I think it is challenging to be mid-career and have to go back to that beginning.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>You know, Yeah, I feel a certain.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Confidence that all of a sudden is going away.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, yeah. So. So I. I just think people need to be a little less hard on themselves, push themselves a little, be okay with failing and talk to people, talk to people. Just keep going, Just keep swimming, as the fish say in Finding Nemo.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah. All right, so you&#8217;ve listened here to a very experienced theme developer and yeah, it&#8217;s never going to be easy. You need to start now. What is it, the Chinese proverb to the best time to plant a tree was 20 years ago. The second best time is now. So it&#8217;s kind of exactly for that. Yeah. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Announcements</h3>\n\n\n\n<p>So, okay, so we have a few announcements. Now we&#8217;re going a little bit into the Gutenberg change log message here. We have a few announcements and they&#8217;re all calls for testing because we get new stuff and. And the testing team is really on top of things. Last week a call for testing was made for the new template management features that are coming to Core, which. have you checked it out, Beth, on what&#8217;s going to come with that? We talked about it here two weeks ago with Anne Katzeff and it&#8217;s the tool where you can now have multiple templates with the same slug and of the theme hierarchy and then activate and deactivate the ones that you want to use or not use. So it kind of puts a new layer in there and gets the user a little bit more in control on how the template management actually works and figure that out in there. Because template management is something WordPress users have never done before because it was always a developer designer kind of scope and there was no user interface for it. And now it&#8217;s here and the confusion is there, but it&#8217;s also something that can be learned and can be helped with.</p>\n\n\n\n<p><em>Beth Soderberg:</em> I think it&#8217;s also going to be great for launching changes to live sites where. And you know how to launch code for Gutenberg is a whole other conversation. But the best practice is to keep your live site database as your database of record. Right. And some of what I see with the new template management changes are enabling you to more easily respect that without having weird, momentary blips of your content looking bizarre while you&#8217;re changing something over on a live site. So I think it&#8217;s going to be, again, another adjustment in how we think about how we work. But ultimately we&#8217;ll offer more granular tooling that will allow for the elimination of some of these use cases that haven&#8217;t always ended up being really strange, where you&#8217;re like, yeah, should we put up a maintenance message while we&#8217;re doing this? Because everything is going to look bizarre for the next 20 minutes. That kind of stuff. I think it&#8217;s going to be good.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>It&#8217;s really good. Yeah. Yeah. And the first version is going to be not perfect and probably have some bugs, but that&#8217;s why the call for testing is there. So I leave the link in the show notes for you so you can start testing and share your experience with it and also share what still confuses you or what didn&#8217;t work or where you thought it would work, but it didn&#8217;t. It&#8217;s definitely something &#8211; conversation needs to happen. And if you are not sure what to do, come into the W in the WordPress Slack into the Outreach channel and there are a lot of people there that will help you figure that out. So if you don&#8217;t know if it&#8217;s a bug or you don&#8217;t, you&#8217;re not doing it right. I know that&#8217;s often kind of that with new things. Did I get this right or is it not working? Most people, and I&#8217;m one of them, I default to okay, I&#8217;m not doing this right. What&#8217;s happening? And there are two more console testing. </p>\n\n\n\n<p>One is on the ability to hide blocks, which is kind of the first iteration of a blocks visibility kind of plugin idea that you can hide and show blocks conditionally. Right now it&#8217;s only on and off or hide and show. So you could have a block in the editor, but you hide it on the front end. But because you&#8217;re still working on it or you don&#8217;t want to, you want to put it in there so your editor knows about it, but it&#8217;s not going to be pushed to the show version until a certain date or until a certain sale happens or something like that. The instructions for the call for testing are really good and they also show you with little videos how it&#8217;s supposed to work to kind of offset my am I doing this right or not? Idea. And the other one that I wanted to point out in this podcast is the accordion block calls for testing. That seems to be really settled. Came in 20.5, I think, and had some iterations, especially for those of you who started styling it. You need to double check your references because the name changes in between for the panel and for the items and all that. So call for testing for accordion block and what you can do with it. Have you experimented with the accordion block?</p>\n\n\n\n<p><em>Beth Soderberg: </em>Mm, I&#8217;m really excited about it. This is one of the ones that I&#8217;ve been dreaming of for years. It&#8217;s one of the ones where I had an external plugin where like, the only reason I was using the external plugin was because I needed accordions. The detail block is sort of an approximation, but it&#8217;s not the same semantically speaking. So I&#8217;m excited about this one. This one and Tabs are my two that have been a thorn in my side for years.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, I&#8217;m also. Well, we can talk about the other blocks that are supposedly come or at least been worked on for Core, even if they don&#8217;t make it into 6.9 at a later date. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Community Contributions</h3>\n\n\n\n<p>There&#8217;s this new AI feature out there, it&#8217;s called Telex, which is automatic block building AI. And there are a few designers and developers that have actually done some great experimentations with that. One is Tammy Lister. She has started a challenge, kind of the blocktober, meaning every day in October she will build a new block with Telex. And I&#8217;ll of course share the site in the show notes. She started out with a kind of reaching back into history of computers and started out with an esky Tetris game. And that&#8217;s when my afternoon, uploaded my afternoon was shot because I got addicted to Tetris again. Yeah. Did you do any experimentations with that?</p>\n\n\n\n<p><em>Beth Soderberg: </em>Nope. That one, I mean, I know about it, I know about Tammy&#8217;s blocktober. I&#8217;m paying attention, but I don&#8217;t have time to just play with it right now.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, yeah, I. I feel the same way. It&#8217;s kind of letting other people do that. I. I look at what other people do. Yeah. And there&#8217;s Marco Ivanovich. He&#8217;s a designer at Automattic. He has some animated icon blocks. They were kind of sparkling and all that. And then he also created a post-it note block where you can put post-its on your site with an image and with a background gradient background. So pretty cool to look at. </p>\n\n\n\n<p>And then there was Jeff Paul from Ten Up. He actually also created a game of Pong Hung block that&#8217;s kind of the tennis kind of back and forth where you need to up. It was just handy as an easy, medium and hard. Yeah, that was another afternoon. I tried to figure it out. Yeah. Juan Margarito, he created a mermaid diagram which is actually a markdown diagram. And then you put the. The diagram code in markdown and then it kind of creates a. A diagram with errors back and forth. Yeah, it&#8217;s kind of a flow diagram if you want to. So that was really interesting to see. Yeah. Anyway, so I just. Yeah, check it out. If you want to play around with it. It&#8217;s telex.automattic.com automatic with double T. The second T. Yeah.</p>\n\n\n\n<h3 class=\"wp-block-heading\">What’s Released &#8211; WordPress 6.8.3</h3>\n\n\n\n<p>Okay. So now we come to the heart of the show, which is what&#8217;s released. And before we head into Gutenberg 20.8, I wanted to let everybody know WordPress 6. 8.3 is out. It&#8217;s a security issue. No, it&#8217;s a security release fixing two security issues. And if you haven&#8217;t updated yet, please do we wait. Go and update. The two issues were mentioned in the release post. One was data exposure issues and the other one issue and the other one was a cross scripting vulnerability for the nav menus which has been fixed and you are in a secure environment again. But don&#8217;t forget to update. Yeah. Any thoughts?</p>\n\n\n\n<p><em>Beth Soderberg: </em>Always update. I&#8217;m. I&#8217;m of the. I&#8217;m of the camp. I always update on the security releases right away and then major releases. I always wait and see what happens.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>How long do you wait? How long do you wait?</p>\n\n\n\n<p><em>Beth Soderberg: </em>I usually wait until a point release has come out.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Okay.</p>\n\n\n\n<p><em>Beth Soderberg:</em> That&#8217;s usually the trigger but sometimes it&#8217;s really stable and we&#8217;re like, well there. I guess there&#8217;s no point release and it&#8217;s been three weeks.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I do the same thing with updating like my iPhone. Yeah, I don&#8217;t. I&#8217;m. As much as I am interested in technology, I am also somebody who just recently started using mobile deposit for checks. I&#8217;m skeptical.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Well, I think that makes that an early above to decide where to early adopt and where to be cautious.</p>\n\n\n\n<p><em>Beth Soderberg:</em> That&#8217;s true. Yeah. My risk tolerance is very high for certain things and very low for other things.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>And if it changes my work environment that I need to retrain my muscle memory. I&#8217;m opposed to any change, but I recently had to change my Mac updated and they fixed a bug. That&#8217;s the problem with bug fixes. Yeah. If you, if you have for years known about a workaround and the muscle memory is in. You hate that bug fix that fixes that once and for all. So kind of. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Anyway, that&#8217;s a whole other conversation. Moving on.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Thank you. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Gutenberg 21.8</h3>\n\n\n\n<p>So Gutenberg 21.8 is the second last before 6.9 beta. There&#8217;s one more coming, that&#8217;s a 21.9, of course, and that&#8217;s coming on October 17th. So we are recording this on October 8th and next week we have the last Gutenberg release before 6.9 beta comes. Which means bug fixes, yes. New features, no. From that point on forward to get into Core. Gutenberg 21.8 had 118 PRs by 47 contributors and five people were first time contributors. Congratulations, you got your merge done. That&#8217;s fantastic. Because I can see that the first one is always a little tricky getting it past the reviewers. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Enhancements</h3>\n\n\n\n<p>For Gutenberg, we start with the enhancements to the block content. Comments. Block comments is a feature that creates a commenting method for each block in your editor so you and others can add comments to your blocks and have an editorial kind of process going. It&#8217;s a a lot of PRs made it into that. But the first one that I wanted to point out is a discussion field with trackbacks and comment status aggregated for the post page Quick Edit. So you know, in the Quick edit, are there commenting places? Quick Edit is not the quick edit in the WP admin. It&#8217;s a quick edit in the design. But that&#8217;s actually not the commenting. The block commenting thing.</p>\n\n\n\n<p><em>Beth Soderberg:</em> Yeah, this is hard to contextualize even looking at the PR, right? Yeah, the PR. I think ultimately it&#8217;s unifying. It&#8217;s again, it&#8217;s one of those things that&#8217;s unifying design across components to make things more consistent no matter where you find them.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So when you have the new design view, what was missing that you were able to manage trackbacks and comments. So it&#8217;s not the feature that I just said. It&#8217;s just getting on par with the previous WP admin kind of thing. Especially for pages. The posts haven&#8217;t been included yet in these new designs, but for pages, definitely. And if there&#8217;s a post experiment in Gutenberg where you can have the post view also in the new design view, as the site editor. And that&#8217;s where this actually comes to pass. So that is kind of labeled wrong in that changelog, but that&#8217;s okay. We can handle that. Do you want to do the next one?</p>\n\n\n\n<p><em>Beth Soderberg: </em>Sure. So displaying a message when there is no related block, which is the most logical thing you could do with commentary that has no source attached to it anymore.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Anymore.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Anymore, anymore. Right. So again, it&#8217;s giving context to something so that your actual conversations make sense. And basically what it&#8217;s doing is just adding a little message that says, hey, your original block was deleted so that somebody reading through it understands and also gives you the ability to&#8230;part of why I like this one is because you&#8217;re going to end up with people who in collaborating with each other are going to remove things. And you want to have a record of the conversation for editorial purposes, but understanding what has happened is a key part of creating that record.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So yeah, definitely you want to have a record of the decision making process for certain things. Yeah. The other one that I wanted to point out is that it now shows the dates of the comments in a more human readable part, like 30 minutes ago or two hours ago or three days ago. So you get a little bit more relation to the timestamps of that. I think there was an option to do this, but I&#8217;m not quite sure that you can switch it on and off. But if not. No, it&#8217;s not. It&#8217;s the first. It&#8217;s the first iteration and there are no options.</p>\n\n\n\n<p><em>Beth Soderberg:</em> I think that&#8217;s coming later.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah, yeah, but it&#8217;s. It&#8217;s known that there will be something like that needed.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yep. And then the highlighting of the related block. Again, a lot of these changes are improving context indicators and so, you know, this just gives you a clearer sense of what you&#8217;re connecting to and which thing you&#8217;re actually talking about with the comments.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So I&#8217;m just going to look through. If we missed something new, we can now go right into the block library section and there&#8217;s a ton of PRs that actually work on the accordion blocks. That&#8217;s also in the bug fix sections. But I think the most prominent stuff is more like the term description block with the context support. So that if it&#8217;s in a template or in an archive template that the term description block is more. You can use it in patterns like you can do post title and query title for that. Yeah, the term description block is something that&#8217;s a little bit of a… I have seen people that are quite adamant that they need the block editor in the category description section for editing the description because I wanted to make it more there. Design it a little bit or make it a little bit more versatile. That&#8217;s quite interesting because you also can now create a page with all the features that you want on that for a particular category and then just have a query loop on that category displayed on it. So you get around that need to have the term description be a block editor or something like that.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah. I had never thought about that before because theoretically you always could do the latter. Right?</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>But you had to have a certain level of technical skill and knowledge to do that. The idea of adding block support to that description opens up possibilities for folks who are not as technical to make modifications in that presentation of the. The term pages. I don&#8217;t know. I could go either way there.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I could also create massive. I can see this going very wrong.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah. I think that&#8217;s why nobody touched it for now.</p>\n\n\n\n<p><em>Beth Soderberg: </em>That&#8217;s a new concept to me. But I don&#8217;t know. My gut says no.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. So. And then we get a new block. It&#8217;s the time to read block. And now it has been in the Guternberg plugin for ages. Similar to the table of content block. But they were to get it into core. There were always kind of missing things or quirkinesses that weren&#8217;t dealt with. And the time to read had massive accessibility objections because it only had one time that it takes to read a block. Not everybody has that reading skill or is on that level like a lot of people are. English as a second language. They don&#8217;t. They don&#8217;t read so fast or dyslexia is pretty. Yeah. It&#8217;s out there. And they don&#8217;t read that fast. And so it kind of makes them feel bad about not reading in that 15 minutes kind of thing. What they&#8217;re doing now is kind of offering a range option. It says it takes one to five minutes or something like that. And which I feel is kind of even for someone who is fast reading but tired is a good indicator. Yeah. That&#8217;s how long it&#8217;s going to actually take. And then they added also a word count to it.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, I like that.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. When there are word count plugins out there. Word count blocks, plugins out there say that 15 times fast. But I think having a core block that actually offers it option is really cool.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. I&#8217;m sorry I didn&#8217;t bold that, but I wanted to talk about it.</p>\n\n\n\n<p><em>Beth Soderberg: </em>No, I agree. I think it&#8217;s. It&#8217;s a kinder way to deal with the problem because you&#8217;re giving people enough information to very quickly self assess without shaming them.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah. So the next one is part of the Data Views section actually. It&#8217;s the data forms package. And there&#8217;s now support for certain form elements validation in the data forms package. So if you use that as a plugin or your settings pages. You now get help from the packages that drive that. I think that&#8217;s a. Yeah, it&#8217;s an enhancement for extensibility, for sure.</p>\n\n\n\n<p><em>Beth Soderberg:</em> In the block editor section, block multi selection, disabling transforms and inspector controls.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. That&#8217;s an interesting one. So when you select multiple blocks, you still get the. Sometimes the options that you can transform them. And for paragraphs, a series of paragraphs. I like it. Because then you have. You can transform them to list views. But if you have a mixture of selected blocks, you don&#8217;t need transforms or inspectors back the controls. You just probably want to move it or move the selection. Yeah. So I think it&#8217;s a good way to not confuse people.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Right. And that&#8217;s a good example of a tiny change from an end user perspective that probably won&#8217;t be noticed, but will reduce friction for people. All right. In global styling, adding a reset button to our background controls panel. Hooray.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Hooray. You don&#8217;t have to unselect stuff. Yeah. Just click on things and you make it all go away. It&#8217;s pretty cool. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg:</em> And then making the additional CSS UI less prominent, which is great because the less random CSS everywhere, the better.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yes. And. Well, it&#8217;s. I totally agree with that. And that&#8217;s also the. The justification why they want to put it some. So they&#8217;re going to hide it. Again, it was hidden on the left hand side of the global styles or styles panel. You always could edit it on the right hand side when the styles panel where sooner or later we probably need to decide if we want to use the left hand side or the right hand side for the styles features. But it now is going to be in the ellipse menu in the header of the styles section. So it says add additional CSS as a menu item on top. So. So you are not going to be. Well, it was there and then it wasn&#8217;t there. So where is it kind of thing situation. It ended up in the ellipse menu on top of the screen.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Block bindings. I love block bindings.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. There&#8217;s an experimental feature there.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>To support block attributes from the server side. I haven&#8217;t completely read through it. I&#8217;m not quite sure I understand that. So I would need to go back to the developers and say what&#8217;s the use case and why you&#8217;re doing it kind of thing.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>I think. Did you get something?</p>\n\n\n\n<p><em>Beth Soderberg:</em> I would have to clarify, but my understanding of it is the big thing with block bindings is like which things are supported and which things aren&#8217;t supported and how that is communicated is improved from doing this.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah. Doing it service sort of the nugget.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Of truth there. But I think anything like that. I know it&#8217;s experimental but making block bindings easier and more accessible for people to use anything that helps. That is a good thing.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. I think there are two areas where they come from. One is to make block bindings available for more than 14 blocks which has been the case until now. That&#8217;s one thing. But also to increase extensibility and use have not only blocks use the block bindings but also whole features use the block bindings for external things like the remote block plugin by WordPress VIP USO. Yeah. They also use block bindings to identify the data that comes in and put it into the block editor. But I think it&#8217;s hard to bring the server side and the client side together with the same information. And this one will have the server side be the moment of truth. No, the source of truth for block bindings. Yeah, it&#8217;s definitely a late edition. I&#8217;m not sure it&#8217;s going to make it to 6.9. I&#8217;m skeptical though. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah. Right. Right. Mode Try adding content roles to navigation blocks is the name of the PR which I think is delightfully named and I. Even the way that this is written is pretty great. I wanted to see how far we can go with just adding content roles to nav link in some menu blocks given the improvements to content only logic we&#8217;ve had. And then it references another pr. The next sentence is I think it&#8217;s working better now. Whoever this contributor is, I love your writing. Tell the machines.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Oh, that&#8217;s.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Fun times. But I think it&#8217;ll.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Isabelle Bryson. Yeah, she&#8217;s been on the podcast before and she&#8217;s actually worked also on the grid layouts and yeah, she works for Automattic on the team. And the other I think the tri part is okay. We experiment with things. So that&#8217;s when it says try and then there&#8217;s also add is kind of definitely need to fix this or add this feature or fix means fix this bug. Yeah. So they have these prefixes on their PRs and the try thing is. Yeah, let&#8217;s try it out and see what happens. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah. But this one, it looks cool. People should check it out. Components. The text area component. Adding a default resize vertical rule just to make things more make sense visually so that you can move stuff around the way you need to.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. And you can control the vertical size of things. That&#8217;s always a good thing. And then the other component PR is actually adding storybook examples for the fields package. So there&#8217;s more documentation there for the plugin developers who want to use it. Also of course, for the core developers who are going to use the Fields.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Package for their work patterns, we have a change to the block inspector adding a content tab for section blocks that displays content only descendant blocks. So similar to the existing styles tab, but for content.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. And it&#8217;s up until now it lists the blocks that can be edited in a section pattern or in a content only block. But that&#8217;s all part of the write mode, and we will see how which part of it actually will come into 6.9. But I think it&#8217;s very helpful for content creators who use a pattern to just see the pieces that you can edit and not be confused with any styling of that, even if it&#8217;s only the section styles. And from the PR before and after, you can see that the little drop water drop that&#8217;s in the block toolbar actually gives you a way to browse through the styles for this particular section. So it&#8217;s not taking anything away, it&#8217;s just kind of making it clear where the things the information is going to be for you. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I think for anyone who might be confused about what we&#8217;re talking about, look at the pr. The screenshots will help you.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, yeah. It&#8217;s a little bit. Sometimes it&#8217;s a little bit hard on the podcast to make things come to life on a. In a visual component.</p>\n\n\n\n<p><em>Beth Soderberg: </em>The screenshots make it make sense if you&#8217;re confused by what we just said.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> And the PR we&#8217;re talking about is 71714. The next one is an easy one, but it&#8217;s definitely something to talk about for Black Friday and all the WooCommerce stuff. There is now a WordPress gift icon available for content creators and developers. So you can use that. It comes from a WooCommerce team, but they contributed to Core so anybody can use it. </p>\n\n\n\n<h3 class=\"wp-block-heading\">New API</h3>\n\n\n\n<p>The next thing I want to point out was the block API has now the block visibility, control support and the ui. That&#8217;s the part where the underlying architecture for the hide and show of blocks I think it is. And that also is the foundation for when you. Later on we will have the conditional Hide and seek. No hide and show. Yeah. When you want to say okay, I want it for logged in users or not. I want it for people who come from Twitter or not. These kinds of conditionals, they&#8217;re not yet in there. For that you still need the block visibility plugin by Nick Diego. So I think we have one more. No. Yeah, there&#8217;s an accordion block also in write mode. We hide the add button in write mode so you can add an additional accordion block in write mode. But I&#8217;m not quite sure that&#8217;s particularly helpful for a content creator. But time will tell.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Yeah, that could go either way.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah, it&#8217;s a 5050 kind of thing. You do it right for 50 people and the others are going to hate you for that. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Bug Fix</h3>\n\n\n\n<p>And then one bug fix I wanted to point out there is a bug in the pattern override. Some users might have found it is that editing was allowed on non-enabled override blocks which kind of defeated the purpose, but it&#8217;s now fixed. So there&#8217;s another experiment. I don&#8217;t know how that comes about, but the PR definitely has some interesting conversations. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Experiments</h3>\n\n\n\n<p>There is allow registering PHP only blocks. What do you say for that?</p>\n\n\n\n<p><em>Beth Soderberg: </em>I say I think this is gonna be, this is gonna be so much bigger than it sounds.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yes.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Because basically what you&#8217;re doing is you&#8217;re enabling developers to create blocks using only PHP. So you&#8217;re opening up the can of worms about who knows PHP and who knows JavaScript and are we gatekeeping by moving everything to JavaScript and blah blah.</p>\n\n\n\n<p>But then you&#8217;re also changing the structure in a way that might make things less portable between projects. So I don&#8217;t know.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Well, it&#8217;s definitely an experiment.</p>\n\n\n\n<p><em>Beth Soderberg: </em>That&#8217;s true. I think, you know, and I. One of the things I have noticed, there is a developer on my team that I have been mentoring for years and really started learning WordPress specifically post Gutenberg. And what&#8217;s fascinating about watching her is that she struggles with some of the traditional ways of doing things, but can do them the new way. Right. So for somebody like that this might be terrible, you know, and I. It just becomes a context thing about what you know and how you&#8217;ve been progressing with different skills along the way if you&#8217;ve completely forgotten PHP or you know, various things. So I, I don&#8217;t know, I think this, this one is going to be a much bigger deal than I think.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, I think so too. And there will be restrictions to that and I think the documentation will show that because it actually uses something the server side render component that actually was not considered best practice to use until now and the registration of PHP only blocks will actually use the server render component. So I think there is also something a little bit of a movement in the core contributing ranks about that. And it definitely needs some more. Yeah. Experimenting with it and exploration and. But it&#8217;s in there. One listened and maybe there&#8217;s something that can be pushed to the finish line outside the experiments. All the developers out there who were waiting for something like this go have at it.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Oh. Interesting to see what people do.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, me too. And I added a. The label needs developer documentation and a project manager on the team also removed it because it&#8217;s experimental. So the developers that created it have some leeway in backwards compatibility. And it&#8217;s experimental. It means it&#8217;s not documented. You cannot build on it. You need to be part of the experiment spirit about it to use it and not rely on it. That it&#8217;s going to be working like that for the foreseeable future. So yeah. It&#8217;s also that caveat on it. Just wanted to point it out.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I just saw that that&#8217;s important because you&#8217;re going to have somebody who goes off and builds a whole new thing on it and then in two weeks it&#8217;ll break.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. Which. Yeah. Any plugin developer that built plugins for Gutenberg has been doing kind of living through that for multiple years now. Yeah. So. But that&#8217;s 21.8 release with quite a few new features and the final release will be today on October 10th. </p>\n\n\n\n<h3 class=\"wp-block-heading\">What’s in Active Development or Discussed</h3>\n\n\n\n<p>And now we are coming to the section where we talk a little bit about what&#8217;s in development and discuss. And there are new blocks in the works and we know this because Matthias has. Matthias Ventura has published that discussion about new blocks that were previously thought about plug into territory. And now quite a few theme developers think that they are held back with their designs if there are not more additional blocks in core because then now they can style it in their themes and make it available on templates and all that. So Justin Tadlock also did an opinion piece on the Gutenberg Times for it about four weeks ago. I can link it again in the show notes. But we are getting new blocks and the ones that have been merged they&#8217;re not entirely out of experiments yet. Time to read. And we talked about it because it just was merged. We also talked about the accordion block that was merged a while ago and still in experiments. But there are two. Oh, we also talked about the terms query block that has been merged but we haven&#8217;t talked about the breadcrumbs block. And I&#8217;m really excited about that because it felt such a need in the template area that people are getting so confused where am I? And I have a better map and I have breadcrumbs and all that. Yeah, it&#8217;s such a useful tool and I&#8217;m looking forward to get that tested. And yeah, watch out on the test team. They&#8217;re putting some more calls for testing together to get this all in the hands of people who want to help with making it better.</p>\n\n\n\n<p><em>Beth Soderberg: </em>I&#8217;m excited about the breadcrumbs block too. That&#8217;s another one where I&#8217;ve had to do sort of weird things to make things work over time and it&#8217;s going to be nice to not have to do the weird things.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. I was using Justin Tadock&#8217;s breadcrumbs block that he developed and he had some thoughts in this VR on how broad or restricted this new. This first version is going to be. And I think we all going to like it because depending on the context you can get additional. The breadcrumbs will change. And I really like that.</p>\n\n\n\n<p><em>Beth Soderberg:</em> Yeah, I&#8217;ve. I&#8217;ve used his plugin too. I forget which one it was. There&#8217;s a few independent plugins for breadcrumbs and my team has run into some weird edge cases of what they will do depending on your content structure. So I think that&#8217;s part of why the scope of the breadcrumbs block being limited at first makes so much sense, because the complexity of what you&#8217;re actually trying to do from a templating level, depending on where you are in a site and how your site is structured can get incredibly complex. I don&#8217;t remember which plugin it was, but we had a site. It may have been the Voter Guide. The Voter Guide within the site that completely killed everything. Like something about the logic of where we were just. And we had to use a different plugin just for that one site to make it work.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg:</em> I might have even re. Ended up doing something sort of manual instead. I don&#8217;t remember. But those plugins have been incredibly useful, but are also prone to edge case weirdness. Basically generating navigation on the fly. And if you don&#8217;t know where you are within the structure of the site from a structural standpoint, or if someone has made some odd decisions about where they&#8217;re putting things or how their hierarchy works, you&#8217;re going to end up with a really confusing breadcrumb.</p>\n\n\n\n<p><em>Birgit Pauli-Haack:</em> Yeah, yeah. And sometimes you don&#8217;t have the controls to actually make changes. It&#8217;s just all this black box kind of mystery mute kind of thing again. Yeah, yeah. And I. While we&#8217;re running a little bit out of time or short on time, I just wanted to mention there&#8217;s also a dialogue block in the works. There&#8217;s an icon block in the works. My favorite one is the stretchy text. It sounds so weird, but it actually makes sense. It&#8217;s text that stretches over a certain container and it&#8217;s flexible depending on how the container works. So you could do this for hero sections, all that. And then here&#8217;s your bestest favorite. The tabs block is in the works. And then also my favorite is a table of contents block. Because I have these long posts all the time and I want to do the table of contents block. But it had some weird issues. That&#8217;s why it&#8217;s not in Core yet. And they&#8217;re trying to figure that out how that all can be done. It&#8217;s now attempted to be a dynamic one and allow usage outside of the post or page that is actually referring to. But for instance, in a template, you could put it in a single post template in the sidebar and you will always have a table of content for your posts. So I think that&#8217;s a really good use case for pages, when you have landing pages or tutorial pages or documentation pages that you don&#8217;t have to fiddle with it while you&#8217;re creating the content. And it&#8217;s just there in the template.</p>\n\n\n\n<p><em>Beth Soderberg: </em>This is one where my weird workaround for it. There&#8217;s one of the SEO plugins has a table of contents block built into it. I forget which one offhand, but I&#8217;ve used that before to get this type of functionality.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p><em>Beth Soderberg: </em>Because it. Sometimes you really just need it.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah, absolutely. Yeah. Yeah. </p>\n\n\n\n<p>So that&#8217;s it. That is the Gutenberg changelog 122. Thank you so much for being with me on this, Beth. And it was great to chat with you and talk about block themes and all these good things. Block style stuff. Yeah.</p>\n\n\n\n<p><em>Beth Soderberg:</em> Thanks for having me. It was fun.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>Yeah. Dear listeners, as always, the show notes will be published on the <a href=\"http://gutenbergtimes.com/podcast\">gutenbergtimes.com/podcast</a>. This is 122. I already said that. But if you have questions or suggestions or news you want us to include, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a> that&#8217;s <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a> and I forgot a question for you, Beth. And that is if people want to get in touch with you, what is a good place to do that?</p>\n\n\n\n<p><em>Beth Soderberg: </em>You can find me in the WordPress slack under my name, Beth Soderberg. And then you can find me at work at our website, which is Bethink.studio or bethinkstudio.com. but you know, it&#8217;s really fun when you can get the non.coms to work with your name.</p>\n\n\n\n<p><em>Birgit Pauli-Haack: </em>So. Yes, all right. So I&#8217;ll list of course, all those contact information, more in the show notes.</p>\n\n\n\n<p>And thank you all for listening. Thank you for being here and see you when I&#8217;ll see you back. Well, in two weeks. Goodbye, and have a good time. </p>\n\n\n\n<p></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 12 Oct 2025 10:58:13 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:24;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Matt: In Canada\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150205\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2025/10/in-canada/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:731:\"<p>I&#8217;ve been trying to find time in my calendar to attend more WordCamps as I love meeting <a href=\"https://ma.tt/2025/09/wordpresser/\">WordPressers</a> all over the world. The stars aligned, and I&#8217;ll be swinging by <a href=\"https://canada.wordcamp.org/2025/\">WordCamp Canada</a> next week. They&#8217;ve put together an amazing program, including open web pioneer and inventor Dave Winer, so I&#8217;m looking forward to checking out the sessions. I wish I could go to every WordCamp, like I used to! I&#8217;ve been recording videos and messages for those I can&#8217;t physically attend. Ottawa is also great as the only other commercial board I&#8217;m on is <a href=\"https://fieldeffect.com/\">Field Effect</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 11 Oct 2025 15:35:19 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:25;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: Twitter Hacked\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150193\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:37:\"https://ma.tt/2025/10/twitter-hacked/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:662:\"<p>Sorry everybody, my @photomatt on Twitter has been hacked, I&#8217;m trying to regain account access, but it is not currently in my control. <strong>Update: </strong>Thank you to the fine teams at X/Twitter and <a href=\"https://x.com/nikitabier\">Nikita Bier</a>, my account has been recovered. Just for future reference, I will never promote cryptocurrencies or similar investments. If you see anything from me or WordPress claiming that, be highly skeptical. Invest in open source, public stocks, and great companies like Automattic. <img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f642.png\" style=\"height: 1em;\" /></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 11 Oct 2025 00:34:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:26;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:129:\"Gutenberg Times: Mega Menus in core, WordPress 6.9 calls for testing, going from Elementor to Site Editor — Weekend Edition 344\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=42168\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:134:\"https://gutenbergtimes.com/mega-menus-in-core-wordpress-6-9-calls-for-testing-going-from-elementor-to-site-editor-weekend-edition-344/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:23201:\"<p>Howdy,</p>\n\n\n\n<p>After meeting so many people at WordCamp Gdynia, on the plane and then on the train, I caught a nasty cold and struggled all week. I call this stage mushbrain, and everything becomes much harder, especially reading comprehension suffers. I am over it now, though. It also wasn&#8217;t the first time that I sounded horsey on a podcast episode. </p>\n\n\n\n<p>It&#8217;s the time of year now here in Munich when the days get shorter and the weather is cold, drissly and overcast. A time when snow would brighten the sights, with its whiteness covering partly the darkgray, dark brown background. </p>\n\n\n\n<p>Enjoy again  this weekend edition  and stay healthy. </p>\n\n\n\n<p>Yours, <img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<p><strong>Table of Contents</strong></p>\n\n\n\n<nav class=\"wp-block-table-of-contents\"><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/mega-menus-in-core-wordpress-6-9-calls-for-testing-going-from-elementor-to-site-editor-weekend-edition-344/#0-word-press-release-information\">Developing Gutenberg and WordPress</a><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/mega-menus-in-core-wordpress-6-9-calls-for-testing-going-from-elementor-to-site-editor-weekend-edition-344/#help-testing-new-features-for-wordpress-6-9\">Help testing new features for WordPress 6.9</a></li></ol></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/mega-menus-in-core-wordpress-6-9-calls-for-testing-going-from-elementor-to-site-editor-weekend-edition-344/#0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/mega-menus-in-core-wordpress-6-9-calls-for-testing-going-from-elementor-to-site-editor-weekend-edition-344/#2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/mega-menus-in-core-wordpress-6-9-calls-for-testing-going-from-elementor-to-site-editor-weekend-edition-344/#3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor</a><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/mega-menus-in-core-wordpress-6-9-calls-for-testing-going-from-elementor-to-site-editor-weekend-edition-344/#what-s-new-in-and-around-playground\">What&#8217;s new in and around Playground</a></li></ol></li></ol></nav>\n</div></div>\n</section>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"></div>\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p>Gutenberg 21.8 is now available and release lead <strong>Carlos Bravo</strong> hightlighed in his release post <a href=\"https://make.wordpress.org/core/2025/10/08/whats-new-in-gutenberg-21-8-08-october/\"><strong>What’s new in Gutenberg 21.8? (8 October)</strong></a></p>\n\n\n\n<ol class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2025/10/08/whats-new-in-gutenberg-21-8-08-october/#block-visibility-support-ui\">Block Visibility Control Support and UI</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/10/08/whats-new-in-gutenberg-21-8-08-october/#block-comments-improvements\">Block Comments Improvements</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/10/08/whats-new-in-gutenberg-21-8-08-october/#accordion-time-to-read\">Accordion and Time To Read Blocks</a></li>\n</ol>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>This week <strong>Gutenberg Changelog 122</strong> recording, <strong>Beth Soderberg</strong>, lead developer at <a href=\"https://bethink.studio/\">Bethink.studio</a> and I chatted about the release and other WordPress topics around Block themes and on going change. The episode arrive at your favorite podcast app over the weekend. </p>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/\">Gutenberg Changelog #122 – Gutenberg 21.8 and WordPress 6.9</a> with Beth Soderberg of <a href=\"https://bethink.studio/\">Bethink Studio</a></p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Gutenberg Changelog 122 with Beth Soderberg\" class=\"wp-image-42236\" height=\"193\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-11-at-12.32.48.png?resize=652%2C193&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p class=\"has-small-font-size\"><em>If you are listening via Spotify, please leave a comment. If you listen via other podcast apps, please leave a review. It&#8217;ll help with the distribution.</em></p>\n</div></div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>It was <strong>JuanMa Garrido</strong>&#8216;s turn to write the monthly roundup post <a href=\"https://developer.wordpress.org/news/2025/10/whats-new-for-developers-october-2025/\"><strong>What’s new for developers? (October 2025)</strong></a> on the WordPress Developer Blog. The 21.6, 21.7, and 21.8 Gutenberg releases add features for developers. The Command Palette now works throughout the admin, the new Terms Query block makes taxonomy layouts easier, and Block Visibility controls allow for conditional display. Notes (that&#8217;s how we call Block Comments now) improve team collaboration, while content-only editing maintains design integrity during client handoffs.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"help-testing-new-features-for-wordpress-6-9\">Help testing new features for WordPress 6.9</h3>\n\n\n\n<p>Release test co-leads <strong>Krupa Nanda</strong> and <strong>Jonathan Bossenger</strong>, published several calls for testing in preparation in WordPress of the 6.9 release. Each of the post has a detailed description of the feature, and instructions on how to test is with specific scenarios. It&#8217;s much easier to follow along with any of the calls for testing, to also learn what&#8217;s new in the next release. </p>\n\n\n\n<p><a href=\"https://make.wordpress.org/test/2025/10/03/help-test-changes-to-template-management/\"><strong>Help test changes to template management</strong></a> is probably the most elaborate call for testing, as template management received a completely new feature, and it needs to be working for many different use cases, and has consquences on existing sites.</p>\n\n\n\n<p><a href=\"https://make.wordpress.org/test/2025/10/04/call-for-testing-ability-to-hide-blocks/\"><strong>Call for Testing: Ability to Hide Blocks</strong></a> for this feature it&#8217;s the bare minimum of a new feature, that will be in future releases see some refinement and extensiblity. </p>\n\n\n\n<p><a href=\"https://make.wordpress.org/test/2025/10/06/call-for-testing-accordion-block/\"><strong>Call for Testing: Accordion Block</strong></a> lets you dive into a whole new block, many users asked for an several plugins are already available for. Now it will come to core. </p>\n\n\n\n<p>Your time spent on testing the new features for WordPress 6.9, has a lot of impact, as the bugs found now, make the release the best it can be for millions of other users. </p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p><strong>Lesley Sim</strong> informed us that <a href=\"https://wordpress.org/plugins/eventkoi-lite/\"><strong>EventKoi Lite</strong></a> is now available from the WordPress Plugin Repository. I mentioned the premium version before, Event Koi is modern, WordPress events calendar. Create single or multi-day events and display month, week, or list views via blocks (or shortcodes).</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Mike McAlister </strong>announced a new product: <strong>OlliePro Extensions</strong> on Bluesky. He mentions: Animations, advanced grid + column controls, keyboard shortcuts, and more. Watch the vidoe <a href=\"https://www.youtube.com/watch?v=qq2DLc43pTk\"><strong>Introducing Ollie Pro Extensions &#8211; Supercharge Your WordPress Block Editor</strong></a></p>\n\n\n\n<p>All controls are seamlessly integrated with the Core editor sitebar sections. <strong>Mark Howells-Mead</strong> <a href=\"https://wordpress.slack.com/archives/C015GUFFC00/p1760046957248569\">commented</a> in the WordPress Slack #outreach channel: &#8221; I’m very impressed with how he’s been able to integrate the little add-ons many of us are integrating to our own projects, but in such a seamless way by extending core controls.&#8221;  McAlister shared an <a href=\"https://gist.github.com/mikemcalister/937664ea19e87d61add7fc9902f10ac9\">example Gist on GitHub</a>.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>David McCan</strong> took a deep dive into the world of Block plugins. In this blog post   <a href=\"https://dynamicwp.co/performance-of-third-party-blocks-and-core-compared/\"><strong>Performance of Third Party Blocks and Core Compared</strong></a> he tries to answer the questions many site builders and owners have: &#8220;Can you add the features Gutenberg is missing yet still be performant like core?&#8221;. McCan tested ten third-party Gutenberg block plugins with WordPress core, specifically focusing on performance.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Matt Medeiros</strong>, WPMinute, took the <em>Mega Menu Designer</em>, also made  by Mike McAlister, out for the spin. He shared his thoughts in the Video <a href=\"https://www.youtube.com/watch?v=7NYskePLDM0#feedback\"><strong>How to Build Mega Menus with WordPress Blocks</strong></a>. He provides a detailed walkthrough calls it &#8220;Perfect for anyone looking to enhance their website&#8217;s navigation experience.&#8221; As reported earlier <a href=\"https://wordpress.org/plugins/ollie-menu-designer/\">the plugin is available for free</a> in the WordPress plugin repository. </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<p><strong>Rae Morey</strong>, publisher or The Repository, reported <strong><a href=\"https://www.therepository.email/ollies-menu-designer-flagged-for-core-with-automattic-developers-set-to-help-shepherd-it?utm_source=mailpoet&amp;utm_medium=email&amp;utm_source_platform=mailpoet&amp;utm_campaign=issue-276\">Ollie&#8217;s Menu Designer Flagged for Core, With Automattic Developers Set to Help Shepherd It</a></strong>. Automattic&#8217;s Anne McCarthy says developers are preparing to review Ollie&#8217;s Menu Designer for inclusion in the Gutenberg plugin, marking the start of a collaborative push to bring the plugin&#8217;s features into WordPress. This follows WordPress co-founder Matt Mullenweg&#8217;s suggestion that the menu functionality should be part of core. Details and links in Moery&#8217;s article. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p>This episode of <em>Greyd Conversations</em> show, <strong><a href=\"https://www.youtube.com/watch?v=cRM4FjR_UbE\">Switching to FSE from a pagebuilder</a>, </strong>covers the story of <em>Buro Staal</em>, a smal dutch agency, which switched from Elementor to Full site editing cold turkey. Greyd&#8217;s host <strong>Sandra Kurze</strong> and agency owner <strong>Rosanne van Staalduinen</strong> shared why and how her agency switched and the lessons learned along the way. </p>\n\n\n\n<p>The biggest hurdles were limited functionality of navigation block, not able to create Mega Menus, and the need for controls for mobile sites and responsiveness. So they augmented their tech stack with Kadence Blocks and Ollie Pro theme. </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n<section class=\"wp-block-newsletterglue-callout undefined not-color-set\" style=\"border-color: #f9f9e5; border-radius: 22px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f9f9e5;\">\n<p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2025&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. The previous years are also available: <strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p>\n</section>\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor</h2>\n\n\n\n<p><strong>Ryan Welcher</strong> published another recipe from his Blockdevelopment Cook Book on YouTube.  <strong><a href=\"https://www.youtube.com/watch?v=dJ4gUrxTgjM\">How To Make A Simple Fade In Effect Fast</a></strong>. &#8220;In this recipe, we’re adding a little flair by loading custom JavaScript and CSS for the Cover and Image blocks to create a smooth fade-in effect as they scroll into view. To keep things efficient, we’ll only enqueue these files when the blocks are actually on the page.&#8221; </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<h3 class=\"wp-block-heading\" id=\"what-s-new-in-and-around-playground\">What&#8217;s new in and around Playground</h3>\n\n\n\n<p><strong>Nick Diego</strong> announces that <a href=\"https://wordpress.com/blog/2025/10/08/introducing-blueprints-in-wordpress-studio-1-6-0/\"><strong>WordPress Studio version 1.6.0</strong></a> now supports Blueprints, which are lightweight JSON files that predefine site configurations for quick and consistent setup. Instead of starting with empty sites or using large snapshots, teams can create portable recipes specifying WordPress versions, plugins, and settings. Studio offers three featured blueprints for quick starts, development, and commerce, while users can also upload custom blueprints. The feature integrates into the standard site creation flow and helps streamline workflows for solo developers and teams alike.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><a href=\"https://wordpress.github.io/wordpress-playground/\"><strong>Playground documentation</strong></a> now has Ask AI button, to get help finding and understanding feature sets and APIs.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://wordpress.github.io/wordpress-playground/\"><img alt=\"\" class=\"wp-image-42203\" height=\"339\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-09-at-18.50.23.png?resize=652%2C339&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Ajit Bohra</strong> of Lubus <a href=\"https://x.com/ajitbohra/status/1975920964266258538\">shared on X</a> &#8220;The Visual BluePrint Builder for Playground is shaping up nicely. All the latest updates are in, and it’s feeling solid. Stable version coming soon, but you can already check it out and start building visually.&#8221; A blueprint builder with blocks, how nice.  You can test it via <a href=\"https://playground.wordpress.net/?blueprint-url=https%3A%2F%2Fraw.githubusercontent.com%2FlubusIN%2Fvisual-blueprint-builder%2Fplayground%2F_playground%2Fblueprint-github.json\">this Playground link</a>. The code is available on <a href=\"https://github.com/lubusIN/visual-blueprint-builder\">GitHub</a>. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Jamie Marsland</strong> also tries to make it easier to create blueprints for Playground sites and open up the WordPress in a browser tool for a broader audience. Details in his post <a href=\"https://www.pootlepress.com/2025/10/introducing-pootle-playground-my-experimental-wordpress-blueprint-builder/\" rel=\"noreferrer noopener\" target=\"_blank\"><strong>Introducing Pootle Playground — My Experimental WordPress Blueprint Builder</strong></a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Adam Zielinski</strong> created an <a href=\"https://playground.wordpress.net/php-playground.html\"><strong>online PHP code editor</strong></a> using Playground. It allows developers to test PHP snippets quickly in their browser. The tool supports WordPress functions, enables switching between PHP and WordPress versions, and allows sharing code configurations through links. Built with WordPress Playground, it runs entirely client-side with network access and popular PHP extensions included. He&#8217;s currently experimenting with adding CLI and file browser capabilities to support composer packages and frameworks like Laravel or Symfony.</p>\n\n\n<section class=\"wp-block-newsletterglue-callout undefined not-color-set\" style=\"border-color: #eeeeee; border-radius: 26px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f3efe9;\">\n<p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review. </p>\n\n\n\n<p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience</p>\n\n\n\n<p><img alt=\"GitHub all releases\" src=\"https://img.shields.io/github/downloads/bph/gutenberg/total?style=for-the-badge\" /></p>\n</section>\n\n\n<p class=\"has-text-align-center has-small-font-size\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<p>Featured Image: Free colorful building blocks image by <a href=\"https://www.rawpixel.com/image/5906195/photo-image-public-domain-free-game\">Rawpixel </a></p>\n\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-left\"><strong>Don&#8217;t want to miss the next Weekend Edition? </strong></p>\n\n\n<form action=\"https://gutenbergtimes.com/feed/\" autocomplete=\"on\" class=\"wp-block-newsletterglue-form ngl-form ngl-portrait\" method=\"post\"><div class=\"ngl-form-container\"><div class=\"ngl-form-field\" style=\"margin-bottom: 25px;\"><label class=\"ngl-form-label\" for=\"ngl_email\"><br />Type in your Email address to subscribe.</label><div class=\"ngl-form-input\"><input autocomplete=\"email\" class=\"ngl-form-input-text\" id=\"ngl_email\" name=\"ngl_email\" required=\"required\" style=\"border-radius: 21px;\" type=\"email\" /></div></div><button class=\"ngl-form-button\" style=\"background-color: #005075; border-color: #005075; border-width: 1px; border-style: solid; color: #ffffff; border-radius: 21px;\" type=\"submit\">Subscribe</button><p class=\"ngl-form-text\">We hate spam, too, and won&#8217;t give your email address to anyone <br />except Mailchimp to send out our Weekend Edition</p></div><div class=\"ngl-message-overlay\"><div class=\"ngl-message-svg-wrap\"><svg fill=\"none\" height=\"24\" stroke=\"#fff\" stroke-width=\"2\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><polyline points=\"20 6 9 17 4 12\"></polyline></svg></div><div class=\"ngl-message-overlay-text\">Thanks for subscribing.</div></div><input id=\"ngl_list_id\" name=\"ngl_list_id\" type=\"hidden\" value=\"26f81bd8ae\" /><input id=\"ngl_double_optin\" name=\"ngl_double_optin\" type=\"hidden\" value=\"yes\" /></form>\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n</section>\n\n\n<p></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Oct 2025 23:35:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:27;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Matt: Jeremy Kranz and Sentinel\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150173\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2025/10/jeremy-kranz/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2487:\"<p>I&#8217;d like to introduce you to <a href=\"https://www.linkedin.com/in/jeremykranz/\">Jeremy Kranz</a>. With his career as an investor at <a href=\"https://www.intelcapital.com/\">Intel Capital</a>, then <a href=\"https://en.wikipedia.org/wiki/GIC_(sovereign_wealth_fund)\">GIC</a>, which is the sovereign wealth fund of Singapore rumored to manage over $700B, to now running his own fund <a href=\"https://www.sentinelglobal.xyz/\">Sentinel Global</a>, he has had a front-row seat to investments in industry changing companies such as ByteDance (which became TikTok), Alibaba, Uber, DoorDash, Zoom, DJI (which changed the drone industry and argubly modern warfare), and many more I&#8217;m probably not even aware of.</p>\n\n\n\n<p>When I first met Jeremy in 2014, I was amazed that a late-stage financial investor could understand Open Source so well, and he immediately grokked what <a href=\"https://automattic.com/\">Automattic</a> was doing in a way that I think has little parallel in the world. (Today, it reminds me of Joseph Jacks at <a href=\"https://oss.capital/\">OSS Capital</a>.) <a href=\"https://www.insightpartners.com/team/deven-parekh/\">Deven Perekh of Insight Partners</a> led Automattic&#8217;s 1.16B valuation Series C round, making us one of only forty &#8220;unicorns&#8221; (private companies valued over a billion dollars) at the time, and one of the reasons they beat out others as the lead of the round was that GIC/Jeremy was a LP of Insight so they could directly co-invest. GIC is so intensely private <a href=\"https://ma.tt/2014/05/new-funding-for-automattic/\">I couldn&#8217;t even mention them in the announcement at the time</a> even though they were the catalyst for the round.  Since then, Jeremy has become a close friend and advisor, and he even took me to <a href=\"https://www.nugs.net/live-download-of-dead-and-company-dos-equis-pavilion-dallas-tx-10-14-2021-mp3-flac-or-online-music-streaming/26749.html\">my first Grateful Dead concert</a>.</p>\n\n\n\n<p>Eleven years later, this is his first podcast! Jeremy shares incredible <a href=\"https://www.investopedia.com/terms/a/alpha.asp\">alpha</a> around China, AI and its adoption in the enterprise, how asset allocation is evolving, and at the end, a beautiful tie together of the Grateful Dead and Open Source.</p>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Oct 2025 19:30:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:28;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Matt: Kathy Sierra\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150166\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2025/10/kathy-sierra/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:774:\"<p>I was reminded today of the profound marketing influence of <a href=\"https://en.wikipedia.org/wiki/Kathy_Sierra\">Kathy Sierra</a>, who was a pretty prolific blogger and speaker back in the day. I would summarize her thesis as such: <strong>Your best marketing and communication should talk about how you make your users awesome, not how you&#8217;re awesome</strong>. If you&#8217;d like to check out some of her talks, <a href=\"https://href.li/?https://wordpress.tv/2008/10/31/wordcamp-sf-2008-kathy-sierra-kicking-ass-and-creating-passionate-users/\">she spoke at WordCamp in 2008</a>, <a href=\"https://vimeo.com/81625882?fl=pl&amp;fe=ti\">at Business of Software in 2013</a>, and at <a href=\"https://www.youtube.com/watch?v=iBtcGwHPMKM\">Mind the Product in 2015</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Oct 2025 01:22:50 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:29;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"Open Channels FM: Bootstrapping a Successful WordPress Business Through Customer Feedback and Iteration\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110936\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:110:\"https://openchannels.fm/bootstrapping-a-successful-wordpress-business-through-customer-feedback-and-iteration/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:218:\"In this episode, Mark chats with Aurelio Volle from WPUmbrella about his journey in creating a WordPress management tool, maintaining customer focus, and the importance of community and transparency in business growth.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Oct 2025 10:47:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:30;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Matt: Battery Scan\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150146\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2025/10/battery-scan/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1067:\"<p>One of the cooler companies I&#8217;ve seen in a while is <a href=\"https://www.lumafield.com/\">LumaField</a>, which does industrial CT scanning, as they describe it.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>Industrial X-ray CT (Computed Tomography) works on the same basic principle as medical CT, taking hundreds of X-ray images from different angles to capture the internal and external structure of objects in three dimensions.</p>\n</blockquote>\n\n\n\n<p>In addition to providing amazing graphics of these scans, they also gather some valuable data. <a href=\"https://www.lumafield.com/battery-report\">Their Lumafield Battery Quality Report does a deep dive into lithium ion battery manufacturing</a>, showing the wild differences between different brands. </p>\n\n\n\n<p>I love this stuff, whether you call it QA, evals, testing, or whatever, it reminds me of <a href=\"https://www.principles.com/principles/8b086563-5bb4-4741-8713-c62bd1a0d749/\">Ray Dalio&#8217;s Principle to embrace reality and deal with it</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Oct 2025 06:24:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:31;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"WPTavern: #188 – Bud Kraus on Teaching and Using WordPress With Low Vision\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=199897\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:90:\"https://wptavern.com/podcast/188-bud-kraus-on-teaching-and-using-wordpress-with-low-vision\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:39989:\"<details>Transcript<div>\n<p>[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p>Jukebox is a podcast which is dedicated to all things WordPress. The people, the events, the plugins, the blocks, the themes, and in this case teaching and using WordPress with low vision.</p>\n\n\n\n<p>If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice. Or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p>If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox and use the form there.</p>\n\n\n\n<p>So on the podcast today we have Bud Kraus. Bud was diagnosed with mascular degeneration, a condition often associated with old age, when he was 37. Affecting both eyes, this gradually eroded his central vision, making it difficult for him to see straight ahead, recognize faces, drive or read.</p>\n\n\n\n<p>Despite these challenges, Bud&#8217;s peripheral vision remained intact, sparing him the need for a cane or guide dog, and allowing him to continue to navigate daily life. Through perseverance and adaptation, Bud continues to live fully, facing the hurdles of vision loss with resilience and optimism.</p>\n\n\n\n<p>Bud opens up the podcast by talking about his experience living with legal blindness, how his central vision loss has shaped everything from everyday activities to his professional routines. He explains the practical ways he adapts his devices and workflow, including tweaks to operating system settings, using screen zoom functions, and relying on pattern recognition to teach coding, write tutorials, and even host his Seriously, Bud? podcast. His unique perspective sheds light on the often overlooked nuances of accessibility, reminding us that every user interacts with technology differently.</p>\n\n\n\n<p>Bud also chats about the broader impact of accessibility in the WordPress space, from frustrations with hard to navigate interfaces, to the importance of not excluding users who may become your audience or customers. His reflections reveal how living with low vision pushed him beyond mere acceptance, helping him discover new opportunities, hone his teaching skills, and even find humour in daily challenges.</p>\n\n\n\n<p>Bud&#8217;s story serves as a powerful reminder of the importance of designing with empathy, embracing adaptation, and viewing accessibility, not just as a technical requirement, but as a source of creativity and connection. It&#8217;s full of real world tips, personal anecdotes, and a dose of inspiration.</p>\n\n\n\n<p>Whether you&#8217;re a designer, developer, educator, or simply passionate about building a more inclusive web, this episode is for you.</p>\n\n\n\n<p>If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p>And so without further delay, I bring you Bud Kraus.</p>\n\n\n\n<p>I am joined on the podcast by Bud Kraus. Hello, Bud.</p>\n\n\n\n<p>[00:03:35] <strong>Bud Kraus:</strong> Hello, Nathan. Thanks for having me.</p>\n\n\n\n<p>[00:03:37] <strong>Nathan Wrigley:</strong> Yeah, you&#8217;re very welcome. This is not the first time we&#8217;ve spoken, but it is the first time we&#8217;ve spoken at an event because we&#8217;re both at WordCamp US in Portland, it&#8217;s 2025. We&#8217;re in a corridor, so I&#8217;ve got to say at the very outset, if it ends up being quite noisy, there&#8217;s not a lot we can do about that. But we&#8217;ve done our best. We&#8217;ve found a nice quiet little alcove, and we&#8217;re going to be chatting today to Bud about his experience online. Before we do that, Bud, do you mind just telling us a little bit about yourself? Give us your potted bio, if you like.</p>\n\n\n\n<p>[00:04:01] <strong>Bud Kraus:</strong> Yeah, sure. So I create WordPress content for WordPress businesses, articles, blog posts, tutorials, videos, and I am the host of the podcast called Seriously, Bud?</p>\n\n\n\n<p>[00:04:14] <strong>Nathan Wrigley:</strong> And the talk that you&#8217;re doing at WordCamp US, which I guess you haven&#8217;t yet done, because we&#8217;re on the first day of presentations and it&#8217;s fairly early on. You haven&#8217;t done it, right?</p>\n\n\n\n<p>[00:04:23] <strong>Bud Kraus:</strong> No, I actually, no, I haven&#8217;t done it yet, but I&#8217;ve done this a couple times, so this is not my first time doing this talk.</p>\n\n\n\n<p>[00:04:29] <strong>Nathan Wrigley:</strong> So you know how it&#8217;s going to go. It&#8217;s called using low vision as my tool to help me teach WordPress. Now, that kind of leads us into the subject at hand really. We&#8217;re going to be talking about how it is that your experience of the web may differ from other people.</p>\n\n\n\n<p>Are you willing to just tell us a little bit about your experience in the offline world as well as the online world? What is it that you are dealing with on a day-to-day basis?</p>\n\n\n\n<p>[00:04:50] <strong>Bud Kraus:</strong> Sure. So I have macular degeneration, which is a condition of old age, which I got when I was 37. And it&#8217;s the leading cause of legal blindness in the United States. It&#8217;s a destruction of your central vision.</p>\n\n\n\n<p>I have the condition in both eyes, which means I really have it. And it makes it very hard for me to see straight ahead, recognise faces, reading. I can&#8217;t drive a car, which is okay. So anything that&#8217;s straight ahead.</p>\n\n\n\n<p>Now, my peripheral vision&#8217;s perfectly intact, so that means I don&#8217;t need to have a seeing eye dog or a cane, or I don&#8217;t bump into things because the peripheral vision&#8217;s fine. But the very fine vision that we all use to see straight ahead, like to thread a needle, that&#8217;s what I&#8217;m missing.</p>\n\n\n\n<p>[00:05:30] <strong>Nathan Wrigley:</strong> So are you able to describe what you are seeing in that area. And is it like the central portion of your site?</p>\n\n\n\n<p>[00:05:38] <strong>Bud Kraus:</strong> It is the exact central portion of my sight. So I tend to see elliptically, which means I move my eyes around to get a better picture. Like, when I&#8217;m looking at you right now, I&#8217;m moving my eyes around so I can see better because of the destruction of the centre part of my vision.</p>\n\n\n\n<p>[00:05:52] <strong>Nathan Wrigley:</strong> And does that rule out certain tasks? So for example, you mentioned reading there. Obviously I do not have what you have, and so it&#8217;s a given to me that when I&#8217;m staring as I am doing at the moment at my laptop, my eyes, the bullseye, if you like, of my eyes go straight to the letter looking at. And for me, it&#8217;s hard to imagine deploying my peripheral vision to do that, but can you, for example, do things like reading or is that out of the?</p>\n\n\n\n<p>[00:06:16] <strong>Bud Kraus:</strong> You can&#8217;t, peripheral vision is not a, it&#8217;s not even close to being a perfect substitute for central vision. So the answer is no. You cannot read with peripheral vision. You cannot understand. You can see, but you can&#8217;t understand. And it just makes things difficult.</p>\n\n\n\n<p>[00:06:33] <strong>Nathan Wrigley:</strong> Yeah. So how does that affect your real life? So obviously you mentioned things like being unable to drive a car or things like that. Is there anything else that might give us a frame of reference for just how profound it is?</p>\n\n\n\n<p>[00:06:44] <strong>Bud Kraus:</strong> Well, I like to look at it differently. So I have a different approach to this. So when I first was diagnosed with this when I was 37, I thought, oh, this is the worst thing that could ever happen. And that makes sense, but it is not the worst thing that could ever happen.</p>\n\n\n\n<p>And having lived with this for quite a long time now, I look at this not as a curse, but as a blessing. Because what it&#8217;s done is allow me to have so many different opportunities, experiences, ideas, thoughts, whatever that I would&#8217;ve not otherwise had.</p>\n\n\n\n<p>So that process of going, it&#8217;s the grief process when you start from, you know, this is the most horrible thing in the world, to acceptance. I&#8217;m actually beyond acceptance. It&#8217;s like, I like this. This is okay with me. And do I wish it on other people? No, I don&#8217;t. But like I said, it&#8217;s not the end of the world. There are conditions and diseases that are far worse than this.</p>\n\n\n\n<p>So I do think of, and in fact in my talk that I&#8217;m giving, at the end I talk about why this is a blessing and not a curse. I mean, like for example, you can get as inebriated as you want at parties because you&#8217;re not going to be driving the car home. So there&#8217;s lots of that, okay. Or you don&#8217;t see your friends get older because you can&#8217;t see the detail on their face. When I go in a grocery store, I don&#8217;t see all the junk food, so that&#8217;s good. Is it inconvenient? Yes. Do I have a hard time finding people at a large event like this? Yes. But I manage.</p>\n\n\n\n<p>[00:08:09] <strong>Nathan Wrigley:</strong> So in the wider world, you can obviously deploy your peripheral vision. So we&#8217;re sitting in a, I don&#8217;t know, it&#8217;s maybe this room&#8217;s about 10 meters by 10 meters. There&#8217;s a lot of space. Whereas the thing that we&#8217;re talking about, WordPress, building websites and so on, it&#8217;s usually this constrained little, well, let&#8217;s say rectangle. It could be something that we&#8217;re holding our hands, a mobile phone or a computer, laptop, something like that. How does your situation, how does it get impacted by this then? Are you doing this peripheral vision, glancing left and right and trying to figure out what&#8217;s going on? Or do you have other tools, mechanisms, things that you deploy?</p>\n\n\n\n<p>[00:08:39] <strong>Bud Kraus:</strong> I do, and that&#8217;s what my talk is about. So, for example, I&#8217;ve taught WordPress and I taught coding for a long time. And people say, well, how do you do that if you can&#8217;t see?</p>\n\n\n\n<p>Well, one thing is I&#8217;m always very prepared. So when I go into a class, I can&#8217;t wing it. I just have to know exactly what I&#8217;m going to be doing. And in code there&#8217;s a lot of patterns and I recognise patterns.</p>\n\n\n\n<p>And, yes, I do use Zoom. I use audio. I use touch. Now, touch is not really relevant here, but I&#8217;m able to, with the technology as good as it has become for me, I&#8217;m able to Zoom in and out of the screen and I&#8217;m able to read things out loud. And then I have to do a fair amount of memory. But that&#8217;s okay.</p>\n\n\n\n<p>[00:09:22] <strong>Nathan Wrigley:</strong> So do you have adaptations that you make, let&#8217;s say for example, you go out today and you purchase a new computer, do you have adaptations that you make on an operating system level?</p>\n\n\n\n<p>[00:09:30] <strong>Bud Kraus:</strong> Yeah, I do.</p>\n\n\n\n<p>[00:09:31] <strong>Nathan Wrigley:</strong> Okay. I&#8217;m curious to hear about these because I make no modifications when I purchase, so tell me more.</p>\n\n\n\n<p>[00:09:35] <strong>Bud Kraus:</strong> Yeah, good question. So one of the things I do, and I&#8217;ll be demonstrating, is my resolution is a low resolution, meaning 1024 by 768 would be low today. In the olden days, that would be high. But it makes the screen, it makes it easier for me to see the screen. And then I make all kinds of adjustments to make icons bigger, letters bigger, so that it&#8217;s just works for me. And yeah, I don&#8217;t have a problem with it.</p>\n\n\n\n<p>Now, it does cause me to do things maybe a little slower because it&#8217;s just harder for me to maybe find something. But I think I mentioned that patterns is a very important thing to me. So if I&#8217;m going to a website and they change the UI totally around, that&#8217;s going to be a pain in the neck for me, because then I have to relearn where everything is.</p>\n\n\n\n<p>It&#8217;s sort of like changing the furniture if you were blind, I mean, really blind, which most people aren&#8217;t. So I&#8217;m legally blind but, you know, I&#8217;m not like lights out blind. If you change where things are, then it&#8217;s going to make things very difficult for me, whether it&#8217;s in the real world or in the virtual world. I have to relearn everything.</p>\n\n\n\n<p>[00:10:35] <strong>Nathan Wrigley:</strong> A sort of curious question that&#8217;s just occurred to me. When you buy a new computer, is there a process whereby you have to combat the regular default icon size and default tech size, just for a moment in order to wrangle it into the version of the OS that you need?</p>\n\n\n\n<p>[00:10:50] <strong>Bud Kraus:</strong> You&#8217;re absolutely right. So if you&#8217;re booting up for the first time, it&#8217;s a hole in the whole process, which is at least the last time I did, which is there&#8217;s no audio, there&#8217;s no nothing, and you&#8217;re seeing like little tiny print to, you know, configure the language and the location and the time and all that stuff that you do when you work with a computer for the first time. That is a real problem, yeah.</p>\n\n\n\n<p>[00:11:11] <strong>Nathan Wrigley:</strong> You would imagine that there&#8217;d be some mechanism to invoke that as the first thing that happens?</p>\n\n\n\n<p>[00:11:17] <strong>Bud Kraus:</strong> I think so.</p>\n\n\n\n<p>[00:11:17] <strong>Nathan Wrigley:</strong> Yeah, that&#8217;s interesting.</p>\n\n\n\n<p>Okay, so we&#8217;ve talked about the wider world. We&#8217;ve talked about a computer that you may modify. Let&#8217;s get onto the bit which we are all here for, which is WordPress. Are there any adjustments or tools, or this could extend to the browser, so it may be browser tools, what have you, but for the internet, let&#8217;s say, what are the modifications that you are making to make your life possible there?</p>\n\n\n\n<p>[00:11:37] <strong>Bud Kraus:</strong> You know, I don&#8217;t think there&#8217;s anything really any different than anybody else makes. I mean, the biggest thing is I will either zoom in or out of a webpage. And it&#8217;s really funny because, if you&#8217;re using a certain screen size with a certain resolution, things can get very hard to work with. I don&#8217;t think enough companies, like I&#8217;m thinking of even LinkedIn, for example, that I was using today. Sorry to call them out, but it&#8217;s just like their chat areas were just really, I just had to do all kinds of crazy things to actually see the text. And then the text was really small.</p>\n\n\n\n<p>I think because I&#8217;m a stress case, that they don&#8217;t always test down to my level. And I think it&#8217;s, I just accept it. But that&#8217;s the way it is, I guess. But I think that you don&#8217;t want to exclude people from anything really, because they may be your customer. And if I can&#8217;t buy something because it&#8217;s really hard to do, and that is something, I don&#8217;t know if I&#8217;ve ever talked to you about it, but other people, that if I am discouraged from buying something because it&#8217;s just, the UI is just too hard to work with, I&#8217;ll just find an alternative. I will. Or I&#8217;ll ask my wife.</p>\n\n\n\n<p>[00:12:39] <strong>Nathan Wrigley:</strong> I guess you&#8217;re in a curious space as well in that we hear a lot in the accessibility space about things like screen readers and those kind of assistive technologies. I guess you are not deploying those because you have enough sight to not have that as a, something to lean upon.</p>\n\n\n\n<p>[00:12:54] <strong>Bud Kraus:</strong> Yeah, that&#8217;s exactly right. I have not, and don&#8217;t use JAWS or any of those big fancy screen reader technologies. I just use what&#8217;s built into the macOS and I just highlight the text and I press a button and it reads. I think it&#8217;s called voiceover, or it&#8217;s text to speech, or whatever it is. And it&#8217;s in the accessibility part of the settings.</p>\n\n\n\n<p>I don&#8217;t use technology beyond what I need it for. It&#8217;s just overkill. What do I, those are complicated systems to master, so I stay away from that because they don&#8217;t need it.</p>\n\n\n\n<p>[00:13:22] <strong>Nathan Wrigley:</strong> So when you are building websites, is there anything unique about the way that you do that? Is there any sort of, again, a tool that you deploy? Or maybe you are relying on other human beings to sort of cast their eye over it a second time after you&#8217;ve done the work. I don&#8217;t know, just talk us through that whole thing.</p>\n\n\n\n<p>[00:13:37] <strong>Bud Kraus:</strong> Well, I don&#8217;t make websites. No, I have, okay. I&#8217;ve done everything, but I don&#8217;t make websites because I don&#8217;t like to make websites. It&#8217;s not because of my vision. But yes, if I am working, in the past like I have, I would ask people to help me with, particularly with colour because I have a very, I think I have a poor colour palette. And I think that&#8217;s either, it&#8217;s because of me. So I have to ask, does this go good with this?</p>\n\n\n\n<p>It&#8217;s just something that I, either I&#8217;m not good at, or I&#8217;m not interested, or my vision, or whatever it is. So I do have a problem with colour in that regard. But because of the technology and the tools that are built in, it&#8217;s not as difficult as one might think.</p>\n\n\n\n<p>[00:14:15] <strong>Nathan Wrigley:</strong> Interesting. Yeah, okay. We&#8217;ll get into that. But you do make a podcast, and there&#8217;s lots and lots of different spinning wheels that have to done there. You know, you&#8217;ve got to book people onto the show, you&#8217;ve got to have calendars, you&#8217;ve got to have posts and pages and things like that on the website. Is there anything uniquely interesting about, I understand the process of making a website from my perspective, there anything that would be different to my process than would be for yours?</p>\n\n\n\n<p>[00:14:36] <strong>Bud Kraus:</strong> Yes, I think one thing I could think of is like a lot of times I won&#8217;t, let&#8217;s say in WordPress, you can write into the editor, you could write a page or a post right into the Gutenberg, the block editor. I choose not to do that. What I do is use a notepad, or not notepad, what is it for a Mac? I forgot.</p>\n\n\n\n<p>[00:14:53] <strong>Nathan Wrigley:</strong> TextEdit.</p>\n\n\n\n<p>[00:14:54] <strong>Bud Kraus:</strong> Yes, TextEdit. Thanks. I&#8217;ll use that and I&#8217;ll have the font blown up bigger than normal, and I&#8217;ll just edit in there, and then I&#8217;ll just take that and then I&#8217;ll copy that and paste that into WordPress. It&#8217;s just easier for me to do it that way. So I just like it that way. You know, everybody has their own little thing. That&#8217;s my little thing. And I think it&#8217;s because of my vision.</p>\n\n\n\n<p>[00:15:14] <strong>Nathan Wrigley:</strong> And in terms of kind of getting the recording software to work and things like that, how do those UIs function for you?</p>\n\n\n\n<p>[00:15:19] <strong>Bud Kraus:</strong> Yeah, pretty good. The problem I have with learning something new and complicated is that, I think it&#8217;s like everybody, quite frankly, I get confused and try to figure out where&#8217;s what. And like I was using, I use Descript, and it just took me quite a while to figure out, how do I do this? How do I do that? But like anything else, once I learn it, it&#8217;s pretty solid and it gets easier.</p>\n\n\n\n<p>Now I do tend to blow things up to make it bigger. And my wife is always telling me, I can&#8217;t use your computer because stuff is too big. Now, I don&#8217;t think it&#8217;s too big, but she does. And when I look at other people&#8217;s computers, then I realise, no, it&#8217;s bigger than theirs.</p>\n\n\n\n<p>[00:15:53] <strong>Nathan Wrigley:</strong> Okay, so we&#8217;re in the era of Gutenberg. It sounds like you&#8217;ve been using WordPress for a fairly long time, presumably before Gutenberg. What&#8217;s your opinion on whether or not that was a move in the right direction? In other words, is it favorable? Is it more straightforward for you to create a post? I know that you said in the scenario for a podcast, you&#8217;re writing it elsewhere and copying and pasting it in. But with other things like, I don&#8217;t know, laying out content and writing paragraphs and things, do you think it&#8217;s a good experience? Did we go in the right direction there?</p>\n\n\n\n<p>[00:16:18] <strong>Bud Kraus:</strong> That&#8217;s a very hard question for me to answer. I&#8217;ll answer it in a couple of different ways. One, as far as accessibility goes, I&#8217;m no expert in this. I am not an accessibility expert. Am I a stakeholder? We all are. But I can&#8217;t answer it in that regard.</p>\n\n\n\n<p>But from a more technical standpoint, because I write technical articles for Kinsta, Hostinger, others, that I find it to be difficult. I know I was told it&#8217;s not supposed to be easy, so it certainly doesn&#8217;t match the easy. Yeah, and that has nothing to do with my vision. It&#8217;s just, I feel it&#8217;s just complicated, even though I&#8217;ve learned quite a bit of the technical side of this stuff. I&#8217;m not trying to be cute here, but I&#8217;m trying to be cute, and I just can&#8217;t answer that question that&#8217;s going to provide any value so.</p>\n\n\n\n<p>[00:17:06] <strong>Nathan Wrigley:</strong> I was kind of wondering if there was a thing which, if you could click your fingers and make it appear in the Block Editor or the Gutenberg interface, which you would, and I don&#8217;t know that you&#8217;ve got got an answer to that.</p>\n\n\n\n<p>[00:17:15] <strong>Bud Kraus:</strong> I, let me think. No, I don&#8217;t think so. No. And I use Elementor too. So I think from a logic standpoint, Elementor seems to be easier for me. What I just don&#8217;t like is a lot of confusion. Too much information built into a UI is a real problem for me.</p>\n\n\n\n<p>Nathan, the funny thing is I feel like I have a special filter on the world that other people don&#8217;t have. This is another one of these blessings, that gives me the ability to understand what works and what doesn&#8217;t work without having to ask somebody because it&#8217;s just built in.</p>\n\n\n\n<p>Now, the thing about disability or this field in general, which is huge, it&#8217;s very idiosyncratic. So my setup is good for me, but it may not work for somebody else. And it&#8217;s very hard to, as those who keep accessibility in mind, and hopefully it&#8217;s everybody. It&#8217;s a very difficult subject because how do we design our systems, our content so that the greatest number of people can access this information, or whatever, on the largest number of devices. I mean, that&#8217;s what accessibility to me is about.</p>\n\n\n\n<p>[00:18:24] <strong>Nathan Wrigley:</strong> It&#8217;s curious that you said, I think you said at the beginning that your condition is one which will deteriorate over time.</p>\n\n\n\n<p>[00:18:31] <strong>Bud Kraus:</strong> Well, macular degeneration, generally, can get worse over time. But fortunately, for reasons that we don&#8217;t need to get into, since 1992 it&#8217;s been very stable, which I&#8217;m really fortunate because trust me, I don&#8217;t want it to get any worse than this. I don&#8217;t need another, that much of a blessing.</p>\n\n\n\n<p>[00:18:50] <strong>Nathan Wrigley:</strong> Yeah, I was wondering from that, whether or not the accessibility side of WordPress is something that you lean into. Do you attend those kind of, I don&#8217;t know, WP Accessibility Day, those kind of events?</p>\n\n\n\n<p>[00:18:59] <strong>Bud Kraus:</strong> No, it just doesn&#8217;t really interest me. You know, back in like 1999, 2000, I was teaching a course at Pratt Institute in New York called Accessible Web Design. And it was way ahead of its time. And the concepts I was teaching were basically concepts because the browsers and technology just wasn&#8217;t there yet. So you&#8217;d have to say, well, one day, and one day did happen in large measure.</p>\n\n\n\n<p>And then I started realising, I just didn&#8217;t want to like make a career out of teaching this or testing or, you know, I started to meet people in the field and I just said, I don&#8217;t really like this. I mean, just because I&#8217;m, I have a disability doesn&#8217;t mean I have to like the field of accessible design, you know, accessibility.</p>\n\n\n\n<p>[00:19:40] <strong>Nathan Wrigley:</strong> Yeah, that&#8217;s interesting. You are wearing a WordCamp Montclair t-shirt, which kind of tells me that not only are you attending this event, WordCamp US, but you&#8217;re also attending other ones as well. Is that a big part of your life? If it is, how accessible are things like this event? Do you come here fully expecting of yourself that you&#8217;ll have a full experience the same way that everybody else does?</p>\n\n\n\n<p>[00:19:59] <strong>Bud Kraus:</strong> Well, I have a good experience, but it is not the same way everybody else does. For example, I can&#8217;t see the screens at all. And when they&#8217;re doing stuff, the slides, I&#8217;m just listening, okay. It&#8217;s sort of like, I watch TV a lot that way too. I hear things. Unless I got really close, I&#8217;m not going to be able to see what&#8217;s on the screen. If I took a picture of something that&#8217;s really important, yeah, that&#8217;ll help.</p>\n\n\n\n<p>But generally speaking, that doesn&#8217;t work for me. And then it could be kind of a, yes, I&#8217;ve gone to many WordCamps, but they&#8217;re all sort of the same in terms of the issues. And I don&#8217;t even think of them as issues anymore. I just think of it as like, we&#8217;re all different. This is the way I&#8217;m different. And talking about this stuff, quite frankly is like talking about being right-handed. Would you do an interview of me being right-handed?</p>\n\n\n\n<p>[00:20:42] <strong>Nathan Wrigley:</strong> Yeah, fascinating. I guess, from my perspective, because I just don&#8217;t, I can&#8217;t prize that open my own life, it&#8217;s really intriguing to sort of try to have some sort of understanding of how it differs from my experience to your experience. And I guess for you it&#8217;s, this is how I live.</p>\n\n\n\n<p>[00:20:58] <strong>Bud Kraus:</strong> Yeah. But Nathan, you know, vision is a spectrum. It&#8217;s a continuum. It isn&#8217;t just everybody looks at things the same way. No. So I don&#8217;t think, alright, I&#8217;m like sort of on one end of the spectrum, I get it, but everybody looks at things differently. And I don&#8217;t mean that figuratively, I mean that literally. So I don&#8217;t think of it anymore much as a handicap, you know, other than the fact that, yeah, that&#8217;s a pain in the neck sometimes. And sometimes you find yourself doing some foolish things.</p>\n\n\n\n<p>And I think the hardest thing for me at these events is that I won&#8217;t know who I&#8217;m talking to until about five minutes after I&#8217;m talking to them, and I figured out by looking at their shape, stuff like that, that I can, oh, I&#8217;m talking to Nathan Wrigley, or your accent, or something like that.</p>\n\n\n\n<p>[00:21:42] <strong>Nathan Wrigley:</strong> Yeah. You&#8217;re obviously quite keen on the sort of education side of things though because you&#8217;re writing tutorials. I&#8217;ll link in the show notes to one that you wrote for Smashing Magazine, which is no mean feat. Getting in there is really rather impressive. So well done for that.</p>\n\n\n\n<p>But you&#8217;re also obviously turning up two events like this. And it sounds from what you said as if this is content that you&#8217;ve done before. So very keen on that, even though it may be talking about, you were describing there, it&#8217;s like talking about whether you&#8217;re right-handed. You&#8217;ve put together this presentation in which you&#8217;re going to share these different bits and pieces about how you make amendments and adjustments to WordPress and the operating system and so on. So do you enjoy the education side of it?</p>\n\n\n\n<p>[00:22:16] <strong>Bud Kraus:</strong> Oh, absolutely. I&#8217;m a teacher at heart. I mean, you know, that&#8217;s what I&#8217;ve been doing for 25 years. And even in the writings that I do, they&#8217;re basically, it&#8217;s a different way of teaching. Now the talk that I&#8217;m giving though here, the funny thing is, as I&#8217;ve said, I&#8217;m sort of like cool to the idea to be honest about it. There are other talks I&#8217;d rather give than this one, but this is the talk that everybody seems to be interested in. And I get that.</p>\n\n\n\n<p>And when you come up with a topic called using low vision is a tool to help me teach WordPress, that&#8217;s a winner because you got two things in there that everybody loves. One, we love disability, and two, we love teaching WordPress. So two weird things got put into one title.</p>\n\n\n\n<p>[00:22:57] <strong>Nathan Wrigley:</strong> It&#8217;s a hit.</p>\n\n\n\n<p>[00:22:58] <strong>Bud Kraus:</strong> It got to be a hit, right.</p>\n\n\n\n<p>[00:22:59] <strong>Nathan Wrigley:</strong> What would be the presentation that you would do?</p>\n\n\n\n<p>[00:23:01] <strong>Bud Kraus:</strong> Ah. The one that I&#8217;m threatening to do instead of this one, because I keep saying, I don&#8217;t wanna do this one, let me do another one. There&#8217;s two.</p>\n\n\n\n<p>One is, burnt out on web design, what your future career could be, which is my story.</p>\n\n\n\n<p>And the other one is, show me the money, how to get sponsors to financially help with your podcast, event, whatever. I like that topic, show me the money.</p>\n\n\n\n<p>[00:23:24] <strong>Nathan Wrigley:</strong> Paraphrasing, just a minute, what are the nuggets? Because I&#8217;m curious about that one.</p>\n\n\n\n<p>[00:23:27] <strong>Bud Kraus:</strong> Oh, come on. You could teach me, okay?</p>\n\n\n\n<p>[00:23:30] <strong>Nathan Wrigley:</strong> What are the nuggets in there though?</p>\n\n\n\n<p>[00:23:32] <strong>Bud Kraus:</strong> Well, in my case with my podcast, I&#8217;ve been sort of lucky in that they came to me and said, we&#8217;d like to sponsor you. Which is a shock because when I started the podcast a year and a half ago, or actually the idea was, it&#8217;s now two years old, I said, I didn&#8217;t care if anybody ever listened, I didn&#8217;t care if anybody ever sponsored. And then of course, over time, I did care.</p>\n\n\n\n<p>But I never thought of my show ever being sponsored. I said, I&#8217;ll just do it. And then I started realising, hey, this takes a lot of time, should get paid for this. And, you know, I feel just, if I have a second or two say how fortunate I am to be a part of all of this because at my advanced age, to be in this community with such smart, brilliant, whatever, people that are friendly. When I talk to people my age who are generally retired or retiring and, their world gets smaller and mine gets bigger.</p>\n\n\n\n<p>[00:24:24] <strong>Nathan Wrigley:</strong> Oh, that&#8217;s interesting.</p>\n\n\n\n<p>[00:24:25] <strong>Bud Kraus:</strong> So I&#8217;m really, really lucky about that.</p>\n\n\n\n<p>[00:24:28] <strong>Nathan Wrigley:</strong> Yeah. I don&#8217;t know what your age is, but I am of a certain age, and I&#8217;m kind of feeling at the moment that there&#8217;s this whole thing which everybody wants to talk about, which is AI. And I&#8217;m kind of feeling as if that train has already, you know, that ship has sailed for me. Can&#8217;t invest all of the time and what have you to learn all of the different bits and pieces. It&#8217;s like there&#8217;s another bus coming. I don&#8217;t know what you think about that.</p>\n\n\n\n<p>[00:24:47] <strong>Bud Kraus:</strong> Well, I&#8217;ll tell you what it is, for me, it&#8217;s been a career extender, because I am now writing at a level for Kinsta, technical articles that I could not otherwise write. And because of my use of, and if you will, mastery of AI, I&#8217;ve been able to code things that I could not do before. So I&#8217;ve always had sort of, for the longest time, because I taught great foundation of HTML, CSS, some JavaScript, whatever. So I know this stuff, okay.</p>\n\n\n\n<p>But to elevate that knowledge, to create stuff now that is much more complicated, sort of like junior development oriented stuff or maybe a little bit beyond that. That is amazing. And it&#8217;s because of AI.</p>\n\n\n\n<p>[00:25:28] <strong>Nathan Wrigley:</strong> That&#8217;s fascinating.</p>\n\n\n\n<p>[00:25:30] <strong>Bud Kraus:</strong> It&#8217;s extending what I can do.</p>\n\n\n\n<p>[00:25:32] <strong>Nathan Wrigley:</strong> Yeah, you feel like you&#8217;ve got a new lease of life there.</p>\n\n\n\n<p>[00:25:34] <strong>Bud Kraus:</strong> Yeah, a bit. So I don&#8217;t have to keep writing the same things over and over about how to create a post. You know, I&#8217;ve done that. I want to be challenged to learn new things, and AI is helping me do that. And we&#8217;re teaching AI, and AI is teaching us. So it&#8217;s really cool.</p>\n\n\n\n<p>[00:25:49] <strong>Nathan Wrigley:</strong> Your presentation, is it today or tomorrow?</p>\n\n\n\n<p>[00:25:51] <strong>Bud Kraus:</strong> Well, it&#8217;s tomorrow.</p>\n\n\n\n<p>[00:25:53] <strong>Nathan Wrigley:</strong> I was going to say, you&#8217;re looking very calm for somebody that has a presentation later today.</p>\n\n\n\n<p>[00:25:56] <strong>Bud Kraus:</strong> Well, you know, I&#8217;ve been around the block. I&#8217;m not going to be nervous. Now what I do have to do is I&#8217;ve got to do some more memorisation. And that&#8217;s what I talked about always being prepared. I just can&#8217;t go in there and read the slides. It&#8217;s not going to happen. So I have to really know what the slides are, what the order is, and what the words are on the screen. I don&#8217;t have to read those words, but I have to know the ideas behind all this.</p>\n\n\n\n<p>[00:26:16] <strong>Nathan Wrigley:</strong> So in some sense, you&#8217;ve memorised it more or less. Oh, that&#8217;s interesting. So you&#8217;ve really applied thought to every, more or less, every sentence that comes out of your mouth.</p>\n\n\n\n<p>[00:26:24] <strong>Bud Kraus:</strong> Basically.</p>\n\n\n\n<p>[00:26:25] <strong>Nathan Wrigley:</strong> But you don&#8217;t get nervous.</p>\n\n\n\n<p>[00:26:26] <strong>Bud Kraus:</strong> We&#8217;re with friends.</p>\n\n\n\n<p>[00:26:28] <strong>Nathan Wrigley:</strong> I would get so nervous.</p>\n\n\n\n<p>[00:26:29] <strong>Bud Kraus:</strong> At least I like to think so.</p>\n\n\n\n<p>[00:26:30] <strong>Nathan Wrigley:</strong> Yeah. No, I agree. Every time I&#8217;ve been to a presentation, even when the person delivering it has been quite nervous, there&#8217;s always been a very positive sentiment in the room.</p>\n\n\n\n<p>[00:26:39] <strong>Bud Kraus:</strong> I&#8217;ll tell you why I don&#8217;t get nervous, I don&#8217;t see their faces.</p>\n\n\n\n<p>[00:26:41] <strong>Nathan Wrigley:</strong> Oh.</p>\n\n\n\n<p>[00:26:42] <strong>Bud Kraus:</strong> So if you don&#8217;t see their faces. There&#8217;s so many advantages of vision impairment. I know it sounds crazy, but if you don&#8217;t see their faces, then you don&#8217;t see their reactions. Now, of course, that&#8217;s a negative too. But then you don&#8217;t get nervous.</p>\n\n\n\n<p>[00:26:55] <strong>Nathan Wrigley:</strong> Absolutely fascinating. Well, I wish you the best of luck with it. It will be out on wordpress.tv at some point. Typically now they come out really soon. These flagship events, they turn them around really quickly.</p>\n\n\n\n<p>[00:27:06] <strong>Bud Kraus:</strong> Well, I don&#8217;t know when this is coming out, but this is going to be live streamed around the world.</p>\n\n\n\n<p>[00:27:09] <strong>Nathan Wrigley:</strong> Is it?</p>\n\n\n\n<p>[00:27:10] <strong>Bud Kraus:</strong> Yeah. So one person can watch.</p>\n\n\n\n<p>[00:27:11] <strong>Nathan Wrigley:</strong> The point being, dear listener, that if you&#8217;ve enjoyed this episode and you want to follow on the talk, the presentation that Bud has given at WordCamp US, by the way, maybe the quickest way to do that is to just Google, either WordCamp US 2025. Or Google, using low vision as my tool to help me teach WordPress. That&#8217;s the other short circuit if you like. You&#8217;ll be able to see exactly what it is that Bud delivered.</p>\n\n\n\n<p>I have no further questions, so unless you&#8217;ve got something to add, I will say thank you very much for chatting to me.</p>\n\n\n\n<p>[00:27:40] <strong>Bud Kraus:</strong> Well, thank you Nathan. And you know I&#8217;m a big fan of what you do and thanks for having me on.</p>\n\n\n\n<p>[00:27:43] <strong>Nathan Wrigley:</strong> Thank you so much.</p>\n</div></details>\n\n\n\n<p>On the podcast today we have <a href=\"https://seriouslybud.com/\">Bud Kraus</a>.</p>\n\n\n\n<p>Bud was diagnosed with macular degeneration, a condition often associated with old age, when he was 37. Affecting both eyes, this gradually eroded his central vision, making it difficult for him to see straight ahead, recognize faces, drive or read. Despite these challenges, Bud’s peripheral vision remained intact, sparing him the need for a cane or guide dog, and allowing him to continue to navigate daily life. Through perseverance and adaptation, Bud continues to live fully, facing the hurdles of vision loss with resilience and optimism.</p>\n\n\n\n<p>Bud opens up the podcast by talking about his experience living with legal blindness, how his central vision loss has shaped everything from everyday activities to his professional routines. He explains the practical ways he adapts his devices and workflow, including tweaks to operating system settings, using screen zoom functions, and relying on pattern recognition to teach coding, write tutorials, and even host his Seriously, Bud podcast. His unique perspective sheds light on the often-overlooked nuances of accessibility, reminding us that every user interacts with technology differently.</p>\n\n\n\n<p>Bud also chats about the broader impact of accessibility in the WordPress space, from frustrations with hard-to-navigate interfaces to the importance of not excluding users who may become your audience or customers. His reflections reveal how living with low vision pushed him beyond mere acceptance, helping him discover new opportunities, hone his teaching skills, and even find humour in daily challenges.</p>\n\n\n\n<p>Bud’s story serves as a powerful reminder of the importance of designing with empathy, embracing adaptation, and viewing accessibility not just as a technical requirement, but as a source of creativity and connection. It’s full of real-world tips, personal anecdotes, and a dose of inspiration.</p>\n\n\n\n<p>Whether you’re a designer, developer, educator, or simply passionate about building a more inclusive web, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p><a href=\"https://us.wordcamp.org/2025/session/using-low-vision-as-my-tool-to-help-me-teach-wordpress/\">Using Low Vision As My Tool To Help Me Teach WordPress</a>, Bud&#8217;s presentation at WordCamp US 2025</p>\n\n\n\n<p><a href=\"https://www.freedomscientific.com/products/software/jaws/\">JAWS, Job Access With Speech software</a></p>\n\n\n\n<p><a href=\"https://www.pratt.edu/\">Pratt Institute</a></p>\n\n\n\n<p><a href=\"https://www.descript.com/\">Descript</a></p>\n\n\n\n<p><a href=\"https://www.smashingmagazine.com/2018/05/using-low-vision-teach-wordpress/\">Using Low Vision As My Tool To Help Me Teach WordPress</a>, Bud&#8217;s post on Smashing Magazine</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 08 Oct 2025 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:32;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"Open Channels FM: From Home Kitchen to International Orders\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110428\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"https://openchannels.fm/from-home-kitchen-to-international-orders/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:163:\"Using WooCommerce and open source to take kitchen baking into an online cake business, embracing cake in a jar and building a vibrant brand with community support.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 08 Oct 2025 12:41:35 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:33;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"Matt: Tim &amp;amp; Pablos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150138\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2025/10/tim-pablos/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:652:\"<p>Two of my favorite humans, <a href=\"https://tim.blog/\">Tim Ferriss</a> and <a href=\"https://pablosspeaks.com/\">Pablos Holman</a>, had a great interview together.</p>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p>Pablos has a <a href=\"https://www.amazon.com/dp/B0F23CLXZP\">great new book out</a>, and <a href=\"https://audrey.co/\">Audrey Capital</a> is a happy LP in his <a href=\"https://deepfuture.tech/\">Deep Future fund</a>. Of my many hacker friends, Pablos is probably the most public.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Oct 2025 13:36:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:34;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:94:\"Open Channels FM: How Decentralized Social Platforms Grew from Identica to Modern-Day Mastodon\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110897\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:101:\"https://openchannels.fm/how-decentralized-social-platforms-grew-from-identica-to-modern-day-mastodon/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:188:\"Matthias Pfefferle discusses the Fediverse\'s origins and evolution with Evan Prodromou, highlighting decentralized social networks, protocols, privacy, and the future of federated systems.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Oct 2025 11:12:52 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:35;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: Beeper Updates\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150133\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:37:\"https://ma.tt/2025/10/beeper-updates/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:277:\"<p><a href=\"https://blog.beeper.com/2025/10/06/beeper-september/\">Beeper has a fun set of September updates</a>, adding support for Google Voice, LinkedIn now runs on-device, typing indicators for Google Messages and Instagram, full Telegram custom emoji support, and more.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 06 Oct 2025 18:22:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:36;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"Open Channels FM: Why Linking and Permalinks Are the Backbone of the Open Web\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110377\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:84:\"https://openchannels.fm/why-linking-and-permalinks-are-the-backbone-of-the-open-web/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:168:\"Dave Winer talks about the open web\'s basics, emphasizing that linking is crucial for real connection. Platforms limiting links miss out on that vibrant web experience.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 06 Oct 2025 12:49:41 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:37;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:37:\"Tammie Lister: September in WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://binatethoughts.com/?p=2455\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:50:\"https://binatethoughts.com/september-in-wordpress/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5187:\"<p>Another month has turned just like the leaves as autumn settles in. I was lucky enough to get time to focus thanks to sponsors, here is what I did within WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">August reflections</h2>\n\n\n\n<p>It’s worth noting I am aware that August didn’t have a month post, this was due to travelling back from being at WordCamp US. This post is a merged month in many sense as the theme has maintained the same as September saw solidifying of what I was doing.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A new team</h2>\n\n\n\n<p>The Core Program team was <a href=\"https://make.wordpress.org/project/2025/09/15/announcing-the-core-program-team/\">announced</a> and I will be the first team rep. This was a huge part of this month as required setting up and focus. I am beyond excited what this means. </p>\n\n\n\n<p>I am thrilled to say <a href=\"https://www.bigscoots.com/\">BigScoots</a> is sponsoring me to cover some time focusing on the Core Program team and thankful for the opportunity to go to sponsors and highlight where I am needed most.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Focusing on AI and editor</h2>\n\n\n\n<p>Relating to the last section a little, <a href=\"https://greyd.io/\">Greyd</a> are now going to be sponsoring me to focus both on Core AI and also on Core Editor. This combination allows me to focus even more my contributions where they can be effective. </p>\n\n\n\n<p>This split focus will add to <a href=\"https://servmask.com/\">ServMask’s</a> sponsorship of me within Core AI already to give me extra time within that area.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Areas of contribution</h2>\n\n\n\n<p>My split this month was given a new focus thanks to being a team rep for a new <a href=\"https://make.wordpress.org/program/2025/09/12/welcome-to-the-core-program-team/\">team announced</a>, Core Program. Beyond that, top areas were:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>&#8216;Needs design&#8217;</strong>: adding design to Core AI experiments.</li>\n\n\n\n<li><strong>Triage:</strong> focused on 6.9 design issues, unblocking and also giving feedback.</li>\n\n\n\n<li><strong>Program team work</strong>: establishing team and getting goals brewing. Weekly posts <a href=\"https://make.wordpress.org/program/tag/this-week/\">here</a>.</li>\n\n\n\n<li><strong>Core AI:</strong> focusing on roadmaps.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Sharing the journey</h2>\n\n\n\n<p>I got to share a few things this month, I also got to attend LoopConf and speak about AI at the local WP London meetup the night before:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://binatethoughts.com/the-sparkle-paradox-how-ai-signalling-undermines-adoption/\">The sparkle paradox</a>: specifically fuelled the designs I worked on for Experiments.</li>\n\n\n\n<li>Spoke at WPLDN about &#8216;<a href=\"https://www.wpldn.uk/talk/when-the-interface-doesnt-matter-anymore/\">When the Interface doesn’t matter anymore</a>&#8216;.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\"><br />Upcoming plans for contribution</h2>\n\n\n\n<p>October is already shaping up to be busy with Core Program and the 6.9 release.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Triage: </strong>focus on 6.9, but I don’t want to ignore the <a href=\"https://core.trac.wordpress.org/tickets/ancient\">ancient and inactive</a> trac log. This month triage won’t be my main focus but more about unblocking</li>\n\n\n\n<li><strong>Core AI:</strong> feedback and iterations for experiments and program work on abilities. I would also love to work on the <a href=\"https://github.com/WordPress/ai/discussions/23\">documentation</a> and handbook if time.\n<ul class=\"wp-block-list\">\n<li>I had some awesome fun working on the issues for experiments. <a href=\"https://github.com/WordPress/ai/issues/13#issuecomment-3352028955\">#</a> <a href=\"https://github.com/WordPress/ai/issues/12#issuecomment-3353681251\">#</a> <a href=\"https://github.com/WordPress/ai/issues/11#issuecomment-3352146880\">#</a> <a href=\"https://github.com/WordPress/ai/issues/10#issuecomment-3352689787\">#</a></li>\n</ul>\n</li>\n\n\n\n<li><strong>Core Program: </strong>shape goals collaboratively, goals will be posted weekly on #core-program in Slack.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Sponsors this month</h2>\n\n\n\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained\">\n<p>I now have these sponsors and from this month I am highlighting the areas they are helping me focus on if sponsoring a particular focus. </p>\n\n\n\n<p><a href=\"https://www.bigscoots.com\">BigScoots</a> (Core Program), <a href=\"https://greyd.io\">Greyd</a> (Core AI / Core Editor), <a href=\"https://kinsta.com\">Kinsta</a> (Triage), <a href=\"https://servmask.com\">ServMask</a> (Core AI), <a href=\"https://github.com/aaronjorbin\">Aaron Jorbin</a>, <a href=\"https://github.com/timnashcouk\">Tim Nash</a>, <a href=\"https://github.com/jeffpaul\">Jeffrey Paul</a> and <a href=\"https://github.com/scotrumery\">Scot Rumery</a> (<a href=\"https://rumspeed.com/about/\">Rumspeed</a>). To everyone who sponsored me and helped me secure sponsorship, thank you.</p>\n\n\n\n<p>Want to sponsor me? You can through <a href=\"https://github.com/sponsors/karmatosed\">GitHub</a>.</p>\n</div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 06 Oct 2025 09:06:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"binatethoughts.com\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:38;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"Matt: Telegram and Weird Al\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150113\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:44:\"https://ma.tt/2025/10/telegram-and-weird-al/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2529:\"<p>I have two interesting interviews to share with you today, the first is <a href=\"https://www.youtube.com/watch?v=qjPH9njnaVU\">Lex Fridman interviewing Pavel Durov</a>, the founder of <a href=\"https://telegram.org/\">Telegram</a>. I started using and advocating for Telegram back in 2015, and <a href=\"https://audrey.co/\">Audrey Capital</a> was part of their aborted fundraise in 2018. As a software craftsperson, I&#8217;ve always had tremendous respect for the team and the rate at which they shipped truly novel design and UI. I&#8217;m amazed by the speed at which they ship major features across multiple platforms. The network also has incredibly resiliency, which they get into on the podcast. As I&#8217;m often in poor connectivity situations in planes or remote locations, Telegram has been one of the networks that works most reliably.</p>\n\n\n\n<p>I&#8217;ve met Pavel only briefly about a decade ago, but have followed his story as he&#8217;s a unique character with an ascetic lifestyle, target of many intelligence agencies, sperm donor father of 100+ children, and many other unique characteristics. I use Telegram like I use X/Twitter, I put things I consider semi-public on it and I think of it like a social network and development platform, and <a href=\"https://ma.tt/2022/08/telegram-channel/\">since 2022 I&#8217;ve cross-posted my blog to a Telegram channel using a Jetpack bot</a>. It&#8217;s probably my favorite community platform. The four hour interview between Lex and Pavel covers a lot of ground, but product builders will probably appreciate most the middle part around the 2-hour mark where they go into their engineering and design philosophies. (BTW I usually watch/listen to these at 2x speed.)</p>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p>If you&#8217;re looking for something a little lighter on a Sunday I recommend this <a href=\"https://www.youtube.com/watch?v=sSu2eMkIyZs\">heart-warming conversation between John Mayer and Weird Al Yankovic</a>.</p>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p>I know this seems like an unusual pairing, but both Pavel and Weird Al are hackers in the sense that they examined the rules of the system and decided to create a new game.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 05 Oct 2025 21:08:02 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:39;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"Tammie Lister: Why Gentle Leadership Builds Better Products\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://binatethoughts.com/?p=2447\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://binatethoughts.com/why-gentle-leadership-builds-better-products/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:11249:\"<p>We&#8217;ve all seen it. A product launches, a feature ships, a choice gets made. And within hours, the not-so-hot, more grumpy takes arrive. Threads dissecting every misstep. Social media posts stating how they&#8217;d have done x or y better. Statements across the web cataloguing failures. Commentary that positions the critic as the one who would have done it better. This happens even more on Open Source projects, we&#8217;ve all seen it across WordPress.</p>\n\n\n\n<p>This is an increasingly prevalent issue in product circles. Yet, we seldom highlight the human impact of this culture and the more effective alternatives that can truly foster better products and stronger teams. Even more so in open source. It&#8217;s also worth noting that those who can drive change, those called and looked to as product leaders, are often the ones who contribute most to the problem. By inspiring others and adopting more positive practices, we can foster a more collaborative and thriving environment for everyone involved.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Changing Position of the Role of Product</h2>\n\n\n\n<p>My experience in product is a journey many of us share as we grew alongside the practice. We often had to fight for our place at the table, sometimes moving gently and other times more forcefully to ensure our voices were heard.</p>\n\n\n\n<p>Times have changed, and now the product is at the centre of much of our work. It no longer needs to prove its worth or challenge existing components; instead, it should avoid adopting harmful practices seen in longer traditions, such as design, which have led to dangerous and destructive patterns of critique. It&#8217;s possible to disagree without resorting to tearing others down or stripping away their contributions. In fact, taking a more constructive approach is a sign of greater skill, as many of us have come to learn.</p>\n\n\n\n<p>Throughout my career, I have learned a great deal through trial and error, thanks to the incredible mentors who guided me and the space they provided for me to understand. Their compassion and calmness shaped my understanding of leadership; it&#8217;s not just about being in the spotlight, which was a breath of fresh air for someone like me who thrives behind the scenes.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Psychology of What We&#8217;re Really Doing</h2>\n\n\n\n<p>When we share our thoughts on products and the teams behind them, we&#8217;re doing more than just providing feedback; we&#8217;re meant to encourage accountability and nurture growth. The impact of our words can ripple far beyond the initial conversation, creating a meaningful dialogue.</p>\n\n\n\n<p>Studies in self-determination theory reveal that environments filled with criticism, rather than constructive support, can lead to loss of motivation. This is especially true over time. In open-source and collaborative spaces, the consequences are even more significant. Unhelpful criticism can generate conflicts and discourage participation, particularly for those from underrepresented backgrounds. Our language truly matters, and it becomes even more powerful when coming from influential voices.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>&#8220;Leadership is about making others better as a result of your presence and making sure that impact lasts in your absence.&#8221;</p>\n\n\n\n<p><a href=\"https://www.goodreads.com/quotes/785876-leadership-is-about-making-others-better-as-a-result-of\" rel=\"noreferrer noopener\" target=\"_blank\">Sheryl Sandber</a>g</p>\n</blockquote>\n\n\n\n<p>The evidence suggests that public criticism, especially when not accompanied by constructive input, doesn&#8217;t enhance products. Instead, it risks stifling the very voices we should be championing to drive improvement and innovation. Let&#8217;s strive to uplift one another and create positive pathways for making. I know I want to create in a space like that, and I&#8217;m reasonably sure those who often critique the loudest do.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What Leadership Actually Looks Like</h2>\n\n\n\n<p>This isn&#8217;t about being soft or avoiding critical conversations, far from it. But if harsh criticism is all you&#8217;re known for, people eventually stop listening. By taking this approach, you are showing an understanding that great products emerge from empowered teams, not demoralised ones.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>&#8220;To me, leadership is about encouraging people. It&#8217;s about stimulating them. It&#8217;s about enabling them to achieve what they can achieve — and to do that with a purpose.&#8221;</p>\n\n\n\n<p><a href=\"https://www.washingtonpost.com/business/on-leadership/lagarde-on-leadership-its-about-encouraging-people/2014/07/11/4696f284-06b5-11e4-a0dd-f2b22a257353_story.html\" rel=\"noreferrer noopener\" target=\"_blank\">Christine Lagarde</a></p>\n</blockquote>\n\n\n\n<p>The difference between critique and leadership is simple. Leaders focus on building capability, not broadcasting judgment. They build up whilst also setting on a path for that building. It&#8217;s certainly a harder thing to do, but in the long term, far more rewarding for both the leader and those involved. Being the critic, even if you have been elevated to a lead, eventually casts you as the villain of the piece, and that&#8217;s not good for anyone&#8217;s heart. Most leads got there through being incredible makers in the first place; somewhere along the way, they shifted from making to criticising, from building to broadcasting judgment.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The Alternative: Being Part of the Solution</h2>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>&#8220;I raise my own voice—not so that I can shout, but so that those without a voice can be heard.&#8221;</p>\n\n\n\n<p><a href=\"https://www.goodreads.com/quotes/6628892-i-raise-up-my-voice-not-so-that-i-can\" rel=\"noreferrer noopener\" target=\"_blank\">Malala Yousafzai</a></p>\n</blockquote>\n\n\n\n<p>If you see a product or team struggling, you have choices beyond posting about it.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Mentor someone on the team.</strong> Reach out privately. Offer your experience. It is often more impactful to say it privately. Share what you&#8217;ve learned from similar challenges. </li>\n\n\n\n<li><strong>Contribute directly.</strong> If it&#8217;s open source, submit a thoughtful pull request. If it&#8217;s not, offer specific, actionable feedback through proper channels. Build the bridge instead of pointing out it&#8217;s incomplete.</li>\n\n\n\n<li><strong>Support publicly, guide privately.</strong> Public spaces should be for celebrating attempts, acknowledging effort, and showing solidarity. Save detailed feedback for contexts where it can actually be heard and acted upon.</li>\n\n\n\n<li><strong>Balance your critiques with equal praise. </strong>When was the last time you praised a feature? Do that as much as you also critique and balance.</li>\n\n\n\n<li><strong>Build knowledge, not status.</strong> Research shows that when team members feel their psychological needs met, such as autonomy, competence, and relatedness, they&#8217;re far more likely to develop intrinsic motivation and engage meaningfully with their work. Your role as a leader isn&#8217;t to prove you could have done better. It&#8217;s to help others actually do better. </li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">The Myth of &#8220;Necessary Toughness&#8221;</h2>\n\n\n\n<p>There&#8217;s a belief in some communities that toxicity is &#8220;a naturally occurring if not necessary facet of culture.&#8221; This is demonstrably false. Toxic behaviour causes contributors to leave projects and creates barriers to participation, particularly for newcomers and those from underrepresented communities. It causes burnout not just in those receiving but also in those giving. It eats at you.</p>\n\n\n\n<p>Gentle leadership isn&#8217;t weak leadership. It&#8217;s strategic leadership. It&#8217;s essential to understand that the long-term health of products and communities depends on creating environments where people want to contribute their best work, not environments where they&#8217;re afraid to take risks and fail.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Evaluating Your Leadership</h2>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>&#8220;You can evaluate the quality of your authority by looking deeply to see if compassion is the foundation of your leadership.&#8221;</p>\n\n\n\n<p><a href=\"https://laidlawscholars.network/posts/see-if-compassion-is-the-foundation-of-your-leadership\" rel=\"noreferrer noopener\" target=\"_blank\">Zen Buddhist monk Thích Nhất Hạnh</a> </p>\n</blockquote>\n\n\n\n<p>This isn&#8217;t just an abstract philosophy. You can apply a practical lens for examining how we show up as leaders. The next time you&#8217;re tempted to post about what&#8217;s wrong with someone else&#8217;s or your own product, ask yourself:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Will this help the team, the product improve, or position me as knowledgeable?</li>\n\n\n\n<li>Who does this harm and who does this serve?</li>\n\n\n\n<li>Could I offer this insight in a way that builds rather than breaks?</li>\n\n\n\n<li>Am I solving a problem or performing expertise?</li>\n</ul>\n\n\n\n<p>The products that endure, the teams that innovate, they don&#8217;t come from cultures of constant public criticism. They come from environments where people feel safe to experiment, supported when they stumble, and mentored toward excellence.</p>\n\n\n\n<p>Your influence as a product leader isn&#8217;t measured by how effectively you can identify flaws; it&#8217;s also about how effectively you can address them. It&#8217;s measured by how many people do better work because you were there.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Building Better, Together</h2>\n\n\n\n<p>Every product you see represents countless hours of human effort, difficult trade-offs, and people doing their best with the information and resources available to them. Before you critique, consider how you might contribute. Before pointing out failures, consider how you can prevent them in the future by teaching, mentoring, and supporting.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>&#8220;At the end of the day, at the end of the week, at the end of my life, I want to say I contributed more than I criticised.&#8221;</p>\n\n\n\n<p><a href=\"https://www.goodreads.com/work/quotes/62183586-dare-to-lead-brave-work-tough-conversations-whole-hearts\" rel=\"noreferrer noopener\" target=\"_blank\">Brené Brown</a></p>\n</blockquote>\n\n\n\n<p>The industry doesn&#8217;t need more critics. It needs more builders. It requires leaders who understand that gentle doesn&#8217;t mean permissive, and that the strongest teams are built on foundations of trust, growth, and mutual support.</p>\n\n\n\n<p>If I can leave one thought at the end of this, it would be to consider: &#8220;What impact will your leadership have?&#8221; Great products are built by great teams. Great teams are built by leaders who lift others. Choose to be that leader.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 05 Oct 2025 11:03:52 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"binatethoughts.com\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:40;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Matt: Greenwashing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150105\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2025/10/greenwashing/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3909:\"<p>Tonight there was a lovely event at <a href=\"https://tinkertendo.com/\">TinkerTendo</a> by Raman Frey and Karin Johnson of <a href=\"https://www.gpdinners.com/\">Good People Dinners</a>, this one honoring <a href=\"https://davidgelles.com/\">David Gelles&#8217;</a> new book, <a href=\"https://www.amazon.com/Dirtbag-Billionaire-Chouinard-Patagonia-Fortune/dp/1668032260?tag=photomatt08-20\">Dirtbag Billionaire: How Yvon Chouinard Built Patagonia, Made a Fortune, and Gave It All Away</a>. I&#8217;m a huge fan of Yvon Chouinard and really enjoyed his book <a href=\"https://www.amazon.com/Let-People-Surfing-Education-Businessman/dp/1594200726/?tag=photomatt08-20\">Let My People Go Surfing</a> which I read back in 2018. It was the first time hosting such a large 60-person dinner in the TinkerTendo warehouse, and thanks to <a href=\"https://copperhome.com/\">this Copper battery-operated induction stovetop</a> and an amazing local chef, <a href=\"https://www.komaaj.com/\">Hanif Sadr</a>, the food turned out amazing.</p>\n\n\n\n<p>I&#8217;ve only started the new book, but I&#8217;m interested to see what&#8217;s happened in the 20 years between Yvon&#8217;s book and David&#8217;s, especially the story of <a href=\"https://www.nytimes.com/2022/09/14/climate/patagonia-climate-philanthropy-chouinard.html\">how Yvon gave away all his equity and control in the company</a> to ensure a focus on his lifelong goal of environmentalism and conservation. Patagonia is one of the better corporate entities fighting for good, but it reminded me of how companies can put on a jacket of doing good while actually being evil underneath.</p>\n\n\n\n<p>Like I talked about the <a href=\"https://ma.tt/2025/09/externalities/\">economic concept of Externalties a few weeks ago</a>, I think it&#8217;s imperative that the WordPress community understands the history of <a href=\"https://en.wikipedia.org/wiki/Greenwashing\">Greenwashing</a>, which the <a href=\"https://www.un.org/en/climatechange/science/climate-issues/greenwashing\">United Nations defines as follows</a>:</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>Claiming that the company will achieve future environment milestones while not putting sufficient plans in place to do so.</li>\n\n\n\n<li>Being intentionally vague about operations or using vague claims that cannot be specifically proven (like saying they are &#8220;environmentally friendly&#8221; or &#8220;green&#8221;).</li>\n\n\n\n<li>Saying that a product does not contain harmful materials or use harmful practices that they would not use anyway.</li>\n\n\n\n<li>Highlighting one thing the company does well regarding the environment while not doing anything else.</li>\n\n\n\n<li>Promoting products that meet regulatory minimums as if peer products do not.</li>\n</ol>\n\n\n\n<p>In <a href=\"https://wordpress.org/\">WordPress</a> and open source our environmental crisis comes from companies that frack the open source software and brands, which shows up as lack of investment in the code which falls fallow <a href=\"https://tech.eu/2025/07/25/chronic-underfunding-of-open-source-software-poses-strategic-risk-to-europes-digital-sovereignty/\">especially in the security sense</a>, or by attaching themselves to a brand or trademark and tricking people into thinking they&#8217;re associated with the Good Open thing, when they&#8217;re really a parasitic cancer on it.</p>\n\n\n\n<p>This is happening right now in WordPress, so when you see a company hire a good person or sponsor an event that seems on its own a good thing, and probably represents hundreds of thousands of dollars of investment, weigh that against the tens of millions they&#8217;re spending with their other hand to destroy the source of everything they&#8217;ve benefited from, and if they were to win, endanger every open source project. It&#8217;s an open source form of greenwashing, perhaps call it <a href=\"https://en.wikipedia.org/wiki/Openwashing\">openwashing</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 05 Oct 2025 06:44:42 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:41;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:113:\"Gutenberg Times: Blocks galore, test template management, Woo product collections, and more—Weekend Edition 343\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=42093\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:119:\"https://gutenbergtimes.com/blocks-galore-test-template-management-woo-product-collections-and-more-weekend-edition-343/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:20342:\"<p>Howdy, </p>\n\n\n\n<p>And just like that, the last quarter of 2025 has begun. It&#8217;s been an interesting year again, and now we are on the home stretch, heading into a Holiday season. It&#8217;s become my favorite time of the year when Autumn make nature paint trees and bushes in so many colors. After a life near evergreen Everglades of Florida, the middle European changing colors of the fall seems magical.</p>\n\n\n\n<p>Soon it&#8217;s time to plan for 2026. Speaking of which, in case you missed it, WordCamp Asia <a href=\"https://asia.wordcamp.org/2026/call-for-speakers-is-now-open/\">Call for Speakers</a> has been out for a couple of week, and the deadline is quite early: October 31, 2025. If you were thinking about going to WordCamp Asia, what would be a talk you would be interested in seeing in April of 2026? </p>\n\n\n\n<p>Anyway, the present is pretty amazing right now, too. So without further ado, the news. </p>\n\n\n\n<p>Yours, <img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n\n<p>PS: This weekend, on October 3rd, Germany celebrates the <a href=\"https://en.wikipedia.org/wiki/German_Unity_Day\">35th anniversary of the Reunion</a> after the Iron Curtain was lifted. </p>\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<p><strong>Table of Contents</strong></p>\n\n\n\n<nav class=\"wp-block-table-of-contents\"><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/blocks-galore-test-template-management-woo-product-collections-and-more-weekend-edition-343/#0-word-press-release-information\">Developing Gutenberg and WordPress</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/blocks-galore-test-template-management-woo-product-collections-and-more-weekend-edition-343/#0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/blocks-galore-test-template-management-woo-product-collections-and-more-weekend-edition-343/#blocks-galore-with-telex\">Blocks Galore with Telex </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/blocks-galore-test-template-management-woo-product-collections-and-more-weekend-edition-343/#2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/blocks-galore-test-template-management-woo-product-collections-and-more-weekend-edition-343/#3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor.</a></li></ol></nav>\n</div></div>\n</section>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"></div>\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p>.<strong>Jonathan Bossenger</strong>, WordPress 6.9 release co-lead for testing, is asking for your <a href=\"https://make.wordpress.org/test/2025/10/03/help-test-changes-to-template-management/\"><strong>help to test changes to the template management</strong></a>. The new feature is a great enhancement to the way templates are handled in the Site Editor. More eyes are needed to make sure it&#8217;s the best it can be in the short amount of time until the first Beta version is released. The instructions are detailed, and Bossenger added a video to show how the various sections of this test should work.</p>\n\n\n<section class=\"wp-block-newsletterglue-callout undefined is-color-set\" style=\"color: #4c38c1; border-color: #eeeeee; border-radius: 26px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f3efe9;\">\n<p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review. </p>\n\n\n\n<p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience</p>\n</section>\n\n\n<div class=\"wp-block-spacer\" style=\"height: 39px;\"></div>\n\n\n\n<p>The security and maintenance release, <a href=\"https://wordpress.org/news/2025/09/wordpress-6-8-3-release/\"><strong>WordPress 6.8.3 </strong></a>is now available. John Blackbourn led the release and shares the details in his release post. Update as soon as you can, as it plugs a few security holes.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Carlos Bravo</strong> issues the <a href=\"https://github.com/WordPress/gutenberg/releases/tag/v21.8.0-rc.1\"><strong>release candidate for Gutenberg 21.8</strong></a> and it&#8217;s available for testing. The final release is scheduled for October 8. </p>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p><img alt=\"?\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/\">Gutenberg Changelog #122 – Gutenberg 21.8 and WordPress 6.9</a> with Beth Soderberg of <a href=\"https://bethink.studio/\">Bethink Studio</a></p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Gutenberg Changelog 122 with Beth Soderberg\" class=\"wp-image-42236\" height=\"193\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-11-at-12.32.48.png?resize=652%2C193&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p class=\"has-small-font-size\"><em>If you are listening via Spotify, please leave a comment. If you listen via other podcast apps, please leave a review. It&#8217;ll help with the distribution.</em></p>\n</div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p>In the WordPress VIP blog post and video, <a href=\"https://wpvip.com/case-studies/pew-research-center/\"><strong>Pew Research Center Builds Interactive Content at Scale</strong></a>, the Seth Rubenstein and his team share how they rebuilt their website using WordPress VIP to tackle challenges in a world where people seldom visit original sources. Their old method took weeks of custom coding for interactive content, which delayed publishing. By adopting a block-first strategy in 2022, they cut production time from weeks to minutes, enabling editors and designers to create quizzes and maps on their own. This shift allowed developers to focus on innovation while increasing publishing frequency and lowering costs with evergreen interactive content that engages audiences directly.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In his video <a href=\"https://www.youtube.com/watch?v=l7GRSnSd7SM\"><strong>Level up your Product Collections</strong></a>, <strong>Brian Coords</strong> demonstrates the new features in WooCommerce 10.2. He covered carousel layouts, taxonomy filters (Category/Brand/Tag), and an improved Cross-Sells collection for displaying products.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Joanne Courtright</strong> of Groundworx released a new <a href=\"https://wordpress.org/plugins/groundworx-testimonial/\"><strong>Testimonials plugin</strong></a> in the WordPress repository. Get the skinny from her blog post:   <a href=\"https://groundworx.dev/blog/introducing-groundworx-testimonial-modern-testimonials-for-wordpress-block-themes/\">Introducing Groundworx Testimonial: Modern Testimonials for WordPress Block Themes</a>. &#8220;Most testimonial plugins are still stuck in the classic era. This one is designed for developers and site builders who want testimonials that “just work” with Gutenberg, she wrote. It aims to be Gutenberg-native, theme.json aware, and accessibility-first. It includes a dedicated Testimonial post type + flexible blocks.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Justin Tadlock</strong> released the first version of an <strong><a href=\"https://wordpress.org/plugins/x3p0-authors/\">Authors List Block</a></strong> for multi-author sites. &#8220;This is especially useful if you’re coming over from using a classic WordPress theme and need a block that’s similar to the old <code>wp_list_authors()</code> template tag,&#8221; he wrote. The plugin comes with a full array of block design tools. It also sports options to display number of posts, various order filters, and feed links. </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42113\" height=\"354\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-02-at-16.34.38-2.png?resize=652%2C354&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p><strong>Mike McAlister</strong> released his <a href=\"https://wordpress.org/plugins/ollie-menu-designer/\"><strong>Ollie Menu Designer</strong></a> for free in the WordPress repository. It is a powerful way to build  mobile and dropdown menus in the WordPress block editor—no coding required. For more details, watch <a href=\"https://www.youtube.com/watch?v=w96lghXWhiI\">his announcement video on YouTube. </a></p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"blocks-galore-with-telex\">Blocks Galore with Telex </h2>\n\n\n\n<p>In his post, <a href=\"https://www.pootlepress.com/2025/10/if-automattics-telex-builds-this-you-might-not-need-that-page-builder/\"><strong>If Automattic’s Telex Builds This, You Might Not Need That Page Builder</strong></a>, <strong>Jamie Marsland</strong> explores how Automattic&#8217;s Telex AI tool could transform WordPress by enabling users to extend existing core blocks rather than just creating new ones. Currently, Telex generates custom blocks like video effects and timelines, but extending core blocks like paragraphs, tables, or buttons requires complex developer skills. If Telex could extend core blocks and offer a public directory for sharing these extensions, it could replace traditional page builders by unlocking the full potential of WordPress&#8217;s native blocks without adding technical debt or duplication.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Tammie Lister </strong>started her personal <a href=\"https://blocktober.fun/\"><strong>Blocktober</strong></a>, posting a block a day on the newly created site. Every day at noon, she uses Automattic&#8217;s Telex and builds a new block. Spanning the arc of history back to the 1980s, Lister started with an <a href=\"https://blocktober.fun/ascii-tetris/\">ASCII Tetris</a> block. Here goes my Thursday morning&#8230;. </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42099\" height=\"377\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-02-at-11.22.33.png?resize=652%2C377&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p>In his latest blog post, <strong>Marko Ivanovic</strong> made a set of <strong><a href=\"https://ivanovicmarko.com/2025/09/25/telex-for-designers/\">blocks for designers</a></strong> with the help of Automattic&#8217;s Telex. Earlier he also created <a href=\"https://ivanovicmarko.com/2025/09/20/interactive-icons/\">animated icon blocks</a>. Ivanovic is a designer working for Automattic, and since 2022. His post on <a href=\"https://ivanovicmarko.com/2025/10/01/wordpress-and-design/\"><strong>how he rediscovered WordPress</strong></a> and why any designer should embrace WordPress is worth a read, too. And I love those sticky notes.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://ivanovicmarko.com/2025/09/25/telex-for-designers/\"><img alt=\"\" class=\"wp-image-42101\" height=\"331\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/Screenshot-2025-10-02-at-11.30.51.png?resize=652%2C331&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p>In preparation for the WordPress 6.9 release on December 2,  <strong>Justin Tadlock </strong>published a new tutorial on the WordPress Developer Blog: You  on how to implement <a href=\"https://developer.wordpress.org/news/2025/09/border-radius-size-presets-in-wordpress-6-9/\"><strong>Border radius size presets in WordPress 6.9</strong></a>. &#8220;You define an array of sizes that users can apply to blocks that support border radius. You can also reuse them within your own theme stylesheets and <code>theme.json</code> file.&#8221;, he wrote.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"border radius presets coming to WordPress 6.9 \" class=\"wp-image-42118\" height=\"337\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/border-radius-on-gradient.webp?resize=652%2C337&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p>At WordCamp Gdynia I shared how to <strong><a href=\"https://wordpress.tv/2025/09/30/streamlined-block-theme-development-using-wordpress-playground-and-github-for-no-code-version-contr/\">use WordPress Playground and GitHub for No-Code Version Control of Site Editor Changes</a></strong> The recording of my talk is now on WordPress TV. You will learn how theme developers can leverage WordPress Playground alongside the Create Block Theme plugin to create a seamless, browser-based development environment that integrates directly with GitHub for version control—all without writing a single line of code. <a href=\"https://docs.google.com/presentation/d/1ffMAVMjFxm1Ai7p2JWWwZAK5vQN5ryCbh-VXOqDjRiQ/edit?usp=drive_web&amp;ouid=101776844630674138344\">The slides are available on Google Drive. </a></p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://wordpress.tv/2025/09/30/streamlined-block-theme-development-using-wordpress-playground-and-github-for-no-code-version-contr/\"><img alt=\"\" class=\"wp-image-42115\" height=\"408\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/10/WCGdynia_-Block-Theme-Development-Playground-CBT-GitHub.jpg?resize=652%2C408&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<div class=\"wp-block-spacer\" style=\"height: 19px;\"></div>\n\n\n<section class=\"wp-block-newsletterglue-callout undefined not-color-set\" style=\"border-color: #f9f9e5; border-radius: 22px; border-style: solid; border-width: 0; padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; text-align: left; margin-left: 0; margin-right: 0; margin-top: 0px; margin-bottom: 0px; background-color: #f9f9e5;\">\n<p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2025&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. The previous years are also available: <strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p>\n</section>\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor.</h2>\n\n\n\n<p>Long-time block developer <strong>Kevin Batdorf</strong> at <em>Extendify</em> just updated his <a href=\"https://github.com/KevinBatdorf/block-starter\"><strong>Block Starter plugin</strong> </a>repo—an &#8220;opinionated starter template for crafting WordPress block plugins,&#8221; as he calls it. It uses Tailwind v4 with output for the editor and frontend, TypeScript and Biome.js for code quality and type safety, and runs Playwright tests on PR using the Playground CLI. It also includes a Plugin Check on commits to main and before a release.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 10px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; margin-top: 0px; margin-bottom: 0px;\">\n<p>Featured Image: &#8220;Building blocks&#8221; by jgbarah is licensed under CC BY-SA 2.0 and found on WordPress.org/openverse.</p>\n\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-left\"><strong>Don&#8217;t want to miss the next Weekend Edition? </strong></p>\n\n\n<form action=\"https://gutenbergtimes.com/feed/\" autocomplete=\"on\" class=\"wp-block-newsletterglue-form ngl-form ngl-portrait\" method=\"post\"><div class=\"ngl-form-container\"><div class=\"ngl-form-field\" style=\"margin-bottom: 25px;\"><label class=\"ngl-form-label\" for=\"ngl_email\"><br />Type in your Email address to subscribe.</label><div class=\"ngl-form-input\"><input autocomplete=\"email\" class=\"ngl-form-input-text\" id=\"ngl_email\" name=\"ngl_email\" required=\"required\" style=\"border-radius: 21px;\" type=\"email\" /></div></div><button class=\"ngl-form-button\" style=\"background-color: #005075; border-color: #005075; border-width: 1px; border-style: solid; color: #ffffff; border-radius: 21px;\" type=\"submit\">Subscribe</button><p class=\"ngl-form-text\">We hate spam, too, and won&#8217;t give your email address to anyone <br />except Mailchimp to send out our Weekend Edition</p></div><div class=\"ngl-message-overlay\"><div class=\"ngl-message-svg-wrap\"><svg fill=\"none\" height=\"24\" stroke=\"#fff\" stroke-width=\"2\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><polyline points=\"20 6 9 17 4 12\"></polyline></svg></div><div class=\"ngl-message-overlay-text\">Thanks for subscribing.</div></div><input id=\"ngl_list_id\" name=\"ngl_list_id\" type=\"hidden\" value=\"26f81bd8ae\" /><input id=\"ngl_double_optin\" name=\"ngl_double_optin\" type=\"hidden\" value=\"yes\" /></form>\n\n\n<hr class=\"wp-block-separator has-css-opacity is-style-wide\" />\n</section>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 04 Oct 2025 07:41:54 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:42;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Matt: Linkrot\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150093\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://ma.tt/2025/10/linkrot/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2861:\"<p>One of the things I hate most on the internet, and part of the reason I started <a href=\"https://wordpress.org/\">WordPress</a>, was to fight linkrot. Ever since 1998, when <a href=\"https://www.w3.org/People/Berners-Lee/\">Tim Berners-Lee</a> wrote &#8220;<a href=\"https://www.w3.org/Provider/Style/URI\">Cool URIs Don&#8217;t Change</a>,&#8221; I&#8217;ve been obsessed with content management and ensuring that links don&#8217;t break. (BTW, TBL, a pioneer of creating the World Wide Web, <a href=\"https://www.newyorker.com/magazine/2025/10/06/tim-berners-lee-invented-the-world-wide-web-now-he-wants-to-save-it\">has a great new profile out in the New Yorker</a>.)</p>\n\n\n\n<p>I learned today from the <a href=\"https://newspack.com/\">Newspack</a> newsletter that the <a href=\"https://www.houstonpress.com/\">Houston Press</a> is now on WordPress. Newspack is a distribution or bundle of WordPress designed for journalism, and it is led by <a href=\"https://kinsey.nyc/\">Kinsey Wilson</a>, who began his career as a night-shift journalist covering cops for a newspaper in Chicago, went on to have top editorial and business positions at The New York Times, NPR, and USA TODAY, and ran WordPress.com for a few years, which gives him a very unique position to help craft WordPress for journalists and publishers.</p>\n\n\n\n<p>The Houston Press is an alt-weekly that wrote the very first profile of me in the world, <a href=\"https://ma.tt/2004/10/press-and-cnet/\">which I blogged about here</a>. There&#8217;s a funny quote in there:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>He recently considered taking a job with a San Francisco search-engine start-up, but ended up turning them down. “They have a ton of money…But it would be 50- or 60- or 70-hour weeks, a lot of work, and I wouldn’t have time” to do WordPress. </p>\n</blockquote>\n\n\n\n<p>That &#8220;search-engine start-up&#8221; was <a href=\"https://www.google.com/\">Google</a>! How the internet might have turned out differently if I had taken that job, as my Mom wanted me to (because they offered free food). I still think Google is one of the most interesting companies in the world, one of the few places I&#8217;d consider working if I weren&#8217;t running <a href=\"https://automattic.com/\">Automattic</a>.</p>\n\n\n\n<p>Back to linkrot, the original link to the profile in that article was <code>http://www.houstonpress.com/issues/2004-10-28/feature2.html</code>, which this morning didn&#8217;t work, but thanks to the Houston Press being on Newspack/WordPress I was able to ping Kinsey and his colleague Jason Lee was able to fix it so it redirects to the new canonical URL for that content in minutes. A little corner of the internet tidied up! I love the <a href=\"https://web.archive.org/\">Wayback Machine</a>, but not needing it is even better.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 04 Oct 2025 00:24:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:43;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Blocktober\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150063\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2025/10/blocktober/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:406:\"<p>It&#8217;s so exciting to see what the creative minds like <a href=\"https://iconick.io/\">Nick Hamze</a> or <a href=\"https://tammielister.com/\">Tammie Lister</a> are doing with Automattic&#8217;s AI vibe coding tool, <a href=\"https://telex.automattic.ai/\">Telex</a>. Tammie is doing a Blocktober, <a href=\"https://blocktober.fun/\">a block every day this month of October, you should follow along</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 02 Oct 2025 22:15:34 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:44;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: Fight For Open\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150050\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:37:\"https://ma.tt/2025/10/fight-for-open/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2067:\"<p>Sometimes the battle for open source and freedom can take on very prosaic and practical terms, but the wins can benefit everybody. To give an example: In <a href=\"https://www.beeper.com/\">Beeper</a> we need more memory for showing notifications, because we support end-to-end encryption for networks like Signal, but Apple&#8217;s default was to only give 15 megabytes — barely enough to do anything. The previous CEO of Beeper, Eric Migicovsky, started a lobbying effort with the <a href=\"https://digital-markets-act.ec.europa.eu/index_en\">EU’s Digital Markets Act</a> on behalf of the team to give third-party apps the same memory limits that Apple provides for their own apps, which is 50MB instead of 15MB. (And up to 250MB on their higher end devices.)</p>\n\n\n\n<p>Today we’ve gotten a notification that as part of iOS 26 update Apple has shipped to 2.3B devices around the world, our memory limits issue has been addressed globally, for every application developer, and some interoperability requests we had for <a href=\"https://developer.apple.com/documentation/telephonymessagingkit\">SMS/RCS</a> have been addressed for EU users. Kudos and huge thank you to Apple for giving us all new capabilities to build amazing experiences for users on par with what they seek to deliver themselves. If you want to geek out on this, <a href=\"https://blog.beeper.com/2025/10/01/how-beeper-ios-implements-notifications/\">check out the technical deep dive that Beeper just posted</a>.</p>\n\n\n\n<p>BTW, if you haven&#8217;t heard of it yet, <a href=\"https://www.beeper.com/\">Beeper</a> is an Automattic product which aims to democratize messaging, just like WordPress democratized publishing for the world, by allowing you to get all your messages from friends across 11 different networks, like WhatsApp, Instagram, Telegram, Twitter/X, Signal, Discord, in one single inbox. The new version we launched in July does this in a completely secure way that&#8217;s local to your device, so the same encryption, privacy, and security each network provides is maintained.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 01 Oct 2025 20:29:45 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:45;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:114:\"WPTavern: #187 – June Liu and David Denedo on Making the Web Accessible: The Mission Behind WP Accessibility Day\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=199767\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:127:\"https://wptavern.com/podcast/187-june-liu-and-david-denedo-on-making-the-web-accessible-the-mission-behind-wp-accessibility-day\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:48317:\"<details>Transcript<div>\n<p>[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p>Jukebox is a podcast which is dedicated to all things WordPress, the people, the events, the plugins, the blocks, the themes, and in this case, making the web accessible, and the mission behind WP Accessibility Day.</p>\n\n\n\n<p>If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p>If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox, and use the form there.</p>\n\n\n\n<p>So on the podcast today, we have June Liu and David Denedo.</p>\n\n\n\n<p>Both June and David are key members of the WP Accessibility Day organizing team, a global, volunteer driven, event focused on improving accessibility in the WordPress ecosystem.</p>\n\n\n\n<p>June serves as the marketing team co-lead, and works with sponsors, bringing her background in project management to keep the events efforts on track.</p>\n\n\n\n<p>David, a web designer and content creator based in London, contributes to the marketing and post-event teams, with his interest in web accessibility stemming from his personal experience as a visually impaired user.</p>\n\n\n\n<p>WP Accessibility Day has grown significantly in the past few years, uniting a large international group of volunteers, and organizers, to drive awareness and practical change in web accessibility.</p>\n\n\n\n<p>The event is powered by a host of teams, marketing, sponsors, tech and vendor, post-event, translation, speakers, and more, ensuring that everything from live captioning to sign language interpretation is in place.</p>\n\n\n\n<p>We begin by learning about June and David&#8217;s unique paths to accessibility advocacy. One through direct lived experience, and the other through supporting a loved one with cognitive challenges. Their stories highlight why accessibility can&#8217;t be an afterthought, and how events like WP Accessibility Day are raising awareness in this important area.</p>\n\n\n\n<p>We discuss what attendees can expect at this year&#8217;s event happening from the 15th of October, 2025. It&#8217;s free, fully virtual, and runs for 24 hours, making space for a diverse range of speakers and topics.</p>\n\n\n\n<p>Whether you&#8217;re interested in the moral, legal or technical cases for accessibility, there&#8217;s something for you here, including sessions on accessible design, risk management for agencies, legal compliance, and demonstrations of assistive technologies.</p>\n\n\n\n<p>June and David share how the event format, a combination of prerecorded talks and live chat, mixes polished content with real time engagement. Plus how translation and community involvement are key to its growing impact.</p>\n\n\n\n<p>If you want to learn more about how you can make your WordPress sites, and the web in general, more inclusive, or if you&#8217;re motivated by global collaboration or personal stories, this episode is for you.</p>\n\n\n\n<p>If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p>And so without further delay, I bring you June Liu and David Denedo.</p>\n\n\n\n<p>I am joined on the podcast by two fabulous guests. I&#8217;ve got June Liu and David Denedo. Hello both. How are you both doing?</p>\n\n\n\n<p>[00:03:58] <strong>June Jiu:</strong> Hi there.</p>\n\n\n\n<p>[00:03:59] <strong>David Denedo:</strong> Hello. I&#8217;m doing all right.</p>\n\n\n\n<p>[00:04:00] <strong>Nathan Wrigley:</strong> Well, it&#8217;s very nice to have you both with us. The intention of today&#8217;s podcast is to draw attention to something which well, I&#8217;m sure many of you will know about. If you don&#8217;t know about it, I certainly hope that by the end of this, not only do you know about it, but you are highly engaged, and hopefully going to attend and all of those kind of things, maybe even contribute some of your time, you never know.</p>\n\n\n\n<p>It&#8217;s called WP Accessibility Day, and we&#8217;re going to get into that in a moment. Before we do that, I just want to get the little bio, the introduction from both of you, one at a time, just telling us who you are, what your interest is in WordPress and accessibility, I guess.</p>\n\n\n\n<p>So we&#8217;ll keep it nice and short and sweet. So I&#8217;ll go to June first. Just let us know who you are, June.</p>\n\n\n\n<p>[00:04:39] <strong>June Jiu:</strong> Thank you, Nathan. I&#8217;m June, I serve on the organising team for WP Accessibility Day as the marketing team co-lead, and I also work on the sponsors team.</p>\n\n\n\n<p>My background is mostly project management, so my forte right now is helping the team coordinate tasks, and keeping the initiatives on track. Yeah, I coordinate between the sponsors and the marketing team to get the sponsor page prepared. So that&#8217;s basically my work with WPAD.</p>\n\n\n\n<p>[00:05:08] <strong>Nathan Wrigley:</strong> Thank you so much. That&#8217;s great. And David, let&#8217;s go to you next. Same question really.</p>\n\n\n\n<p>[00:05:11] <strong>David Denedo:</strong> Hi, I&#8217;m David. I&#8217;m visually impaired, so that&#8217;s why I love accessibility. I work in London as a web designer and a content creator, and I&#8217;m part of the WP Accessibility Day organising team, as part of the post-event people. But I&#8217;m also in the marketing team, just jumping around, and at least trying to put as much as I can into web accessibility.</p>\n\n\n\n<p>Yeah, I got into web accessibility mainly because of some talks I had two years ago from the WP Accessibility Day, and that just encouraged me. And then here we are two years later.</p>\n\n\n\n<p>[00:05:53] <strong>Nathan Wrigley:</strong> Thank you so much. So, WP Accessibility Day, one thing that just jumped out at me straight away from what you were both talking about there, you both talked about, I&#8217;m on the, and then you mentioned a team. That implies that there&#8217;s quite a lot of you in the background.</p>\n\n\n\n<p>So just to give credit where credit&#8217;s due, I think it&#8217;s always important to make sure that we credit not just the two of you, because there&#8217;s probably a lot of people behind this as well. I don&#8217;t want to go down the route of missing anybody out. So I wonder if it&#8217;s possible for us to just mention the kind of teams and things like that. And if there are any people in particular that you&#8217;ve been working with that you do wish to name, caveat emptor, dear listener, I apologise on behalf of everybody on this panel. If we miss anybody&#8217;s name out, sorry about that. But let&#8217;s go for the, how many teams there are and how big an enterprise is this these days?</p>\n\n\n\n<p>[00:06:39] <strong>June Jiu:</strong> I don&#8217;t think I&#8217;ve ever counted how many teams there are, but I&#8217;ll list some of them. And David, add yours if I miss any, please.</p>\n\n\n\n<p>There is a volunteer team that&#8217;s, right now, pivotal. That&#8217;s their work right now in preparing the event. The event is on October 15th, so we&#8217;re just about a month away. So the volunteer team is very active right now in onboarding the volunteers.</p>\n\n\n\n<p>Then we have the tech and vendors. And those are also very active. They work closely with the volunteer team to prepare the day of. So they&#8217;re the ones that prepare the Zoom platform for us. So making sure that it all runs well.</p>\n\n\n\n<p>Then we have website, APAC, post event, translation, sponsors, marketing. What else? I feel like there&#8217;s a few others that I&#8217;m missing. But there is a huge team behind Amber, Bet and Joe, working and making sure that we can make the event as smooth as possible, and take some of the load off of them.</p>\n\n\n\n<p>[00:07:36] <strong>Nathan Wrigley:</strong> The Amber, the Bet and the Joe that you just mentioned, we have got Amber Hinds, Bet Hannon and Joe Dolson. So there&#8217;s three names. Do you have any recollection whether they were the people that kind of kickstarted the event, whenever that was? Because if that was the case, it sounds like it&#8217;s gone gangbusters since then with lots of people joining on, and you two being some examples.</p>\n\n\n\n<p>[00:07:56] <strong>June Jiu:</strong> We do have a pretty big team this year. And yes, you&#8217;re right, the history is that Joe Dolson did start WP Accessibility Day. I don&#8217;t recall all of the specifics, but I think the second year, Bet, I think it might&#8217;ve started with Bet and Joe, and then Amber also came on soon after that.</p>\n\n\n\n<p>But we&#8217;re in our fifth year. It&#8217;s very exciting. I joined last year as an organiser and it was a point in my time where I was returning to work. So finding WPAD was kind of a sweet spot for me to test out my skill sets again, get used to being out in the public, so I have a soft spot for them.</p>\n\n\n\n<p>[00:08:35] <strong>Nathan Wrigley:</strong> Thank you. Okay, so there&#8217;s a few that we&#8217;ve rattled off. David, I don&#8217;t know if you can fill in any gaps that might have been left there. If so, go now.</p>\n\n\n\n<p>[00:08:42] <strong>David Denedo:</strong> Yeah, I think those are the main ones that were involved. And I would say Amber Hinds, when she came on board, she brought in a lot of organisation because, you know, with Joe, Joe understands the technical bits of things, but he&#8217;s not really so organised. So when she came in, that&#8217;s why the team grew exponentially from 2022, I believe when she joined. And then the year after, things just kept spiraling. And then now we have a massive team with lots of volunteers, everybody&#8217;s happy to help.</p>\n\n\n\n<p>The other thing that is quite nice is that there was a nice spread of people who are volunteering. So it&#8217;s not just maybe from one region or one country. We are a very nice spread of people, so that&#8217;s really nice. So from different parts, from Asia, from Africa, from the Americas and all of that, they&#8217;re all wide base.</p>\n\n\n\n<p>[00:09:33] <strong>Nathan Wrigley:</strong> That&#8217;s amazing. Everybody from all over the place. That&#8217;s really lovely.</p>\n\n\n\n<p>David, in your introduction, in your bio, you described that you are kind of eating your own dog food a little bit here in that, I can&#8217;t remember the exact phrasing that you had around your eyes. How did you describe the condition that you have, if that&#8217;s the right word?</p>\n\n\n\n<p>[00:09:50] <strong>David Denedo:</strong> Okay, yeah. So I am visually impaired, so I have very high myopia and high astigmatism. I also struggle to see myself, so that&#8217;s one reason why I got really interested when I saw how people are able to make the web more accessible. Because I grew up in a background where we had to adapt to so many stressful things, like there wasn&#8217;t really much help for people with accessibility needs.</p>\n\n\n\n<p>So I didn&#8217;t really know there were ways to help people out. Until I came into the whole system and I realised that, oh wow, so you can actually do this to help somebody else. Because I was always struggling, most times I couldn&#8217;t see the screen. So I&#8217;m always like relying on other people to tell me what&#8217;s in front of me, what&#8217;s on the screen, and all of that.</p>\n\n\n\n<p>But then when you start to see that, oh yeah, we can use a screen reader, you can use screen magnifier, you can do this, you can do that, you can just improve a little bit on your website, or even on the reality, makes things more accessible. I was like, wow, I&#8217;ve been living under the rock basically.</p>\n\n\n\n<p>[00:10:53] <strong>Nathan Wrigley:</strong> Yeah, that&#8217;s absolutely fascinating. I&#8217;m just wondering, June, if you have a similar story to tell in that, is there anything that you would like to share in that regard?</p>\n\n\n\n<p>[00:11:01] <strong>June Jiu:</strong> I do. My mother had a stroke, and from that she had vascular dementia. And being her caregiver for that many years, and seeing the decline in her loss of independence, because she wasn&#8217;t able to navigate the medical system by herself anymore. It was kind of, I learned everything in hindsight. I wish I had the knowledge that I have today to have helped her like 8, 10 years ago. But that drew me in.</p>\n\n\n\n<p>I was telling you how I came back into the workforce, and one of the things that somebody said to me was, hey, there&#8217;s this free event. It&#8217;s online, you don&#8217;t have to leave your house, just try it out. And it was WPAD. And when I was listening to the talks, I was like, yeah, wait a second, you mean that websites can be laid out differently so that it would be easier for somebody to navigate it, even with a mental decline?</p>\n\n\n\n<p>And it&#8217;s those simple, to us, it initially could be simple, but in the back end it might not be so simple. But just having her read through an online PDF, you know, it was difficult for her to hit the right area, because the PDF lines were so tiny. And her eye, hand coordination was reduced, so she&#8217;s not able to hit those lines to fill in the PDF.</p>\n\n\n\n<p>So for me it was the acknowledgement of, oh my gosh, it doesn&#8217;t have to be this way going forward. So it&#8217;s me trying to learn as much as I can to direct my future clients into a direction that gives better accessibility to all, and not just their one demographic.</p>\n\n\n\n<p>[00:12:41] <strong>Nathan Wrigley:</strong> It&#8217;s so curious that you&#8217;ve both got two stories where the end of it, the target, if you like, is the same, but how you&#8217;ve arrived at the things are entirely different.</p>\n\n\n\n<p>David, a very personal story about your own life. And June, well, another personal story, but viewed through the prism of somebody else. Almost like standing over somebody&#8217;s shoulder and being able to ascertain, well, this person&#8217;s not getting what they could out of the internet.</p>\n\n\n\n<p>And it strikes me that if you rewound the clock, I don&#8217;t know, let&#8217;s say 30 years ago before the internet was in any way, shape, or form common, but you could describe what would be available in 30 years time. And you could say, well, so many people, they&#8217;d have this little device in their hand, and there&#8217;d be these machines where there&#8217;d be screens on desktops and things like that.</p>\n\n\n\n<p>At that moment, you would be thinking to yourself, this is literally the perfect technology to help people who, let&#8217;s say for example, are struggling to see. Are unable to get out of the house. There may be an aspect of their body which doesn&#8217;t function in the way that your body or my body might function.</p>\n\n\n\n<p>You would describe that and you&#8217;d think, oh, this is like manna from heaven. This is the perfect thing. But it never turned out that way. The internet went in a way entirely leaving those people behind, I think, which was such a lost opportunity.</p>\n\n\n\n<p>So we&#8217;re kind of 25 years or whatever it is into the internet, and we&#8217;re now going back and filling in all of the gaps that probably, with the benefit of hindsight, should never have been left.</p>\n\n\n\n<p>I mean, I don&#8217;t know that there&#8217;s any question in there, but it&#8217;s curious that that one technology which could have made the lives of so many people so much more straightforward, really hasn&#8217;t serviced those people particularly well until events like this come along and educate the rest of us in how to do it.</p>\n\n\n\n<p>[00:14:23] <strong>June Jiu:</strong> I think, Nathan, you hit two big points. Everyone&#8217;s journey with accessibility is very personal, and unless you experienced it firsthand, or even secondhand in my case, you don&#8217;t really see that impact.</p>\n\n\n\n<p>And the second part is that the second nail that you hit is that a lot of times it becomes an afterthought. Accessibility becomes the afterthought. I think that with an event like WPAD, we want it to become the foundational, so we&#8217;re hoping to make that change.</p>\n\n\n\n<p>[00:14:53] <strong>Nathan Wrigley:</strong> For example, I&#8217;m imagining, again harking back to how the internet could have been, we&#8217;ve now got a technology where a small rectangle held in your hand, with a few clicks of a few buttons can enable you to more or less have anything delivered to your front door, in a very short space of time. Which is like, how incredible is that, that that is even possible?</p>\n\n\n\n<p>And so this is the perfect answer to people, let&#8217;s say for example, who struggle to get out of the front door, and navigate the shops and what have you.</p>\n\n\n\n<p>And yet we&#8217;re faced with a situation where that sublimely cool technology is impenetrable, and unavailable, to many people because it never got baked in as a requirement, and we can come to that later. David, I&#8217;m sorry, I think I interrupted.</p>\n\n\n\n<p>[00:15:36] <strong>David Denedo:</strong> Oh no. Yeah, what you said is quite right. There is an imbalance in the way things are getting better, but it&#8217;s getting better for a certain set of people, but leaving some other people behind. So that is the problem.</p>\n\n\n\n<p>With the web, it was improving at a very fast rate in terms of how to build the web, but somewhere along the line, people forgot that the whole essence of worldwide web, the man who created the W3C consortium, who basically created the web, the father of the web, his whole idea was that the web should be accessible to all. That was his vision, his goal from the very start.</p>\n\n\n\n<p>But as people are trying to push the boundaries, sometimes they forget, well, it is quite normal that sometimes unless you are experiencing a certain problem, you will not find a solution to it. So now that we are bringing the awareness to people, then they&#8217;re now finding out, okay, we forgot this certain set of people, let&#8217;s now incorporate them into our thinking, into our design, into everything.</p>\n\n\n\n<p>So that is one nice thing about having a conference like WPAD, to help spread awareness to people. Because if you&#8217;ve never experienced a certain problem, for example, you&#8217;ve never been blind or you&#8217;ve never had something with your mobility. You may not really appreciate the struggles of those people. But when they&#8217;re able to express it out and explain to you in these conferences, then you can now get that third party understanding, and at least you can incorporate accessibility into your own lifestyle.</p>\n\n\n\n<p>[00:17:21] <strong>Nathan Wrigley:</strong> Yeah, I have a question around that, because I am in the position where my eyes, despite the fact I wear glasses, once the glasses are on my nose, my eyes, functionally, I think you would describe them as normal, and I have good ish hearing, and my body functions. And so, David, you&#8217;ve basically just described me.</p>\n\n\n\n<p>It can be, it has been hard to imagine, what is the lived experience of people who are not in the same boat as I am?</p>\n\n\n\n<p>And I did wonder if a part of WPAD, I did wonder if a part of that was that educational piece? Whether it was explaining to people, web developers, people who may not be accustomed to what the conference is about, and what the summit will, you know, the educational pieces. I wondered if there was a piece where you explained, okay, this is the setup that somebody using a screen reader, this is what it feels like to them when they&#8217;re on the internet. This is what it would feel like, for example, I don&#8217;t know, if you are using a puff and sip system or something like that.</p>\n\n\n\n<p>So I don&#8217;t know if you are providing content like that, but I&#8217;d be curious to know whether you explain what the lived experience would be for people who may benefit as a result of the tech talks in the conference.</p>\n\n\n\n<p>[00:18:34] <strong>David Denedo:</strong> Yeah, so from what we have planned, there are a few of the conference talks that will reflect about accessibility. I think one of them is by Dennis, he&#8217;s going to show how a screen reader user will access a website. And then there are also talks about post-production of videos. So some people will incorporate the talks in, or at least talk about the experiences, but it may not be like a full on description.</p>\n\n\n\n<p>But yeah, I&#8217;ve seen a few of the talks that will be happening and they will be incorporating some of the disabilities that we know, like colorblindness, and then like audio and other things. So that will help people to get an awareness of what disabilities are out there, and how to incorporate that into building a more accessible system.</p>\n\n\n\n<p>[00:19:26] <strong>Nathan Wrigley:</strong> Okay, that&#8217;s really interesting. I suppose the old adage is, you know, a picture says the same as a thousand words or something like that. And being able to perceive what&#8217;s going on. I&#8217;ve always found that incredibly motivating, because immediately I can see how the internet is a more difficult place than a thousand words could describe and what have you.</p>\n\n\n\n<p>So, okay, so that&#8217;s interesting. And then moving on to the conference itself, I&#8217;m presuming that this is aimed squarely at people already using WordPress as their content management system, their website builder. But it is curious because, I don&#8217;t know exactly where you land on this, maybe what I&#8217;m about to say doesn&#8217;t fit at all, but I&#8217;m presuming the conference is designed to enable everybody to get some way along the road of producing an accessible website.</p>\n\n\n\n<p>But presumably also the audience is a little bit of, trying to do what I&#8217;ve just described, make the case, the moral case, the legal case for needing to do it as well. So it&#8217;s the tech side of how to do it, as well as the sort of the moral and the legal obligations that might sort of follow that in train.</p>\n\n\n\n<p>[00:20:32] <strong>June Jiu:</strong> Yeah, there is one session that I think you might find interesting along that line, is that it&#8217;s talking about accessibility as a risk management for agencies and for business owners. So I think that in particular, I have found it most interesting. With a background in project management, I&#8217;ve often had conversations where somebody will say to me, but why do I need to have it assessable? And then you&#8217;d have to take that pause and go, okay. But I think that to have the angle of risk management is certainly something that business owners will be able to relate to a little bit better.</p>\n\n\n\n<p>We also have another one that is talking about what features you should be on a lookout for so that you can kind of mitigate the legal portion of it. I&#8217;m not saying that you can avoid it completely, but at least you&#8217;re more aware of it.</p>\n\n\n\n<p>So there&#8217;s that one and, of course, our keynote speaker is Vitaly Friedman, from Smashing Magazine. He&#8217;s going to come at it from the UI, UX portion of it. So it&#8217;s not just all on the development, but it&#8217;s also on different aspects of website building and different viewpoints on business and ownership of a website.</p>\n\n\n\n<p>[00:21:48] <strong>Nathan Wrigley:</strong> Yeah, it&#8217;s kind of interesting because there are many threads there aren&#8217;t there. If you were just to take the technical side, you could probably do a conference that lasted many, many weeks about the technicalities of how to do it.</p>\n\n\n\n<p>But it&#8217;s curious that you&#8217;ve also leaned into the things like, well, the compulsion, the kind of maybe the advent of the ambulance chasing lawyer, dare I say it, who has realised, latched onto the fact that the European Accessibility Act over this side of the Atlantic is now a thing. There is no longer just a moral component to doing the accessibility work on your website. There is now increasingly a big legal hammer, which could be deployed.</p>\n\n\n\n<p>And so that alone, I presume will draw a certain audience who, you know, if the only thing that they want to hear about is how to mitigate that problem, well, maybe that&#8217;s not the ideal motivation for it, but nevertheless, it is a bit of a carrot and stick, and it will bring some people into the arena, which is good.</p>\n\n\n\n<p>[00:22:41] <strong>June Jiu:</strong> And here&#8217;s why I&#8217;d like to give a shout out to a team that I forgot, the speaker team. They&#8217;re the ones that put together the application, and they vetted through all the applications to see what would be more interesting for everybody.</p>\n\n\n\n<p>The rating system is, when they go through the rating system, they kind of make it anonymous of who the presenter would be. So it makes it, you are really looking at what the topic is being talked about, rather than who might be presenting. And that gives us an edge in finding topics that might not be as well known and from areas that are less featured.</p>\n\n\n\n<p>So we do have a couple of speakers that are coming from the continent of Africa, and those are always very interesting to hear. In the past, because of the location and the technical availability, there had been technical issues. But this year we&#8217;re having it so that the sessions are all prerecorded. So that will kind of help with the presentation of it, the clarity. But each of the speakers will be in the chat and they&#8217;ll be available to answer questions in the chat.</p>\n\n\n\n<p>So I think that&#8217;s an interesting fold into this year&#8217;s event, to have that feature in there so that the speaker is not just presenting, but they&#8217;re in the chat room answering questions. I think that adds another layer to the event.</p>\n\n\n\n<p>[00:24:04] <strong>Nathan Wrigley:</strong> Yeah, I think what&#8217;s really nice about that as well is that if everything&#8217;s prerecorded, the speaker will get the chance to create and then re-edit, and then adapt and modify. And what you end up with hopefully is the best version of that talk.</p>\n\n\n\n<p>With the best will in the world, some people are not as great as others at doing live things. You know, they go down rabbit holes, and they lose their train of thought or what have you. This completely gets rid of that problem. They can do it as many times as they like and give you the best version.</p>\n\n\n\n<p>But also that lovely aspect of, they suddenly become available to have a conversation in the chat, whereas before, they was presenting, you know, and presumably needed to go and have a bit of a lie down afterwards. Whereas in this situation, much more relaxed, you can ask them the questions.</p>\n\n\n\n<p>I really appreciate that format. I think that&#8217;s actually, that&#8217;s my preferred way of a summit, kind of like this, the Accessibility Day in this case, being put together. I think that&#8217;s very forward thinking. And I hope that you continue doing it that way because I think the presenters probably appreciate it. Your audience will appreciate it, because it will be polished, and also you get to chat with the person involved. Anything on that, David?</p>\n\n\n\n<p>[00:25:11] <strong>David Denedo:</strong> Yeah. Another thing we forgot to talk about is the translation team. So as the talks are being presented, there are also some nice volunteers who are translating it into other languages to have as much diversity as possible. Because some people, English is not their first language, so we have a team trying to convert to like French. We have the one for Spanish. There are also some other ones, even like Hebrew and so many other ones. So it&#8217;s a very nice feeling to have so many translations and everybody is doing their bit.</p>\n\n\n\n<p>That is one thing I love about WP Accessibility, the entire organising team is the fact that everybody&#8217;s skill level, it doesn&#8217;t matter your skill level, you can always put in something. So that is something great. Whether you are a web designer, you are just a business owner, you can sponsor the event. If you are good with multilingual, you can be part of the translation. You can apply to speak.</p>\n\n\n\n<p>The whole talks is not all technical, like you already mentioned. The talks are varied, so we talk about risk management, we talk about designers can give their own bits. People who are in business can give the business case for accessibility. So it&#8217;s all, it&#8217;s a lovely spread and I really love it.</p>\n\n\n\n<p>[00:26:30] <strong>Nathan Wrigley:</strong> There really is a lovely spread. I mean, firstly, one thing that I should have done right top of the show, which I didn&#8217;t, and I will mention it because I record a preamble before we actually start talking, one thing I will do is I&#8217;ll read into the record the URL. But I&#8217;ll do that now as well.</p>\n\n\n\n<p>So the URL is fabulous, by the way. It&#8217;s just ideal. If you are returning customer, if you like, it&#8217;s wpaccessibility.day. Just one more time, wpaccessibility, the regular spelling, no underscores, no hyphens or anything like that, dot day.</p>\n\n\n\n<p>And then as a subdomain you are going to put in the year. So in this case it&#8217;s going to be 2 0 2 5, 2025.wpaccessibility.day. And you&#8217;re going to find all the different bits and pieces over there.</p>\n\n\n\n<p>And one of the things that I noticed about the getting involved side of things is, yeah, there&#8217;s the whole sponsorship thing. So you can become a sponsor if you&#8217;d like to do that. But also you can volunteer, you can become a media partner. If you feel philanthropic and you just want to donate some of your money into the project, that is also an option. And then there&#8217;s a whole tab for the attendees as well. It&#8217;s under community. There&#8217;s an attendee section as well.</p>\n\n\n\n<p>So it sounds like it&#8217;s not just this little event which flicks on for a couple of days and then turns off again. I mean, certainly from your side, it sounds like there&#8217;s a whole fun community of things happening in the background.</p>\n\n\n\n<p>And really that&#8217;s the glue that binds a successful project together. If it was all very uninteresting and dry and a bit boring and you were all feeling under pressure, it wouldn&#8217;t have so many legs, it wouldn&#8217;t be able to run for this many years. But I&#8217;m guessing that you&#8217;ve had nice experiences, right, in the background?</p>\n\n\n\n<p>[00:28:04] <strong>June Jiu:</strong> Oh, yes. Yes. We have a lot of fun. But thank you for mentioning those links.</p>\n\n\n\n<p>[00:28:08] <strong>Nathan Wrigley:</strong> No, I think that&#8217;s wonderful. So again, go and check that out.</p>\n\n\n\n<p>The other thing to say though is, let&#8217;s talk about how it&#8217;s actually happening. Obviously you&#8217;ve described that it&#8217;s going to be prerecorded videos. How are you making that content available? What&#8217;s going to be the platform of choice, or how are you going to get it?</p>\n\n\n\n<p>Is there a way that you can, I don&#8217;t know, for example, download all of the bits and pieces so you can watch them in your own time? Is it an event which is spanning a single day, you know, a 24 hour time?</p>\n\n\n\n<p>[00:28:35] <strong>June Jiu:</strong> Yeah, we do say that it is 24 hours, but all the content and the videos, they&#8217;re going to be available for replay after we go through the post-event production. Either from each subdomain, as you mentioned, the 2025 will be available on the 2025.wpaccessibility.day.</p>\n\n\n\n<p>Last year&#8217;s event is available on the 2024.wpaccessibility.day. So you can rewatch them. It&#8217;s also available through YouTube. So if you need some background noise, I often do it. I just turn on that and let it roll.</p>\n\n\n\n<p>I have to say, it is a lot of information to absorb, but I do find it to be very resourceful. I know that one of David&#8217;s work this year is to put in chapters for these past event videos. So that has been very helpful to me when I find the relevant video from the past. And I said, I remember somebody saying something about that. Now with the chapters there, it&#8217;s much easier to navigate and find it. So good work, David. Thank you.</p>\n\n\n\n<p>[00:29:37] <strong>Nathan Wrigley:</strong> Yeah, indeed. Good work. But what&#8217;s this, in the show notes that were shared before we actually joined the call, it describes, it says here, and I don&#8217;t know which one of you wrote it, but it says, the event will be hosted through Zoom events. And Zoom is capitalised, so I presume it&#8217;s the platform Zoom that we&#8217;re all familiar with. I don&#8217;t know what a Zoom event is. Does that differ from a regular Zoom call? Is there some key difference?</p>\n\n\n\n<p>[00:29:59] <strong>June Jiu:</strong> Yes. It&#8217;s different from like a Zoom webinar or a Zoom call. It&#8217;s a platform that has a lobby. You&#8217;re registering on our site, but then on event day you&#8217;ll be able to go into the Zoom event.</p>\n\n\n\n<p>There&#8217;ll be a lobby and there&#8217;ll be a chat room, that&#8217;s where you can find all the information for the event. So, it&#8217;s not like a traditional webinar where there&#8217;s just one link in order to go and join it, to join that session, or that sector of sections. So now you can go in and when that hour pops up, that session would pop up.</p>\n\n\n\n<p>[00:30:32] <strong>Nathan Wrigley:</strong> Oh, I see. Right. So you go to this one central place, and everything&#8217;s kind of bound in this one, so as soon as you&#8217;re in, you&#8217;re in, basically, and you don&#8217;t have to keep clicking links in emails to find the latest session, which is going live.</p>\n\n\n\n<p>[00:30:44] <strong>June Jiu:</strong> Exactly.</p>\n\n\n\n<p>[00:30:45] <strong>Nathan Wrigley:</strong> Okay. That&#8217;s really nice. Dave, anything to add to that?</p>\n\n\n\n<p>[00:30:47] <strong>David Denedo:</strong> Yeah. And you also have access to like swag. Everything will be in the event, so you can get some of the sponsor swag, you can chat with the speakers, you can chat with other event members, all within the same platform. So not having to jump from one platform to another platform to chat and then come back. You can lose people that way, but now everything all packaged together.</p>\n\n\n\n<p>[00:31:12] <strong>June Jiu:</strong> I wanted to give a shout out to the platform itself. It allows us to do live captioning. A lot of times with webinars, it is just automated caption. We actually do have live captioners typing into Zoom. That is another layer to WP Accessibility Day that is not a feature in other events.</p>\n\n\n\n<p>[00:31:32] <strong>Nathan Wrigley:</strong> No kidding, yeah.</p>\n\n\n\n<p>[00:31:33] <strong>June Jiu:</strong> Yes. And the other big one, expense for us is the American Sign Language interpreters. So they will be also on hand on event day, and there&#8217;s a team of them that will be available to us, and they do the ASL.</p>\n\n\n\n<p>This year one of our speakers is from Australia and he will be bringing in Australian Sign Language, which is different from American Sign Language. So there&#8217;s another layer to the accessibility. We understand either British Sign Language or American Sign Language but, yeah, there&#8217;s Australian Sign Language too.</p>\n\n\n\n<p>[00:32:08] <strong>Nathan Wrigley:</strong> You drop this as if it&#8217;s really straightforward, but when my head starts spinning on the technicalities there, the idea of injecting real time, typed transcriptions, somehow overlaying that into the video, there&#8217;s a whole technical piece there.</p>\n\n\n\n<p>And then you&#8217;ve got a sign language person. That&#8217;s a whole nother layer as well. That all needs, presumably, I don&#8217;t know if that&#8217;s going to be done live or filmed. Maybe there&#8217;s an opportunity.</p>\n\n\n\n<p>[00:32:33] <strong>June Jiu:</strong> It&#8217;s live.</p>\n\n\n\n<p>[00:32:33] <strong>Nathan Wrigley:</strong> Yeah, okay. So all of that, there are lots and lots of moving parts here.</p>\n\n\n\n<p>[00:32:37] <strong>June Jiu:</strong> That&#8217;s why we have the technical and vendor team, and the volunteer team. They&#8217;re pivotal on event day to have those two teams in place.</p>\n\n\n\n<p>[00:32:47] <strong>Nathan Wrigley:</strong> Can I just ask, because I know there&#8217;ll be some people that are curious about the, how to describe it, the business status, let&#8217;s put it that way. And maybe this is not something that either of you can answer, I don&#8217;t know.</p>\n\n\n\n<p>What&#8217;s the structure of WP Accessibility Day? So, for example, if I was to donate, in the UK we call these things charities. I think in the US the correct term is non-profit. So if I was to donate, do I have some sort of assurance that the money isn&#8217;t going to end up in some, I don&#8217;t even want to say the words because I know that nobody&#8217;s ethics are this poorly thought through, but I&#8217;m going to say it anyway. Just want to make sure that the money doesn&#8217;t end in somebody&#8217;s back pocket.</p>\n\n\n\n<p>Where did the donations end up? How is the structure of this organisation ensuring that everything is out in the open and clear and easy to understand?</p>\n\n\n\n<p>[00:33:28] <strong>June Jiu:</strong> Well, this year WordPress Accessibility Day was recognised by IRS as the 501 C3 public charity. So based upon that, a hundred percent of our income that comes in goes right back into the event.</p>\n\n\n\n<p>Organisers and volunteers are not paid. Every one of us who are working on this is out of the goodness of our heart, and what time availability that we have.</p>\n\n\n\n<p>The one caveat I will say, some of our translators are paid because translation is an income based business. And this is a recent development. In the past we&#8217;ve had to ask them to please donate their time to do the translation. But now we have a little bit more security to be able to pay them.</p>\n\n\n\n<p>People who have the ability to speak multiple languages, look into the translation because if you aren&#8217;t able to participate as an organiser or a volunteer, donating your time to translate or being paid for be translators for us is a huge difference for us to bring all these sessions available to a greater audience.</p>\n\n\n\n<p>[00:34:36] <strong>Nathan Wrigley:</strong> I think everybody would understand that there&#8217;s, that is how that industry works, isn&#8217;t it? When you go to a WordCamp, for example, and you see the people doing the live captioning, or you see the people standing on the stage and they&#8217;re doing the sign language, I think it&#8217;s understood that that is what they do for a living.</p>\n\n\n\n<p>[00:34:51] <strong>June Jiu:</strong> And I would be remiss not to give credit to our sponsors too. We have many sponsors who are repeat sponsors year after year, and they support us with their sponsorship. We are very appreciative of that.</p>\n\n\n\n<p>This year we have some new ones and a lot of repeating ones from every range. Our higher level are of course now closed, but we still have the bronze level, which is at a $500, or a micro sponsor which is at $150. And the difference between that is the Bronze has a webpage, a dedicated webpage for their company, and the micro sponsor has a logo on our sponsor page.</p>\n\n\n\n<p>[00:35:28] <strong>Nathan Wrigley:</strong> So as of recording, and maybe that will keep going right up to the deadline, I don&#8217;t know, so if what you&#8217;ve heard has made you feel that you&#8217;d like to be involved on a sponsorship level, bronze is available, that one is $500, and there&#8217;s a micro one. And obviously you can go onto the 2025 Accessibility Day website and discover for yourself what&#8217;s available in there.</p>\n\n\n\n<p>So we found out what&#8217;s happening. We found out why it&#8217;s being done. We found out some of the people that are being involved. I suppose what we ought to do at this point is drive people toward the schedule.</p>\n\n\n\n<p>Well, you&#8217;ve announced it already, but let&#8217;s just make sure we&#8217;re doing it again. The date for this event is when?</p>\n\n\n\n<p>[00:36:03] <strong>David Denedo:</strong> So it&#8217;ll be happening on October 15th to the 16th, and it&#8217;ll be 24 hour long event. So it&#8217;s going to go right up for 24 hours. We have the speakers all in the schedule, so you can go ahead and check it out. The link will be in the shownotes.</p>\n\n\n\n<p>[00:36:19] <strong>Nathan Wrigley:</strong> It will. Yeah, that&#8217;s absolutely right. So the 15th of October, it&#8217;s a 24 hour event. So I don&#8217;t know if you start in the sort of Pacific neck of the woods, that seems to be the traditional way that things are done. So Australia, they&#8217;re the sort of first people to receive the content, and then it just goes around the globe. And maybe the people in, on the west coast of the US and Hawaii and what have you, they get the content more towards the end of the day. I assume that&#8217;s how it&#8217;s working.</p>\n\n\n\n<p>But if you go to the URL that we mentioned earlier and just add forward slash schedule to it, you will be able to see through opening remarks from Joe Dolson right at the beginning of the day, right through the keynotes and everything, to the closing remarks, or at least the last presentation, which is happening some 23 or so hours later.</p>\n\n\n\n<p>I think that&#8217;s all the questions that I had. Is there anything that you feel it would&#8217;ve been important to say that we didn&#8217;t say? If that&#8217;s the case, please feel free to use this platform now.</p>\n\n\n\n<p>[00:37:09] <strong>June Jiu:</strong> The event is free, but we do ask that you register, so that we do have a good count of how many people are coming. So please sign up at 2025.wpaccessibility.day and you&#8217;ll find the registration link there.</p>\n\n\n\n<p>[00:37:26] <strong>Nathan Wrigley:</strong> Is that a mere request or is that a requirement? In order to gain access, do you need to have, yeah, okay. So I&#8217;m getting a nod of the head there from June. So go and register in order to access the content as well. David, anything we missed?</p>\n\n\n\n<p>[00:37:38] <strong>David Denedo:</strong> Yeah, the only thing is that I&#8217;m excited for Vitaly Friedman, because he has a very wide following, so he will bring more people into our event, hopefully. And he is going to be talking about accessible designs, which is something quite powerful. Because in this day and age, people always associate accessibility with very boring designs. But he&#8217;s coming to show you that you can have very beautiful designs in 2025 and still be accessible. So that&#8217;s a very important topic.</p>\n\n\n\n<p>[00:38:09] <strong>Nathan Wrigley:</strong> Well, the WP Accessibility Day website is an example of that. It&#8217;s actually a really tasteful, beautiful design. I&#8217;m going to guess that it&#8217;s, you know, the accessibility credentials of it are fairly strong. Let&#8217;s just, make that assumption, but it&#8217;s beautifully designed.</p>\n\n\n\n<p>Yeah, we didn&#8217;t really touch on the names of the speakers or what have you. But yeah, I&#8217;ll just go through a few just as I scroll through, just to give you some ideas.</p>\n\n\n\n<p>So accessible design patterns is Vitaly. Being a colorblind designer, typography, readability, digital accessibility, building accessibility that works in the global south, hyper accessible web design for the blind, audio accessibility, accessibility lawsuits, gosh, we&#8217;re only like six or seven in, and we&#8217;ve run the full gamut already. So here we go. Why accessibility matters, video and media your post-production, guide making WordPress events accessible, gosh, that&#8217;s fascinating. Auditing WordPress plugin accessibility, demystifying screen readers, technical checklists. That means testing WordPress themes and plugins for accessibility. The future is automated, will it be accessible? Making Gutenberg blocks accessible. I&#8217;m going to stop there, but you get the idea. There&#8217;s absolutely loads of breadth and depth.</p>\n\n\n\n<p>It&#8217;s very much the case that if you were to show up, I would guarantee more or less that there&#8217;s going to be something which will pique your interest and keep you engaged. The schedule, like I said, is at forward slash schedule.</p>\n\n\n\n<p>Okay, if that&#8217;s the case, I will just say thank you so much for being one of many cogs in this very important wheel. Thank you for doing what is incredibly important work, making the web accessible to far more people. Thank you. That&#8217;s quite amazing.</p>\n\n\n\n<p>So June and David, thanks for joining us today. Really appreciate it.</p>\n\n\n\n<p>[00:39:46] <strong>June Jiu:</strong> Thanks for having us.</p>\n\n\n\n<p>[00:39:48] <strong>David Denedo:</strong> Thanks for having us.</p>\n</div></details>\n\n\n\n<p>On the podcast today we have <a href=\"https://2025.wpaccessibility.day/people/june-liu/\">June Liu</a> and <a href=\"https://2025.wpaccessibility.day/people/david-denedo/\">David Denedo</a>.</p>\n\n\n\n<p>Both June and David are key members of the <a href=\"https://2025.wpaccessibility.day/\">WP Accessibility Day</a> organising team, a global, volunteer-driven event focused on improving accessibility in the WordPress ecosystem. June serves as the marketing team co-lead and works with sponsors, bringing her background in project management to keep the event’s efforts on track. David, a web designer and content creator based in London, contributes to the marketing and post-event teams, with his interest in web accessibility stemming from his personal experience as a visually impaired user.</p>\n\n\n\n<p>WP Accessibility Day has grown significantly in the past few years, uniting a large, international group of volunteers and organisers to drive awareness and practical change in web accessibility. The event is powered by a host of teams, marketing, sponsors, tech and vendor, post-event, translation, speakers, and more, ensuring that everything from live captioning to sign language interpretation is in place.</p>\n\n\n\n<p>We begin by learning about June and David’s unique paths to accessibility advocacy, one through direct lived experience, and the other through supporting a loved one with cognitive challenges. Their stories highlight why accessibility can&#8217;t be an afterthought and how events like WP Accessibility Day are raising awareness in this important area.</p>\n\n\n\n<p>We discuss what attendees can expect at this year’s event, happening from October 15th, 2025. It’s free, fully virtual, and runs for 24 hours, making space for a diverse range of speakers and topics. Whether you’re interested in the moral, legal, or technical cases for accessibility, there’s something for you here, including sessions on accessible design, risk management for agencies, legal compliance, and demonstrations of assistive technologies.</p>\n\n\n\n<p>June and David share how the event format, a combination of pre-recorded talks and live chat, mixes polished content with real-time engagement, plus how translation and community involvement are key to its growing impact.</p>\n\n\n\n<p>If you want to learn more about how you can make your WordPress sites, and the web in general, more inclusive, or if you’re motivated by global collaboration and personal stories, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p><a href=\"https://2025.wpaccessibility.day/\">WP Accessibility Website</a></p>\n\n\n\n<p><a href=\"https://2025.wpaccessibility.day/about/organizers/\">The WP Accessibility Day Team</a></p>\n\n\n\n<p><a href=\"https://2025.wpaccessibility.day/schedule/\">The WP Accessibility Day Schedule</a></p>\n\n\n\n<p><a href=\"https://www.youtube.com/channel/UCes9XCUZd51CAigbBEGlfNg\">WP Accessibility Day YouTube Channel</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 01 Oct 2025 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:46;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"WordPress.org blog: WordPress 6.8.3 Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=19204\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://wordpress.org/news/2025/09/wordpress-6-8-3-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4937:\"<p><strong>WordPress 6.8.3 is now available!</strong></p>\n\n\n\n<p>This is a security release that features two fixes.</p>\n\n\n\n<p>Because this is a security release,<strong> it is recommended that you update your sites immediately</strong>.</p>\n\n\n\n<p>You can <a href=\"https://wordpress.org/wordpress-6.8.3.zip\">download WordPress 6.8.3 from WordPress.org</a>, or visit your WordPress Dashboard, click “Updates”, and then click “Update Now”. If you have sites that support automatic background updates, the update process will begin automatically.</p>\n\n\n\n<p>The next major release will be <a href=\"https://make.wordpress.org/core/6-9/\">version 6.9</a>, which is planned for December 2nd, 2025.<br />For more information on WordPress 6.8.3, please visit the <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-8-3/\">version page on the HelpHub site</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Security updates included in this release</h2>\n\n\n\n<p>The security team would like to thank the following people for <a href=\"https://hackerone.com/wordpress?type=team\">responsibly reporting vulnerabilities</a>, and allowing them to be fixed in this release:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>A data exposure issue where authenticated users could access some restricted content. Independently reported by <a href=\"https://hackerone.com/mnelson4\">Mike Nelson</a>, <a href=\"https://hackerone.com/hurayraiit\">Abu Hurayra</a>, <a href=\"https://profiles.wordpress.org/timothyblynjacobs/\">Timothy Jacobs</a>, and <a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a>.</li>\n\n\n\n<li>A cross-site scripting (XSS) vulnerability requiring an authenticated user role that affects the nav menus. Reported by <a href=\"https://x.com/Savphill\">Phill Savage</a>.</li>\n</ul>\n\n\n\n<p>As a courtesy, these fixes have also been made available to all branches eligible to receive security fixes (currently through 4.7). As a reminder, <strong>only the most recent version of WordPress is actively supported</strong>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Thank you to these WordPress contributors</h2>\n\n\n\n<p>This release was led by <a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a>.</p>\n\n\n\n<p>In addition to the security researchers and release squad members mentioned above, WordPress 6.8.3 would not have been possible without the contributions of the following people:</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/hurayraiit\">Abu Hurayra</a>, <a href=\"https://profiles.wordpress.org/zieladam\">Adam Zieliński</a>, <a href=\"https://profiles.wordpress.org/xknown\">Alex Concha</a>, <a href=\"https://profiles.wordpress.org/andraganescu%20\">Andrei Draganescu</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/ehtis\">Ehtisham Siddiqui</a>, <a href=\"https://profiles.wordpress.org/iandunn\">Ian Dunn</a>, <a href=\"https://profiles.wordpress.org/whyisjake\">Jake Spurlock</a>, <a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/joehoyle\">Joe Hoyle</a>, <a href=\"https://profiles.wordpress.org/johnbillion\">John Blackbourn</a>, <a href=\"https://profiles.wordpress.org/jonsurrell\">Jon Surrell</a>, <a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/mnelson4\">Michael Nelson</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/phillsav\">Phill</a>, <a href=\"https://profiles.wordpress.org/noisysocks\">Robert Anderson</a>, <a href=\"https://profiles.wordpress.org/rmccue\">Ryan McCue</a>, <a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>, <a href=\"https://profiles.wordpress.org/timothyblynjacobs\">Timothy Jacobs</a>, <a href=\"https://profiles.wordpress.org/vortfu\">vortfu</a>, <a href=\"https://profiles.wordpress.org/westonruter\">Weston Ruter</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">How to contribute</h2>\n\n\n\n<p>To get involved in WordPress core development, head over to Trac, <a href=\"https://core.trac.wordpress.org/report/6\">pick a ticket</a>, and join the conversation in the <a href=\"https://app.slack.com/client/T024MFP4J/C02RQBWTW\">#core</a> Slack channel. Need help? Check out the <a href=\"https://make.wordpress.org/core/handbook/tutorials/faq-for-new-contributors/\">Core Contributor Handbook</a>.</p>\n\n\n\n<p>Props to <a href=\"https://profiles.wordpress.org/ehtis/\">Ehtisham Siddiqui</a>, <a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a>, <a href=\"https://profiles.wordpress.org/paulkevan/\">Paul Kevan</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/westonruter\">Weston Ruter</a> for reviewing.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Sep 2025 19:31:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"John Blackbourn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:47;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"Matt: What’s Your Time?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150037\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2025/09/tick-tock/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:908:\"<p>I think some of the best writing about technology PR is this ten-year-old article by <a href=\"https://www.onbackground.com/\">Aaron Zamost</a>: <a href=\"https://medium.com/backchannel/how-the-tech-press-forces-a-narrative-on-companies-it-covers-5f89fdb7793e\">What’s Your Hour in ‘Silicon Valley Time’?</a> It describes the cycles that companies go through in public perception, and the beauty of revisiting it ten years later is that you can see which of the examples are still relevant, or the domains that 404. As someone who has been around this clock probably a dozen times now, I highly suggest this for anyone &#8220;going through it.&#8221; Some of the most powerful words in the English language: <em>This too shall pass</em>. </p>\n\n\n\n<p>See also: The Zen fable or old Chinese poem of <a href=\"https://en.wikipedia.org/wiki/The_old_man_lost_his_horse\">the old man who loses his horse</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Sep 2025 17:30:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:48;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"Open Channels FM: Surviving the WordPress Plugin Grind Growth, Marketing and Overcoming Burnout\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=110777\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:101:\"https://openchannels.fm/surviving-the-wordpress-plugin-grind-growth-marketing-and-overcoming-burnout/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:237:\"In this WP Behind the Builds episode, guest Devin Walker discusses his transition from corporate IT to successful WordPress plugin development, focusing on GiveWP, WP Rollback, and lessons learned about business and community engagement.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Sep 2025 11:34:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:49;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Matt: Om 59\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150022\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"https://ma.tt/2025/09/om-59/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3905:\"<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-150030\" height=\"340\" src=\"https://i0.wp.com/ma.tt/files/2025/09/IMG_0803-1-edited-scaled.jpeg?resize=604%2C340&#038;quality=89&#038;ssl=1\" width=\"604\" /></figure>\n\n\n\n<p>I want to dedicate my blog post today to my dear friend and brother, <a href=\"https://om.co/\">Om Malik</a>, whose birthday it is. Om is a multi-hyphenate, but at his core, he&#8217;s a writer, someone who looks at the world and parses it down for others, a seeker who appreciates the spark of creation before most others.</p>\n\n\n\n<p>Om was one of the earliest users of WordPress and he was one of <a href=\"https://ma.tt/2005/01/meetup-aftermath/\">8 people who came to the very first WordPress meetups at Chaat Cafe on 3<sup>rd</sup> street in San Francisco in 2005</a>. (You can tell what an early adopter he is because he has the username &#8220;Om&#8221; <a href=\"https://x.com/om\">on Twitter/X</a> and <a href=\"https://www.instagram.com/om/\">Instagram</a> and WordPress and probably more.) We had connected on the WordPress support forums when I helped him get set up around the 1.0 days. After I moved to San Francisco to take the job at CNET he connected me to people like Phil Black, Tony Conrad, and Toni Schneider who would become, respectively, an investor, board member, and CEO of Automattic. These are folks I still work with and consider close friends today. As a journalist, he had a keen nose for BS and made sure as a naïve 20-something in SF I was connecting with quality people.</p>\n\n\n\n<p>Since we met we&#8217;ve both had a shared love for photography, and I&#8217;ve seen Om blossom into an amazing photographer with a really unique style and approach, <a href=\"https://www.photosbyom.com/\">in fact you can even buy some of his photography prints</a>.</p>\n\n\n\n<p>Over the years, we&#8217;ve dipped in and out of shared obsessions with cameras, watches, shoes, fashion, and design. We have a fair number of matching things in each. In photography we&#8217;ve shivered in minus thirty weather in Antarctica and Jackson Hole at odd hours to catch a special shot. We&#8217;ve traveled to Europe and Japan dozens of times, being very early (pre John Mayer and Kanye) to brands like <a href=\"https://www.visvim.tv/\">Visvim</a>. <span style=\"margin: 0px; padding: 0px;\">When I wear something like a bespoke<span style=\"margin: 0px; padding: 0px;\">, hand-made piece from <a href=\"https://45rglobal.com/\" target=\"_blank\">45R</a> to <a href=\"https://www.youtube.com/watch?v=45HRzzc0waU\" target=\"_blank\">speak at WordCamp US</a>, he recognizes it off the cuff </span>and even knows the one store on Crosby Street in New York where you can buy it.</span> He is a tastemaker and an aesthetic connoisseur in every area he&#8217;s interested in, from food to coffee to pens, and everything in between. Sometimes we&#8217;ll start a journey together, for example, trying nice pens, and years later, I&#8217;ve moved on and he&#8217;s gone deep into collecting dozens of them, being in obscure forums and Reddits, or attending events like the <a href=\"https://sanfranciscopenshow.com/\">SF Pen Show last month</a>.</p>\n\n\n\n<p>When you walk into a coffee shop with Om he doesn&#8217;t just know the barista&#8217;s name, he knows their dog&#8217;s name and the story of every person working there.</p>\n\n\n\n<p>I&#8217;m 500 words in, and I still haven&#8217;t even scratched the surface of describing Om&#8217;s journey, from growing up in Delhi to becoming a journalist for a Japanese publication in New York, a book author, party promoter, entrepreneur, venture capitalist, photographer, and explorer. If you want to understand the AI bubble we&#8217;re in right now, you should <a href=\"https://www.amazon.com/dp/0471660612?tag=photomatt08-20\">read his book Broadbandits on the crazy telecom / Enron bubble</a>. This is a long way to say, happy birthday Om!</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 29 Sep 2025 15:50:56 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:9:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Sat, 25 Oct 2025 03:09:13 GMT\";s:12:\"content-type\";s:8:\"text/xml\";s:13:\"last-modified\";s:29:\"Sat, 25 Oct 2025 03:00:22 GMT\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 1\";}}s:5:\"build\";i:1727736619;s:21:\"cache_expiration_time\";i:1761404954;s:23:\"__cache_expiration_time\";i:1761404954;}','off'),(4599,'_transient_timeout_dash_v2_a5a61dcab273495c31cd79aafebbdc74','1761404954','off'),(4600,'_transient_dash_v2_a5a61dcab273495c31cd79aafebbdc74','<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://vi.