INSERT INTO `wp_posts` VALUES (2,1,'2022-11-27 04:01:29','2022-11-27 04:01:29','[section padding=\"0px\" class=\"home-banner-slider\"]\n\n[ux_slider freescroll=\"true\" hide_nav=\"true\" nav_size=\"normal\" nav_style=\"simple\" bullets=\"false\" bullet_style=\"simple\" pause_hover=\"false\" class=\"slider-section\"]\n\n[ux_image id=\"78\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" class=\"banner-overlay\"]\n\n[ux_image id=\"78\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" class=\"banner-overlay\"]\n\n\n[/ux_slider]\n<div class=\"banner-content\">\n<h2>NA TIMBERTECH - NỘI THẤT XANH CHO KHÔNG GIAN THƯỢNG HẠNG</h2>\n<h5>Quality - Standards Americatrattra</h5>\n<ul>\n<li>- 100% nguyên vật liệu xanh, an toàn sức khỏe</li>\n<li>- Công nghệ sản xuất chuẩn Mỹ, bền đẹp vượt thời gian</li>\n<li>- Chuyên xuất khẩu qua các cường quốc Mỹ, Đức, Nhật, Canada</li>\n</ul>\n<p class=\"button-banner\"><a href=\"https://zalo.me/4192416328091980939\">Liên hệ tư vấn ngay</a></p>\n</div>\n\n[/section]\n[section label=\"Section2\" class=\"section2 block-cong-nghe\"]\n\n[title style=\"center\" text=\"Công Nghệ Sản Xuất\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[row style=\"large\"]\n\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"1185\" image_height=\"80%\" image_size=\"original\"]\n\n[ux_text class=\"description-cong-nghe\"]\n\n<h3><a href=\"/thiet-ke-noi-that/\">Plato Hydro-Thermal kết hợp Nano Canxi</a></h3>\n<p>Ứng dụng công nghệ thủy nhiệt Plato (160–240°C) kết hợp Nano Canxi giúp gỗ Nam Anh đạt độ cứng chắc, bền vững, chống cong vênh và mục nát</p>\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"1187\" image_height=\"80%\" image_size=\"original\"]\n\n[ux_text class=\"description-cong-nghe\"]\n\n<h3><a href=\"/thiet-ke-noi-that/\">Công nghệ High-frequency pressing</a></h3>\n<p>Công nghệ khắc trực tiếp trên gỗ với độ nét và độ chính xác cao, mang đến sản phẩm tinh xảo, sang trọng và khác biệt, nâng tầm giá trị công trình.</p>\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"1192\" image_height=\"80%\" image_size=\"original\"]\n\n[ux_text class=\"description-cong-nghe\"]\n\n<h3><a href=\"/thi-cong-noi-that/\">Công nghệ Acrylic Coating </a></h3>\n<p>Công nghệ phủ Acrylic cao cấp giúp bề mặt ván ép Nam Anh sáng bóng, chống trầy xước và bền đẹp theo thời gian. Mỗi lớp veneer được chọn lọc, sấy khô dưới 8% độ ẩm và ép với lực 133–150 tấn/m².</p>\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n\n[/row]\n\n[/section]\n[section class=\"slider-the-manh\"]\n\n[title style=\"center\" text=\"Thế Mạnh Trên Thị Trường\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[ux_slider style=\"container\" slide_width=\"25%\" slide_align=\"left\" margin=\"15px\" nav_size=\"normal\"]\n\n[section_inner]\n\n[featured_box img=\"1060\" img_width=\"100\" pos=\"center\"]\n\n[ux_text text_align=\"center\"]\n\n<h3>Tiêu chuẩn quốc tế – An toàn & bền vững</h3>\n<p>Sản phẩm đạt chứng nhận FSC/CE, CARB P2, phát thải thấp, thân thiện môi trường, đảm bảo an toàn cho sức khỏe người dùng và phù hợp xu hướng nội thất xanh hiện đại.</p>\n[/ux_text]\n\n[/featured_box]\n\n[/section_inner]\n[section_inner]\n\n[featured_box img=\"1053\" img_width=\"100\" pos=\"center\"]\n\n[ux_text text_align=\"center\"]\n\n<h3>Dây chuyền tự động – Năng suất ổn định</h3>\n<p>Nhà máy được đầu tư 100% công nghệ Mỹ, đạt chuẩn ISO 9001:2015, giúp kiểm soát chất lượng nghiêm ngặt, đáp ứng nhanh mọi đơn hàng quy mô.</p>\n[/ux_text]\n\n[/featured_box]\n\n[/section_inner]\n[section_inner]\n\n[featured_box img=\"1051\" inline_svg=\"0\" img_width=\"100\" pos=\"center\"]\n\n[ux_text text_align=\"center\"]\n\n<h3>Đội ngũ chuyên nghiệp – Giải pháp tối ưu</h3>\n<p>Với hơn 100 kỹ sư, chuyên gia gỗ nhiều kinh nghiệm, NA luôn tư vấn giải pháp vật liệu xanh phù hợp nhất, an toàn nhất cho người tiêu dùng.</p>\n[/ux_text]\n\n[/featured_box]\n\n[/section_inner]\n[section_inner]\n\n[featured_box img=\"1055\" img_width=\"100\" pos=\"center\"]\n\n[ux_text text_align=\"center\"]\n\n<h3>Chất lượng vượt trội – Bền đẹp theo thời gian</h3>\n<p>NA TimberTech đạt chuẩn xuất khẩu Mỹ, Nhật, Canada,... có độ bền và độ kết dính keo gấp 2 lần ván thông thường, chống ẩm, chống cong vênh, mang lại tính thẩm mỹ lâu dài cho mọi công trình.</p>\n[/ux_text]\n\n[/featured_box]\n\n[/section_inner]\n[section_inner]\n\n[featured_box img=\"1057\" img_width=\"100\" pos=\"center\"]\n\n<h3>Mạng lưới đối tác toàn quốc</h3>\n<p>Hơn 200+ doanh nghiệp nội thất, nhà thầu, showroom tin dùng sản phẩm NA TimberTech – minh chứng cho chất lượng ổn định và uy tín thương hiệu trên thị trường.</p>\n\n[/featured_box]\n\n[/section_inner]\n\n[/ux_slider]\n\n[/section]\n[title style=\"center\" text=\"Sản Phẩm\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[section label=\"Section5\" class=\"section5\"]\n\n[row style=\"small\" width=\"full-width\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_portfolio style=\"overlay\" ids=\"200\" type=\"row\" col_spacing=\"xsmall\" columns=\"1\" image_height=\"65.1%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\" text_bg=\"rgba(0, 0, 0, 0)\" class=\"du-an\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" class=\"na-product-pk\"]\n\n[ux_portfolio style=\"overlay\" ids=\"174,162,178\" type=\"row\" col_spacing=\"xsmall\" columns=\"2\" image_height=\"65%\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" text_align=\"left\" class=\"du-an\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[title style=\"center\" text=\"Ứng Dụng\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[section bg_color=\"rgb(0, 0, 0)\" padding=\"0px\" class=\"section01\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"356\" image_size=\"original\" height=\"100%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\" class=\"na-ung-dung-banner\"]\n\n[row_inner style=\"small\"]\n\n[col_inner span=\"4\" span__sm=\"12\"]\n\n[ux_image id=\"182\" image_size=\"original\" height=\"100%\"]\n\n\n[/col_inner]\n[col_inner span=\"4\" span__sm=\"12\"]\n\n[ux_image id=\"156\" image_size=\"original\" height=\"100%\"]\n\n\n[/col_inner]\n[col_inner span__sm=\"12\" bg_color=\"rgb(39, 44, 94)\" class=\"cot3\"]\n\n<h2>NA TIMBER TECH – LỰA CHỌN HOÀN HẢO CHO CÔNG TRÌNH ĐẲNG CẤP</h2>\n<p>- Nội thất xanh: vật liệu an toàn 100% cho sức khỏe, thân thiện môi trường, sang trọng và bền đẹp theo thời gian.<br />- Vật liệu lót sàn, vách ngăn: Chịu lực vượt trội X2 lần so với ván ép thông thường, chống cong vênh, thi công nhanh gọn, tiết kiệm đến 30% chi phí nhân công<br />- Coppha phủ film, đóng ghe thuyền: khả năng chống nước, kháng mối mọt hiệu quả, ngoài ra gỗ plywood NA còn tái sử dụng nhiều lần, giảm thiểu chi phí xây dựng.</p>\n\n[/col_inner]\n\n[/row_inner]\n\n[/col]\n\n[/row]\n\n[/section]\n[section label=\"Section5\" class=\"section5\"]\n\n[row style=\"small\" width=\"full-width\"]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"Dự án đã hợp tác\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_portfolio style=\"overlay\" number=\"1\" offset=\"4\" type=\"row\" col_spacing=\"xsmall\" columns=\"1\" image_height=\"65.1%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\" text_bg=\"rgba(0, 0, 0, 0)\" class=\"du-an\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_portfolio style=\"overlay\" number=\"4\" offset=\"6\" type=\"row\" col_spacing=\"xsmall\" columns=\"2\" image_height=\"65%\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" text_align=\"left\" class=\"du-an\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section]\n\n[title style=\"center\" text=\"Khách hàng nói gì về NA TimberTech\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[row]\n\n[col span=\"4\" span__sm=\"12\"]\n\n[testimonial image=\"1121\" image_width=\"121\" pos=\"center\" name=\"Anh Tuấn\" company=\"Chủ thầu nội thất tại Hà Nội\"]\n\n<p>Làm chủ thầu, tôi rất kỹ tính trong việc chọn gỗ vì ảnh hưởng trực tiếp đến uy tín. Trước đây, mấy lần gặp sự cố với gỗ kém chất lượng khiến tôi mất ăn mất ngủ. Từ khi chuyển sang plywood của NA Timber Tech, phải nói là khác hẳn: Tấm gỗ chắc chắn, ít cong vênh, thi công nhanh. Quan trọng hơn là có chứng nhận an toàn, nên tôi rất yên tâm khi dùng cho các công trình nhà phố, chung cư cao cấp.</p>\n\n[/testimonial]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[testimonial image=\"1119\" image_width=\"121\" pos=\"center\" name=\"Ms. Anna\" company=\"Khách hàng người Đức\"]\n\n<div class=\"e-box h-p2 -stacked -radius-none\">\n<p class=\"t-body h-my1\">Tôi chọn NA Timber Tech cho dự án cải tạo căn hộ của mình. Ấn tượng đầu tiên là gỗ rất chắc, bề mặt melamine sang trọng, dễ lau chùi và giữ được vẻ mới lâu. Điều khiến tôi an tâm nhất chính là chứng nhận an toàn sức khỏe – điều này quan trọng vì tôi có con nhỏ. Sau vài tháng sử dụng, nội thất vẫn bền đẹp. Tôi cảm thấy rất hài lòng</p>\n</div>\n\n[/testimonial]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[testimonial image=\"1120\" image_width=\"121\" pos=\"center\" name=\"Anh Nam\" company=\"Kiến trúc sư tại Hải Phòng\"]\n\n<p>Làm nghề hơn 15 năm, tôi đánh giá cao plywood Nam Anh ở sự ổn định: bề mặt phẳng, cắt gọt không mẻ, bám dính tốt, thi công chính xác. Sản phẩm có chứng nhận an toàn nên khách hàng yên tâm, nội thất hoàn thiện vừa bền vừa tinh tế, sang trọng – đúng tiêu chuẩn tôi mong muốn.\"</p>\n\n[/testimonial]\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"358\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.791)\" dark=\"true\" padding=\"50px\" class=\"lien-he-section\"]\n\n[row style=\"large\" width=\"custom\" custom_width=\"1110px\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n<h2>Đăng ký<span style=\"color: #f99b1c;\"> tư vấn</span></h2>\n<p>Bạn đã lựa chọn được sản phẩm NA phù hợp chưa?<br />Hãy để lại thông tin, chúng tôi sẽ liên hệ với bạn ngay!<br />Bạn muốn được tư vấn: <br />+ <a href=\"/chinh-sach/\">Chính sách dịch vụ</a><br />+ <a href=\"#\">Báo giá sản phẩm</a><br />+ <a href=\"/du-an/biet-thu,thiet-ke-noi-that/plywood-melamine/\">Cataloge / Map màu</a><br />+ <a href=\"https://zalo.me/4192416328091980939\">Liên hệ chuyên viên tư vấn</a></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[contact-form-7 id=\"505\"]\n\n\n[/col]\n\n[/row]\n\n[/section]','Trang chủ','','publish','closed','open','','trang-chu','','','2025-10-24 15:36:03','2025-10-24 08:36:03','',0,'http://namanh.local/?page_id=2',0,'page','',0),(3,1,'2022-11-27 04:01:29','2022-11-27 04:01:29','<!-- wp:heading --><h2>Who we are</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: https://webdemo.com.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Comments</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Media</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Cookies</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Embedded content from other websites</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Who we share your data with</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>How long we retain your data</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p><!-- /wp:paragraph --><!-- wp:paragraph --><p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>What rights you have over your data</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Where your data is sent</h2><!-- /wp:heading --><!-- wp:paragraph --><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p><!-- /wp:paragraph -->','Privacy Policy','','draft','closed','open','','privacy-policy','','','2022-11-27 04:01:29','2022-11-27 04:01:29','',0,'http://namanh.local/?page_id=3',0,'page','',0),(4,1,'2022-11-27 04:02:02','2022-11-27 04:02:02','{\"version\": 2, \"isGlobalStylesUserThemeJSON\": true }','Custom Styles','','publish','closed','closed','','wp-global-styles-twentytwentythree','','','2022-11-27 04:02:02','2022-11-27 04:02:02','',0,'http://namanh.local/index.php/2022/11/27/wp-global-styles-twentytwentythree/',0,'wp_global_styles','',0),(6,1,'2022-11-27 11:11:18','2022-11-27 04:11:18','','logo nội thất','logo nội thất','inherit','open','closed','','logo-noi-that','','','2022-11-27 11:11:18','2022-11-27 04:11:18','',0,'http://namanh.local/wp-content/uploads/2022/11/logo.jpg',0,'attachment','image/jpeg',0),(9,1,'2022-11-27 11:12:55','2022-11-27 04:12:55','http://namanh.local/wp-content/uploads/2022/11/cropped-logo.jpg','cropped-logo.jpg','','inherit','open','closed','','cropped-logo-jpg','','','2022-11-27 11:12:55','2022-11-27 04:12:55','',0,'http://namanh.local/wp-content/uploads/2022/11/cropped-logo.jpg',0,'attachment','image/jpeg',0),(16,1,'2022-11-27 11:22:27','2022-11-27 04:22:27','','slider01','','inherit','open','closed','','slider01','','','2022-11-27 11:22:27','2022-11-27 04:22:27','',0,'http://namanh.local/wp-content/uploads/2022/11/slider01.jpg',0,'attachment','image/jpeg',0),(17,1,'2022-11-27 11:22:28','2022-11-27 04:22:28','','slider02','','inherit','open','closed','','slider02','','','2022-11-27 11:22:28','2022-11-27 04:22:28','',0,'http://namanh.local/wp-content/uploads/2022/11/slider02.jpg',0,'attachment','image/jpeg',0),(28,1,'2022-11-27 11:26:27','2022-11-27 04:26:27','[section bg=\"329\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.61)\" dark=\"true\" padding=\"200px\" class=\"banner-top\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n[ux_text text_align=\"center\"]\n\n<div class=\"banner-content\">\n<h2>NA TIMBERTECH - NỘI THẤT XANH CHO KHÔNG GIAN THƯỢNG HẠNG</h2>\n<h5>Quality - Standards Americatrattra</h5>\n<p class=\"button-banner\"><a href=\"https://zalo.me/4192416328091980939\">Liên hệ tư vấn ngay</a></p>\n</div>\n[/ux_text]\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"40px\" class=\"gioi-thieu-1\"]\n\n[row width=\"custom\" custom_width=\"1110px\" v_align=\"middle\"]\n\n[col span=\"5\" span__sm=\"12\"]\n\n[ux_image id=\"1074\" image_size=\"original\" height=\"100%\"]\n\n[ux_image id=\"1076\" image_size=\"original\" height=\"100%\" class=\"img01\"]\n\n\n[/col]\n[col span=\"7\" span__sm=\"12\"]\n\n<h3><span style=\"color: #272c5e;\">GIỚI THIỆU DOANH NGHIỆP</span></h3>\n<h2><span style=\"color: #ff6600;\">“Tầm nhìn”</span></h2>\n<p><span style=\"font-size: 110%;\">Với tầm nhìn là người dẫn đầu NA Timber Tech: Trở thành công ty nội thất được yêu thích nhất tại Việt Nam và trên toàn thế giới mang đến những giải pháp về vật liệu nội thất hoàn thiện kiến tạo không gian sống và làm việc đẳng cấp, tiện nghi và thể hiện cá tính riêng của mỗi khách hàng. mang đến vật liệu nội thất xanh thân thiện, an toàn với con người và môi trường. chung tay bảo vệ một thế giới xanh</span></p>\n<h2><span style=\"color: #ff6600;\">“Sứ mệnh”</span></h2>\n<p>- NA TimberTech cung cấp sản phẩm và dịch vụ chất lượng từ nhà máy đến tận tay người dùng sử dụng vật liệu xanh cao cấp và quy trình chuyên nghiệp, tiêu chuẩn, chất lượng tiêu chuẩn Mỹ. <br />- NA TimberTech đề cao vật liệu bền vững, thân thiện môi trường.</p>\n\n[/col]\n[col span=\"7\" span__sm=\"12\"]\n\n<h2><span style=\"color: #ff6600;\">“Giá trị cốt lõi”</span></h2>\n<p>- NA Timber Tech liên tục nghiên cứu và ứng dụng công nghệ tiên tiến nhằm nâng cao chất lượng, tính năng và giá trị sản phẩm.<br />- Cung cấp giải pháp thiết kế nội thất sáng tạo, độc đáo, phù hợp từng nhu cầu, luôn đặt chất lượng sản phẩm và dịch vụ lên hàng đầu.<br />- Lấy khách hàng làm trung tâm, lắng nghe và tư vấn tận tình để mang đến sự hài lòng thực sự, không chỉ dừng ở việc chốt đơn.<br />- Xây dựng môi trường làm việc chuyên nghiệp, sáng tạo và đầy thử thách, khuyến khích tinh thần học hỏi và phát triển đội ngũ tinh hoa.<br />- Hợp tác với đối tác trong và ngoài nước để chia sẻ kiến thức, công nghệ, cùng phát triển ngành gỗ công nghiệp và xây dựng cộng đồng phát triển lâu dài.</p>\n\n[/col]\n[col span=\"5\" span__sm=\"12\"]\n\n[ux_image id=\"1073\" image_size=\"original\" height=\"100%\"]\n\n[ux_image id=\"358\" image_size=\"original\" height=\"100%\" class=\"img01\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"362\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.785)\" dark=\"true\" padding=\"50px\" class=\"cam-ket-section\"]\n\n[row width=\"custom\" custom_width=\"1100px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"font-size: 110%;\">LỜI CAM KẾT CỦA NAM ANH</span></h2>\n<p><span style=\"font-size: 110%;\">Nam Anh thực hiện lời tuyên thệ về sản phẩm do Nam Anh sản xuất:</span></p>\n<p><span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\">- BẢO HÀNH 5 NĂM</span></strong> hậu mãi hàng đầu Việt Nam. Chỉ sử dụng nguyên vật liệu chất lượng cao và bảo trì trọn đời sản phẩm.</span></p>\n<p><span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\">- SAI 1 ĐỀN - 10 Nam Anh</span></strong> cam kết sản xuất nội thất từ chất liệu như đã kí trong hợp đồng, nếu phát hiện ra gian lận, sai sót.</span></p>\n<p><span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\">- NGHIỆM THU 3 BÊN</span> </strong>Chúng tôi sẵn sàng để đối chất nghiệm thu với bên thứ 3 và kiểm định sản phẩm khi hoàn thành.</span></p>\n<p><span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\">- Giá thành sản phẩm của Nam Anh tối ưu nhất</span> </strong>nhưng không rẻ nhất bởi chúng tôi chỉ sử dụng nguyên vật liệu cao cấp, nói không với hàng giá rẻ hay vật liệu thay thế như một số đơn vị cấp thấp khác.</span></p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"gioi-thieu-2\"]\n\n[row style=\"large\" width=\"custom\" custom_width=\"1300px\" v_align=\"middle\"]\n\n[col span=\"5\" span__sm=\"12\"]\n\n<h3><span style=\"color: #272c5e;\">NHÀ MÁY NAM ANH</span></h3>\n<p>- Diện tích: <span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\">200.000m²</span></strong></span></p>\n<p>- Công xuất: <span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\">350.000m³/ năm</span></strong></span></p>\n<p>- Xuất khẩu: <span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\">Hơn 30+ quốc gia Mỹ, Nhật, Đức...</span></strong></span></p>\n\n[/col]\n[col span=\"7\" span__sm=\"12\"]\n\n[ux_image id=\"1079\" image_size=\"original\" class=\"img02\"]\n\n\n[/col]\n[col span__sm=\"12\"]\n\n[ux_image id=\"1335\" height=\"56%\"]\n\n\n[/col]\n\n[/row]\n[row style=\"large\" width=\"custom\" custom_width=\"1300px\" v_align=\"middle\"]\n\n[col span=\"7\" span__sm=\"12\"]\n\n[ux_image id=\"1086\" image_size=\"original\" height=\"50%\" class=\"img02\"]\n\n\n[/col]\n[col span=\"5\" span__sm=\"12\"]\n\n<p><span style=\"font-size: 110%;\"><strong><span style=\"color: #ff6600;\"> Dây chuyền sản xuất Nam Anh</span></strong></span><br />- Gỗ Nam Anh sở hữu nhà máy hiện đại với toàn bộ dây chuyền sản xuất tự động hóa 100%, tích hợp công nghệ tiên tiến bậc nhất thế giới, vận hành theo tiêu chuẩn quốc tế ISO 9001:2015 – chất lượng đạt chuẩn Hoa Kỳ.</p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section class=\"slider-thiet-bi\"]\n\n[row v_align=\"middle\"]\n\n[col span=\"5\" span__sm=\"12\"]\n\n[ux_text text_align=\"left\"]\n\n<p>Các thiết bị và công nghệ tiên tiến đang được vận hành tại Nam Anh bao gồm:</p>\n<p><strong><span style=\"font-size: 110%;\"><span style=\"color: #ff6600;\">Cold press veneer machine</span></span></strong></p>\n<p><strong><span style=\"font-size: 110%;\"><span style=\"color: #ff6600;\">Hot press machine</span></span></strong></p>\n<p><strong><span style=\"font-size: 110%;\"><span style=\"color: #ff6600;\">Cold press machine</span></span></strong></p>\n<p><strong><span style=\"font-size: 110%;\"><span style=\"color: #ff6600;\">UV curing machine </span></span></strong></p>\n<p><strong><span style=\"font-size: 110%;\"><span style=\"color: #ff6600;\">Roller Conveyor </span></span></strong></p>\n[/ux_text]\n\n[/col]\n[col span=\"7\" span__sm=\"12\"]\n\n[ux_slider]\n\n[section_inner]\n\n[ux_image_box img=\"1340\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>Cold press veneer machine</h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n[section_inner]\n\n[ux_image_box img=\"1341\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>Hot press machine</h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n[section_inner]\n\n[ux_image_box img=\"1343\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>Cold press machine</h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n[section_inner]\n\n[ux_image_box img=\"1342\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>UV curing machine</h3>\n\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n[section_inner]\n\n[ux_image_box img=\"1344\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>Roller Conveyor</h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n\n[/ux_slider]\n\n[/col]\n\n[/row]\n\n[/section]','Giới thiệu','','publish','closed','closed','','gioi-thieu','','','2025-10-24 17:36:51','2025-10-24 10:36:51','',0,'http://namanh.local/?page_id=28',0,'page','',0),(30,1,'2022-11-27 11:27:01','2022-11-27 04:27:01','[section bg_color=\"rgb(0, 0, 0)\" padding=\"0px\" class=\"section01\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"356\" image_size=\"original\" height=\"100%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n[row_inner style=\"small\"]\n\n[col_inner span=\"4\" span__sm=\"12\"]\n\n[ux_image id=\"182\" image_size=\"original\" height=\"100%\"]\n\n\n[/col_inner]\n[col_inner span=\"4\" span__sm=\"12\"]\n\n[ux_image id=\"156\" image_size=\"original\" height=\"100%\"]\n\n\n[/col_inner]\n[col_inner span__sm=\"12\" class=\"cot3\"]\n\n<h3>NỘI THẤT GỖ ÓC CHÓ</h3>\n<h2>KIẾN TẠO KHÔNG GIAN ĐẲNG CẤP THƯỢNG LƯU</h2>\n<p><span style=\"font-size: 110%;\">\"Mỹ vương\" gỗ óc chó được tạo hóa ban tặng màu sắc ấm áp, sang trọng; đường vân gỗ đẹp mê hồn; độ bền \"thách thức \" thời gian</span></p>\n\n[/col_inner]\n\n[/row_inner]\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"section02\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\">THIẾT KẾ THI CÔNG NỘI THẤT GỖ ÓC CHÓ</h2>\n<p><span style=\"font-size: 110%;\">NaDu Design tổng thầu thiết kế &amp; thi công nội thất gỗ óc chó trọn gói, Cung cấp giải pháp tổng thể, đảm bảo chất lượng công trình. Chúng tôi luôn tâm niệm, mỗi ngôi nhà là một câu chuyện cuộc đời của gia chủ. Làm sao truyền tải hết thông điệp gia chủ muốn viết thông qua ngôn ngữ là những món đồ nội thất gỗ óc chó. Như vậy là chúng tôi đã thành công. Bởi vậy, NaDu luôn cam kết: Thiết kế “độc bản”; Nội thất hoàn mỹ; thi công hoàn hảo; bảo trì trọn đời.</span></p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"156\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.901)\" dark=\"true\" padding=\"0px\" class=\"section03\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"428\" image_size=\"original\" height=\"70%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #ffffff; font-size: 140%;\">Vật liệu thi công nội thất</span></h3>\n<p><span style=\"font-size: 110%;\">Gỗ óc chó Là đơn vị uy tín, cao cấp, NaDu cam kết sử dụng <br />gỗ óc chó 100% xuất xứ Bắc Mỹ kết hợp <br />với trí tuệ KTS để tạo ra những siêu phẩm nội thất vừa sang trọng, <br />bền bỉ lại cho vẻ đẹp phù hợp mọi không gian</span></p>\n[button text=\"Xem mẫu\" color=\"white\" style=\"outline\" size=\"large\" class=\"nut-xem-them\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #ffffff; font-size: 140%;\">Vật liệu thi công nội thất</span></h3>\n<p><span style=\"font-size: 110%;\">Gỗ óc chó Là đơn vị uy tín, cao cấp, NaDu cam kết sử dụng <br />gỗ óc chó 100% xuất xứ Bắc Mỹ kết hợp <br />với trí tuệ KTS để tạo ra những siêu phẩm nội thất vừa sang trọng, <br />bền bỉ lại cho vẻ đẹp phù hợp mọi không gian</span></p>\n[button text=\"Xem mẫu\" color=\"white\" style=\"outline\" size=\"large\" class=\"nut-xem-them\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_video url=\"https://www.youtube.com/watch?v=NdEHrn6P2Rc&feature=emb_title\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"section02\"]\n\n[row width=\"custom\" custom_width=\"1100px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\">CHẾ TÁC TẠI<br /><span style=\"color: #ff6600;\">XƯỞNG NỘI THẤT HIỆN ĐẠI</span></h2>\n<p><span style=\"font-size: 110%;\">Những thớ gỗ tự nhiên Bắc Mỹ được kiểm tra nghiêm ngặt và tẩm sấy theo tiêu chuẩn quốc tế trước khi chuyển về Xưởng Sản xuất nội thất 3000m2 của NaDu. Tại đây, các nghệ nhân gỗ “thổi hồn” để chế tác thành bộ bàn, ghế, giường, tủ sinh động nhất. Sau đó được đội ngũ thợ thi công lắp đặt tại các công trình cao cấp để trao tặng không gian sống tối ưu công năng sử dụng, thẩm mỹ và sang trọng.</span></p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"208\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.866)\" dark=\"true\" padding=\"10px\" class=\"section02\"]\n\n[row style=\"collapse\" width=\"full-width\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 200px\"]\n\n<h2>QUY TRÌNH<br />SẢN XUẤT THI CÔNG NỘI THẤT GỖ ÓC CHÓ</h2>\n<p><span style=\"font-size: 110%;\">NaDu đã thiết lập quy trình hoàn thiện sản phẩm nội thất gỗ óc chó khoa học và chỉn chu nhất với những công đoạn chính như:</span></p>\n<h3><span style=\"font-size: 110%; color: #f99b1c;\">1. Công đoạn xử lý gỗ</span></h3>\n<p><span style=\"font-size: 110%;\">Lựa chọn những phiến gỗ có màu sắc và hệ vân đẹp, phù hợp với từng loại hình nhà ở, hài hòa với mỗi không gian cụ thể.</span></p>\n<h3><span style=\"font-size: 110%; color: #f99b1c;\">2. Thiết kế và chế tác sản phẩm</span></h3>\n<p><span style=\"font-size: 110%;\">Sự kết hợp hoàn hảo giữa máy móc hiện đại và bàn tay Handmade điêu luyện của người nghệ nhân để tạo nên những sản phẩm \"tinh\" nhất.</span></p>\n<h3><span style=\"font-size: 110%; color: #f99b1c;\">3. Kiểm tra và xuất xưởng</span></h3>\n<p><span style=\"font-size: 110%;\">Sản phẩm hoàn thiện sẽ được kiểm tra kỹ lưỡng mẫu mã và chất lượng sau đó đóng hộp, in rõ tem mác để xuất xưởng chuyển đến công trình lắp đặt, thi công.</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"446\" image_size=\"original\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"40px\" class=\"thi-cong-section\"]\n\n[row style=\"large\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\" align=\"center\"]\n\n<h2 style=\"text-align: left;\">Thi công nội thất gỗ óc chó</h2>\n<h3 style=\"text-align: left;\">HIỆN ĐẠI &amp; TIỆN NGHI</h3>\n<p style=\"text-align: left;\"><span style=\"font-size: 110%;\">Thi công nội thất gỗ óc chó cao cấp theo các phong cách hiện đại, tân cổ điển, luxury là thế mạnh hàng đầu của NaDu. Với những căn hộ có nền kiến trúc có sẵn, NaDu hiểu được nhu cầu thể hiện cái tôi khác biệt và tìm cách hiện thực hóa chúng bằng việc mang lại những sản phẩm nội thất có giá trị về mặt thẩm mỹ lẫn công năng. Căn hộ của quý vị chính là phiên bản duy nhất đầy cá tính.</span></p>\n[button text=\"Hotline tư vấn: 0123.456.890\" color=\"secondary\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n[button text=\"Chi tiết công trình\" style=\"outline\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_slider bullets=\"false\"]\n\n[ux_image id=\"182\" image_size=\"original\"]\n\n[ux_image id=\"356\" image_size=\"original\"]\n\n\n[/ux_slider]\n\n[/col]\n\n[/row]\n[row style=\"large\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_slider bullets=\"false\"]\n\n[ux_image id=\"182\" image_size=\"original\"]\n\n[ux_image id=\"356\" image_size=\"original\"]\n\n\n[/ux_slider]\n\n[/col]\n[col span=\"6\" span__sm=\"12\" align=\"center\"]\n\n<h2 style=\"text-align: left;\">Thiết công nội thất gỗ óc chó</h2>\n<h3 style=\"text-align: left;\">SANG TRỌNG - ĐẲNG CẤP</h3>\n<p style=\"text-align: left;\"><span style=\"font-size: 110%;\">Thiết kế thi công nội thất gỗ óc chó đặc biệt là biệt thự đòi hỏi tính chuyên nghiệp cao trong việc xử lý toàn bộ mặt bằng rộng lớn và quan tâm đến từng tiểu tiết nhỏ nhất để tạo nên không gian sống đẳng cấp, khẳng định vị thế của gia chủ. NaDu Design thấu hiểu được những ông chủ thượng lưu với cái tôi đầy bản ngã sẽ biết cách kiến tạo nên những siêu phẩm không gian phải khiến quý vị cảm thấy kiêu hãnh và tự hào</span></p>\n[button text=\"Hotline tư vấn: 0123.456.890\" color=\"secondary\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n[button text=\"Chi tiết công trình\" style=\"outline\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"156\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.785)\" dark=\"true\" padding=\"100px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"color: #f99b1c; font-size: 120%;\">ĐA DẠNG KHÔNG GIAN SỐNG</span></h2>\n<p><span style=\"font-size: 110%;\">Với đội ngũ KTS có trình độ chuyên môn cao, luôn lắng nghe và thấu hiểu nhu cầu, sở thích của khách hàng. Từ đó đưa vào trong thiết kế, truyền tải trọn vẹn trong không gian sống. Những căn biệt thự, penthouse, chung cư, nhà phố bàn giao đến khách hàng đều đảm bảo đạt đúng tiêu chuẩn chất lượng, được chăm chút từng chi tiết từ khâu thiết kế đến lựa chọn nguyên liệu và thi công.</span></p>\n<p><span style=\"font-size: 110%;\">\"Mỗi không gian sống hoàn hảo cần được chăm chút từ khi lên ý tưởng, thiết kế, sản xuất, thi công. Tất cả phải chỉn chu đến từng đường nét, chi tiết”</span></p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg_overlay=\"rgba(255, 255, 255, 0.785)\" padding=\"50px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"font-size: 130%; color: #f99b1c;\">PHONG CÁCH THƯỢNG LƯU</span><br /><span style=\"font-size: 130%;\">TÔN VINH BẢN SẮC RIÊNG</span></h2>\n<p><span style=\"font-size: 110%;\">Những không gian sống mang thương hiệu NaDu đều là sự kết hợp hài hòa giữa nội thất gỗ óc chó với các vật liệu cao cấp của các thương hiệu nổi tiếng để tạo ra tinh tế và đầy cảm xúc. Đó là phong cách sống sang trọng, đẳng cấp thượng lưu.</span></p>\n<p><span style=\"font-size: 110%;\">Những không gian sống với nội thất gỗ óc chó luôn là mong chờ của các gia chủ. Nghiên cứu và sáng tạo không ngừng, đội ngũ kiến trúc sư đã kiến tạo không gian sống dành riêng cho từng gia chủ. Đó sẽ là sự truyền tải trọn vẹn cảm xúc và nguyện vọng của chính chủ nhân ngôi nhà trong từng món đồ nội thất gỗ cao cấp.</span></p>\n\n[/col]\n\n[/row]\n[row width=\"custom\" custom_width=\"85%\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"78\" image_size=\"original\" height=\"55%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"205\" image_size=\"original\" height=\"55%\"]\n\n\n[/col]\n\n[/row]\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n[gap]\n\n<h2 style=\"text-align: center;\"><span style=\"font-size: 130%;\">KHẲNG ĐỊNH <span style=\"color: #f99b1c;\">CHẤT LƯỢNG CUỘC SỐNG</span></span></h2>\n<p style=\"text-align: left;\">Là đơn vị thiết kế thi công nội thất gỗ óc chó uy tín hàng đầu hiện nay, NaDu luôn không ngừng sáng tạo để cung cấp những sản phẩm, dịch vụ phù hợp với văn hóa, con người Việt nhưng mang chất lượng quốc tế. Những công trình biệt thự, chung cư, nhà phố mang phong cách hiện đại, sang trọng và tinh tế trong từng đường nét, chi tiết là những điều khách hành cảm nhận qua từng sản phẩm đầy tâm huyết của NaDu.</p>\n<p style=\"text-align: left;\">Kiến tạo không gian, nâng tầm đẳng cấp thượng lưu - đó là sứ mệnh của NaDu. Chúng tôi đã xây dựng những giá trị bền vững về đội ngũ nhân sự với những KTS có tài năng và dày dạn kinh nghiệm thực tiễn. Hệ thống cơ sở vật chất gồm xưởng sản xuất quy mô 3000m2, Showroom tại Lô E9, A10, KĐT Nam Trung Yên, Cầu Giấy dành riêng cho quý khách.</p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"356\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.808)\" dark=\"true\" padding=\"100px\" class=\"du-an-section\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"font-size: 130%;\">MỘT SỐ DỰ ÁN <span style=\"color: #f99b1c;\">GỖ ÓC CHÓ</span> THỰC TẾ</span></h2>\n<p style=\"text-align: center;\">Dưới đây là một số dự án thi công gỗ óc chó thực tế của chúng tôi</p>\n[gap visibility=\"hide-for-small\"]\n\n[ux_portfolio style=\"overlay\" columns=\"3\" slider_nav_style=\"simple\" slider_nav_color=\"light\" image_height=\"60%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"cau-hoi-section\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h3>1. Gỗ óc chó là gì?</h3>\n<p>Theo các tài liệu uy tín và chuyên sâu, gỗ óc chó có tên tiếng Anh là Walnut, tên khoa học là Junglan Nigra. Gỗ phân bố chủ yếu ở các nước Ba Tư cũ, các khu rừng già nước Anh, miền Nam California Mỹ và Bắc Mỹ. Trong đó, Bắc Mỹ được đánh giá là khu vực hội tụ đầy đủ các yếu tố thuận lợi để cho ra đời loại gỗ được đánh giá là có màu sắc và vân gỗ đẹp nổi bật nhất hiện nay.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>2. Màu gỗ óc chó</h3>\n<p>Gỗ óc chó là biểu tượng của đẳng cấp, hiện thân cho sự giàu sang, quyền quý. Sở hữu căn hộ gỗ óc chó là lời khẳng định chất lượng nhất về vị thế của một gia đình. Màu socolacủa óc chó được ca ngợi là sang trọng và lịch lãm.Trong quá trình chế tác đồ nội thất, dưới tác động của máy sấy hơi nước, màu này sẽ càng sắc nét, bóng đẹp hơn nhiều lần nên dễ dàng hấp dẫn được mọi ánh nhìn và tạo thiện cảm sâu sắc ngay từ lần đầu tiếp xúc.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>3. Vân gỗ óc chó</h3>\n<p>Vân gỗ cuộn xoáy, uyển chuyển là yếu tố quan trọng làm tăng thêm vẻ đẹp mê hồn của óc chó. Từng đường vân mềm mại thuần khiết và trong trẻo tựa như tái hiện trước mắt người xem một khung cảnh thiên nhiên kỳ thú, tươi mát và đắm say.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>4. Gỗ óc chó có tốt không?</h3>\n<p>Nếu như vân và màu gỗ là vẻ đẹp thu hút sự chú ý của mọi người thì chất lượng và đặc tính vượt trội về độ bền mới là điều làm nên đẳng cấp của gỗ óc chó. Một sản phẩm nội thất gỗ óc chó có tuổi thọ lên tới 30 – 50 năm nhờ sở hữu những ưu điểm nổi bật như:<br />• Khả năng kháng mối mọt tốt nên gỗ óc chó giúp bảo quản vật dụng cá nhân một cáchan toàn và vẹn nguyên nhất.<br />• Thớ gỗ óc chó cứng, chắc nên khôngdễ móp méo nếu lỡ có xảy ra va chạm.<br />• Gỗ không bị co ngót, cong vênh dù chịu tác động của thời tiết nắng nóng, ẩm ướt như tại Việt Nam.<br />• Màu sắc, vân gỗ càng dùng càng nổi bật, sáng bóng.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>5. Ứng dụng gỗ óc chó trong sản xuất nội thất</h3>\n<p>Ban đầu, gỗ óc chó được ứng dụng trong sản xuất nội thất ô tô hạng sang. Tuy vậy, với nhiều ưu điểm nổi trội cả về vẻ đẹp lẫn độ bền, gỗ óc chó đã nhanh chóng trở thành trào lưu mới trong thiết kế nội thất nhà ở cao cấp. Từ những năm 2007 – 2008, gỗ óc chó du nhập về Việt Nam và ngay lập tức nhận được sự yêu thích từ đông đảo người dùng. Vừa sở hữu vẻ ngoài hấp dẫn lại mang trong mình những đặc tính vượt trội, nên gỗ óc chó được ứng dụng đa dạng trong tất cả các không gian nội thất. Từ phòng khách, phòng ngủ cho tới không gian phòng bếp hay bất kì không gian sang trọng nào đều có thể sử dụng dòng vật liệu cao cấp này.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>6. Nội thất gỗ óc chó có đắt không?</h3>\n<p>Bạn có đang băn khoăn “Gỗ óc chó giá bao tiền 1m3?” hay “nội thất gỗ óc chó có đắt không?”. Vậy hãy cùng NaDu xem xét các khía cạnh sau đây: Tìm hiểu thị trường sẽ thấy óc chó có giá thành đắt hơn so với các loại gỗ tự nhiên khác. Tuy vậy,độ bền vững, vẻ đẹp không bay màu theo thời gian và giá trị về đẳng cấp thì hiện nay không một loại gỗ nào có thể sánh kịp với óc chó. Quý khách sẽ chỉ cần đầu tư 1 lần mà không cần bận tâm các vấn đề như hỏng hóc, lỗi mốt hay mất giá. Gỗ óc chó cũng là lựa chọn lý tưởng cho những ai muốn bảo vệ áo quần hay đồ dùng cá nhân khỏi sự tấn công của mối, mọt và các loại côn trùng gặm nhấm phổ biến khác tại Việt Nam. Hơn tất cả, với đặc tính dễ dàng uốn cong bằng hơi nước, gỗ óc chó giúp mang đến những món đồ tinh xảo bậc nhất, vừa sang trọng lại vừa độc đáo. Sở hữu nội thất gỗ óc chó cũng đã là 1 lời khẳng định cho vị thế của gia chủ - điều mà không một loại gỗ nào hiện nay có thể làm được.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>7. So sánh gỗ óc chó và gỗ hương</h3>\n<p>Nếu vẫn phân vân không biết có nên làm nội thất gỗ óc chó không thì bạn hãy đọc tiếp thông tin sau: Xét về màu sắc, gỗ óc chó có màu nâu trầm, khi lên đồ nội thất chúng sẽ mang nét đẹp của sự tinh tế, sang trọng cho căn hộ. Gỗ hương có màu hơi đỏ, tone màu sẽ sáng hơn nên thường được ứng dụng làm đồ mỹ nghệ hoặc các món đồ trang trí trong nhà. Cả hai loại này đều sở hữu những đường vân đẹp mắt, độc đáo, phù hợp với thị hiếu. Về chất lượng, độ bền, vẻ tinh xảo của từng món đồ thì gỗ óc chó luôn luôn vượt trội hơn hẳn. Gỗ hương cần tẩm sấy kỹ càng và bảo quản thật tốt nếu không muốn bị mối mọt tấn công và biến dạng do tác động của khí hậu.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>8. So sánh gỗ óc chó và gỗ sồi</h3>\n<p>Cả gỗ óc chó và gỗ sồi đều có độ bền cao, khả năng chịu lực tốt và dễ dàng tạo dáng nghệ thuật. Tuy vậy, so về tuổi thọ gỗ óc chó lại là top đầu. Gỗ sồi đỏ có màu nâu đỏ, sồi trắng cho màu trắng nhạt, tâm gỗ từ nâu nhạt đến nâu sậm, vân gỗ thẳng. Nếu yêu thích gam màu trầm và những đường vân độc đáo thì lựa chọn tốt nhất sẽ là gỗ óc chó và hướng tới màu sáng thì có thể chọn gỗ sồi.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>9. Gỗ óc chó có thân thiện với môi trường không?</h3>\n<p>Về mặt thân thiện với môi trường, gỗ óc chó là một lựa chọn tuyệt vời. Từ khâu lựa chọn giống đến chăm sóc và thu hoạch đều được giám sát bởi các quy định chặt chẽ của Hoa Kỳ.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>10. Gỗ óc chó có Có mấy loại gỗ óc chó tự nhiên trên thế giới?</h3>\n<p>Trên thế giới, có 6 loại gỗ óc chó tự nhiên gồm gỗ óc chó Anh, gỗ óc chó đen, gỗ óc chó Claro, gỗ óc chó trắng, gỗ óc chó Bastogne và gỗ óc chó Peru, trong đó nổi bật nhất là Gỗ óc chó đen hay còn gọi là Gỗ óc chó Bắc Mỹ.<br />Gỗ óc chó đen (Black Walnut) được lấy từ những cây óc chó phân bố rộng rãi ở miền Đông Hoa Kỳ. Loại gỗ tự nhiên này có màu sắc nổi bật, đường vân độc đáo và độ bền cao. Đây là lý do khiến gỗ óc chó Bắc Mỹ đen được các tín đồ nội thất ưu ái sử dụng, được nhập khẩu đến nhiều quốc gia, trong đó có Việt Nam.</p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"358\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.791)\" dark=\"true\" padding=\"50px\" class=\"lien-he-section\"]\n\n[row style=\"large\" width=\"custom\" custom_width=\"1110px\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n<h2>Đăng ký<span style=\"color: #f99b1c;\"> tư vấn</span></h2>\n<p><span style=\"font-size: 110%;\">Để có những trải nghiệm thực tế không gian nội thất gỗ óc chó tinh tế, sang trọng và đẳng cấp, Quý khách có thể tham qua trực tiếp tại Showroom Nội thất của NaDu tại Lô E9, A10, KĐT Nam Trung Yên, Cầu Giấy hoặc để lại những mong muốn tham quan các công trình thực tế tại NaDuDesign qua mẫu Đăng ký. Đội ngũ tư vấn viên của chúng tôi sẽ ngay lập tức liên lạc để cùng Quý khách kiến tạo không gian sống tối ưu, thẩm mỹ và trọn vẹn cảm xúc.</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[contact-form-7 id=\"505\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg_color=\"rgb(236, 236, 236)\" padding=\"50px\" class=\"cong-trinh-section\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"Công trình gỗ óc chó tự nhiên\" tag_name=\"h2\"]\n\n[ux_portfolio style=\"normal\" number=\"8\" type=\"row\" image_height=\"60%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"color: #ff6600;\">TÀI NĂNG VÀ TÂM HUYẾT</span> – YẾU TỐ QUYẾT ĐỊNH THÀNH CÔNG CỦA NADU</h2>\n<p><span style=\"font-size: 110%;\">Mang vẻ đẹp đắm say lòng người nhưng gỗ óc chó vẫn cần phải được tạo dáng và trau chuốt mới có thể trở thành kiệt tác nghệ thuật. Những bộ óc sáng tạo và đôi tay tài hoa vẫn luôn sẵn có tại NaDu. Nhưng điều làm nên sự khác biệt của chúng tôi chính là tình yêu, tâm huyết và sự tỉ mỉ trên từng thớ gỗ óc chó, để từ đó “khai sinh” ra những món đồ tuyệt phẩm thế gian.</span></p>\n<p><span style=\"font-size: 110%;\">Quá trình tuyển chọn kỹ càng cả về trình độ chuyên môn và đạo đức nghề nghiệp đã xây dựng lên đội ngũ nhân sự NaDu chất lượng, tinh thần trách nhiệm cao, đam mê, nhiệt huyết với nghề nghiệp trong từng giây phút. KTS NaDu luôn tìm tòi, nắm bắt những xu hướng thiết kế thịnh hành trên thế giới để sáng tạo ra những sản phẩm phù hợp với văn hóa, thẩm mỹ của người Việt. Cùng với nguồn nguyên liệu gỗ óc chó tự nhiên loại 1, nhập khẩu trực tiếp từ Bắc Mỹ, đã qua kiểm định nghiêm ngặt và được xử lí tẩm sấy theo quy trình quốc tế trước khi nhập xưởng sản xuất đã giúp NaDu tự tin đáp ứng được mọi yêu cầu cao nhất từ phía khách hàng cũng như khẳng định được thứ hạng nổi bật trong lĩnh vực nội thất.</span></p>\n<p><span style=\"font-size: 110%;\">NaDu luôn có 1 lời cam kết về chất lượng, tiến độ và tính thẩm mỹ cho sản phẩm. Đó vừa là thước đo độ tin cậy và cũng là động lực để đội ngũ KTS dồn hết tâm huyết hoàn thành công việc một cách tốt nhất.</span></p>\n<p><span style=\"font-size: 110%;\">Hãy trải nghiệm thực tế bằng cách gặp gỡ, trao đổi trực tiếp với KTS NaDu hoặc gọi qua Hotline: 0904.666.138 nếu bạn đang có nhu cầu thiết kế, thi công nội thất gỗ óc chó. NaDu rất hân hạnh khi được khách hàng trao gửi căn nhà mơ ước, sẵn sàng đưa rước khách tham quan trực tiếp xưởng gỗ, showroom sản xuất và công trình thực tế của chúng tôi.</span></p>\n\n[/col]\n\n[/row]\n[gap]\n\n[row style=\"large\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[title style=\"center\" text=\"Video gỗ óc chó\" tag_name=\"h2\"]\n\n[ux_video url=\"https://www.youtube.com/watch?v=KRrlAlYb7lU\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[title style=\"center\" text=\"Tin tức chuyên mục gỗ óc chó\" tag_name=\"h2\"]\n\n[blog_posts style=\"vertical\" type=\"row\" col_spacing=\"small\" columns=\"1\" columns__md=\"1\" posts=\"3\" show_date=\"text\" excerpt_length=\"31\" comments=\"false\" image_height=\"65%\" image_width=\"25\" image_size=\"original\" text_align=\"left\" class=\"list-post2\"]\n\n\n[/col]\n\n[/row]\n\n[/section]','Gỗ óc chó','','publish','closed','closed','','go-oc-cho','','','2022-11-27 20:51:16','2022-11-27 13:51:16','',0,'http://namanh.local/?page_id=30',0,'page','',0),(32,1,'2022-11-27 11:27:17','2022-11-27 04:27:17','[ux_image id=\"541\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" class=\"banner-overlay\"]\n\n[section padding=\"50px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1200px\"]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"THIẾT KẾ NỘI THẤT\" tag_name=\"h2\"]\n\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n<h3><span style=\"color: #f99b1c; font-size: 140%;\">01.</span> THIẾT KẾ ĐỘC BẢN</h3>\n<p>Mang lại giải pháp thiết kế tối ưu, bảo toàn công năng, tiện nghi hiện đại cho mọi loại hình nhà ở hiện nay. Chúng tôi đem đến cho khách hàng những sản phẩm ấn tượng, độc bản, mới lạ và không trùng lặp.</p>\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n<h3><span style=\"color: #f99b1c; font-size: 140%;\">02.</span> XƯỞNG SẢN XUẤT LỚN MẠNH</h3>\n<p>NaDu Design sở hữu xưởng sản xuất hơn 2000m2 được trang bị công nghệ sản xuất siêu hiện đại để cho ra đời những sản phẩm nội thất chất lượng tốt nhất thị trường, thẩm mỹ cao, giá cả tối ưu.</p>\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n<h3><span style=\"color: #f99b1c; font-size: 140%;\">03.</span> THỰC TẾ ĐẸP HƠN CẢ 3D</h3>\n<p>Công trình NaDu trao tay cho khách hàng là sản phẩm đẹp từ bản vẽ đến thực tế. Được thiết kế thi công bởi: Kiến trúc sư giàu kinh nghiệm – Thợ, kỹ thuật viên tâm huyết – Chất liệu nội thất cao cấp.</p>\n\n[/col]\n[col span__sm=\"12\" align=\"center\"]\n\n[ux_image id=\"560\" image_size=\"original\"]\n\n[title style=\"center\" text=\"Một số dự án tiêu biểu\" tag_name=\"h2\"]\n\n[ux_portfolio style=\"normal\" number=\"9\" type=\"row\" columns=\"3\" image_height=\"65%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\"]\n\n[title style=\"center\" text=\"5 phong cách thiết kế thịnh hành\" tag_name=\"h2\"]\n\n[ux_text text_align=\"left\"]\n\n<h3><span style=\"color: #ed1c24; font-size: 130%;\">Phong cách hiện đại</span></h3>\r\n<ul>\r\n 	<li><span style=\"font-size: 110%;\">Diện tích: Phù hợp với mọi loại diện tích nhà ở hiện nay</span></li>\r\n 	<li><span style=\"font-size: 110%;\">Kinh phí: Kinh phí đầu tư phù hợp với ngân sách gia chủ</span></li>\r\n</ul>\r\n<span style=\"font-size: 110%;\">Chất liệu nội thất: Thường sử dụng các chất liệu cao cấp hiện đại như gỗ óc chó, gỗ công nghiệp An Cường, đá nhân tạo, cùng các bề mặt kim loại, da cao cấp.</span>\r\n<span style=\"font-size: 110%;\">Màu sắc: Màu sắc của phong cách hiện đại thường rất linh hoạt. NaDu thường lựa chọn màu sắc chủ đạo cho căn hộ hiện đại theo các tiêu chí như: sở thích của gia chủ, đề tài theo đuổi, phối màu sáng tạo… để phù hợp với lối sống của gia đình hiện đại, năng động.</span>\r\n\r\n<span style=\"font-size: 110%;\">Phong cách hiện đại là một trong những lựa chọn vừa an toàn vừa mang tính đột phá. An toàn bởi phù hợp với cuộc sống hiện đại, đột phá bởi đây là nơi các KTS có thể \"vẫy vùng\" với những sáng tạo mà không bị bó buộc bởi bất kỳ nguyên tắc nào.</span>\n[/ux_text]\n[ux_image id=\"261\" image_size=\"original\" width=\"69\"]\n\n[ux_text text_align=\"left\"]\n\n<span style=\"font-size: 110%;\">Sáng tạo không ngừng là phương châm NaDu Design chinh phục những khách hàng khó tính của mình. Những căn hộ hiện đại được KTS NaDu sáng tạo là minh chứng cho việc không có giới hạn nào cho phong cách thiết kế nội thất hiện đại.</span>\r\n\r\n<span style=\"font-size: 110%;\">Các không gian từ phòng khách đến phòng bếp được các kiến trúc sư vẽ nên nhịp sống trọn vẹn đáp ứng được nhu cầu sinh hoạt thoải mái. Màu sắc sử dụng nhã nhặn tinh tế, mang lại cảm giác thư thái nhẹ nhàng cho gia đình yêu thích không gian tối ưu công năng, tinh tế và sang trọng.</span>\r\n\r\n<span style=\"font-size: 110%;\">NaDu Design đã tận dụng tối đa không gian và không bị lãng phí một thước đất nào trong tổng thể diện tích. Điểm nhấn trong những mẫu thiết kế nội thất chính là yếu tố \"độc bản\" với những giải pháp kiến tạo không gian \"đột phá\" thể hiện qua sự kết hợp hoàn hảo của màu sắc, ánh sáng với các vật liệu nội thất.  </span>\r\n<h3 class=\"title-boder\"><span style=\"color: #ed1c24; font-size: 130%;\">Phong cách tân cổ điển</span></h3>\r\n<ul>\r\n 	<li><span style=\"font-size: 110%;\"><strong>Diện tích:</strong> Phù hợp với căn hộ có diện tích từ 80m2</span></li>\r\n 	<li><span style=\"font-size: 110%;\"><strong>Kinh phí:</strong> Phù hợp với gia chủ có ngân sách tốt, có khả năng đầu tư</span></li>\r\n 	<li><span style=\"font-size: 110%;\"><strong>Màu sắc:</strong> Màu sắc chủ đạo thường là màu trắng, màu be hoặc màu kem kết hợp với nâu, xám, xanh rêu, đỏ booc-đô để làm nổi bật không gian tráng lệ</span></li>\r\n 	<li><span style=\"font-size: 110%;\"><strong>Chất liệu nội thất:</strong> Da, nỉ, đá hoa cương, đá pha lê, gỗ</span></li>\r\n</ul>\r\n<span style=\"font-size: 110%;\">Tân cổ điển là một trong những phong cách thiết kế thời thượng được rất nhiều khách đại gia lựa chọn.</span>\r\n\r\n<span style=\"font-size: 110%;\">Giống như việc nhắc lại thời kỳ son vàng một thuở, tân cổ điển \"kéo\" con người sống chậm lại, hưởng thụ nhiều hơn. Đây cũng là cách NaDu muốn mang lại cho quý khách những cảm xúc phải có khi sống trong ngôi nhà của mình: thư giãn, nghỉ dưỡng và gạt bỏ hết những mệt mỏi của thế giới ngoài kia.</span>\n[/ux_text]\n[ux_image id=\"267\" image_size=\"original\" width=\"69\"]\n\n[title style=\"center\" text=\"Dịch vụ thiết kế nội thất trọn gói\" tag_name=\"h2\"]\n\n<p><span style=\"font-size: 110%;\">NaDu cung cấp dịch vụ thiết kế và thi công nội thất trọn gói từ A – Z. Với vai trò là tổng thầu, NaDu sẽ trực tiếp thi công công trình, theo dõi tiến độ, đánh giá về chất lượng và hiệu quả công việc.</span></p>\n<p><span style=\"font-size: 110%;\">Thi công trọn gói khách hàng sẽ được gì?</span><br />\n<span style=\"font-size: 110%;\">Được tư vấn phương pháp tối ưu không gian sử dụng mà vẫn đảm bảo nhu cầu cá nhân và tính thẩm mỹ.</span><br />\n<span style=\"font-size: 110%;\">Tiết kiệm thời gian nhờ không phải tìm kiếm đơn vị thiết kế, đơn vị thi công, tìm mua đồ nội thất, giám sát thi công và kiểm định chất lượng. Khi đó, quý khách sẽ có nhiều thời gian để đầu tư cho công việc, con cái và bản thân.</span><br />\n<span style=\"font-size: 110%;\">Sử dụng nội thất 100% từ gỗ tự nhiên nhập khẩu, gỗ công nghiệp cao cấp An Cường với mẫu mã đa dạng, độ tinh xảo cao.</span><br />\n<span style=\"font-size: 110%;\">Tối ưu chi phí một cách tốt nhất, hạn chế tối đa chi phí phát sinh.</span><br />\n<span style=\"font-size: 110%;\">Dễ dàng theo dõi tiến độ bởi NaDu có dealine rõ ràng cho từng hạng mục. Nhận bàn giao công trình theo đúng tiến độ.</span><br />\n<span style=\"font-size: 110%;\">Hưởng chế độ bảo hành, bảo trì lâu dài và thiết thực.</span><br />\n<span style=\"font-size: 110%;\">Ngôi nhà mang vẻ đẹp hoàn hảo, thống nhất.</span><br />\n<span style=\"font-size: 110%;\">Thiết kế, thi công trọn gói là cách tốt nhất giúp tổ ấm của quý khách đạt tới đỉnh cao của sự hoàn hảo, không mất thời gian, công sức cho từng khâu mà lại có được giải pháp tối ưu hóa không gian hiệu quả và đặc biệt là kiểm soát chi phí tốt nhất. Ngoài dịch vụ trọn gói, NaDu cũng cung cấp dịch vụ thiết kế, thi công riêng biệt theo yêu cầu cụ thể của từng khách hàng.</span></p>\n[title style=\"center\" text=\"Chế độ bảo hành - bảo trì\" tag_name=\"h2\"]\n\n<p><span style=\"font-size: 110%;\">NaDu cam kết bảo hành 36 tháng và bảo trì trọn đời sản phẩm cho khách hàng. Không đợi nhắc nhở, chúng tôi luôn chủ động trong việc đảm bảo quyền và lợi ích cao nhất cho khách hàng của mình.</span></p>\n<p><span style=\"font-size: 110%;\">Với phương châm làm hài lòng khách hàng trên mọi phương diện, cung cấp dịch vụ cao cấp, đa dạng… NaDu tự tin đáp ứng được mọi đòi hỏi khắt khe nhất của bạn.</span></p>\n<p><span style=\"font-size: 110%;\">Hãy gọi tới số Hotline: 0904.666.138 hoặc để lại SĐT, KTS NaDu sẽ liên hệ tư vấn sớm nhất.</span></p>\n<p><span style=\"font-size: 110%;\">NaDu đã từng bước chinh phục những đỉnh cao bằng cách ghi dấu ấn tại nhiều công trình chung cư, biệt thự và nhà phố cao cấp tại thủ đô Hà Nội. Mời quý khách hàng cùng chiêm ngưỡng những sản phẩm mới nhất tại NaDu Design và các hạng mục thi công của chúng tôi.</span></p>\n<p><span style=\"font-size: 110%;\">ID bài viết: HD2345K</span></p>\n[title style=\"center\" text=\"Các câu hỏi của khách hàng\" tag_name=\"h2\"]\n\n[accordion auto_open=\"true\"]\n\n[accordion-item title=\"Giá thiết kế nội thất là bao nhiêu?\"]\n\n[ux_text text_align=\"left\"]\n\n<span style=\"font-size: 110%;\">Giá thiết kế nội thất của NaDu Design thường giao động từ 250.000VNĐ/M2 đến 300.000VNĐ/M2 tùy thuộc vào phong cách thiết kế mà bạn chọn. Tuy nhiên, NaDu sẽ có các chương trình áp dụng cho khách hàng thi công nội thất như: giảm 50% hoặc 100% giá thiết kế tùy thuộc vào từng chương trình khuyến mãi.</span>\r\n\r\n<span style=\"font-size: 110%;\">Bạn còn đang băn khoăn về giá hoặc các chương trình khuyến mãi hãy liên hệ tới số Hotline hoặc Zalo: 0904666138 của NaDu Design. Chúng tôi sẽ giải đáp thắc mắc của bạn</span>\n[/ux_text]\n\n[/accordion-item]\n[accordion-item title=\"Thế mạnh của NaDu là gì trong thiết kế thi công nội thất?\"]\n\n[ux_text text_align=\"left\"]\n\n<span style=\"font-size: 110%;\">Với đội ngũ kiến trúc sư đông đảo và giàu kinh nghiệm, NaDu hiện đang là đơn vị được khách hàng đánh giá cao trong việc thiết kế nội thất, tạo dựng các không gian sống chất lượng mới, tân tiến hiện đại, thời thượng cho: chung cư cao cấp, biệt thự, nhà phố.</span>\r\n\r\n<span style=\"font-size: 110%;\">NaDu tự tin với mọi loại hình nhà ở đều là những thế mạnh vượt trội với chất liệu chủ đạo như: gỗ óc chó cao cấp, gỗ công nghiệp An Cường và các nội thất cao cấp. Phong cách nổi bật: hiện đại, tân cổ điển, tối giản.</span>\n[/ux_text]\n\n[/accordion-item]\n[accordion-item title=\"Tôi cần thiết kế thi công nhà ở thì cần bao nhiêu tiền?\"]\n\n<p><span style=\"font-size: 110%;\">Giá thiết kế thi công nhà ở bao gồm các chi phí sau:</span></p>\n<p><span style=\"font-size: 110%;\">Chi phí thiết kế: Giá thiết kế nội thất nhà ở của NaDu giao động từ: 150.000VNĐ/M2 đến 250.000VNĐ/M2 tùy thuộc vào phong cách thiết kế mà quý vị lựa chọn.</span></p>\n<p><span style=\"font-size: 110%;\">Chi phí thi công:. Chi phí thi công trọn gói của NaDu phụ thuộc vào các yếu tố: phong cách thiết kế, ngân sách của gia chủ. Tùy thuộc vào từng ngân sách và KTS sẽ đưa ra các bản vẽ tối ưu khác nhau. Vậy nên, hãy thương thảo với KTS về khả năng tài chính của bạn để KTS đưa ra những bản vẽ phù hợp.</span></p>\n<p><span style=\"font-size: 110%;\">Ngoài ra, nếu khách hàng thiết kế và thi công nội thất ở NaDu, chi phí thiết kế sẽ được giảm từ 50% đến 100% tùy vào chương trình khuyến mãi vào từng thời điểm.</span></p>\n\n[/accordion-item]\n[accordion-item title=\"Sẽ làm sao nếu như chúng tôi không hài lòng với bản thiết kế?\"]\n\n<p><span style=\"font-size: 110%;\">Trong quá trình thiết kế công trình, các KTS sẽ làm việc trực tiếp với các quý khách hàng. Từ việc lên bản vẽ 2D đến 3D, chúng tôi đều trực tiếp thương thảo với quý vị từng bước một. Nếu khách hàng không hài lòng chỗ nào chúng tôi sẽ lắng nghe, góp ý, đề xuất ý tưởng và đưa ra những giải pháp tốt nhất.</span></p>\n<p><span style=\"font-size: 110%;\">Bản vẽ cuối cùng mà NaDu mang lại chính là sản phẩm hoàn hảo được thừa hưởng trọn vẹn ý tưởng của khách hàng và đội ngũ chuyên môn của NaDu. Khách hàng hoàn toàn yên tâm vì quý vị sẽ là người phê duyệt từng bước một trong thiết kế của NaDu.</span></p>\n\n[/accordion-item]\n[accordion-item title=\"Tôi đã có bản vẽ phù hợp và muốn NaDu thi công được không?\"]\n\n<p><span style=\"font-size: 110%;\">Được. NaDu tôn trọng thiết kế mà quý khách ưng ý và đáp ứng lại một cách hoàn hảo nhất để công trình giống bản vẽ 100%.</span></p>\n<p><span style=\"font-size: 110%;\">NaDu Design sẽ xem bản thiết kế mà bạn có, sau đó căn cứ vào số liệu chính xác của bản vẽ để lên danh sách các sản phẩm và báo giá một cách rõ ràng chi tiết tới quý khách.</span></p>\n<p><span style=\"font-size: 110%;\">Nếu quý khách đồng ý với bảng báo giá, NaDu sẽ lên tiến hành lên tiến độ thi công, ký kết hợp đồng và thực hiện theo những gì hợp đồng đã đưa ra.</span></p>\n\n[/accordion-item]\n[accordion-item title=\"Tôi muốn cải tạo căn hộ 70m2 thì cần bao nhiêu tiền?\"]\n\n<p><span style=\"font-size: 110%;\">Tùy thuộc vào ngân sách của khách hàng mà NaDu Design sẽ đưa ra các phương án, các gói thiết kế thi công cải tạo để khách hàng lựa chọn. Tuy nhiên, NaDu chỉ thiết kế và thi công bằng các nội thất có chất lượng cao, tốt và bền đẹp (không sử dụng các mặt hàng giá rẻ đại trà).</span></p>\n\n[/accordion-item]\n[accordion-item title=\"Tôi chỉ có nhu cầu thiết kế, không có nhu cầu thi công có được không?\"]\n\n<p><span style=\"font-size: 110%;\">Tất nhiên, NaDu Design thường có có các hợp đồng thiết kế - thi công riêng biệt. Sau khi ký kết hợp đồng thiết kế và mang lại bản vẽ ưng ý cho khách hàng, việc thi công hay không hoàn toàn tùy thuộc vào lựa chọn của quý khách. Nếu khách hàng đồng ý thi công, NaDu sẽ đưa ra bảng báo giá và hợp đồng để khách hàng tham khảo và ký kết.</span></p>\n\n[/accordion-item]\n[accordion-item title=\"Nếu chúng tôi sử dụng thiết kế của NaDu và thuê một bên khác để thi công có được không?\"]\n\n<p><span style=\"font-size: 110%;\">Điều này bạn có quyền để lựa chọn. Bạn có thể chọn NaDu để thiết kế và thuê một đơn vị khác để thi công. Tuy nhiên, NaDu sẽ không đảm bảo chất lượng công trình bạn nhận được sẽ giống 100% bản vẽ 3D, bởi NaDu không kiểm soát được các sản phẩm và chất liệu nội thất mà đơn vị khác sẽ sử dụng cho căn hộ của bạn.</span></p>\n\n[/accordion-item]\n[accordion-item title=\"Bản thiết kế căn hộ của tôi có bị copy hay trùng lặp không?\"]\n\n<p><span style=\"font-size: 110%;\">NaDu nói không với những thiết kế trùng lặp, đụng hàng. Tiêu chí của chúng tôi trong thiết kế đó chính là: độc bản, khác biệt. NaDu nghiêm cấm các KTS của mình copy và rập khuôn trong thiết kế. Chúng tôi đề cao sự sáng tạo, mới lạ và kích hoạt sự đam mê cho các KTS. Sáng tạo, sáng tạo và sáng tạo không ngừng chính là kim chỉ nam trong hoạt động thiết kế của NaDu.</span></p>\n\n[/accordion-item]\n\n[/accordion]\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg_color=\"rgb(240, 240, 240)\" padding=\"60px\" class=\"thiet-ke-noi-that\"]\n\n[row]\n\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"205\" image_height=\"40%\" image_size=\"original\" image_hover=\"zoom\"]\n\n<h3 style=\"text-align: center;\">Thiết kế nội thất biệt thự</h3>\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"356\" image_height=\"40%\" image_size=\"original\" image_hover=\"zoom\"]\n\n<h3 style=\"text-align: center;\">Thiết kế nội thất chung cư</h3>\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"261\" image_height=\"40%\" image_size=\"original\" image_hover=\"zoom\"]\n\n<h3 style=\"text-align: center;\">Thiết kế nội thất nhà phố</h3>\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"182\" image_height=\"40%\" image_size=\"original\" image_hover=\"zoom\"]\n\n<h3 style=\"text-align: center;\">Thiết kế nội thất gỗ óc chó</h3>\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"201\" image_height=\"40%\" image_size=\"original\" image_hover=\"zoom\"]\n\n<h3 style=\"text-align: center;\">Thiết kế nội thất cao cấp</h3>\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"156\" image_height=\"40%\" image_size=\"original\" image_hover=\"zoom\"]\n\n<h3 style=\"text-align: center;\">Thiết kế nội thất theo yêu cầu</h3>\n\n[/ux_image_box]\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"thiet-ke-noi-that thietke-noithat2\"]\n\n[row v_align=\"middle\"]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"QUy trình thiết kế nội thất\" tag_name=\"h2\"]\n\n<p style=\"text-align: center;\">Với kinh nghiệm trên 7 năm trong lĩnh vực thiết kế nội thất cao cấp,<br />\nNaDu Design cung cấp dịch vụ thiết kế và thi công trọn gói. Chúng tôi đã hoàn thiện bộ quy trình bài bản và chuyên nghiệp.<br />\nThông qua đó, đội ngũ của Nadu Design nghiêm túc tuân thủ để đảm bảo tiến độ làm việc và chất lượng cho công trình.<br />\nNhờ vậy, gia chủ có thể nắm rõ được từng bước và vững tâm tin tưởng.</p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"358\" image_size=\"original\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[accordion auto_open=\"true\"]\n\n[accordion-item title=\"BƯỚC 1: TIẾP NHẬN VÀ TƯ VẤN\"]\n\n<p><span style=\"font-size: 110%;\">Tiếp nhận thông tin khách hàng có nhu cầu thiết kế nội thất.</span></p>\n<p><span style=\"font-size: 110%;\">Chuyên viên của NaDu Design tiếp xúc với khách hàng và tìm hiểu về yêu cầu thiết kế của khách hàng. Chuyên viên mời khách lên thăm căn hộ mẫu, tư vấn và bóc giá sơ bộ cho khách ngay tại khu căn hộ mẫu. Tiếp theo là phổ biến quy trình thiết kế và quy trình sản xuất.</span></p>\n<p><span style=\"font-size: 110%;\">NaDu Design triển khai hợp đồng thiết kế và tiến hành tạm ứng chi phí thiết kế.</span></p>\n\n[/accordion-item]\n[accordion-item title=\"BƯỚC 2: TRIỂN KHAI THIẾT KẾ\"]\n\n<p><span style=\"font-size: 110%;\">KTS sẽ gọi điện hẹn quý khách thời gian gặp gỡ để triển khai công việc chi tiết.</span></p>\n<p><span style=\"font-size: 110%;\">KTS trực tiếp tới công trình: khảo sát, đo đạc chi tiết, chụp ảnh hiện trạng và xem xét tất cả các yếu tố ảnh hưởng tới thiết kế.</span></p>\n\n[/accordion-item]\n[accordion-item title=\"BƯỚC 3: BÀN GIAO THIẾT KẾ\"]\n\n<p>Hồ sơ thiết kế (2D, 3D) được hoàn thiện trong vòng 15 - 20 ngày làm việc của KTS.</p>\n<p>Bàn giao thiết kế cho khách, thanh lý hợp đồng thiết kế.<br />\nChuyển sang giai đoạn Thi Công Nội Thất</p>\n\n[/accordion-item]\n\n[/accordion]\n\n[/col]\n\n[/row]\n\n[/section]','Thiết kế nội thất','','publish','closed','closed','','thiet-ke-noi-that','','','2022-11-28 16:46:08','2022-11-28 09:46:08','',0,'http://namanh.local/?page_id=32',0,'page','',0),(34,1,'2022-11-27 11:27:23','2022-11-27 04:27:23','[ux_image id=\"1265\" height=\"30%\" image_overlay=\"rgba(0, 0, 0, 0)\"]\n\n[section padding=\"50px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1200px\"]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"PHỤ KIỆN\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n<p><span style=\"font-size: 110%;\">Thi công nội thất trọn gói - Phụ kiện chất lượng cao là dịch vụ giúp tiết kiệm tối đa thời gian, công sức và tiền bạc cho chủ đầu tư. Thay vì phải tự tay lên kế hoạch sắp xếp hoàn toàn mọi công việc như tìm vật liệu, đơn giá, so sánh đơn giá, dự toán chi phí, tìm nhà thầu, giám sát chất lượng thi công… Nam Anh sẽ trực tiếp lo liệu thay bạn. Chúng tôi có kinh nghiệm lâu năm trong ngành luôn sẵn danh sách những thầu phụ làm việc hiệu quả, chất lượng.</span></p>\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n<h3><span style=\"color: #272c5e; font-size: 140%;\">01.</span> DỊCH VỤ TOÀN DIỆN</h3>\n<p>Với tiềm lực mạnh mẽ, chúng tôi cung cấp giải pháp toàn diện từ thiết kế, thi công đến hoàn thiện nội thất cao cấp cho nhà chung cư, nhà phố và biệt thự.</p>\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n<h3><span style=\"color: #272c5e; font-size: 140%;\">02.</span> ĐÚNG TIẾN ĐỘ</h3>\n<p>Nam Anh có quy trình và tiến độ công việc rõ ràng. Đảm bảo bàn giao sản phẩm theo đúng thời hạn cam kết. Mang lại sự hài lòng tuyệt đối cho khách hàng trong tất cả các khâu.</p>\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n<h3><span style=\"color: #272c5e; font-size: 140%;\">03.</span> TỐI ƯU CHI PHÍ</h3>\n<p>Cam kết mang đến không gian sống tiện nghi, đẳng cấp với chi phí tối ưu nhất. Dịch vụ bảo hành, bảo trì, hậu mãi luôn tốt hơn so với thị trường.</p>\n\n[/col]\n\n[/row]\n\n[/section]\n[title style=\"center\" text=\"Một số Phụ Kiện tiêu biểu\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[section bg_color=\"rgb(240, 240, 240)\" padding=\"60px\" class=\"thiet-ke-noi-that\"]\n\n[row]\n\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"1424\" image_height=\"80%\" image_size=\"original\" image_hover=\"zoom\"]\n\n[ux_text text_align=\"left\" text_color=\"rgb(39, 44, 94)\"]\n\n<h3 style=\"text-align: center;\"><strong>Bản lề bật hơi</strong></h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"1426\" image_height=\"80%\" image_size=\"original\" image_hover=\"zoom\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3 style=\"text-align: center;\"><strong>Ray bi 3 tầng không giảm chấn</strong></h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"1425\" image_height=\"80%\" image_size=\"original\" image_hover=\"zoom\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3 style=\"text-align: center;\"><strong>Ray bi 3 tầng giảm chấn</strong></h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"thiet-ke-noi-that thietke-noithat2 bang-gia-phu-kien\"]\n\n[row v_align=\"middle\"]\n\n[col span__sm=\"12\"]\n\n<table style=\"border-collapse: collapse; width: 100%; text-align: center;\" border=\"1\" cellspacing=\"0\" cellpadding=\"6\">\n<thead>\n<tr>\n<th style=\"font-size: 20px; text-align: center;\" colspan=\"6\"><span style=\"color: #272c5e;\">Bảng Giá Phụ Kiện</span></th>\n</tr>\n<tr>\n<th style=\"text-align: center;\" rowspan=\"2\"> Tên sản phẩm</th>\n<th style=\"text-align: center;\" rowspan=\"2\">Quy cách đóng gói</th>\n<th style=\"text-align: center;\" colspan=\"2\">Tiêu chuẩn</th>\n<th style=\"text-align: center;\" rowspan=\"2\">ĐVT</th>\n<th style=\"text-align: center;\" rowspan=\"2\">Giá bán (VND)<br />\n(VAT included)</th>\n</tr>\n<tr>\n<th style=\"text-align: center;\">Thông số</th>\n<th style=\"text-align: center;\">Kích thước (g)</th>\n</tr>\n</thead>\n<tbody><!-- Bản lề bật hơi --></p>\n<tr>\n<td style=\"text-align: center;\" rowspan=\"2\"> Bản Lề Bật Hơi</td>\n<td style=\"text-align: center;\">200 Cái/Thùng</td>\n<td style=\"text-align: center;\">Chất liệu: Inox 201</td>\n<td style=\"text-align: center;\">107</td>\n<td style=\"text-align: center;\">Thùng</td>\n<td style=\"text-align: center;\">16,200,000</td>\n</tr>\n<tr>\n<td style=\"text-align: center;\"> 100 Cái/Thùng</td>\n<td style=\"text-align: center;\">Chất liệu: Inox 304</td>\n<td style=\"text-align: center;\">107</td>\n<td style=\"text-align: cent