"simple\" bullets=\"false\" bullet_style=\"simple\" pause_hover=\"false\" class=\"slider-section\"]\n\n[ux_image id=\"78\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" class=\"banner-overlay\"]\n\n[ux_image id=\"78\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" class=\"banner-overlay\"]\n\n\n[/ux_slider]\n<div class=\"banner-content\">\n<h2>NA TIMBERTECH - NỘI THẤT XANH CHO KHÔNG GIAN THƯỢNG HẠNG</h2>\n<h5>Quality - Standards Americatrattra</h5>\n<ul>\n<li>- 100% nguyên vật liệu xanh, an toàn sức khỏe</li>\n<li>- Công nghệ sản xuất chuẩn Mỹ, bền đẹp vượt thời gian</li>\n<li>- Chuyên xuất khẩu qua các cường quốc Mỹ, Đức, Nhật, Canada</li>\n</ul>\n<p class=\"button-banner\"><a href=\"https://zalo.me/4192416328091980939\">Liên hệ tư vấn ngay</a></p>\n</div>\n\n[/section]\n[section label=\"Section2\" padding=\"60px\" class=\"section2 block-cong-nghe\"]\n\n[row style=\"large\"]\n\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"78\" image_height=\"80%\" image_size=\"original\" image_hover=\"zoom\"]\n\n[ux_text class=\"description-cong-nghe\"]\n\n<h3><a href=\"/thiet-ke-noi-that/\">Plato Hydro-Thermal kết hợp Nano Canxi</a></h3>\n<p>Ứng dụng công nghệ thủy nhiệt Plato (160–240°C) kết hợp Nano Canxi giúp gỗ Nam Anh đạt độ cứng chắc, bền vững, chống cong vênh và mục nát</p>\n\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"78\" image_height=\"80%\" image_size=\"original\" image_hover=\"zoom\"]\n\n[ux_text class=\"description-cong-nghe\"]\n\n<h3><a href=\"/thiet-ke-noi-that/\">Công nghệ High-frequency pressing</a></h3>\n<p>Công nghệ khắc trực tiếp trên gỗ với độ nét và độ chính xác cao, mang đến sản phẩm tinh xảo, sang trọng và khác biệt, nâng tầm giá trị công trình.</p>\n\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_image_box img=\"79\" image_height=\"80%\" image_size=\"original\" image_hover=\"zoom\"]\n\n[ux_text class=\"description-cong-nghe\"]\n\n<h3><a href=\"/thi-cong-noi-that/\">Công nghệ Acrylic Coating </a></h3>\n<p>Công nghệ phủ Acrylic cao cấp giúp bề mặt ván ép Nam Anh sáng bóng, chống trầy xước và bền đẹp theo thời gian. Mỗi lớp veneer được chọn lọc, sấy khô dưới 8% độ ẩm và ép với lực 133–150 tấn/m².</p>\n\n[/ux_text]\n\n[/ux_image_box]\n\n[/col]\n\n[/row]\n\n[/section]\n[section]\n\n[ux_slider]\n\n[section_inner]\n\n[featured_box img=\"664\"]\n\n<h3>Chất lượng vượt trội – Bền đẹp theo thời gian</h3>\n<p>NA TimberTech đạt chuẩn xuất khẩu Mỹ, Nhật, Canada,... có độ bền và độ kết dính keo gấp 2 lần ván thông thường, chống ẩm, chống cong vênh, mang lại tính thẩm mỹ lâu dài cho mọi công trình.</p>\n\n\n[/featured_box]\n\n[/section_inner]\n[section_inner]\n\n[featured_box img=\"664\"]\n\n<h3>Chất lượng vượt trội – Bền đẹp theo thời gian</h3>\n<p>NA TimberTech đạt chuẩn xuất khẩu Mỹ, Nhật, Canada,... có độ bền và độ kết dính keo gấp 2 lần ván thông thường, chống ẩm, chống cong vênh, mang lại tính thẩm mỹ lâu dài cho mọi công trình.</p>\n\n\n[/featured_box]\n\n[/section_inner]\n\n[/ux_slider]\n\n[/section]\n[section label=\"Section5\" class=\"section5\"]\n\n[row style=\"small\" width=\"full-width\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_portfolio style=\"overlay\" number=\"1\" offset=\"4\" type=\"row\" col_spacing=\"xsmall\" columns=\"1\" image_height=\"65.1%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\" text_bg=\"rgba(0, 0, 0, 0)\" class=\"du-an\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_portfolio style=\"overlay\" number=\"4\" offset=\"6\" type=\"row\" col_spacing=\"xsmall\" columns=\"2\" image_height=\"65%\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" text_align=\"left\" class=\"du-an\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section label=\"Section3\" bg_color=\"rgb(244, 244, 251)\" padding=\"0px\" class=\"section3\"]\n\n[row style=\"collapse\" width=\"full-width\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\" padding=\"100px 200px 100px 200px\"]\n\n<h4>Khám phá Showroom</h4>\n<h2>SHOWROOM nội thất NaDu!</h2>\n<p>Showroom nội thất NaDu là một biệt thự liền kề gồm 4 tầng sử dụng với diện tích 90m2/mặt sàn. Tại đây, công ty trưng bày đầy đủ các sản phẩm gỗ nội thất từ phòng khách, phòng ngủ cho đến phòng bếp… Từ đó, tạo nên trải nghiệm về một không gian sống đa chiều và rõ nét cho khách hàng.</p>\n<p>Địa chỉ: 9E, A10 - Nam Trung Yên, Phường Yên Hòa, Quận Cầu giấy, Hà Nội.</p>\n[button text=\"Hotline: 0123.456.xxx\" letter_case=\"lowercase\" style=\"outline\" size=\"large\" icon=\"icon-phone\" icon_pos=\"left\" link=\"tel:01234567890\" class=\"nut-xem-them-2\"]\n\n<div class=\"form-inner-cont\">\n<div class=\"wrapper\">\n<div class=\"form-right-inf\">\n<p class=\"action-link\"><span style=\"color: #808080;\">Hãy gọi cho chúng tôi để được tư vấn miễn phí!</span></p>\n</div>\n</div>\n</div>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_video url=\"https://www.youtube.com/watch?v=NdEHrn6P2Rc\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[ux_image_box img=\"78\" image_height=\"50%\" image_size=\"original\" image_hover=\"zoom\"]\n\n<h2><a href=\"/thiet-ke-noi-that/\">THIẾT KẾ NỘI THẤT</a></h2>\n<p>NaDu Design tự hào là đơn vị Thiết kế nội thất uy tín hàng đầu trên thị trường nội thất Việt. Chuyên tư vấn thiết kế nội thất phong cách hiện đại, sang trọng. Dịch vụ uy tín, chuyên nghiệp.</p>\n[button text=\"Xem thêm\" letter_case=\"lowercase\" style=\"outline\" radius=\"5\" icon=\"icon-angle-right\" icon_reveal=\"true\" link=\"/thiet-ke-noi-that/\" class=\"nut-xem-them\"]\n\n\n[/ux_image_box]\n[section label=\"Section 4\" class=\"section4\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"XƯỞNG NỘI THẤT - XƯỞNG SẢN XUẤT NỘI THẤT TẠI HÀ NỘI\" tag_name=\"h2\"]\n\n[ux_text text_align=\"left\"]\n\n<p>Nội thất NaDu cung cấp dịch vụ trọn gói từ : Thiết kế nội thất – Sản xuất nội thất – Thi công nội thất – Lắp đặt nội thất. Không chỉ là xưởng thiết kế nội thất mà đồng thời là xưởng đóng đồ nội thất, xưởng đóng nội thất trực tiếp không qua trung gian. Xưởng nội thất NaDu là một trong những xưởng nội thất lâu năm tại Hà Nội. Với kinh nghiệm hơn 10 năm trong nghề, xưởng sản xuất nội thất Nadu chuyên sản xuất nội thất gỗ với giá thành cạnh tranh ưu đãi, chất lượng.</p>\n<p>Nhà máy sản xuất rộng hơn 2000m vuông ngay tại thủ đô Hà Nội. Đến với NaDu, bạn sẽ thực sự yên tâm, tin tưởng từ tất cả những điều hiện hữu chứ không phải sự chủ quan từ “cảm nhận”.!</p>\n[/ux_text]\n[ux_video url=\"https://www.youtube.com/watch?v=klIDQHAtugM\"]\n\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[featured_box img=\"146\" img_width=\"40\" pos=\"left\"]\n\n<h3>TIẾN ĐỘ RÕ RÀNG</h3>\n<p>Tất cả các bước đều được tiến hành theo quy trình chuyên nghiệp, có tiến độ rõ ràng, có giám sát trực tiếp về chất lượng và đảm bảo hoàn thiện theo đúng thời gian cam kết.</p>\n\n[/featured_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[featured_box img=\"147\" img_width=\"40\" pos=\"left\"]\n\n<h3>QUY TRÌNH CHUYÊN NGHIỆP</h3>\n<p>Quy trình làm việc chuyên nghiệp sẽ giúp KTS trực tiếp phối hợp ăn ý cùng thợ thủ công để cho ra đời sản phẩm hoàn mỹ nhất.</p>\n\n[/featured_box]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[featured_box img=\"148\" img_width=\"40\" pos=\"left\"]\n\n<h3>SẢN PHẨM HOÀN HẢO</h3>\n<p>Trước khi gửi đến khách hàng, NaDu luôn kiểm tra sản phẩm một cách toàn diện.</p>\n\n[/featured_box]\n\n[/col]\n\n[/row]\n\n[/section]\n[section label=\"Section5\" class=\"section5\"]\n\n[row style=\"small\" width=\"full-width\"]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"Dự án mới hoàn thành\" tag_name=\"h2\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_portfolio style=\"overlay\" number=\"4\" type=\"row\" col_spacing=\"xsmall\" columns=\"2\" image_height=\"65%\" image_size=\"original\" image_overlay=\"rgba(0, 0, 0, 0)\" image_hover=\"zoom\" text_align=\"left\" class=