\n\n\n[/col]\n[col span=\"3\" span__sm=\"12\"]\n\n[ux_image id=\"248\" image_size=\"original\" image_hover=\"zoom\" link=\"#\" target=\"_blank\"]\n\n\n[/col]\n[col span=\"3\" span__sm=\"12\"]\n\n[ux_image id=\"247\" image_size=\"original\" image_hover=\"zoom\" link=\"#\" target=\"_blank\"]\n\n\n[/col]\n[col span=\"3\" span__sm=\"12\"]\n\n[ux_image id=\"245\" image_size=\"original\" image_hover=\"zoom\" link=\"#\" target=\"_blank\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section label=\"Secction8\" bg_color=\"rgb(237, 237, 237)\" class=\"section8\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"DỰ ÁN ĐÃ HỢP TÁC\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[blog_posts style=\"normal\" columns=\"3\" columns__md=\"1\" slider_nav_style=\"simple\" slider_nav_position=\"outside\" show_date=\"text\" excerpt_length=\"41\" comments=\"false\" image_height=\"50%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\" class=\"list-post\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section label=\"Secction8\" bg_color=\"rgb(237, 237, 237)\" class=\"section8\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"DỰ ÁN ĐÃ HỢP TÁC\" tag_name=\"h2\" color=\"rgb(39, 44, 94)\"]\n\n[blog_posts style=\"normal\" columns=\"3\" columns__md=\"1\" slider_nav_style=\"simple\" slider_nav_position=\"outside\" show_date=\"text\" excerpt_length=\"41\" comments=\"false\" image_height=\"50%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\" class=\"list-post\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"358\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.791)\" dark=\"true\" padding=\"50px\" class=\"lien-he-section\"]\n\n[row style=\"large\" width=\"custom\" custom_width=\"1110px\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n<h2>Đăng ký<span style=\"color: #f99b1c;\"> tư vấn</span></h2>\n<p>Bạn đã lựa chọn được sản phẩm NA phù hợp chưa?<br />Hãy để lại thông tin, chúng tôi sẽ liên hệ với bạn ngay!<br />Bạn muốn được tư vấn: <br />+ Chính sách dịch vụ<br />+ Báo giá sản phẩm<br />+ Cataloge / Map màu<br />+ Liên hệ chuyên viên tư vấn</p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[contact-form-7 id=\"505\"]\n\n\n[/col]\n\n[/row]\n\n[/section]','Trang chủ','','inherit','closed','closed','','2-revision-v1','','','2025-10-19 00:05:39','2025-10-18 17:05:39','',2,'http://namanh.local/?p=1091',0,'revision','',0),(1092,1,'2025-10-19 16:40:56','2025-10-19 09:40:56','[section bg_color=\"rgb(0, 0, 0)\" padding=\"0px\" class=\"section01\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"356\" image_size=\"original\" height=\"100%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n[row_inner style=\"small\"]\n\n[col_inner span=\"4\" span__sm=\"12\"]\n\n[ux_image id=\"182\" image_size=\"original\" height=\"100%\"]\n\n\n[/col_inner]\n[col_inner span=\"4\" span__sm=\"12\"]\n\n[ux_image id=\"156\" image_size=\"original\" height=\"100%\"]\n\n\n[/col_inner]\n[col_inner span__sm=\"12\" class=\"cot3\"]\n\n<h3>NỘI THẤT GỖ ÓC CHÓ</h3>\n<h2>KIẾN TẠO KHÔNG GIAN ĐẲNG CẤP THƯỢNG LƯU</h2>\n<p><span style=\"font-size: 110%;\">\"Mỹ vương\" gỗ óc chó được tạo hóa ban tặng màu sắc ấm áp, sang trọng; đường vân gỗ đẹp mê hồn; độ bền \"thách thức \" thời gian</span></p>\n\n[/col_inner]\n\n[/row_inner]\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"section02\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\">THIẾT KẾ THI CÔNG NỘI THẤT GỖ ÓC CHÓ</h2>\n<p><span style=\"font-size: 110%;\">NaDu Design tổng thầu thiết kế &amp; thi công nội thất gỗ óc chó trọn gói, Cung cấp giải pháp tổng thể, đảm bảo chất lượng công trình. Chúng tôi luôn tâm niệm, mỗi ngôi nhà là một câu chuyện cuộc đời của gia chủ. Làm sao truyền tải hết thông điệp gia chủ muốn viết thông qua ngôn ngữ là những món đồ nội thất gỗ óc chó. Như vậy là chúng tôi đã thành công. Bởi vậy, NaDu luôn cam kết: Thiết kế “độc bản”; Nội thất hoàn mỹ; thi công hoàn hảo; bảo trì trọn đời.</span></p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"156\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.901)\" dark=\"true\" padding=\"0px\" class=\"section03\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"428\" image_size=\"original\" height=\"70%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #ffffff; font-size: 140%;\">Vật liệu thi công nội thất</span></h3>\n<p><span style=\"font-size: 110%;\">Gỗ óc chó Là đơn vị uy tín, cao cấp, NaDu cam kết sử dụng <br />gỗ óc chó 100% xuất xứ Bắc Mỹ kết hợp <br />với trí tuệ KTS để tạo ra những siêu phẩm nội thất vừa sang trọng, <br />bền bỉ lại cho vẻ đẹp phù hợp mọi không gian</span></p>\n[button text=\"Xem mẫu\" color=\"white\" style=\"outline\" size=\"large\" class=\"nut-xem-them\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #ffffff; font-size: 140%;\">Vật liệu thi công nội thất</span></h3>\n<p><span style=\"font-size: 110%;\">Gỗ óc chó Là đơn vị uy tín, cao cấp, NaDu cam kết sử dụng <br />gỗ óc chó 100% xuất xứ Bắc Mỹ kết hợp <br />với trí tuệ KTS để tạo ra những siêu phẩm nội thất vừa sang trọng, <br />bền bỉ lại cho vẻ đẹp phù hợp mọi không gian</span></p>\n[button text=\"Xem mẫu\" color=\"white\" style=\"outline\" size=\"large\" class=\"nut-xem-them\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_video url=\"https://www.youtube.com/watch?v=NdEHrn6P2Rc&feature=emb_title\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"section02\"]\n\n[row width=\"custom\" custom_width=\"1100px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\">CHẾ TÁC TẠI<br /><span style=\"color: #ff6600;\">XƯỞNG NỘI THẤT HIỆN ĐẠI</span></h2>\n<p><span style=\"font-size: 110%;\">Những thớ gỗ tự nhiên Bắc Mỹ được kiểm tra nghiêm ngặt và tẩm sấy theo tiêu chuẩn quốc tế trước khi chuyển về Xưởng Sản xuất nội thất 3000m2 của NaDu. Tại đây, các nghệ nhân gỗ “thổi hồn” để chế tác thành bộ bàn, ghế, giường, tủ sinh động nhất. Sau đó được đội ngũ thợ thi công lắp đặt tại các công trình cao cấp để trao tặng không gian sống tối ưu công năng sử dụng, thẩm mỹ và sang trọng.</span></p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"208\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.866)\" dark=\"true\" padding=\"10px\" class=\"section02\"]\n\n[row style=\"collapse\" width=\"full-width\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 200px\"]\n\n<h2>QUY TRÌNH<br />SẢN XUẤT THI CÔNG NỘI THẤT GỖ ÓC CHÓ</h2>\n<p><span style=\"font-size: 110%;\">NaDu đã thiết lập quy trình hoàn thiện sản phẩm nội thất gỗ óc chó khoa học và chỉn chu nhất với những công đoạn chính như:</span></p>\n<h3><span style=\"font-size: 110%; color: #f99b1c;\">1. Công đoạn xử lý gỗ</span></h3>\n<p><span style=\"font-size: 110%;\">Lựa chọn những phiến gỗ có màu sắc và hệ vân đẹp, phù hợp với từng loại hình nhà ở, hài hòa với mỗi không gian cụ thể.</span></p>\n<h3><span style=\"font-size: 110%; color: #f99b1c;\">2. Thiết kế và chế tác sản phẩm</span></h3>\n<p><span style=\"font-size: 110%;\">Sự kết hợp hoàn hảo giữa máy móc hiện đại và bàn tay Handmade điêu luyện của người nghệ nhân để tạo nên những sản phẩm \"tinh\" nhất.</span></p>\n<h3><span style=\"font-size: 110%; color: #f99b1c;\">3. Kiểm tra và xuất xưởng</span></h3>\n<p><span style=\"font-size: 110%;\">Sản phẩm hoàn thiện sẽ được kiểm tra kỹ lưỡng mẫu mã và chất lượng sau đó đóng hộp, in rõ tem mác để xuất xưởng chuyển đến công trình lắp đặt, thi công.</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"446\" image_size=\"original\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"40px\" class=\"thi-cong-section\"]\n\n[row style=\"large\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\" align=\"center\"]\n\n<h2 style=\"text-align: left;\">Thi công nội thất gỗ óc chó</h2>\n<h3 style=\"text-align: left;\">HIỆN ĐẠI &amp; TIỆN NGHI</h3>\n<p style=\"text-align: left;\"><span style=\"font-size: 110%;\">Thi công nội thất gỗ óc chó cao cấp theo các phong cách hiện đại, tân cổ điển, luxury là thế mạnh hàng đầu của NaDu. Với những căn hộ có nền kiến trúc có sẵn, NaDu hiểu được nhu cầu thể hiện cái tôi khác biệt và tìm cách hiện thực hóa chúng bằng việc mang lại những sản phẩm nội thất có giá trị về mặt thẩm mỹ lẫn công năng. Căn hộ của quý vị chính là phiên bản duy nhất đầy cá tính.</span></p>\n[button text=\"Hotline tư vấn: 0123.456.890\" color=\"secondary\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n[button text=\"Chi tiết công trình\" style=\"outline\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_slider bullets=\"false\"]\n\n[ux_image id=\"182\" image_size=\"original\"]\n\n[ux_image id=\"356\" image_size=\"original\"]\n\n\n[/ux_slider]\n\n[/col]\n\n[/row]\n[row style=\"large\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_slider bullets=\"false\"]\n\n[ux_image id=\"182\" image_size=\"original\"]\n\n[ux_image id=\"356\" image_size=\"original\"]\n\n\n[/ux_slider]\n\n[/col]\n[col span=\"6\" span__sm=\"12\" align=\"center\"]\n\n<h2 style=\"text-align: left;\">Thiết công nội thất gỗ óc chó</h2>\n<h3 style=\"text-align: left;\">SANG TRỌNG - ĐẲNG CẤP</h3>\n<p style=\"text-align: left;\"><span style=\"font-size: 110%;\">Thiết kế thi công nội thất gỗ óc chó đặc biệt là biệt thự đòi hỏi tính chuyên nghiệp cao trong việc xử lý toàn bộ mặt bằng rộng lớn và quan tâm đến từng tiểu tiết nhỏ nhất để tạo nên không gian sống đẳng cấp, khẳng định vị thế của gia chủ. NaDu Design thấu hiểu được những ông chủ thượng lưu với cái tôi đầy bản ngã sẽ biết cách kiến tạo nên những siêu phẩm không gian phải khiến quý vị cảm thấy kiêu hãnh và tự hào</span></p>\n[button text=\"Hotline tư vấn: 0123.456.890\" color=\"secondary\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n[button text=\"Chi tiết công trình\" style=\"outline\" size=\"larger\" link=\"tel:0123546890\" class=\"nut-xem-them2\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"156\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.785)\" dark=\"true\" padding=\"100px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"color: #f99b1c; font-size: 120%;\">ĐA DẠNG KHÔNG GIAN SỐNG</span></h2>\n<p><span style=\"font-size: 110%;\">Với đội ngũ KTS có trình độ chuyên môn cao, luôn lắng nghe và thấu hiểu nhu cầu, sở thích của khách hàng. Từ đó đưa vào trong thiết kế, truyền tải trọn vẹn trong không gian sống. Những căn biệt thự, penthouse, chung cư, nhà phố bàn giao đến khách hàng đều đảm bảo đạt đúng tiêu chuẩn chất lượng, được chăm chút từng chi tiết từ khâu thiết kế đến lựa chọn nguyên liệu và thi công.</span></p>\n<p><span style=\"font-size: 110%;\">\"Mỗi không gian sống hoàn hảo cần được chăm chút từ khi lên ý tưởng, thiết kế, sản xuất, thi công. Tất cả phải chỉn chu đến từng đường nét, chi tiết”</span></p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg_overlay=\"rgba(255, 255, 255, 0.785)\" padding=\"50px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"font-size: 130%; color: #f99b1c;\">PHONG CÁCH THƯỢNG LƯU</span><br /><span style=\"font-size: 130%;\">TÔN VINH BẢN SẮC RIÊNG</span></h2>\n<p><span style=\"font-size: 110%;\">Những không gian sống mang thương hiệu NaDu đều là sự kết hợp hài hòa giữa nội thất gỗ óc chó với các vật liệu cao cấp của các thương hiệu nổi tiếng để tạo ra tinh tế và đầy cảm xúc. Đó là phong cách sống sang trọng, đẳng cấp thượng lưu.</span></p>\n<p><span style=\"font-size: 110%;\">Những không gian sống với nội thất gỗ óc chó luôn là mong chờ của các gia chủ. Nghiên cứu và sáng tạo không ngừng, đội ngũ kiến trúc sư đã kiến tạo không gian sống dành riêng cho từng gia chủ. Đó sẽ là sự truyền tải trọn vẹn cảm xúc và nguyện vọng của chính chủ nhân ngôi nhà trong từng món đồ nội thất gỗ cao cấp.</span></p>\n\n[/col]\n\n[/row]\n[row width=\"custom\" custom_width=\"85%\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"78\" image_size=\"original\" height=\"55%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"205\" image_size=\"original\" height=\"55%\"]\n\n\n[/col]\n\n[/row]\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n[gap]\n\n<h2 style=\"text-align: center;\"><span style=\"font-size: 130%;\">KHẲNG ĐỊNH <span style=\"color: #f99b1c;\">CHẤT LƯỢNG CUỘC SỐNG</span></span></h2>\n<p style=\"text-align: left;\">Là đơn vị thiết kế thi công nội thất gỗ óc chó uy tín hàng đầu hiện nay, NaDu luôn không ngừng sáng tạo để cung cấp những sản phẩm, dịch vụ phù hợp với văn hóa, con người Việt nhưng mang chất lượng quốc tế. Những công trình biệt thự, chung cư, nhà phố mang phong cách hiện đại, sang trọng và tinh tế trong từng đường nét, chi tiết là những điều khách hành cảm nhận qua từng sản phẩm đầy tâm huyết của NaDu.</p>\n<p style=\"text-align: left;\">Kiến tạo không gian, nâng tầm đẳng cấp thượng lưu - đó là sứ mệnh của NaDu. Chúng tôi đã xây dựng những giá trị bền vững về đội ngũ nhân sự với những KTS có tài năng và dày dạn kinh nghiệm thực tiễn. Hệ thống cơ sở vật chất gồm xưởng sản xuất quy mô 3000m2, Showroom tại Lô E9, A10, KĐT Nam Trung Yên, Cầu Giấy dành riêng cho quý khách.</p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"356\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.808)\" dark=\"true\" padding=\"100px\" class=\"du-an-section\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"font-size: 130%;\">MỘT SỐ DỰ ÁN <span style=\"color: #f99b1c;\">GỖ ÓC CHÓ</span> THỰC TẾ</span></h2>\n<p style=\"text-align: center;\">Dưới đây là một số dự án thi công gỗ óc chó thực tế của chúng tôi</p>\n[gap visibility=\"hide-for-small\"]\n\n[ux_portfolio style=\"overlay\" columns=\"3\" slider_nav_style=\"simple\" slider_nav_color=\"light\" image_height=\"60%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"cau-hoi-section\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h3>1. Gỗ óc chó là gì?</h3>\n<p>Theo các tài liệu uy tín và chuyên sâu, gỗ óc chó có tên tiếng Anh là Walnut, tên khoa học là Junglan Nigra. Gỗ phân bố chủ yếu ở các nước Ba Tư cũ, các khu rừng già nước Anh, miền Nam California Mỹ và Bắc Mỹ. Trong đó, Bắc Mỹ được đánh giá là khu vực hội tụ đầy đủ các yếu tố thuận lợi để cho ra đời loại gỗ được đánh giá là có màu sắc và vân gỗ đẹp nổi bật nhất hiện nay.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>2. Màu gỗ óc chó</h3>\n<p>Gỗ óc chó là biểu tượng của đẳng cấp, hiện thân cho sự giàu sang, quyền quý. Sở hữu căn hộ gỗ óc chó là lời khẳng định chất lượng nhất về vị thế của một gia đình. Màu socolacủa óc chó được ca ngợi là sang trọng và lịch lãm.Trong quá trình chế tác đồ nội thất, dưới tác động của máy sấy hơi nước, màu này sẽ càng sắc nét, bóng đẹp hơn nhiều lần nên dễ dàng hấp dẫn được mọi ánh nhìn và tạo thiện cảm sâu sắc ngay từ lần đầu tiếp xúc.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>3. Vân gỗ óc chó</h3>\n<p>Vân gỗ cuộn xoáy, uyển chuyển là yếu tố quan trọng làm tăng thêm vẻ đẹp mê hồn của óc chó. Từng đường vân mềm mại thuần khiết và trong trẻo tựa như tái hiện trước mắt người xem một khung cảnh thiên nhiên kỳ thú, tươi mát và đắm say.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>4. Gỗ óc chó có tốt không?</h3>\n<p>Nếu như vân và màu gỗ là vẻ đẹp thu hút sự chú ý của mọi người thì chất lượng và đặc tính vượt trội về độ bền mới là điều làm nên đẳng cấp của gỗ óc chó. Một sản phẩm nội thất gỗ óc chó có tuổi thọ lên tới 30 – 50 năm nhờ sở hữu những ưu điểm nổi bật như:<br />• Khả năng kháng mối mọt tốt nên gỗ óc chó giúp bảo quản vật dụng cá nhân một cáchan toàn và vẹn nguyên nhất.<br />• Thớ gỗ óc chó cứng, chắc nên khôngdễ móp méo nếu lỡ có xảy ra va chạm.<br />• Gỗ không bị co ngót, cong vênh dù chịu tác động của thời tiết nắng nóng, ẩm ướt như tại Việt Nam.<br />• Màu sắc, vân gỗ càng dùng càng nổi bật, sáng bóng.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>5. Ứng dụng gỗ óc chó trong sản xuất nội thất</h3>\n<p>Ban đầu, gỗ óc chó được ứng dụng trong sản xuất nội thất ô tô hạng sang. Tuy vậy, với nhiều ưu điểm nổi trội cả về vẻ đẹp lẫn độ bền, gỗ óc chó đã nhanh chóng trở thành trào lưu mới trong thiết kế nội thất nhà ở cao cấp. Từ những năm 2007 – 2008, gỗ óc chó du nhập về Việt Nam và ngay lập tức nhận được sự yêu thích từ đông đảo người dùng. Vừa sở hữu vẻ ngoài hấp dẫn lại mang trong mình những đặc tính vượt trội, nên gỗ óc chó được ứng dụng đa dạng trong tất cả các không gian nội thất. Từ phòng khách, phòng ngủ cho tới không gian phòng bếp hay bất kì không gian sang trọng nào đều có thể sử dụng dòng vật liệu cao cấp này.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>6. Nội thất gỗ óc chó có đắt không?</h3>\n<p>Bạn có đang băn khoăn “Gỗ óc chó giá bao tiền 1m3?” hay “nội thất gỗ óc chó có đắt không?”. Vậy hãy cùng NaDu xem xét các khía cạnh sau đây: Tìm hiểu thị trường sẽ thấy óc chó có giá thành đắt hơn so với các loại gỗ tự nhiên khác. Tuy vậy,độ bền vững, vẻ đẹp không bay màu theo thời gian và giá trị về đẳng cấp thì hiện nay không một loại gỗ nào có thể sánh kịp với óc chó. Quý khách sẽ chỉ cần đầu tư 1 lần mà không cần bận tâm các vấn đề như hỏng hóc, lỗi mốt hay mất giá. Gỗ óc chó cũng là lựa chọn lý tưởng cho những ai muốn bảo vệ áo quần hay đồ dùng cá nhân khỏi sự tấn công của mối, mọt và các loại côn trùng gặm nhấm phổ biến khác tại Việt Nam. Hơn tất cả, với đặc tính dễ dàng uốn cong bằng hơi nước, gỗ óc chó giúp mang đến những món đồ tinh xảo bậc nhất, vừa sang trọng lại vừa độc đáo. Sở hữu nội thất gỗ óc chó cũng đã là 1 lời khẳng định cho vị thế của gia chủ - điều mà không một loại gỗ nào hiện nay có thể làm được.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>7. So sánh gỗ óc chó và gỗ hương</h3>\n<p>Nếu vẫn phân vân không biết có nên làm nội thất gỗ óc chó không thì bạn hãy đọc tiếp thông tin sau: Xét về màu sắc, gỗ óc chó có màu nâu trầm, khi lên đồ nội thất chúng sẽ mang nét đẹp của sự tinh tế, sang trọng cho căn hộ. Gỗ hương có màu hơi đỏ, tone màu sẽ sáng hơn nên thường được ứng dụng làm đồ mỹ nghệ hoặc các món đồ trang trí trong nhà. Cả hai loại này đều sở hữu những đường vân đẹp mắt, độc đáo, phù hợp với thị hiếu. Về chất lượng, độ bền, vẻ tinh xảo của từng món đồ thì gỗ óc chó luôn luôn vượt trội hơn hẳn. Gỗ hương cần tẩm sấy kỹ càng và bảo quản thật tốt nếu không muốn bị mối mọt tấn công và biến dạng do tác động của khí hậu.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>8. So sánh gỗ óc chó và gỗ sồi</h3>\n<p>Cả gỗ óc chó và gỗ sồi đều có độ bền cao, khả năng chịu lực tốt và dễ dàng tạo dáng nghệ thuật. Tuy vậy, so về tuổi thọ gỗ óc chó lại là top đầu. Gỗ sồi đỏ có màu nâu đỏ, sồi trắng cho màu trắng nhạt, tâm gỗ từ nâu nhạt đến nâu sậm, vân gỗ thẳng. Nếu yêu thích gam màu trầm và những đường vân độc đáo thì lựa chọn tốt nhất sẽ là gỗ óc chó và hướng tới màu sáng thì có thể chọn gỗ sồi.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>9. Gỗ óc chó có thân thiện với môi trường không?</h3>\n<p>Về mặt thân thiện với môi trường, gỗ óc chó là một lựa chọn tuyệt vời. Từ khâu lựa chọn giống đến chăm sóc và thu hoạch đều được giám sát bởi các quy định chặt chẽ của Hoa Kỳ.</p>\n\n[/col]\n[col span__sm=\"12\"]\n\n<h3>10. Gỗ óc chó có Có mấy loại gỗ óc chó tự nhiên trên thế giới?</h3>\n<p>Trên thế giới, có 6 loại gỗ óc chó tự nhiên gồm gỗ óc chó Anh, gỗ óc chó đen, gỗ óc chó Claro, gỗ óc chó trắng, gỗ óc chó Bastogne và gỗ óc chó Peru, trong đó nổi bật nhất là Gỗ óc chó đen hay còn gọi là Gỗ óc chó Bắc Mỹ.<br />Gỗ óc chó đen (Black Walnut) được lấy từ những cây óc chó phân bố rộng rãi ở miền Đông Hoa Kỳ. Loại gỗ tự nhiên này có màu sắc nổi bật, đường vân độc đáo và độ bền cao. Đây là lý do khiến gỗ óc chó Bắc Mỹ đen được các tín đồ nội thất ưu ái sử dụng, được nhập khẩu đến nhiều quốc gia, trong đó có Việt Nam.</p>\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg=\"358\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.791)\" dark=\"true\" padding=\"50px\" class=\"lien-he-section\"]\n\n[row style=\"large\" width=\"custom\" custom_width=\"1110px\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n<h2>Đăng ký<span style=\"color: #f99b1c;\"> tư vấn</span></h2>\n<p><span style=\"font-size: 110%;\">Để có những trải nghiệm thực tế không gian nội thất gỗ óc chó tinh tế, sang trọng và đẳng cấp, Quý khách có thể tham qua trực tiếp tại Showroom Nội thất của NaDu tại Lô E9, A10, KĐT Nam Trung Yên, Cầu Giấy hoặc để lại những mong muốn tham quan các công trình thực tế tại NaDuDesign qua mẫu Đăng ký. Đội ngũ tư vấn viên của chúng tôi sẽ ngay lập tức liên lạc để cùng Quý khách kiến tạo không gian sống tối ưu, thẩm mỹ và trọn vẹn cảm xúc.</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[contact-form-7 id=\"505\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section bg_color=\"rgb(236, 236, 236)\" padding=\"50px\" class=\"cong-trinh-section\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n[title style=\"center\" text=\"Công trình gỗ óc chó tự nhiên\" tag_name=\"h2\"]\n\n[ux_portfolio style=\"normal\" number=\"8\" type=\"row\" image_height=\"60%\" image_size=\"original\" image_hover=\"zoom\" text_align=\"left\"]\n\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"50px\" class=\"khong-gian-song\"]\n\n[row width=\"custom\" custom_width=\"1110px\"]\n\n[col span__sm=\"12\"]\n\n<h2 style=\"text-align: center;\"><span style=\"color: #ff6600;\">TÀI NĂNG VÀ TÂM HUYẾT</span> – YẾU TỐ QUYẾT ĐỊNH THÀNH CÔNG CỦA NADU</h2>\n<p><span style=\"font-size: 110%;\">Mang vẻ đẹp đắm say lòng người nhưng gỗ óc chó vẫn cần phải được tạo dáng và trau chuốt mới có thể trở thành kiệt tác nghệ thuật. Những bộ óc sáng tạo và đôi tay tài hoa vẫn luôn sẵn có tại NaDu. Nhưng điều làm nên sự khác biệt của chúng tôi chính là tình yêu, tâm huyết và sự tỉ mỉ trên từng thớ gỗ óc chó, để từ đó “khai sinh” ra những món đồ tuyệt phẩm thế gian.</span></p>\n<p><span style=\"font-size: 110%;\">Quá trình tuyển chọn kỹ càng cả về trình độ chuyên môn và đạo đức nghề nghiệp đã xây dựng lên đội ngũ nhân sự NaDu chất lượng, tinh thần trách nhiệm cao, đam mê, nhiệt huyết với nghề nghiệp trong từng giây phút. KTS NaDu luôn tìm tòi, nắm bắt những xu hướng thiết kế thịnh hành trên thế giới để sáng tạo ra những sản phẩm phù hợp với văn hóa, thẩm mỹ của người Việt. Cùng với nguồn nguyên liệu gỗ óc chó tự nhiên loại 1, nhập khẩu trực tiếp từ Bắc Mỹ, đã qua kiểm định nghiêm ngặt và được xử lí tẩm sấy theo quy trình quốc tế trước khi nhập xưởng sản xuất đã giúp NaDu tự tin đáp ứng được mọi yêu cầu cao nhất từ phía khách hàng cũng như khẳng định được thứ hạng nổi bật trong lĩnh vực nội thất.</span></p>\n<p><span style=\"font-size: 110%;\">NaDu luôn có 1 lời cam kết về chất lượng, tiến độ và tính thẩm mỹ cho sản phẩm. Đó vừa là thước đo độ tin cậy và cũng là động lực để đội ngũ KTS dồn hết tâm huyết hoàn thành công việc một cách tốt nhất.</span></p>\n<p><span style=\"font-size: 110%;\">Hãy trải nghiệm thực tế bằng cách gặp gỡ, trao đổi trực tiếp với KTS NaDu hoặc gọi qua Hotline: 0904.666.138 nếu bạn đang có nhu cầu thiết kế, thi công nội thất gỗ óc chó. NaDu rất hân hạnh khi được khách hàng trao gửi căn nhà mơ ước, sẵn sàng đưa rước khách tham quan trực tiếp xưởng gỗ, showroom sản xuất và công trình thực tế của chúng tôi.</span></p>\n\n[/col]\n\n[/row]\n[gap]\n\n[row style=\"large\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[title style=\"center\" text=\"Video gỗ óc chó\" tag_name=\"h2\"]\n\n[ux_video url=\"https://www.youtube.com/watch?v=KRrlAlYb7lU\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[title style=\"center\" text=\"Tin tức chuyên mục gỗ óc chó\" tag_name=\"h2\"]\n\n[blog_posts style=\"vertical\" type=\"row\" col_spacing=\"small\" columns=\"1\" columns__md=\"1\" posts=\"3\" show_date=\"text\" excerpt_length=\"31\" comments=\"false\" image_height=\"65%\" image_width=\"25\" image_size=\"original\" text_align=\"left\" class=\"list-post2\"]\n\n\n[/col]\n\n[/row]\n\n[/section]','CMS Page','','publish','closed','closed','','cms-page','','','2025-10-19 16:40:56','2025-10-19 09:40:56','',0,'http://namanh.local/?ux_template=cms-page',0,'ux_template','',0),(1093,1,'2025-10-19 16:42:22','2025-10-19 09:42:22','[section bg_overlay=\"rgb(39, 44, 94)\" dark=\"true\" class=\"section03\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"1099\" image_size=\"original\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #fff; font-size: 140%;\">Chứng nhận phù hợp quy chuẩn khí thải của bang California và EPA Hoa Kỳ (CARB & TSCA VI)</span></h3>\n<p><span style=\"color: #fff; font-size: 110%;\">Là đơn vị uy tín, cao cấp, chúng tôi cam kết tạo ra những siêu phẩm nội thất vừa sang trọng, bền bỉ cho vẻ đẹp phù hợp mọi không gian</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #fff; font-size: 140%;\">Chứng nhận kiểm định khí thải formaldehyde ASTM D6007-22</span></h3>\n<p><span style=\"color: #fff; font-size: 110%;\">Chứng nhận BC Test xác nhận sản phẩm gỗ dán của NA TIMBER TECH đạt chuẩn quốc tế về phát thải formaldehyde – đảm bảo an toàn cho sức khỏe người dùng. Điều này giúp chủ xưởng và thợ mộc yên tâm thi công trong nhà dân; các công ty thiết kế dễ dàng duyệt hồ sơ vật liệu với chủ đầu tư, đặc biệt trong các dự án cao cấp; người tiêu dùng cuối an tâm sử dụng trong không gian sống có trẻ nhỏ, người già hoặc phòng kín.</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"1133\" image_size=\"original\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"1135\" image_size=\"original\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #fff; font-size: 140%;\">Chứng nhận an toàn hóa chất nhựa Urea Formaldehyde Resin (QM-9105)</span></h3>\n<p><span style=\"color: #fff; font-size: 110%;\"> Chứng chỉ ES-127 do tổ chức ICC-ES (Mỹ) cấp, xác nhận sản phẩm đủ tiêu chuẩn khí thải và chất lượng để xuất khẩu sang thị trường Mỹ. Với chứng nhận này, chủ xưởng có thể nhận đơn hàng từ đối tác quốc tế; công ty thiết kế tăng uy tín khi tư vấn vật liệu cao cấp; thợ mộc nhỏ có thể tham gia vào các dự án quy mô lớn; còn người tiêu dùng thì yên tâm về chất lượng đạt chuẩn xuất khẩu.</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #fff; font-size: 140%;\">Chứng nhận cơ sở sản xuất đạt chuẩn khí thải formaldehyde</span></h3>\n<p><span style=\"color: #fff; font-size: 110%;\">Chứng chỉ ES-127 do tổ chức ICC-ES (Mỹ) cấp, xác nhận sản phẩm đủ tiêu chuẩn khí thải và chất lượng để xuất khẩu sang thị trường Mỹ. Với chứng nhận này, chủ xưởng có thể nhận đơn hàng từ đối tác quốc tế; công ty thiết kế tăng uy tín khi tư vấn vật liệu cao cấp; thợ mộc nhỏ có thể tham gia vào các dự án quy mô lớn; còn người tiêu dùng thì yên tâm về chất lượng đạt chuẩn xuất khẩu.</span></p>\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"1104\" image_size=\"original\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"1117\" image_size=\"original\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #fff; font-size: 140%;\">Chứng nhận FSC (Forest Stewardship Council)</span></h3>\n<p><span style=\"color: #fff; font-size: 110%;\">Chứng chỉ FSC (Forest Stewardship Council) là minh chứng quan trọng khẳng định gỗ plywood NA Timber Tech có nguồn gốc hợp pháp, được khai thác từ rừng được quản lý bền vững, chuỗi cung ứng minh bạch. Với chứng chỉ này, sản phẩm không chỉ đảm bảo an toàn cho sức khỏe người dùng, mà còn góp phần bảo vệ môi trường và hệ sinh thái rừng. Đồng thời, việc đạt chuẩn quốc tế FSC giúp nâng cao uy tín, mở rộng cơ hội tiếp cận các thị trường khó tính như châu Âu, Mỹ, Nhật Bản.\"</span></p>\n\n[/col]\n\n[/row]\n\n[/section]','Chứng Nhận Chất Lượng','','publish','closed','closed','','chung-nhan-chat-luong','','','2025-10-20 10:57:11','2025-10-20 03:57:11','',0,'http://namanh.local/?page_id=1093',0,'page','',0),(1094,1,'2025-10-19 16:42:22','2025-10-19 09:42:22','','Chứng Nhận Chất Lượng','','inherit','closed','closed','','1093-revision-v1','','','2025-10-19 16:42:22','2025-10-19 09:42:22','',1093,'http://namanh.local/?p=1094',0,'revision','',0),(1095,1,'2025-10-19 16:58:04','2025-10-19 09:58:04','[section bg=\"156\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.901)\" dark=\"true\" padding=\"0px\" class=\"section03\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_image id=\"428\" image_size=\"original\" height=\"70%\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #ffffff; font-size: 140%;\">Vật liệu thi công nội thất</span></h3>\n<p><span style=\"font-size: 110%;\">Gỗ óc chó Là đơn vị uy tín, cao cấp, NaDu cam kết sử dụng <br />gỗ óc chó 100% xuất xứ Bắc Mỹ kết hợp <br />với trí tuệ KTS để tạo ra những siêu phẩm nội thất vừa sang trọng, <br />bền bỉ lại cho vẻ đẹp phù hợp mọi không gian</span></p>\n[button text=\"Xem mẫu\" color=\"white\" style=\"outline\" size=\"large\" class=\"nut-xem-them\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\" padding=\"50px 50px 50px 50px\"]\n\n<h3><span style=\"color: #ffffff; font-size: 140%;\">Vật liệu thi công nội thất</span></h3>\n<p><span style=\"font-size: 110%;\">Gỗ óc chó Là đơn vị uy tín, cao cấp, NaDu cam kết sử dụng <br />gỗ óc chó 100% xuất xứ Bắc Mỹ kết hợp <br />với trí tuệ KTS để tạo ra những siêu phẩm nội thất vừa sang trọng, <br />bền bỉ lại cho vẻ đẹp phù hợp mọi không gian</span></p>\n[button text=\"Xem mẫu\" color=\"white\" style=\"outline\" size=\"large\" class=\"nut-xem-them\"]\n\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[ux_video url=\"https://www.youtube.com/watch?v=NdEHrn6P2Rc&feature=emb_title\"]\n\n\n[/col]\n\n[/row]\n\n[/section]','Block 2 column','','publish','closed','closed','','block-2-column','','','2025-10-19 16:58:04','2025-10-19 09:58:04','',0,'http://namanh.local/?ux_template=block-2-column',0,'ux_template','',0),(1096,1,'2025-10-19 17:00:38','2025-10-19 10:00:38','','MSDS KEO 9105 PT-Quang Minh','','inherit','open','closed','','msds-keo-9105-pt-quang-minh','','','2025-10-19 17:00:38','2025-10-19 10:00:38','',0,'http://namanh.local/wp-content/uploads/2025/10/MSDS-KEO-9105-PT-Quang-Minh.pdf',0,'attachment','application/pdf',0),(1097,1,'2025-10-19 17:00:44','2025-10-19 10:00:44','','BC test 04122024','','inherit','open','closed','','bc-test-04122024','','','2025-10-19 17:00:44','2025-10-19 10:00:44','',0,'http://namanh.local/wp-content/uploads/2025/10/BC-test-04122024.pdf',0,'attachment','application/pdf',0),(1098,1,'2025-10-19 17:00:45','2025-10-19 10:00:45','','Chứng chỉ ES-127 2024','','inherit','open','closed','','chung-chi-es-127-2024','','','2025-10-19 17:00:45','2025-10-19 10:00:45','',0,'http://namanh.local/wp-content/uploads/2025/10/Chung-chi-ES-127-2024.pdf',0,'attachment','application/pdf',0),(1099,1,'2025-10-19 17:18:18','2025-10-19 10:18:18','','Chứng chỉ ES-127 2024','','inherit','open','closed','','chung-chi-es-127-2024-2','','','2025-10-19 17:18:36','2025-10-19 10:18:36','',0,'http://namanh.local/wp-content/uploads/2025/10/Chung-chi-ES-127-2024.jpg',0,'attachment','image/jpeg',0),(1100,1,'2025-10-19 17:18:57','2025-10-19 10:18:57','[section bg=\"156\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.901)\" dark=\"true\" padding=\"0px\" class=\"section03\"]\n\n[row style=\"collapse\" v_align=\"middle\"]\n\n[col span