>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n[section_inner]\n\n[ux_image_box img=\"1343\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>Hot press machine</h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n[section_inner]\n\n[ux_image_box img=\"1343\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>Cold press machine</h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n[section_inner]\n\n[ux_image_box img=\"1344\" image_height=\"50%\"]\n\n[ux_text text_color=\"rgb(39, 44, 94)\"]\n\n<h3>Roller Conveyor</h3>\n[/ux_text]\n\n[/ux_image_box]\n\n[/section_inner]\n\n[/ux_slider]\n\n[/col]\n\n[/row]\n\n[/section]','Giới thiệu','','inherit','closed','closed','','28-revision-v1','','','2025-10-24 17:34:24','2025-10-24 10:34:24','',28,'http://namanh.local/?p=1431',0,'revision','',0),(1432,1,'2025-10-24 17:36:24','2025-10-24 10:36:24','[section bg=\"329\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.61)\" dark=\"true\" padding=\"200px\" class=\"banner-top\"]\n\n[row]\n\n[col span__sm=\"12\"]\n\n[ux_text text_align=\"center\"]\n\n<div class=\"banner-content\">\n<h2>NA TIMBERTECH - NỘI THẤT XANH CHO KHÔNG GIAN THƯỢNG HẠNG</h2>\n<h5>Quality - Standards Americatrattra</h5>\n<p class=\"button-banner\"><a href=\"https://zalo.me/4192416328091980939\">Liên hệ tư vấn ngay</a></p>\n</div>\n[/ux_text]\n\n[/col]\n\n[/row]\n\n[/section]\n[section padding=\"40px\" class=\"gioi-thieu-1\"]\n\n[row width=\"custom\" custom_width=\"1110px\" v_align=\"middle\"]\n\n[col span=\"5\" span__sm=\"12\"]\n\n[ux_image id=\"1074\" image_size=\"original\" height=\"100%\"]\n\n[ux_image id=\"1076\" image_size=\"original\" height=\"100%\" class=\"img01\"]\n\n\n[/col]\n[col span=\"7\" span__sm=\"12\"]\n\n<h3><span style=\"color: #272c5e;\">GIỚI THIỆU DOANH NGHIỆP</span></h3>\n<h2><span style=\"color: #ff6600;\">“Tầm nhìn”</span></h2>\n<p><span style=\"font-size: 110%;\">Với tầm nhìn là người dẫn đầu NA Timber Tech: Trở thành công ty nội 